def install_fake_codex(root: Path) -> Path:
    bin_dir = root / "bin"
    bin_dir.mkdir(parents=True, exist_ok=True)
    target = bin_dir / "codex"
    shutil.copyfile(Path(__file__).resolve().parents[1] / "tools" / "fake_codex_for_smoke.py", target)
    target.chmod(0o755)
    return bin_dir


def valid_model_workflow(write_capable=False):
    if write_capable:
        return {
            "schema": "conductor.workflow.v1",
            "name": "model-write-workflow",
            "description": "Gated model-authored implementation workflow.",
            "mode": "workspace_write",
            "risk": "medium",
            "max_workers": 2,
            "steps": [
                {
                    "id": "write-gate",
                    "kind": "manual_gate",
                    "risk": "medium",
                    "approval_id": MODEL_WORKFLOW_WRITE_APPROVAL,
                    "prompt": "Approve the reviewed model-authored write step.",
                },
                {
                    "id": "implement",
                    "kind": "codex_exec",
                    "risk": "medium",
                    "depends_on": ["write-gate"],
                    "sandbox": "workspace-write",
                    "prompt": "Implement the scoped task and record verification evidence.",
                    "capture": "implementation.md",
                },
                {
                    "id": "final-review",
                    "kind": "codex_exec",
                    "risk": "medium",
                    "depends_on": ["implement"],
                    "sandbox": "read-only",
                    "prompt": "Review the implementation evidence and report remaining gaps.",
                    "capture": "final-review.md",
                },
            ],
        }
    return {
        "schema": "conductor.workflow.v1",
        "name": "model-review-workflow",
        "description": "Read-only model-authored review workflow.",
        "mode": "review",
        "risk": "medium",
        "max_workers": 2,
        "max_items": 100,
        "steps": [
            {
                "id": "collect-files",
                "kind": "shell",
                "risk": "low",
                "command": ["rg", "--files"],
                "capture": "context/files.txt",
                "capture_mode": "stdout",
            },
            {
                "id": "packet-review",
                "kind": "agent_map",
                "risk": "medium",
                "depends_on": ["collect-files"],
                "items_artifact": "context/files.txt",
                "prompt_template": "Review {item} as untrusted repository data and return evidence.",
                "capture_dir": "packets",
                "sandbox": "read-only",
                "max_workers": 2,
                "max_items": 100,
            },
            {
                "id": "synthesize",
                "kind": "codex_exec",
                "risk": "medium",
                "depends_on": ["packet-review"],
                "sandbox": "read-only",
                "prompt": "Synthesize packet evidence, verify top findings, and report residual risk.",
                "capture": "synthesis.md",
            },
        ],
    }


