class FakeAgentWorkflowRunner(WorkflowRunner):
    def __init__(
        self,
        *args,
        fail_on_calls=None,
        no_output_on_calls=None,
        symlink_on_calls=None,
        timeout_on_calls=None,
        mutate_paths_on_calls=None,
        emit_secret_logs=False,
        **kwargs,
    ):
        self.agent_calls = []
        self.fail_on_calls = set(fail_on_calls or [])
        self.no_output_on_calls = set(no_output_on_calls or [])
        self.symlink_on_calls = set(symlink_on_calls or [])
        self.timeout_on_calls = set(timeout_on_calls or [])
        self.mutate_paths_on_calls = mutate_paths_on_calls or {}
        self.emit_secret_logs = emit_secret_logs
        super().__init__(*args, **kwargs)

    def _codex_command(self, step, output_path):
        call_number = len(self.agent_calls) + 1
        self.agent_calls.append(output_path.name)
        if call_number in self.fail_on_calls:
            return ["python3", "-c", "import sys; sys.exit(7)"]
        if call_number in self.no_output_on_calls:
            return ["python3", "-c", "import sys; sys.stdin.read(); sys.exit(0)"]
        if call_number in self.timeout_on_calls:
            return ["python3", "-c", "import time; time.sleep(5)"]
        if call_number in self.symlink_on_calls:
            code = (
                "import pathlib, sys; "
                "target = pathlib.Path(sys.argv[2]); "
                "target.write_text('outside', encoding='utf-8'); "
                "path = pathlib.Path(sys.argv[1]); "
                "path.parent.mkdir(parents=True, exist_ok=True); "
                "path.symlink_to(target)"
            )
            return ["python3", "-c", code, str(output_path), str(self.workspace / "outside-output.txt")]
        if call_number in self.mutate_paths_on_calls:
            code = (
                "import pathlib, sys; "
                "pathlib.Path(sys.argv[1]).write_text(sys.stdin.read(), encoding='utf-8'); "
                "pathlib.Path(sys.argv[2]).write_text('changed during execution\\n', encoding='utf-8')"
            )
            return ["python3", "-c", code, str(output_path), str(self.mutate_paths_on_calls[call_number])]
        if self.emit_secret_logs:
            code = (
                "import pathlib, sys; "
                "print('token=stdoutsecret'); "
                "print('token=stderrsecret', file=sys.stderr); "
                "pathlib.Path(sys.argv[1]).write_text(sys.stdin.read(), encoding='utf-8')"
            )
            return ["python3", "-c", code, str(output_path)]
        code = "import pathlib, sys; pathlib.Path(sys.argv[1]).write_text(sys.stdin.read(), encoding='utf-8')"
        return ["python3", "-c", code, str(output_path)]


class SimulatedAgentMapCrash(BaseException):
    pass


class TerminalAgentMapRunner(FakeAgentWorkflowRunner):
    def __init__(
        self,
        *args,
        terminal_crash_phase=None,
        terminal_crash_index=None,
        **kwargs,
    ):
        self.terminal_crash_phase = terminal_crash_phase
        self.terminal_crash_index = terminal_crash_index
        self.terminal_crashed = False
        super().__init__(*args, **kwargs)

    def _run_process(
        self,
        argv,
        cwd,
        timeout,
        input_text=None,
        output_limit_bytes=1024 * 1024,
        stdout_line_callback=None,
        interrupt_check=None,
    ):
        del cwd, timeout, output_limit_bytes, interrupt_check
        output = Path(argv[-1])
        output.parent.mkdir(parents=True, exist_ok=True)
        output.write_text(input_text or "", encoding="utf-8")
        index = int(output.name.split("-", 1)[0])
        session_id = "00000000-0000-4000-8000-%012d" % index
        lines = [
            json.dumps({"type": "thread.started", "thread_id": session_id}),
            json.dumps({"type": "turn.started"}),
            json.dumps(
                {
                    "type": "turn.completed",
                    "usage": {
                        "input_tokens": 7,
                        "output_tokens": 3,
                        "total_tokens": 10,
                    },
                }
            ),
        ]
        if stdout_line_callback is not None:
            for line in lines:
                stdout_line_callback(line)
        return ProcessResult(returncode=0, stdout="\n".join(lines) + "\n", stderr="")

    def _agent_map_packet_terminal_checkpoint(self, phase, terminal):
        if (
            not self.terminal_crashed
            and phase == self.terminal_crash_phase
            and (
                self.terminal_crash_index is None
                or terminal["index"] == self.terminal_crash_index
            )
        ):
            self.terminal_crashed = True
            raise SimulatedAgentMapCrash(phase)


