class CheckpointCodexWorkflowRunner(WorkflowRunner):
    def __init__(self, *args, session_id=FAKE_CODEX_SESSION_ID, provider_delay=0.0, **kwargs):
        self.session_id = session_id
        self.provider_delay = provider_delay
        self.initial_commands = []
        self.resume_commands = []
        self.process_inputs = []
        super().__init__(*args, **kwargs)

    def _provider_command(self, output_path, content):
        started = json.dumps({"type": "thread.started", "thread_id": self.session_id})
        completed = json.dumps(
            {
                "type": "turn.completed",
                "thread_id": self.session_id,
                "usage": {"input_tokens": 5, "output_tokens": 2, "total_tokens": 7},
            }
        )
        code = (
            "import pathlib, sys, time; "
            "print(sys.argv[2], flush=True); "
            "time.sleep(float(sys.argv[4])); "
            "pathlib.Path(sys.argv[1]).write_text(sys.argv[3], encoding='utf-8'); "
            "print(sys.argv[5], flush=True)"
        )
        return [
            sys.executable,
            "-c",
            code,
            str(output_path),
            started,
            content,
            str(self.provider_delay),
            completed,
        ]

    def _codex_command(self, step, output_path):
        command = self._provider_command(output_path, "initial result")
        self.initial_commands.append(command)
        return command

    def _codex_resume_command(self, step, output_path, session_id):
        base = WorkflowRunner._codex_command(self, step, output_path)
        resume_command = base[:-1] + ["resume", session_id, "-"]
        self.resume_commands.append(resume_command)
        return self._provider_command(output_path, "resumed result")

    def _run_process(
        self,
        argv,
        cwd,
        timeout,
        input_text=None,
        output_limit_bytes=1024 * 1024,
        stdout_line_callback=None,
    ):
        self.process_inputs.append(input_text)
        return super()._run_process(
            argv,
            cwd,
            timeout,
            input_text=input_text,
            output_limit_bytes=output_limit_bytes,
            stdout_line_callback=stdout_line_callback,
        )


class SimulatedCodexStepCrash(BaseException):
    pass


class TerminalCodexWorkflowRunner(WorkflowRunner):
    def __init__(
        self,
        *args,
        terminal_crash_phase=None,
        completion_verdict_output=None,
        **kwargs,
    ):
        self.terminal_crash_phase = terminal_crash_phase
        self.terminal_crashed = False
        self.completion_verdict_output = completion_verdict_output
        self.provider_calls = []
        self.process_inputs = []
        super().__init__(*args, **kwargs)

    def _codex_command(self, step, output_path):
        self.provider_calls.append("started")
        return ["fake-codex", str(output_path)]

    def _codex_resume_command(self, step, output_path, session_id):
        self.provider_calls.append("resumed")
        return ["fake-codex-resume", session_id, str(output_path)]

    def _run_process(
        self,
        argv,
        cwd,
        timeout,
        input_text=None,
        output_limit_bytes=1024 * 1024,
        stdout_line_callback=None,
        interrupt_check=None,
    ):
        del cwd, timeout, output_limit_bytes, interrupt_check
        self.process_inputs.append(input_text)
        output = Path(argv[-1])
        output.parent.mkdir(parents=True, exist_ok=True)
        step = next(value for value in self.workflow["steps"] if value["id"] == "agent")
        if step.get("completion_verdict") == "strict-v1":
            verdict = self.completion_verdict_output
            if verdict is None:
                verdict = {
                    "satisfied": True,
                    "feedback": "",
                    "evidence": ["terminal recovery evidence"],
                    "confidence": "high",
                }
            output.write_text(json.dumps(verdict), encoding="utf-8")
        else:
            output.write_text("terminal result token=codexterminal", encoding="utf-8")
        if step.get("sandbox", "read-only") == "workspace-write":
            (self.workspace / "changed.txt").write_text(
                "provider result\n",
                encoding="utf-8",
            )
        lines = [
            json.dumps(
                {"type": "thread.started", "thread_id": FAKE_CODEX_SESSION_ID}
            ),
            json.dumps({"type": "turn.started"}),
            json.dumps(
                {
                    "type": "turn.completed",
                    "usage": {
                        "input_tokens": 11,
                        "output_tokens": 4,
                        "total_tokens": 15,
                    },
                }
            ),
        ]
        if stdout_line_callback is not None:
            for line in lines:
                stdout_line_callback(line)
        return ProcessResult(
            returncode=0,
            stdout="\n".join(lines) + "\n",
            stderr="",
        )

    def _codex_step_terminal_checkpoint(self, phase, terminal):
        if not self.terminal_crashed and phase == self.terminal_crash_phase:
            self.terminal_crashed = True
            raise SimulatedCodexStepCrash(phase)


PROVIDER_PROGRESS_PRIVATE_SENTINEL = "provider-private-progress-sentinel"


class ProgressEventCodexWorkflowRunner(WorkflowRunner):
    def __init__(self, *args, provider_delay=0.0, native_events=False, **kwargs):
        self.provider_delay = provider_delay
        self.native_events = native_events
        self.provider_calls = []
        super().__init__(*args, **kwargs)

    def _codex_command(self, step, output_path):
        self.provider_calls.append(output_path.name)
        return ["fake-progress-codex", str(output_path)]

    def _run_process(
        self,
        argv,
        cwd,
        timeout,
        input_text=None,
        output_limit_bytes=1024 * 1024,
        stdout_line_callback=None,
        interrupt_check=None,
    ):
        del cwd, timeout, input_text, output_limit_bytes, interrupt_check
        output = Path(argv[-1])
        output.parent.mkdir(parents=True, exist_ok=True)
        output.write_text("safe provider result\n", encoding="utf-8")
        match = re.match(r"([0-9]+)-", output.name)
        index = int(match.group(1)) if match else 1
        session_id = "00000000-0000-4000-8000-%012d" % index
        lines = [
            json.dumps({"type": "thread.started", "thread_id": session_id}),
            json.dumps({"type": "turn.started"}),
        ]
        if stdout_line_callback is not None:
            for line in lines:
                stdout_line_callback(line)
        if self.provider_delay:
            time.sleep(self.provider_delay)
        item_types = [
            "agent_message",
            "reasoning",
            "command_execution",
            "file_change",
            "mcp_tool_call",
            "web_search",
            "todo_list",
            "error",
            "unexpected_provider_item",
        ]
        for item_type in item_types:
            item = {
                "type": item_type,
                "status": "failed" if item_type == "error" else "completed",
                "text": PROVIDER_PROGRESS_PRIVATE_SENTINEL + "\x1b[2J",
                "command": "cat /private/provider/path token=provider-secret",
                "payload": {"secret": PROVIDER_PROGRESS_PRIVATE_SENTINEL},
            }
            lines.append(json.dumps({"type": "item.started", "item": item}))
            lines.append(json.dumps({"type": "item.completed", "item": item}))
        if self.native_events:
            child_a = "10000000-0000-4000-8000-%012d" % index
            child_b = "20000000-0000-4000-8000-%012d" % index
            collab_items = [
                {
                    "type": "collab_tool_call",
                    "tool": "spawn_agent",
                    "status": "completed",
                    "receiver_thread_ids": [child_a],
                    "prompt": PROVIDER_PROGRESS_PRIVATE_SENTINEL,
                    "agents_states": {
                        child_a: {
                            "status": "pending_init",
                            "message": PROVIDER_PROGRESS_PRIVATE_SENTINEL,
                        }
                    },
                },
                {
                    "type": "collab_tool_call",
                    "tool": "send_input",
                    "status": "completed",
                    "receiver_thread_ids": [child_a],
                    "prompt": PROVIDER_PROGRESS_PRIVATE_SENTINEL,
                    "agents_states": {child_a: {"status": "running"}},
                },
                {
                    "type": "collab_tool_call",
                    "tool": "wait",
                    "status": "completed",
                    "receiver_thread_ids": [child_a, child_b],
                    "agents_states": {
                        child_a: {"status": "completed"},
                        child_b: {
                            "status": "errored",
                            "message": PROVIDER_PROGRESS_PRIVATE_SENTINEL,
                        },
                    },
                },
                {
                    "type": "collab_tool_call",
                    "tool": "close_agent",
                    "status": "failed",
                    "receiver_thread_ids": [child_a],
                    "agents_states": {child_a: {"status": "shutdown"}},
                },
            ]
            for item_index, item in enumerate(collab_items):
                lines.append(json.dumps({"type": "item.started", "item": item}))
                if item_index == 0:
                    updated = copy.deepcopy(item)
                    updated["agents_states"][child_a]["status"] = "running"
                    lines.append(json.dumps({"type": "item.updated", "item": updated}))
                lines.append(json.dumps({"type": "item.completed", "item": item}))
        lines.extend(
            [
                json.dumps(
                    {
                        "type": "turn.completed",
                        "usage": {
                            "input_tokens": 31,
                            "output_tokens": 9,
                            "total_tokens": 40,
                        },
                    }
                ),
            ]
        )
        if stdout_line_callback is not None:
            for line in lines[2:]:
                stdout_line_callback(line)
        return ProcessResult(
            returncode=0,
            stdout="\n".join(lines) + "\n",
            stderr="",
        )


def mark_codex_run_interrupted(run, step_id="agent"):
    checkpoint = load_codex_step_checkpoint(run, step_id)
    checkpoint["status"] = "active"
    checkpoint["finished_at_utc"] = None
    checkpoint["output_sha256"] = None
    checkpoint["error_class"] = None
    write_codex_step_checkpoint(run, checkpoint)
    state = run.read_state()
    previous = dict(state["steps"][step_id])
    previous["status"] = "running"
    previous["detail"] = "provider process interrupted before terminal state"
    previous.pop("finished_at_utc", None)
    previous.pop("duration_ms", None)
    state["steps"][step_id] = previous
    state["status"] = "running"
    state.pop("finished_at_utc", None)
    state.pop("duration_ms", None)
    run.save_state(state)
    return checkpoint


class RuntimeWorkflowTests(unittest.TestCase):
    def test_skill_interface_metadata_matches_current_contract(self):
        project_root = Path(__file__).resolve().parents[1]
        metadata = (project_root / "codex-conductor" / "agents" / "openai.yaml").read_text(encoding="utf-8")
        self.assertIn('display_name: "Codex Conductor"', metadata)
