    @unittest.skipUnless(os.name == "posix", "direct zipapp execution requires POSIX")
    def test_packaged_runtime_is_directly_executable_and_excludes_bytecode(self):
        project_root = Path(__file__).resolve().parents[1]
        with tempfile.TemporaryDirectory() as tmp:
            dist = Path(tmp) / "dist"
            packaged = subprocess.run(
                [sys.executable, "-B", str(project_root / "tools" / "package_runtime.py"), str(dist)],
                cwd=str(project_root),
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                timeout=30,
            )
            self.assertEqual(packaged.returncode, 0, packaged.stderr)
            runtime = dist / "conductor-runtime.pyz"
            packaged_extras = subprocess.run(
                [sys.executable, "-B", str(project_root / "tools" / "package_extras.py"), str(dist)],
                cwd=str(project_root),
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                timeout=30,
            )
            self.assertEqual(packaged_extras.returncode, 0, packaged_extras.stderr)
            extras = dist / "conductor-extras.pyz"
            self.assertTrue(os.access(runtime, os.X_OK))
            self.assertTrue(runtime.read_bytes().startswith(b"#!/usr/bin/env python3\n"))
            with zipfile.ZipFile(runtime) as archive:
                self.assertIsNone(archive.testzip())
                self.assertIn("conductor_runtime/core/runner.py", archive.namelist())
                self.assertNotIn("conductor_runtime/routine_service.py", archive.namelist())
                self.assertFalse(any(name.startswith("conductor_extras/") for name in archive.namelist()))
                self.assertFalse(any(name.startswith("tools/") for name in archive.namelist()))
                self.assertFalse(
                    any("__pycache__" in name or name.endswith(".pyc") for name in archive.namelist())
                )
            with zipfile.ZipFile(dist / "codex-conductor-bundle.zip") as archive:
                self.assertIsNone(archive.testzip())
                self.assertFalse(
                    any("__pycache__" in name or name.endswith(".pyc") for name in archive.namelist())
                )
                self.assertIn("install.py", archive.namelist())
                self.assertIn("release-manifest.json", archive.namelist())
                self.assertFalse(any(name.startswith("tools/") for name in archive.namelist()))
                self.assertFalse(any(name.startswith(".claude/") for name in archive.namelist()))
                self.assertFalse(any(name.startswith("benchmark-suites/") for name in archive.namelist()))
                self.assertNotIn(".claude/settings.local.json", archive.namelist())
            with zipfile.ZipFile(extras) as archive:
                self.assertIsNone(archive.testzip())
                self.assertIn("conductor_extras/runtime/routine_service.py", archive.namelist())
                self.assertIn("tools/evaluate_implementation_canary.py", archive.namelist())
            second_dist = Path(tmp) / "dist-second"
            packaged_again = subprocess.run(
                [sys.executable, "-B", str(project_root / "tools" / "package_runtime.py"), str(second_dist)],
                cwd=str(project_root),
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                timeout=30,
            )
            self.assertEqual(packaged_again.returncode, 0, packaged_again.stderr)
            self.assertEqual(runtime.read_bytes(), (second_dist / "conductor-runtime.pyz").read_bytes())
            self.assertEqual(
                (dist / "codex-conductor-bundle.zip").read_bytes(),
                (second_dist / "codex-conductor-bundle.zip").read_bytes(),
            )
            self.assertEqual(
                (dist / "release-manifest.json").read_bytes(),
                (second_dist / "release-manifest.json").read_bytes(),
            )
            self.assertEqual(
                (dist / "codex-conductor-marketplace.zip").read_bytes(),
                (second_dist / "codex-conductor-marketplace.zip").read_bytes(),
            )
            packaged_extras_again = subprocess.run(
                [sys.executable, "-B", str(project_root / "tools" / "package_extras.py"), str(second_dist)],
                cwd=str(project_root),
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                timeout=30,
            )
            self.assertEqual(packaged_extras_again.returncode, 0, packaged_extras_again.stderr)
            self.assertEqual(extras.read_bytes(), (second_dist / "conductor-extras.pyz").read_bytes())
            invoked = subprocess.run(
                [str(runtime), "--version"],
                cwd=str(project_root),
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                timeout=10,
            )
            self.assertEqual(invoked.returncode, 0, invoked.stderr)
            self.assertRegex(invoked.stdout.strip(), r"^conductor-runtime \d+\.\d+\.\d+$")
            internal_proxy = subprocess.run(
                [str(extras), "_skill-mcp-stdio-proxy"],
                cwd=str(project_root),
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                timeout=10,
            )
            self.assertEqual(internal_proxy.returncode, 126)
            self.assertEqual(
                internal_proxy.stderr,
                "Conductor rejected the selected Skill stdio MCP launch.\n",
            )

            suite = Path(tmp) / "packaged-benchmark.json"
            suite.write_text(
                json.dumps(
                    {
                        "schema": "conductor.benchmark.v1",
                        "name": "packaged-runtime-child-import",
                        "tasks": [
                            {
                                "id": "runtime-version",
                                "command": ["printf", "extras-ready"],
                                "success_contains": "extras-ready",
                            }
                        ],
                    }
                )
                + "\n",
                encoding="utf-8",
            )
            packaged_benchmark = subprocess.run(
                [
                    str(extras),
                    "benchmark",
                    str(suite),
                    "--system",
                    "conductor",
                ],
                cwd=str(tmp),
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                timeout=10,
            )
            self.assertEqual(packaged_benchmark.returncode, 0, packaged_benchmark.stderr)
            packaged_report = json.loads(packaged_benchmark.stdout)
            self.assertEqual(packaged_report["passed_tasks"], 1)
            self.assertEqual(packaged_report["failed_tasks"], 0)

            saved_dir = Path(tmp) / ".claude" / "workflows"
            saved_dir.mkdir(parents=True)
            (saved_dir / "packaged-result.js").write_text(
                "export const meta = { name: 'packaged-result', phases: [{ title: 'Review' }] }\n"
                "const TOPICS = [{ key: 'correctness', prompt: 'Review correctness.' }]\n"
                "const RESULT_SCHEMA = { type: 'object', properties: { finding: { type: 'string' } }, required: ['finding'] }\n"
                "phase('Review')\n"
                "const reports = (await parallel(TOPICS.map(topic => () => agent(`${topic.prompt} Return one finding.`, { label: `review:${topic.key}`, phase: 'Review', schema: RESULT_SCHEMA })))).filter(Boolean)\n"
                "return reports\n",
                encoding="utf-8",
            )
            packaged_saved = subprocess.run(
                [
                    str(extras),
                    "run-saved-workflow",
                    "packaged-result",
                    "--workspace",
                    str(tmp),
                    "--runs-dir",
                    str(Path(tmp) / "saved-runs"),
                    "--run-id",
                    "packaged-result-dry-run",
                    "--dry-run",
                    "--allow-agent",
                    "--allow-parallel",
                ],
                cwd=str(tmp),
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                timeout=10,
            )
            self.assertEqual(packaged_saved.returncode, 0, packaged_saved.stderr)
            self.assertIn("Result artifact (planned):", packaged_saved.stdout)
            packaged_workflow = json.loads(
                (
                    Path(tmp)
                    / "saved-runs"
                    / "packaged-result-dry-run"
                    / "workflow.json"
                ).read_text(encoding="utf-8")
            )
            self.assertEqual(packaged_workflow["steps"][-1]["kind"], "collect_results")
            self.assertEqual(packaged_workflow["steps"][0]["kind"], "agent_map")
            self.assertEqual(packaged_workflow["steps"][0]["item_semantics"], "opaque")
            self.assertEqual(packaged_workflow["steps"][0]["phase"], "Review")
            self.assertEqual(
                packaged_workflow["result_artifact"],
                "claude-workflow/result.json",
            )

    def test_default_storage_paths_are_workspace_scoped_and_outside_repository(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workspace = root / "workspace"
            workspace.mkdir()
            home = root / "conductor-home"

            with patch.dict(os.environ, {"CODEX_CONDUCTOR_HOME": str(home)}):
                runs_dir = default_runs_dir(workspace)
                self.assertEqual(runs_dir.parent, home / "workspaces" / runs_dir.parent.name)
                self.assertEqual(default_goals_dir(workspace).parent, runs_dir.parent)
                self.assertEqual(default_benchmarks_dir(workspace).parent, runs_dir.parent)
                self.assertEqual(default_dashboard_path(workspace).parent, runs_dir.parent)
                self.assertNotIn(".codex-conductor", runs_dir.parts)

    def test_cli_run_default_storage_does_not_create_repo_local_state(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workspace = root / "workspace"
            workspace.mkdir()
            home = root / "conductor-home"
            workflow_path = workspace / "workflow.json"
            write_json(
                workflow_path,
                workflow_with_steps(
                    [
                        {
                            "id": "noop",
                            "kind": "shell",
                            "risk": "low",
                            "writes": False,
                            "command": ["printf", "ok"],
                        }
                    ]
                ),
            )

            stdout = StringIO()
            with patch.dict(os.environ, {"CODEX_CONDUCTOR_HOME": str(home)}):
                expected_runs_dir = default_runs_dir(workspace)
                with redirect_stdout(stdout):
                    code = cli_main(["run", str(workflow_path), "--workspace", str(workspace), "--dry-run"])

            self.assertEqual(code, 0)
            self.assertFalse((workspace / ".codex-conductor").exists())
            run_line = next(line for line in stdout.getvalue().splitlines() if line.startswith("Run directory: "))
            run_dir = Path(run_line.split(": ", 1)[1])
            self.assertEqual(run_dir.parent, expected_runs_dir)
            self.assertTrue(run_dir.is_dir())
            self.assertEqual(run_dir.parents[3], home)

    def test_repository_templates_validate(self):
        for path in sorted(Path("conductor-workflows").glob("*.json")):
            with self.subTest(path=path):
                load_workflow(path)

    def test_load_workflow_rejects_symlinked_workflow_path(self):
        workflow = workflow_with_steps(
            [
                {"id": "one", "kind": "write_artifact", "output": "one.txt", "content": "one"},
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            target = root / "workflow.json"
            write_json(target, workflow)
            link = root / "linked-workflow.json"
            try:
                link.symlink_to(target)
            except OSError:
                self.skipTest("symlinks are not supported on this filesystem")
            with self.assertRaises(ValidationError) as caught:
                load_workflow(link)
            self.assertIn("workflow must not be a symlink", str(caught.exception))

    def test_load_workflow_rejects_oversized_workflow_json(self):
        with tempfile.TemporaryDirectory() as tmp:
            path = Path(tmp) / "workflow.json"
            path.write_text(" " * (MAX_WORKFLOW_JSON_BYTES + 1), encoding="utf-8")
            with self.assertRaises(ValidationError) as caught:
                load_workflow(path)
            self.assertIn("workflow must be at most", str(caught.exception))

    def test_list_rejects_symlinked_workflow_directory_without_listing_target(self):
        workflow = workflow_with_steps(
            [
                {"id": "one", "kind": "write_artifact", "output": "one.txt", "content": "one"},
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            target_dir = root / "real-workflows"
            target_dir.mkdir()
            secret_path = target_dir / "token=workflowsecret.json"
            write_json(secret_path, workflow)
            linked_dir = root / "linked-workflows"
            try:
                linked_dir.symlink_to(target_dir, target_is_directory=True)
            except OSError:
                self.skipTest("directory symlinks are not supported on this filesystem")

            stdout = StringIO()
            stderr = StringIO()
            with redirect_stdout(stdout), redirect_stderr(stderr):
                code = cli_main(["list", str(linked_dir)])

            self.assertEqual(code, 2)
            self.assertIn("workflow path must not be a symlink", stderr.getvalue())
            self.assertNotIn("workflowsecret", stdout.getvalue() + stderr.getvalue())

