    def test_workflow_schema_encodes_structural_validator_constraints(self):
        workflow_schema = get_schema("workflow")
        self.assertNotIn("type", workflow_schema["properties"]["description"])
        step_schemas = workflow_schema["properties"]["steps"]["items"]["oneOf"]
        shell_schema = next(schema for schema in step_schemas if schema["properties"]["kind"]["const"] == "shell")
        command_schema = shell_schema["properties"]["command"]
        command_string_schema = next(schema for schema in command_schema["oneOf"] if schema.get("type") == "string")
        command_pattern = re.compile(command_string_schema["pattern"])
        self.assertRegex("printf ok", command_pattern)
        self.assertNotRegex("   ", command_pattern)
        for metachar in SHELL_METACHARS:
            self.assertNotRegex("printf%sok" % metachar, command_pattern)
        for hint in ["writes", "destructive", "network", "external_path"]:
            self.assertNotIn("type", shell_schema["properties"][hint])
        self.assertNotIn("type", shell_schema["properties"]["description"])

        agent_map_schema = next(schema for schema in step_schemas if schema["properties"]["kind"]["const"] == "agent_map")
        item_variants = agent_map_schema["properties"]["items"]["items"]["anyOf"]
        opaque_item_schema = next(
            schema for schema in item_variants if schema.get("type") == "string"
        )
        json_item_schema = next(
            schema for schema in item_variants if schema.get("type") == "object"
        )
        self.assertEqual(opaque_item_schema["maxLength"], MAX_OPAQUE_PACKET_ITEM_CHARS)
        self.assertEqual(json_item_schema["minProperties"], 1)
        opaque_semantics = next(
            condition
            for condition in agent_map_schema["allOf"]
            if condition.get("if", {}).get("properties", {}).get("item_semantics")
            == {"const": "opaque"}
        )
        self.assertEqual(
            opaque_semantics["then"]["properties"]["items"]["items"]["type"],
            "string",
        )
        item_schema = agent_map_schema["allOf"][1]["then"]["properties"]["items"]["items"]
        item_pattern = re.compile(item_schema["pattern"])
        self.assertEqual(item_schema["maxLength"], MAX_PACKET_ITEM_CHARS)
        self.assertRegex("src/file.py", item_pattern)
        self.assertRegex(" src/file.py ", item_pattern)
        for bad_item in ["", "   ", "/tmp/file", " ../file", "../file", "src/../file", "a\nb", "a\0b"]:
            self.assertNotRegex(bad_item, item_pattern)

