    def test_write_schema_writes_new_file_and_rejects_overwrite_symlink_and_unknown(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            output = root / "workflow.schema.json"
            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(["write-schema", "workflow", str(output)])
            self.assertEqual(code, 0)
            self.assertIn("Schema written:", stdout.getvalue())
            payload = json.loads(output.read_text(encoding="utf-8"))
            self.assertEqual(payload["properties"]["schema"]["const"], "conductor.workflow.v1")

            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(["write-schema", "workflow", str(output)])
            self.assertEqual(code, 2)
            self.assertIn("schema output already exists", stderr.getvalue())

            link = root / "linked.schema.json"
            try:
                link.symlink_to(output)
            except OSError:
                self.skipTest("symlinks are not supported on this filesystem")
            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(["write-schema", "workflow", str(link)])
            self.assertEqual(code, 2)
            self.assertIn("schema output already exists", stderr.getvalue())

            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(["schema", "missing"])
            self.assertEqual(code, 2)
            self.assertIn("unknown schema type: missing", stderr.getvalue())

