    def test_prepare_run_writes_launch_manifest_and_remains_resumable(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "gate",
                    "kind": "manual_gate",
                    "approval_id": "continue",
                    "prompt": "continue",
                },
                {
                    "id": "write",
                    "kind": "write_artifact",
                    "depends_on": ["gate"],
                    "output": "prepared.txt",
                    "content": "prepared run executed",
                },
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workflow_path = root / "workflow.json"
            write_json(workflow_path, workflow)
            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(
                    [
                        "prepare-run",
                        str(workflow_path),
                        "--workspace",
                        str(root),
                        "--runs-dir",
                        str(root / "runs"),
                        "--run-id",
                        "prepared-run",
                        "--allow-writes",
                        "--approve",
                        "continue",
                    ]
                )
            self.assertEqual(code, 0)
            self.assertIn("Prepared run directory:", stdout.getvalue())
            self.assertIn("Status: needs_resume", stdout.getvalue())
            self.assertNotIn("--approve continue", stdout.getvalue())

            run_dir = root / "runs" / "prepared-run"
            state = json.loads((run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["status"], "needs_resume")
            self.assertEqual(state["steps"]["gate"]["status"], "planned")
            self.assertEqual(state["steps"]["write"]["status"], "planned")
            self.assertNotIn("finished_at_utc", state)
            self.assertEqual(state["prepared_run"]["schema"], "conductor.prepared_run.v1")
            self.assertTrue(state["prepared_run"]["no_process_started"])

            launch = json.loads((run_dir / "launch.json").read_text(encoding="utf-8"))
            launch_text = json.dumps(launch)
            self.assertEqual(launch["schema"], "conductor.launch_manifest.v1")
            self.assertEqual(launch["kind"], "prepared-run")
            self.assertTrue(launch["no_process_started"])
            self.assertEqual(launch["process_model"], "operator-owned external launch")
            self.assertEqual(launch["preflight"]["status"], "planned")
            self.assertTrue(launch["policy"]["allow_writes"])
            self.assertEqual(launch["policy"]["approval_count"], 1)
            self.assertFalse(launch["policy"]["approval_values_persisted"])
            self.assertNotIn("--approve", launch_text)
            self.assertNotIn("continue", launch["resume_command"])
            self.assertIn("--resume", launch["resume_command_argv"])
            self.assertIn(str(run_dir), launch["resume_command_argv"])
            self.assertFalse((run_dir / "artifacts" / "prepared.txt").exists())

            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(
                    [
                        "run",
                        str(workflow_path),
                        "--workspace",
                        str(root),
                        "--runs-dir",
                        str(root / "runs"),
                        "--resume",
                        str(run_dir),
                        "--allow-writes",
                        "--approve",
                        "continue",
                    ]
                )
            self.assertEqual(code, 0)
            self.assertIn("Status: completed", stdout.getvalue())
            final_state = json.loads((run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(final_state["status"], "completed")
            self.assertEqual(final_state["steps"]["write"]["status"], "completed")
            self.assertEqual(
                (run_dir / "artifacts" / "prepared.txt").read_text(encoding="utf-8"),
                "prepared run executed",
            )

    def test_background_run_detaches_and_hands_approval_through_anonymous_pipe(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "gate",
                    "kind": "manual_gate",
                    "approval_id": "background-continue",
                    "prompt": "Approve this detached integration test.",
                },
                {
                    "id": "delay",
                    "kind": "shell",
                    "risk": "low",
                    "writes": False,
                    "command": ["sleep", "1"],
                    "depends_on": ["gate"],
                },
                {
                    "id": "record",
                    "kind": "write_artifact",
                    "output": "background-result.txt",
                    "content": "detached run completed",
                    "depends_on": ["delay"],
                },
            ]
        )
        workflow["name"] = "background-integration"
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workflow_path = root / "workflow.json"
            write_json(workflow_path, workflow)
            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(
                    [
                        "start-background-run",
                        str(workflow_path),
                        "--workspace",
                        str(root),
                        "--runs-dir",
                        str(root / "runs"),
                        "--run-id",
                        "background-integration-run",
                        "--approve",
                        "background-continue",
                    ]
                )
            self.assertEqual(code, 0)
            self.assertIn("Status: active", stdout.getvalue())

            run_dir = root / "runs" / "background-integration-run"
            metadata = load_background_run(run_dir)
            pid = metadata["worker"]["pid"]
            self.assertEqual(metadata["schema"], BACKGROUND_RUN_SCHEMA)
            self.assertEqual(metadata["status"], "active")
            self.assertTrue(metadata["worker"]["detached_session"])
            self.assertEqual(metadata["worker"]["process_group_id"], pid)
            self.assertEqual(metadata["worker"]["session_id"], pid)
            self.assertEqual(metadata["policy"]["approval_count"], 1)
            self.assertFalse(metadata["policy"]["approval_values_persisted"])
            self.assertFalse(metadata["handoff"]["payload_persisted"])
            self.assertFalse(metadata["handoff"]["daemon_installed"])
            self.assertNotIn("--approve", metadata["worker"]["argv"])
            self.assertFalse((run_dir / "artifacts" / "background-result.txt").exists())

            wait_stdout = StringIO()
            with redirect_stdout(wait_stdout):
                wait_code = cli_main(
                    [
                        "wait-background-run",
                        str(run_dir),
                        "--timeout-seconds",
                        "15",
                        "--poll-interval-ms",
                        "50",
                    ]
                )
            self.assertEqual(wait_code, 0)
            final = json.loads(wait_stdout.getvalue())
            self.assertEqual(final["status"], "finished")
            self.assertEqual(final["run_status"], "completed")
            self.assertEqual(final["exit_code"], 0)
            self.assertEqual(
                (run_dir / "artifacts" / "background-result.txt").read_text(encoding="utf-8"),
                "detached run completed",
            )
            final_state = json.loads((run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(final_state["status"], "completed")
            self.assertEqual(final_state["background_run"]["status"], "finished")
            self.assertFalse(final_state["background_run"]["approval_values_persisted"])
            self.assertNotIn("background-continue", (run_dir / "background.json").read_text(encoding="utf-8"))
            self.assertNotIn("background-continue", (run_dir / "launch.json").read_text(encoding="utf-8"))
            self.assertNotIn("background-continue", (run_dir / "logs" / "background-worker.stdout.log").read_text(encoding="utf-8"))
            self.assertNotIn("background-continue", (run_dir / "logs" / "background-worker.stderr.log").read_text(encoding="utf-8"))

            status_stdout = StringIO()
            with redirect_stdout(status_stdout):
                status_code = cli_main(["status-background-run", str(run_dir)])
            self.assertEqual(status_code, 0)
            status = json.loads(status_stdout.getvalue())
            self.assertEqual(status["schema"], "conductor.background_status.v1")
            self.assertEqual(status["background"]["status"], "finished")
            self.assertEqual(status["runner"]["liveness"], "finished")

            summary = collect_runs(root / "runs", max_runs=1)[0]
            self.assertEqual(summary["background"]["status"], "finished")
            detail = collect_run_detail(root / "runs", run_dir.name)
            self.assertEqual(detail["background"]["run_status"], "completed")
            dashboard_path = root / "background-dashboard.html"
            write_dashboard(root / "runs", root / "benchmarks", dashboard_path)
            dashboard_html = dashboard_path.read_text(encoding="utf-8")
            self.assertIn("Background Worker", dashboard_html)
            self.assertIn("anonymous stdin pipe", dashboard_html)

            list_stdout = StringIO()
            with redirect_stdout(list_stdout):
                list_code = cli_main(["list-runs", "--runs-dir", str(root / "runs"), "--json"])
            self.assertEqual(list_code, 0)
            listed = json.loads(list_stdout.getvalue())
            self.assertEqual(listed["runs"][0]["background"]["status"], "finished")

            validate_stdout = StringIO()
            with redirect_stdout(validate_stdout):
                validate_code = cli_main(["validate-background-run", str(run_dir / "background.json")])
            self.assertEqual(validate_code, 0)
            self.assertIn("OK:", validate_stdout.getvalue())

            try:
                os.waitpid(pid, 0)
            except ChildProcessError:
                pass

            tampered = json.loads((run_dir / "background.json").read_text(encoding="utf-8"))
            tampered["policy"]["approval_values_persisted"] = True
            with self.assertRaisesRegex(ValidationError, "must not persist approval values"):
                validate_background_run(tampered)

