    @unittest.skipUnless(os.name == "posix", "background worker termination requires POSIX")
    def test_background_run_terminate_cleans_active_step_process(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "long-step",
                    "kind": "shell",
                    "risk": "low",
                    "writes": False,
                    "command": ["sleep", "30"],
                    "timeout_seconds": 60,
                }
            ]
        )
        workflow["name"] = "background-terminate"
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workflow_path = root / "workflow.json"
            write_json(workflow_path, workflow)
            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(
                    [
                        "start-background-run",
                        str(workflow_path),
                        "--workspace",
                        str(root),
                        "--runs-dir",
                        str(root / "runs"),
                        "--run-id",
                        "background-terminate-run",
                    ]
                )
            self.assertEqual(code, 0)
            run_dir = root / "runs" / "background-terminate-run"
            metadata = load_background_run(run_dir)
            worker_pid = metadata["worker"]["pid"]
            child_pid = None
            deadline = time.monotonic() + 5
            while time.monotonic() < deadline and child_pid is None:
                ps_output = subprocess.check_output(
                    ["ps", "-axo", "pid=,ppid=,comm="],
                    text=True,
                )
                for line in ps_output.splitlines():
                    fields = line.split(None, 2)
                    if len(fields) == 3 and int(fields[1]) == worker_pid:
                        child_pid = int(fields[0])
                        break
                if child_pid is None:
                    time.sleep(0.05)
            self.assertIsNotNone(child_pid)

            terminate_stdout = StringIO()
            with redirect_stdout(terminate_stdout):
                terminate_code = cli_main(
                    ["terminate-run", str(run_dir), "--reason", "integration termination"]
                )
            self.assertEqual(terminate_code, 0)
            self.assertIn("Status: stop_requested", terminate_stdout.getvalue())

            final = wait_for_background_run(run_dir, timeout_seconds=10, poll_interval_seconds=0.05)
            self.assertEqual(final["status"], "finished")
            self.assertEqual(final["run_status"], "stop_requested")
            self.assertEqual(final["exit_code"], 1)
            self.assertEqual(final["error_class"], "BackgroundWorkerTermination")
            os.waitpid(worker_pid, 0)
            with self.assertRaises(ProcessLookupError):
                os.kill(child_pid, 0)

