    def test_run_goal_model_verifier_is_fail_closed_and_does_not_persist_prompt(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "record",
                    "kind": "write_artifact",
                    "output": "record.txt",
                    "content": "goal iteration executed",
                }
            ]
        )
        criteria = "The workspace contains the expected completed behavior."

        def fake_model_process(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(
                json.dumps(
                    {
                        "satisfied": True,
                        "feedback": "Verified token=modelsecret",
                        "evidence": ["recorded workspace evidence"],
                        "confidence": "high",
                    }
                ),
                encoding="utf-8",
            )
            return ProcessResult(
                0,
                json.dumps(
                    {
                        "type": "turn.completed",
                        "usage": {"input_tokens": 10, "output_tokens": 4, "total_tokens": 14},
                    }
                )
                + "\n",
                "",
            )

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workflow_path = root / "workflow.json"
            write_json(workflow_path, workflow)
            stdout = StringIO()
            with patch("conductor_extras.runtime.goal_loop.run_process", side_effect=fake_model_process):
                with redirect_stdout(stdout):
                    code = cli_main(
                        [
                            "run-goal",
                            str(workflow_path),
                            "--workspace",
                            str(root),
                            "--runs-dir",
                            str(root / "runs"),
                            "--goals-dir",
                            str(root / "goals"),
                            "--goal-id",
                            "model-goal",
                            "--check-prompt",
                            criteria,
                            "--allow-agent",
                        ]
                    )
            self.assertEqual(code, 0)
            goal_text = (root / "goals" / "model-goal.json").read_text(encoding="utf-8")
            goal = json.loads(goal_text)
            self.assertEqual(goal["status"], "completed")
            self.assertEqual(goal["verifier"]["kind"], "model")
            self.assertTrue(goal["verifier"]["fail_closed"])
            self.assertNotIn(criteria, goal_text)
            self.assertNotIn("modelsecret", goal_text)
            self.assertEqual(goal["iterations"][0]["check"]["usage"]["total_tokens"], 14)
            artifact_text = (
                root / "runs" / "model-goal-iter-001" / "artifacts" / "goal-model-verifier.json"
            ).read_text(encoding="utf-8")
            self.assertNotIn("modelsecret", artifact_text)
            self.assertIn("token=<redacted>", artifact_text)

    def test_run_goal_resumes_legacy_model_verifier_under_tightened_policy(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "record",
                    "kind": "write_artifact",
                    "output": "record.txt",
                    "content": "goal iteration executed",
                }
            ]
        )
        criteria = "The workspace contains the expected completed behavior."
        verifier_calls = 0

        def fake_model_process(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            nonlocal verifier_calls
            verifier_calls += 1
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(
                json.dumps(
                    {
                        "satisfied": verifier_calls > 1,
                        "feedback": "retry with current evidence" if verifier_calls == 1 else "",
                        "evidence": ["recorded workspace evidence"] if verifier_calls > 1 else [],
                        "confidence": "high" if verifier_calls > 1 else "medium",
                    }
                ),
                encoding="utf-8",
            )
            return ProcessResult(0, json.dumps({"type": "turn.completed"}) + "\n", "")

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workflow_path = root / "workflow.json"
            write_json(workflow_path, workflow)
            goal_path = root / "goals" / "legacy-model-goal.json"
            with patch("conductor_extras.runtime.goal_loop.run_process", side_effect=fake_model_process):
                with redirect_stdout(StringIO()):
                    first_code = cli_main(
                        [
                            "run-goal",
                            str(workflow_path),
                            "--workspace",
                            str(root),
                            "--runs-dir",
                            str(root / "runs"),
                            "--goals-dir",
                            str(root / "goals"),
                            "--goal-id",
                            "legacy-model-goal",
                            "--check-prompt",
                            criteria,
                            "--max-iterations",
                            "1",
                            "--allow-agent",
                        ]
                    )
                self.assertEqual(first_code, 1)

                prepared = prepare_goal_verifier(
                    check_command=None,
                    check_prompt=criteria,
                    check_model=None,
                    policy=RuntimePolicy(allow_agent=True),
                )
                self.assertEqual(len(prepared["compatible_fingerprints"]), 1)
                legacy_state = json.loads(goal_path.read_text(encoding="utf-8"))
                legacy_state["verifier_fingerprint"] = prepared["compatible_fingerprints"][0]
                legacy_state["verifier"] = {
                    key: value
                    for key, value in legacy_state["verifier"].items()
                    if key
                    in {
                        "kind",
                        "prompt_sha256",
                        "prompt_chars",
                        "sandbox",
                        "fail_closed",
                        "model",
                    }
                }
                write_json(goal_path, legacy_state)

                with redirect_stdout(StringIO()):
                    second_code = cli_main(
                        [
                            "run-goal",
                            str(workflow_path),
                            "--workspace",
                            str(root),
                            "--runs-dir",
                            str(root / "runs"),
                            "--resume-goal",
                            str(goal_path),
                            "--check-prompt",
                            criteria,
                            "--max-iterations",
                            "2",
                            "--allow-agent",
                        ]
                    )

            self.assertEqual(second_code, 0)
            self.assertEqual(verifier_calls, 2)
            resumed = load_goal_state(goal_path)
            self.assertEqual(resumed["status"], "completed")
            self.assertEqual(resumed["verifier_fingerprint"], prepared["fingerprint"])
            self.assertEqual(resumed["verifier"]["policy_version"], MODEL_VERIFIER_POLICY_VERSION)
            self.assertTrue(resumed["resumes"][0]["verifier_policy_tightened"])
            self.assertEqual(
                resumed["resumes"][0]["verifier_policy_version"],
                MODEL_VERIFIER_POLICY_VERSION,
            )

    def test_run_goal_composite_verifier_short_circuits_model_after_command_failure(self):
        workflow = workflow_with_steps(
            [{"id": "record", "kind": "write_artifact", "output": "record.txt", "content": "ran"}]
        )
        criteria = "Require semantic completion evidence that must not be persisted."
        verifier_calls = []

        def fake_verifier(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            verifier_calls.append(list(argv))
            self.assertEqual(argv, ["false"])
            return ProcessResult(1, "deterministic checks failed", "")

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workflow_path = root / "workflow.json"
            write_json(workflow_path, workflow)
            with patch("conductor_extras.runtime.goal_loop.run_process", side_effect=fake_verifier):
                with redirect_stdout(StringIO()):
                    code = cli_main(
                        [
                            "run-goal",
                            str(workflow_path),
                            "--workspace",
                            str(root),
                            "--runs-dir",
                            str(root / "runs"),
                            "--goals-dir",
                            str(root / "goals"),
                            "--goal-id",
                            "composite-short-circuit",
                            "--check-command-json",
                            '["false"]',
                            "--check-prompt",
                            criteria,
                            "--check-model",
                            "semantic-verifier",
                            "--allow-agent",
                            "--max-iterations",
                            "1",
                        ]
                    )
            self.assertEqual(code, 1)
            self.assertEqual(verifier_calls, [["false"]])
            goal_text = (root / "goals" / "composite-short-circuit.json").read_text(encoding="utf-8")
            goal = json.loads(goal_text)
            self.assertEqual(goal["status"], "max_iterations_exhausted")
            self.assertEqual(goal["verifier"]["kind"], "command+model")
            self.assertEqual(goal["verifier"]["order"], ["command", "model"])
            self.assertTrue(goal["verifier"]["short_circuit_on_command_failure"])
            self.assertEqual(goal["verifier"]["model"]["model"], "semantic-verifier")
            self.assertNotIn(criteria, goal_text)
            check = goal["iterations"][0]["check"]
            self.assertEqual(check["kind"], "command+model")
            self.assertEqual(check["status"], "failed")
            self.assertTrue(check["short_circuited"])
            self.assertEqual(check["model_provider_calls"], 0)
            self.assertEqual(check["command"]["status"], "failed")
            self.assertIsNone(check["model"])
            detail = collect_goal_detail(root / "goals", goal_handle("composite-short-circuit.json"))
            detail_check = detail["iterations_detail"][0]["check"]
            self.assertEqual(detail_check["command"]["status"], "failed")
            self.assertEqual(detail_check["model"], {})
            self.assertEqual(detail_check["model_provider_calls"], 0)
            live_html = render_live_goal_detail(detail)
            self.assertIn("model skipped", live_html)
            self.assertIn("model verifier calls: 0", live_html)

            calls_before_resume = len(verifier_calls)
            stderr = StringIO()
            with patch("conductor_extras.runtime.goal_loop.run_process", side_effect=fake_verifier):
                with redirect_stderr(stderr):
                    resume_code = cli_main(
                        [
                            "run-goal",
                            str(workflow_path),
                            "--workspace",
                            str(root),
                            "--runs-dir",
                            str(root / "runs"),
                            "--resume-goal",
                            str(root / "goals" / "composite-short-circuit.json"),
                            "--check-command-json",
                            '["false"]',
                            "--check-prompt",
                            "Changed semantic criteria must alter the composite fingerprint.",
                            "--allow-agent",
                            "--max-iterations",
                            "2",
                        ]
                    )
            self.assertEqual(resume_code, 2)
            self.assertIn("verifier does not match", stderr.getvalue())
            self.assertEqual(len(verifier_calls), calls_before_resume)

