            self.assertEqual(goal["iterations"][0]["check"]["model"]["status"], "failed")
            self.assertIn("semantic evidence", goal["iterations"][0]["check"]["feedback"])
            self.assertEqual(goal["iterations"][1]["status"], "goal_satisfied")

