    def test_run_goal_model_feedback_reaches_next_agent_iteration(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "implement",
                    "kind": "codex_exec",
                    "risk": "medium",
                    "sandbox": "workspace-write",
                    "prompt": "Implement and verify the requested behavior.",
                    "capture": "implementation.md",
                }
            ]
        )
        agent_prompts = []
        verdicts = [
            {
                "satisfied": False,
                "feedback": "Add a regression test for the missing edge case.",
                "evidence": ["The edge-case test is absent."],
                "confidence": "high",
            },
            {
                "satisfied": True,
                "feedback": "All criteria are now met.",
                "evidence": ["The regression test is present and the implementation is complete."],
                "confidence": "high",
            },
        ]

        def fake_agent_process(
            self,
            argv,
            cwd,
            timeout,
            input_text=None,
            output_limit_bytes=None,
            stdout_line_callback=None,
        ):
            agent_prompts.append(input_text)
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text("implementation complete", encoding="utf-8")
            return ProcessResult(0, "", "")

        def fake_model_process(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(json.dumps(verdicts.pop(0)), encoding="utf-8")
            return ProcessResult(0, "", "")

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workflow_path = root / "workflow.json"
            write_json(workflow_path, workflow)
            with patch.object(WorkflowRunner, "_run_process", new=fake_agent_process):
                with patch("conductor_extras.runtime.goal_loop.run_process", side_effect=fake_model_process):
                    with redirect_stdout(StringIO()):
                        code = cli_main(
                            [
                                "run-goal",
                                str(workflow_path),
                                "--workspace",
                                str(root),
                                "--runs-dir",
                                str(root / "runs"),
                                "--goals-dir",
                                str(root / "goals"),
                                "--goal-id",
                                "adaptive-model-goal",
                                "--check-prompt",
                                "Implementation and regression evidence must be complete.",
                                "--allow-agent",
                                "--allow-writes",
                                "--max-iterations",
                                "2",
                            ]
                        )
            self.assertEqual(code, 0)
            self.assertEqual(len(agent_prompts), 2)
            self.assertNotIn("prior verifier reported", agent_prompts[0].lower())
            self.assertIn("prior verifier reported", agent_prompts[1].lower())
            self.assertIn("Add a regression test for the missing edge case.", agent_prompts[1])
            goal = json.loads((root / "goals" / "adaptive-model-goal.json").read_text(encoding="utf-8"))
            self.assertEqual(goal["status"], "completed")
            self.assertEqual(goal["iterations"][0]["status"], "goal_not_satisfied")
            self.assertEqual(goal["iterations"][1]["status"], "goal_satisfied")
            runner_text = (
                root / "runs" / "adaptive-model-goal-iter-002" / "runner.json"
            ).read_text(encoding="utf-8")
            runner = json.loads(runner_text)
            self.assertTrue(runner["iteration_context"]["present"])
            self.assertNotIn("missing edge case", runner_text)

    def test_run_goal_workflow_completion_requires_one_authoritative_terminal_gate(self):
        nonterminal = workflow_with_steps(
            [
                {
                    "id": "review",
                    "kind": "codex_exec",
                    "risk": "medium",
                    "sandbox": "read-only",
                    "prompt": "Review too early.",
                    "completion_verdict": "strict-v1",
                },
                {
                    "id": "after-review",
                    "kind": "write_artifact",
                    "depends_on": ["review"],
                    "output": "after.txt",
                    "content": "later work",
                },
            ]
        )
        multiple = workflow_with_steps(
            [
                {
                    "id": "review-a",
                    "kind": "codex_exec",
                    "risk": "medium",
                    "sandbox": "read-only",
                    "prompt": "Review A.",
                    "completion_verdict": "strict-v1",
                },
                {
                    "id": "review-b",
                    "kind": "codex_exec",
                    "risk": "medium",
                    "sandbox": "read-only",
                    "prompt": "Review B.",
                    "completion_verdict": "strict-v1",
                },
            ]
        )
        valid = workflow_with_steps(
            [
                {
                    "id": "review",
                    "kind": "codex_exec",
                    "risk": "medium",
                    "sandbox": "read-only",
                    "prompt": "Review completion.",
                    "completion_verdict": "strict-v1",
                }
            ]
        )
        cases = [
            (nonterminal, [], "transitively depend on every other"),
            (multiple, [], "exactly one strict completion verdict"),
            (
                valid,
                ["--check-command-json", '["true"]'],
                "cannot be combined with an external verifier",
            ),
        ]
        for index, (workflow, extra, expected) in enumerate(cases, 1):
            with self.subTest(index=index):
                validate_workflow(workflow)
                with tempfile.TemporaryDirectory() as tmp:
                    root = Path(tmp)
                    workflow_path = root / "workflow.json"
                    write_json(workflow_path, workflow)
                    stderr = StringIO()
                    with patch.object(WorkflowRunner, "_run_process") as provider:
                        with redirect_stderr(stderr):
                            code = cli_main(
                                [
                                    "run-goal",
                                    str(workflow_path),
                                    "--workspace",
                                    str(root),
                                    "--runs-dir",
                                    str(root / "runs"),
                                    "--goals-dir",
                                    str(root / "goals"),
                                    "--workflow-completion",
                                    "--allow-agent",
                                ]
                                + extra
                            )
                    self.assertEqual(code, 2)
                    self.assertIn(expected, stderr.getvalue())
                    provider.assert_not_called()
                    self.assertFalse((root / "goals").exists())
                    self.assertFalse((root / "runs").exists())

    def test_run_goal_completion_verdict_repairs_without_persisting_feedback(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "final-review",
                    "kind": "codex_exec",
                    "risk": "medium",
                    "sandbox": "read-only",
                    "prompt": (
                        "Review the current workspace and completion evidence without "
                        "exposing token=completionworkflowsecret."
                    ),
                    "capture": "final-review.json",
                    "completion_verdict": "strict-v1",
                }
            ]
        )
        feedback = "Add the missing boundary regression before claiming completion."
        verdicts = [
            {
                "satisfied": False,
                "feedback": feedback,
                "evidence": ["The boundary regression is absent."],
                "confidence": "high",
            },
            {
                "satisfied": True,
                "feedback": "",
                "evidence": ["The requested completion evidence is now present."],
                "confidence": "high",
            },
        ]
        prompts = []

        def fake_agent_process(
            self,
            argv,
            cwd,
            timeout,
            input_text=None,
            output_limit_bytes=None,
            stdout_line_callback=None,
        ):
            prompts.append(input_text)
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(json.dumps(verdicts.pop(0)), encoding="utf-8")
            return ProcessResult(0, "", "")

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workflow_path = root / "workflow.json"
            write_json(workflow_path, workflow)
            with patch.object(WorkflowRunner, "_run_process", new=fake_agent_process):
                with patch("conductor_extras.runtime.goal_loop.run_process") as external_verifier:
                    with redirect_stdout(StringIO()):
                        code = cli_main(
                            [
                                "run-goal",
                                str(workflow_path),
                                "--workspace",
                                str(root),
                                "--runs-dir",
                                str(root / "runs"),
                                "--goals-dir",
                                str(root / "goals"),
                                "--goal-id",
                                "completion-repair-goal",
                                "--workflow-completion",
                                "--max-iterations",
                                "2",
                                "--allow-agent",
                            ]
                        )
            external_verifier.assert_not_called()
            self.assertEqual(code, 0)
            self.assertEqual(len(prompts), 2)
            self.assertNotIn(feedback, prompts[0])
            self.assertIn(feedback, prompts[1])
            self.assertIn("BEGIN_UNTRUSTED_VERIFIER_FEEDBACK", prompts[1])
            goal_path = root / "goals" / "completion-repair-goal.json"
            goal_text = goal_path.read_text(encoding="utf-8")
            goal = json.loads(goal_text)
            self.assertEqual(goal["status"], "completed")
            self.assertEqual(
                [entry["status"] for entry in goal["iterations"]],
                ["completion_not_satisfied", "goal_satisfied"],
            )
            first = goal["iterations"][0]
            self.assertNotIn("check", first)
            self.assertEqual(
                first["completion_verdict"]["schema"],
                "conductor.completion_verdict_feedback.v1",
            )
            self.assertEqual(len(first["completion_verdict"]["feedback_sha256"]), 64)
            self.assertNotIn(feedback, goal_text)
            self.assertNotIn("completionworkflowsecret", goal_text)
            second_check = goal["iterations"][1]["check"]
            self.assertEqual(second_check["kind"], "workflow-completion")
            self.assertEqual(second_check["status"], "passed")
            self.assertEqual(second_check["provider_calls"], 0)
            self.assertTrue(second_check["completion_verdict"]["satisfied"])
            self.assertNotIn("evidence", second_check["completion_verdict"])
            detail = collect_goal_detail(
                root / "goals",
                goal_handle(goal_path.name),
            )
            detail_text = json.dumps(
                detail,
                default=str,
                sort_keys=True,
            )
            self.assertNotIn(feedback, detail_text)
            completion_detail = detail["iterations_detail"][0][
                "completion_verdict"
            ]
            self.assertEqual(completion_detail["confidence"], "high")
            self.assertEqual(completion_detail["evidence_count"], 1)
            self.assertNotIn("feedback", completion_detail)
            check_detail = detail["iterations_detail"][1]["check"]
            self.assertEqual(check_detail["kind"], "workflow-completion")
            self.assertEqual(check_detail["provider_calls"], 0)
            self.assertEqual(
                check_detail["completion_verdict"]["confidence"],
                "high",
            )
            self.assertNotIn("evidence", check_detail["completion_verdict"])
            second_runner = json.loads(
                (
                    root
                    / "runs"
                    / "completion-repair-goal-iter-002"
                    / "runner.json"
                ).read_text(encoding="utf-8")
            )
            self.assertTrue(second_runner["iteration_context"]["present"])
            self.assertNotIn(feedback, json.dumps(second_runner, sort_keys=True))

    def test_run_goal_workflow_completion_uses_bound_workflow_fingerprint(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "final-review",
                    "kind": "codex_exec",
                    "risk": "medium",
                    "sandbox": "read-only",
                    "prompt": "Review completion.",
                    "capture": "final-review.json",
                    "completion_verdict": "strict-v1",
                }
            ]
        )

        def bind_runtime_workflow(value, workspace):
            bound = dict(value)
            bound["description"] = "runtime-bound completion workflow"
            return bound

        def fake_agent_process(
            self,
            argv,
            cwd,
            timeout,
            input_text=None,
            output_limit_bytes=None,
            stdout_line_callback=None,
        ):
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(
                json.dumps(
                    {
                        "satisfied": True,
                        "feedback": "",
                        "evidence": ["The bound workflow completed."],
                        "confidence": "high",
                    }
                ),
                encoding="utf-8",
            )
            return ProcessResult(0, "", "")

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workflow_path = root / "workflow.json"
            write_json(workflow_path, workflow)
            with patch(
                "conductor_extras.runtime.goal_loop.bind_agent_profile_resources",
                new=bind_runtime_workflow,
            ):
                with patch.object(
                    WorkflowRunner,
                    "_run_process",
                    new=fake_agent_process,
                ):
                    with redirect_stdout(StringIO()):
                        code = cli_main(
                            [
                                "run-goal",
                                str(workflow_path),
                                "--workspace",
                                str(root),
                                "--runs-dir",
                                str(root / "runs"),
                                "--goals-dir",
                                str(root / "goals"),
                                "--goal-id",
                                "bound-completion-goal",
                                "--workflow-completion",
                                "--allow-agent",
                            ]
                        )
            self.assertEqual(code, 0)
            goal = json.loads(
                (root / "goals" / "bound-completion-goal.json").read_text(
                    encoding="utf-8"
                )
            )
            self.assertEqual(goal["status"], "completed")
            self.assertEqual(
                goal["workflow_fingerprint"],
                workflow_fingerprint(bind_runtime_workflow(workflow, root)),
            )
            self.assertEqual(
                goal["iterations"][0]["check"]["status"],
                "passed",
            )

