    def test_run_goal_completion_verdict_resume_rejects_artifact_drift(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "final-review",
                    "kind": "codex_exec",
                    "risk": "medium",
                    "sandbox": "read-only",
                    "prompt": "Review completion evidence.",
                    "capture": "final-review.json",
                    "completion_verdict": "strict-v1",
                }
            ]
        )
        feedback = "Original private repair feedback."
        prompts = []

        def fake_agent_process(
            self,
            argv,
            cwd,
            timeout,
            input_text=None,
            output_limit_bytes=None,
            stdout_line_callback=None,
        ):
            prompts.append(input_text)
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(
                json.dumps(
                    {
                        "satisfied": False,
                        "feedback": feedback,
                        "evidence": ["One blocker remains."],
                        "confidence": "high",
                    }
                ),
                encoding="utf-8",
            )
            return ProcessResult(0, "", "")

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workflow_path = root / "workflow.json"
            write_json(workflow_path, workflow)
            common = [
                str(workflow_path),
                "--workspace",
                str(root),
                "--runs-dir",
                str(root / "runs"),
                "--goals-dir",
                str(root / "goals"),
                "--goal-id",
                "completion-resume-goal",
                "--workflow-completion",
                "--allow-agent",
            ]
            with patch.object(WorkflowRunner, "_run_process", new=fake_agent_process):
                with redirect_stdout(StringIO()):
                    first_code = cli_main(
                        ["run-goal"] + common + ["--max-iterations", "1"]
                    )
            self.assertEqual(first_code, 1)
            goal_path = root / "goals" / "completion-resume-goal.json"
            first_goal = json.loads(goal_path.read_text(encoding="utf-8"))
            self.assertEqual(first_goal["status"], "max_iterations_exhausted")
            self.assertEqual(
                first_goal["iterations"][0]["status"],
                "completion_not_satisfied",
            )
            artifact = (
                root
                / "runs"
                / "completion-resume-goal-iter-001"
                / "artifacts"
                / "final-review.json"
            )
            artifact.write_text(
                json.dumps(
                    {
                        "satisfied": False,
                        "feedback": "Tampered feedback.",
                        "evidence": ["Different evidence."],
                        "confidence": "low",
                    }
                ),
                encoding="utf-8",
            )
            stderr = StringIO()
            with patch.object(WorkflowRunner, "_run_process", new=fake_agent_process):
                with redirect_stderr(stderr):
                    resume_code = cli_main(
                        ["run-goal"]
                        + common
                        + [
                            "--resume-goal",
                            str(goal_path),
                            "--max-iterations",
                            "2",
                        ]
                    )
            self.assertEqual(resume_code, 2)
            self.assertEqual(len(prompts), 1)
            self.assertIn("feedback output has drifted", stderr.getvalue())
            failed_goal = json.loads(goal_path.read_text(encoding="utf-8"))
            self.assertEqual(failed_goal["status"], "workflow_failed")
            self.assertEqual(
                failed_goal["error_class"],
                "CompletionVerdictFeedbackInvalid",
            )
            self.assertNotIn(feedback, goal_path.read_text(encoding="utf-8"))

