            runs_text = json.dumps(runs, default=str)
            self.assertNotIn("launchsecret", runs_text)
            self.assertNotIn("launchapprovalsecret", runs_text)

            detail = collect_run_detail(root / "runs", "launch-visible")
            self.assertEqual(detail["launch"]["status"], "prepared")
            resume_issue = next(
                issue
                for issue in detail["diagnostics"]["issues"]
                if issue["code"] == "run_waiting_for_resume"
            )
            self.assertIn("Launch manifest status: prepared.", resume_issue["detail"])
            self.assertEqual(resume_issue["command"], detail["launch"]["resume_command"])

            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(["list-runs", "--runs-dir", str(root / "runs"), "--max-runs", "1"])
            self.assertEqual(code, 0)
            text = stdout.getvalue()
            self.assertIn("prepared,preflight:planned,no-process,approvals:1", text)
            self.assertNotIn("launchsecret", text)
            self.assertNotIn("launchapprovalsecret", text)

            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(["list-runs", "--runs-dir", str(root / "runs"), "--max-runs", "1", "--json"])
            self.assertEqual(code, 0)
            raw_json = stdout.getvalue()
            payload = json.loads(raw_json)
            self.assertEqual(payload["runs"][0]["launch"]["status"], "prepared")
            self.assertIn("--resume", payload["runs"][0]["launch"]["resume_command"])
            self.assertNotIn("launchsecret", raw_json)
            self.assertNotIn("launchapprovalsecret", raw_json)

            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(["diagnose-run", str(run_dir), "--json"])
            self.assertEqual(code, 0)
            diagnostics = json.loads(stdout.getvalue())["diagnostics"]
            self.assertEqual(diagnostics["issues"][0]["command"], detail["launch"]["resume_command"])

            dashboard = root / "dashboard.html"
            write_dashboard(root / "runs", root / "benchmarks", dashboard)
            dashboard_html = dashboard.read_text(encoding="utf-8")
            self.assertIn("Launch: prepared, preflight planned, no process started", dashboard_html)
            self.assertIn("<h4>Launch</h4>", dashboard_html)
            self.assertIn("Resume command", dashboard_html)
            self.assertNotIn("launchsecret", dashboard_html)
            self.assertNotIn("launchapprovalsecret", dashboard_html)

            payload = build_live_payload(root / "runs", root / "benchmarks")
            self.assertEqual(payload["runs"][0]["launch"]["status"], "prepared")
            live_root = render_live_dashboard(payload)
            self.assertIn("Launch: prepared, preflight planned, no process started", live_root)
            live_detail = render_live_run_detail(detail)
            self.assertIn("<th>Launch</th>", live_detail)
            self.assertIn("Resume command", live_detail)
            self.assertNotIn("launchsecret", live_detail)
            self.assertNotIn("launchapprovalsecret", live_detail)

