    def test_launch_manifest_rejects_untrusted_actionable_command_shapes(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "write",
                    "kind": "write_artifact",
                    "output": "prepared.txt",
                    "content": "prepared run executed",
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workflow_path = root / "workflow.json"
            write_json(workflow_path, workflow)
            with redirect_stdout(StringIO()):
                code = cli_main(
                    [
                        "prepare-run",
                        str(workflow_path),
                        "--workspace",
                        str(root),
                        "--runs-dir",
                        str(root / "runs"),
                        "--run-id",
                        "command-shape",
                        "--allow-writes",
                    ]
                )
            self.assertEqual(code, 0)
            run_dir = root / "runs" / "command-shape"
            launch_path = run_dir / "launch.json"
            launch = json.loads(launch_path.read_text(encoding="utf-8"))
            valid_argv = list(launch["resume_command_argv"])

            launch["resume_command"] = "sh -c 'echo commandsecret' --resume /tmp/bad"
            write_json(launch_path, launch)
            detail = collect_run_detail(root / "runs", "command-shape")
            self.assertIn("--resume", detail["launch"]["resume_command"])
            self.assertNotIn("commandsecret", detail["launch"]["resume_command"])
            resume_issue = next(
                issue
                for issue in detail["diagnostics"]["issues"]
                if issue["code"] == "run_waiting_for_resume"
            )
            self.assertEqual(resume_issue["command"], detail["launch"]["resume_command"])
            self.assertNotIn("commandsecret", json.dumps(detail))

            launch["resume_command_argv"] = ["sh", "-c", "echo commandsecret --resume /tmp/bad"]
            write_json(launch_path, launch)
            detail = collect_run_detail(root / "runs", "command-shape")
            self.assertEqual(detail["launch"]["resume_command"], "")
            self.assertEqual(detail["launch"]["resume_command_error"], "invalid resume_command_argv")
            resume_issue = next(
                issue
                for issue in detail["diagnostics"]["issues"]
                if issue["code"] == "run_waiting_for_resume"
            )
            self.assertIn("Resume command unavailable: invalid resume_command_argv.", resume_issue["detail"])
            self.assertEqual(resume_issue["command"], "python3 -m conductor_extras run RUN_WORKFLOW --resume RUN_DIR")
            self.assertNotIn("commandsecret", json.dumps(detail))

            launch = json.loads(launch_path.read_text(encoding="utf-8"))
            launch["resume_command_argv"] = [
                "python3",
                "-B",
                "-m",
                "conductor_extras",
                "run",
                str(workflow_path),
                "--workspace",
                str(root),
                "--runs-dir",
                str(root / "runs"),
                "--resume",
                str(run_dir),
                "--approve",
                "approvalsecret",
            ]
            write_json(launch_path, launch)
            detail = collect_run_detail(root / "runs", "command-shape")
            self.assertEqual(detail["launch"]["resume_command"], "")
            self.assertEqual(detail["launch"]["resume_command_error"], "approval values must not be persisted")
            self.assertNotIn("approvalsecret", json.dumps(detail))

            launch["resume_command_argv"] = valid_argv
            launch["kind"] = "external-run"
            write_json(launch_path, launch)
            detail = collect_run_detail(root / "runs", "command-shape")
            self.assertEqual(detail["launch"]["status"], "invalid")
            self.assertEqual(detail["launch"]["error"], "unsupported kind")
            self.assertNotIn("resume_command", detail["launch"])

    def test_prepare_run_audit_failure_rolls_back_prepared_state(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "write",
                    "kind": "write_artifact",
                    "output": "prepared.txt",
                    "content": "prepared run executed",
                },
            ]
        )
        validate_workflow(workflow)
        import conductor_extras.runtime.artifacts as artifacts_module

        original_replace = artifacts_module.replace_text_file_no_follow

        def patched_replace(path, label, text, temp_prefix, *args, **kwargs):
            if Path(path).name == "05-decision-log.md":
                raise ValidationError("simulated prepare-run audit failure")
            return original_replace(path, label, text, temp_prefix, *args, **kwargs)

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workflow_path = root / "workflow.json"
            write_json(workflow_path, workflow)
            stderr = StringIO()
            with patch("conductor_extras.runtime.artifacts.replace_text_file_no_follow", side_effect=patched_replace):
                with redirect_stderr(stderr):
                    code = cli_main(
                        [
                            "prepare-run",
                            str(workflow_path),
                            "--workspace",
                            str(root),
                            "--runs-dir",
                            str(root / "runs"),
                            "--run-id",
                            "audit-failure-run",
                        ]
                    )
            self.assertEqual(code, 2)
            self.assertIn("failed to append standard artifact", stderr.getvalue())
            run_dir = root / "runs" / "audit-failure-run"
            state = json.loads((run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["status"], "planned")
            self.assertNotIn("prepared_run", state)
            self.assertNotIn(
                "Runtime prepared run",
                (run_dir / "05-decision-log.md").read_text(encoding="utf-8"),
            )

