    def test_runtime_records_run_and_step_metrics(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "write",
                    "kind": "write_artifact",
                    "output": "one.txt",
                    "content": "one",
                },
                {
                    "id": "shell",
                    "kind": "shell",
                    "risk": "low",
                    "writes": False,
                    "command": ["printf", "ok"],
                },
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            run = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            ).execute()
            state = json.loads((run.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["status"], "completed")
            self.assertIn("started_at_utc", state)
            self.assertIn("finished_at_utc", state)
            self.assertIsInstance(state["duration_ms"], int)
            write_step = state["steps"]["write"]
            self.assertEqual(write_step["kind"], "write_artifact")
            self.assertEqual(write_step["status"], "completed")
            self.assertIn("started_at_utc", write_step)
            self.assertIn("finished_at_utc", write_step)
            self.assertIsInstance(write_step["duration_ms"], int)
            shell_step = state["steps"]["shell"]
            self.assertEqual(shell_step["kind"], "shell")
            self.assertEqual(shell_step["returncode"], 0)
            self.assertIsInstance(shell_step["stdout_bytes"], int)
            self.assertFalse(shell_step["timed_out"])
            runner = json.loads((run.run_dir / "runner.json").read_text(encoding="utf-8"))
            self.assertEqual(runner["schema"], "conductor.runner.v1")
            self.assertEqual(runner["status"], "finished")
            self.assertEqual(runner["mode"], "run")
            self.assertEqual(runner["run_status"], "completed")
            self.assertIsInstance(runner["pid"], int)
            self.assertIsInstance(runner["process_group_id"], int)
            self.assertIsInstance(runner["session_id"], int)
            self.assertIsInstance(runner["hostname"], str)
            self.assertIn("started_at_utc", runner)
            self.assertIn("heartbeat_at_utc", runner)
            self.assertIn("finished_at_utc", runner)
            self.assertEqual(runner["workspace"], str(root.resolve()))
            self.assertEqual(runner["max_workers"], 1)
            summary = collect_runs(root / "runs", max_runs=1)[0]
            self.assertEqual(summary["runner"]["status"], "finished")
            self.assertEqual(summary["runner"]["pid"], runner["pid"])
            detail = collect_run_detail(root / "runs", run.run_dir.name)
            self.assertEqual(detail["runner"]["status"], "finished")
            self.assertEqual(detail["runner"]["mode"], "run")

    def test_runner_metadata_is_visible_while_step_runs(self):
        class ObservingRunner(WorkflowRunner):
            def __init__(self, *args, **kwargs):
                super().__init__(*args, **kwargs)
                self.observed_runner = None

            def _run_process(
                self,
                argv,
                cwd,
                timeout,
                input_text=None,
                output_limit_bytes=1024 * 1024,
            ):
                if argv == ["printf", "probe-runner"]:
                    self.observed_runner = json.loads((self.run.run_dir / "runner.json").read_text(encoding="utf-8"))
                    return ProcessResult(returncode=0, stdout="ok", stderr="")
                return super()._run_process(argv, cwd, timeout, input_text, output_limit_bytes)

        workflow = workflow_with_steps(
            [
                {
                    "id": "shell",
                    "kind": "shell",
                    "risk": "low",
                    "writes": False,
                    "command": ["printf", "probe-runner"],
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = ObservingRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            )
            runner.execute()
            self.assertIsNotNone(runner.observed_runner)
            self.assertEqual(runner.observed_runner["schema"], "conductor.runner.v1")
            self.assertEqual(runner.observed_runner["status"], "active")
            self.assertEqual(runner.observed_runner["event"], "step-start:shell")
            self.assertEqual(runner.observed_runner["run_status"], "running")
            self.assertIsInstance(runner.observed_runner["pid"], int)
            self.assertEqual(runner.observed_runner["mode"], "run")
            self.assertEqual(runner.observed_runner["workspace"], str(root.resolve()))
            self.assertEqual(runner.observed_runner["max_workers"], 1)
            self.assertIn("started_at_utc", runner.observed_runner)
            self.assertIn("heartbeat_at_utc", runner.observed_runner)

    @unittest.skipUnless(os.name == "posix", "child process identity uses POSIX sessions")
    def test_runner_metadata_tracks_active_child_without_command_content(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "sleep",
                    "kind": "shell",
                    "risk": "low",
                    "writes": False,
                    "command": ["sleep", "0.5"],
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            )
            errors = []

            def execute():
                try:
                    runner.execute()
                except BaseException as exc:  # pragma: no cover - asserted below.
                    errors.append(exc)

            thread = threading.Thread(target=execute)
            thread.start()
            observed = None
            deadline = time.time() + 3
            while time.time() < deadline:
                path = runner.run.run_dir / "runner.json"
                if path.exists():
                    candidate = json.loads(path.read_text(encoding="utf-8"))
                    if candidate.get("active_processes"):
                        observed = candidate
                        break
                time.sleep(0.01)
            thread.join(timeout=3)
            self.assertFalse(thread.is_alive())
            self.assertEqual(errors, [])
            self.assertIsNotNone(observed)
            process = observed["active_processes"][0]
            self.assertEqual(process["pid"], process["process_group_id"])
            self.assertEqual(process["pid"], process["session_id"])
            self.assertNotIn("argv", process)
            self.assertNotIn("command", process)
            finished = json.loads((runner.run.run_dir / "runner.json").read_text(encoding="utf-8"))
            self.assertEqual(finished["active_processes"], [])

    def test_runner_liveness_classifies_finished_alive_and_stale_runs(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "write",
                    "kind": "write_artifact",
                    "output": "one.txt",
                    "content": "one",
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            run = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            ).execute()
            finished_runner = summarize_runner(run.run_dir)
            self.assertEqual(finished_runner["liveness"], "finished")
            self.assertIsNone(finished_runner["heartbeat_age_seconds"])

            active_dir = root / "runs" / "active"
            active_dir.mkdir()
            write_json(active_dir / "state.json", {"schema": "conductor.run_state.v1", "status": "running", "steps": {}})
            write_json(active_dir / "workflow.json", {"schema": "conductor.workflow.v1", "name": "active", "steps": []})
            write_json(
                active_dir / "runner.json",
                {
                    "schema": "conductor.runner.v1",
                    "status": "active",
                    "event": "heartbeat",
                    "pid": 123,
                    "hostname": "host",
                    "mode": "run",
                    "run_status": "running",
                    "started_at_utc": "2000-01-01T00:00:00.000+00:00",
                    "heartbeat_at_utc": "2000-01-01T00:00:00.000+00:00",
                    "max_workers": 1,
                },
            )
            stale = summarize_runner(active_dir)
            self.assertEqual(stale["liveness"], "stale")
            self.assertGreater(stale["heartbeat_age_seconds"], stale["stale_after_seconds"])
            self.assertIn("older than", stale["liveness_reason"])

            current = json.loads((run.run_dir / "runner.json").read_text(encoding="utf-8"))
            current["status"] = "active"
            current.pop("finished_at_utc", None)
            current["heartbeat_at_utc"] = current["started_at_utc"]
            write_json(active_dir / "runner.json", current)
            alive = summarize_runner(active_dir)
            self.assertEqual(alive["liveness"], "alive")
            self.assertIsInstance(alive["heartbeat_age_seconds"], int)

    @unittest.skipUnless(os.name == "posix", "run ownership recovery requires POSIX locks")
    def test_execution_lock_rejects_concurrent_runner_before_metadata_overwrite(self):
        workflow = workflow_with_steps(
            [{"id": "write", "kind": "write_artifact", "output": "one.txt", "content": "one"}]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            )
            with run_execution_lock(runner.run.run_dir):
                with self.assertRaises(ValidationError) as error:
                    runner.execute()
                probe = subprocess.run(
                    [
                        sys.executable,
                        "-B",
                        "-c",
                        (
                            "import sys; from pathlib import Path; "
                            "from conductor_extras.runtime.run_ownership import run_execution_lock; "
                            "\ntry:\n"
                            "  with run_execution_lock(Path(sys.argv[1]), require_cross_process=True): pass\n"
                            "except Exception as exc:\n"
                            "  print(type(exc).__name__ + ': ' + str(exc)); raise SystemExit(2)\n"
                        ),
                        str(runner.run.run_dir),
                    ],
                    cwd=str(Path(__file__).resolve().parents[1]),
                    capture_output=True,
                    text=True,
                    timeout=5,
                )
                self.assertEqual(probe.returncode, 2)
                self.assertIn("active execution owner", probe.stdout)
            self.assertIn("active execution owner", str(error.exception))
            self.assertFalse((runner.run.run_dir / "runner.json").exists())
            with self.assertRaisesRegex(OSError, "body failure"):
                with run_execution_lock(runner.run.run_dir):
                    raise OSError("body failure")

