            self.assertEqual(len(dry_resumed_state["hook_events"]), 2)
            self.assertEqual(dry_resumed_state["steps"]["write"]["attempt"], 1)

            run = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            ).execute()
            state = json.loads((run.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(len(state["hook_events"]), 2)
            resumed = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
                resume_dir=run.run_dir,
            ).execute()
            resumed_state = json.loads((resumed.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(len(resumed_state["hook_events"]), 2)

