    def test_run_control_request_from_before_step_hook_prevents_step_action(self):
        class StoppingBeforeStepHookRunner(WorkflowRunner):
            def _run_process(
                self,
                argv,
                cwd,
                timeout,
                input_text=None,
                output_limit_bytes=1024 * 1024,
            ):
                if argv == ["printf", "stop-before-action"]:
                    stop_run(self.run.run_dir, reason="before action")
                    return ProcessResult(returncode=0, stdout="", stderr="")
                return super()._run_process(argv, cwd, timeout, input_text, output_limit_bytes)

        workflow = workflow_with_steps(
            [
                {
                    "id": "write",
                    "kind": "write_artifact",
                    "output": "one.txt",
                    "content": "one",
                }
            ]
        )
        workflow["hooks"] = [
            {
                "id": "before-step-stop",
                "event": "before_step",
                "steps": ["write"],
                "command": ["printf", "stop-before-action"],
            }
        ]
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            run = StoppingBeforeStepHookRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            ).execute()
            state = json.loads((run.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["status"], "stopped")
            self.assertEqual(state["steps"]["write"]["status"], "pending")
            self.assertFalse((run.artifacts_dir / "one.txt").exists())
            self.assertEqual(state["hook_events"][0]["status"], "completed")

