    def test_after_hooks_keep_run_non_terminal_until_finished(self):
        class ProbingHookRunner(WorkflowRunner):
            def __init__(self, *args, **kwargs):
                self.observed_statuses = []
                super().__init__(*args, **kwargs)

            def _run_process(
                self,
                argv,
                cwd,
                timeout,
                input_text=None,
                output_limit_bytes=1024 * 1024,
            ):
                if argv[:1] == ["printf"] and len(argv) > 1 and argv[1].startswith("probe-"):
                    state = json.loads(self.run.state_path.read_text(encoding="utf-8"))
                    self.observed_statuses.append((argv[1], state["status"]))
                    return ProcessResult(returncode=0, stdout="", stderr="")
                return super()._run_process(argv, cwd, timeout, input_text, output_limit_bytes)

        workflow = workflow_with_steps(
            [
                {
                    "id": "write",
                    "kind": "write_artifact",
                    "output": "one.txt",
                    "content": "one",
                }
            ]
        )
        workflow["hooks"] = [
            {
                "id": "after-step",
                "event": "after_step",
                "steps": ["write"],
                "command": ["printf", "probe-after-step"],
            },
            {
                "id": "after-run",
                "event": "after_run",
                "command": ["printf", "probe-after-run"],
            },
        ]
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = ProbingHookRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            )
            run = runner.execute()
            state = json.loads((run.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["status"], "completed")
            self.assertEqual(
                runner.observed_statuses,
                [("probe-after-step", "running"), ("probe-after-run", "running")],
            )

