    def test_manual_gate_audit_append_rejects_symlink_swap_after_validation(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "gate",
                    "kind": "manual_gate",
                    "risk": "medium",
                    "approval_id": "continue",
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            import conductor_extras.runtime.security as security_module

            root = Path(tmp)
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(approvals={"continue"}),
            )
            decision_log = runner.run.run_dir / "05-decision-log.md"
            outside_log = root / "outside-log.md"
            outside_log.write_text("outside", encoding="utf-8")
            original_reject = security_module.reject_symlink_path
            checks = {"count": 0}

            def swapping_reject(path, label):
                original_reject(path, label)
                if label == "standard artifact" and Path(path) == decision_log:
                    checks["count"] += 1
                    if checks["count"] == 1:
                        decision_log.unlink()
                        try:
                            decision_log.symlink_to(outside_log)
                        except OSError:
                            self.skipTest("symlinks are not supported on this filesystem")

            with patch("conductor_extras.runtime.security.reject_symlink_path", side_effect=swapping_reject):
                with self.assertRaises(ValidationError):
                    runner.execute()
            self.assertEqual(outside_log.read_text(encoding="utf-8"), "outside")

