    def test_agent_map_high_scale_scheduler_executes_128_synthetic_packets(self):
        items = ["item-%03d" % index for index in range(MAX_AGENT_WORKERS)]
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": items,
                    "prompt_template": "Review {item}",
                    "max_workers": MAX_AGENT_WORKERS,
                }
            ]
        )
        workflow["max_workers"] = MAX_AGENT_WORKERS
        validate_workflow(workflow)
        active = 0
        peak = 0
        lock = threading.Lock()
        release = threading.Event()

        def synthetic_item(step, item, index, capture_dir, cache_context):
            nonlocal active, peak
            with lock:
                active += 1
                peak = max(peak, active)
                if peak >= 17:
                    release.set()
            release.wait(timeout=2)
            with lock:
                active -= 1
            return AgentItemResult(cache_entry=None, telemetry=ProviderTelemetry(events=[]))

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(
                    allow_agent=True,
                    allow_parallel=True,
                    approvals={"high-scale-agent-map"},
                ),
            )
            with patch.object(runner, "_run_agent_item", side_effect=synthetic_item):
                run = runner.execute()
            packet = run.read_state()["steps"]["packet"]
            self.assertEqual(packet["status"], "completed")
            self.assertEqual(packet["agent_items_total"], MAX_AGENT_WORKERS)
            self.assertEqual(packet["agent_workers"], MAX_AGENT_WORKERS)
            self.assertGreaterEqual(peak, 17)

    def test_agent_map_balanced_packet_ceiling_collapses_one_thousand_items_to_twenty_five_calls(self):
        items = ["src/file-%04d.py" % index for index in range(1000)]
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": items,
                    "prompt_template": "Review every scope in {item}",
                    "max_workers": 4,
                    "max_packets": BALANCED_AGENT_MAP_MAX_PACKETS,
                    "max_tokens": 4000,
                    "max_total_tokens": 100000,
                }
            ]
        )
        workflow["max_workers"] = 4
        validate_workflow(workflow)
        calls = []
        lock = threading.Lock()

        def synthetic_packet(step, item, index, capture_dir, cache_context, invocation_token_cap=None):
            with lock:
                calls.append((index, json.loads(item), invocation_token_cap))
            return AgentItemResult(cache_entry=None, telemetry=ProviderTelemetry(events=[]))

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True, allow_parallel=True),
            )
            with patch.object(runner, "_run_agent_item", side_effect=synthetic_packet):
                run = runner.execute()
            self.assertEqual(len(calls), BALANCED_AGENT_MAP_MAX_PACKETS)
            self.assertTrue(all(len(packet_items) == 40 for _, packet_items, _ in calls))
            self.assertTrue(all(token_cap == 4000 for _, _, token_cap in calls))
            state = run.read_state()["steps"]["packet"]
            self.assertEqual(state["agent_items_total"], 1000)
            self.assertEqual(state["agent_packets_total"], 25)
            self.assertEqual(state["agent_invocations"], 25)
            self.assertEqual(state["agent_items_per_packet_max"], 40)

