    def test_pause_run_is_honored_at_step_boundary_and_can_resume(self):
        class PausingRunner(WorkflowRunner):
            def _execute_step(self, step):
                super()._execute_step(step)
                if step["id"] == "one":
                    pause_run(self.run.run_dir, reason="token=pausesecret")

        workflow = workflow_with_steps(
            [
                {"id": "one", "kind": "write_artifact", "output": "one.txt", "content": "one"},
                {"id": "two", "kind": "write_artifact", "output": "two.txt", "content": "two"},
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            run = PausingRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            ).execute()
            state = json.loads((run.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["status"], "paused")
            self.assertNotIn("control_request", state)
            self.assertEqual(state["steps"]["one"]["status"], "completed")
            self.assertNotIn("two", state["steps"])
            self.assertEqual(state["control_events"][-1]["action"], "pause-run")
            self.assertNotIn("pausesecret", json.dumps(state))

            paused_again = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
                resume_dir=run.run_dir,
            ).execute()
            paused_state = json.loads((paused_again.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(paused_state["status"], "paused")
            self.assertNotIn("two", paused_state["steps"])

            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(["resume-run", str(run.run_dir), "--reason", "continue"])
            self.assertEqual(code, 0)
            self.assertIn("Status: needs_resume", stdout.getvalue())
            resumed = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
                resume_dir=run.run_dir,
            ).execute()
            state = json.loads((resumed.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["status"], "completed")
            self.assertEqual(state["steps"]["two"]["status"], "completed")

    def test_stop_run_is_honored_at_step_boundary(self):
        class StoppingRunner(WorkflowRunner):
            def _execute_step(self, step):
                super()._execute_step(step)
                if step["id"] == "one":
                    stop_run(self.run.run_dir, reason="operator stop")

        workflow = workflow_with_steps(
            [
                {"id": "one", "kind": "write_artifact", "output": "one.txt", "content": "one"},
                {"id": "two", "kind": "write_artifact", "output": "two.txt", "content": "two"},
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            run = StoppingRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            ).execute()
            state = json.loads((run.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["status"], "stopped")
            self.assertNotIn("control_request", state)
            self.assertEqual(state["steps"]["one"]["status"], "completed")
            self.assertNotIn("two", state["steps"])
            self.assertIn("finished_at_utc", state)
            self.assertEqual(state["control_events"][-1]["action"], "stop-run")

            resumed = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
                resume_dir=run.run_dir,
            ).execute()
            resumed_state = json.loads((resumed.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(resumed_state["status"], "stopped")
            self.assertNotIn("two", resumed_state["steps"])
            self.assertEqual(resumed_state["finished_at_utc"], state["finished_at_utc"])
            self.assertEqual(resumed_state["duration_ms"], state["duration_ms"])

    def test_terminate_run_signals_isolated_runner_and_records_audit(self):
        workflow = workflow_with_steps(
            [
                {"id": "one", "kind": "write_artifact", "output": "one.txt", "content": "one"},
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            )
            state = runner.run.read_state()
            state["status"] = "running"
            runner.run.save_state(state)
            pid = 987654
            write_json(
                runner.run.run_dir / "runner.json",
                {
                    "schema": "conductor.runner.v1",
                    "status": "active",
                    "event": "heartbeat",
                    "pid": pid,
                    "process_group_id": pid,
                    "session_id": pid,
                    "hostname": os.uname().nodename,
                    "heartbeat_at_utc": fresh_runner_heartbeat(),
                    "run_status": "running",
                },
            )

            with patch("conductor_extras.runtime.run_control._pid_is_running", return_value=True), patch(
                "conductor_extras.runtime.run_control.os.killpg"
            ) as killpg:
                result = terminate_run(runner.run.run_dir, reason="token=terminatesecret")

            killpg.assert_called_once_with(pid, signal.SIGTERM)
            self.assertEqual(result["action"], "terminate-run")
            self.assertEqual(result["status"], "stop_requested")
            self.assertEqual(result["signal"], "TERM")
            state = json.loads((runner.run.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["status"], "stop_requested")
            self.assertEqual(state["control_request"]["action"], "stop")
            self.assertEqual(state["control_events"][-1]["action"], "terminate-run")
            self.assertEqual(state["control_events"][-1]["status"], "sent")
            self.assertEqual(state["termination_events"][-1]["signal"], "TERM")
            self.assertEqual(state["termination_events"][-1]["status"], "sent")
            self.assertEqual(state["termination_events"][-1]["pid"], pid)
            self.assertNotIn("terminatesecret", json.dumps(state))
            decision_log = (runner.run.run_dir / "05-decision-log.md").read_text(encoding="utf-8")
            self.assertIn("Runtime control `terminate-run`", decision_log)
            self.assertIn("signal sent", decision_log)
            self.assertNotIn("terminatesecret", decision_log)

    def test_terminate_run_rejects_unsafe_runner_metadata(self):
        workflow = workflow_with_steps(
            [
                {"id": "one", "kind": "write_artifact", "output": "one.txt", "content": "one"},
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            )
            state = runner.run.read_state()
            state["status"] = "running"
            runner.run.save_state(state)

            def write_runner(**overrides):
                pid = overrides.pop("pid", 456789)
                payload = {
                    "schema": "conductor.runner.v1",
                    "status": "active",
                    "event": "heartbeat",
                    "pid": pid,
                    "process_group_id": pid,
                    "session_id": pid,
                    "hostname": os.uname().nodename,
                    "heartbeat_at_utc": fresh_runner_heartbeat(),
                    "run_status": "running",
                }
                payload.update(overrides)
                write_json(runner.run.run_dir / "runner.json", payload)

            with self.assertRaises(ValidationError) as error:
                terminate_run(runner.run.run_dir, reason="missing")
            self.assertIn("missing runner metadata", str(error.exception))

            (runner.run.run_dir / "runner.json").write_text("{", encoding="utf-8")
            with self.assertRaises(ValidationError) as error:
                terminate_run(runner.run.run_dir, reason="invalid")
            self.assertIn("runner.json is not valid JSON", str(error.exception))

            (runner.run.run_dir / "runner.json").write_text(
                " " * (RUNNER_METADATA_BYTES + 1),
                encoding="utf-8",
            )
            with self.assertRaises(ValidationError) as error:
                terminate_run(runner.run.run_dir, reason="oversized")
            self.assertIn("runner.json must be at most", str(error.exception))

            write_runner(status="finished")
            with self.assertRaises(ValidationError) as error:
                terminate_run(runner.run.run_dir, reason="inactive")
            self.assertIn("runner metadata is not active", str(error.exception))

            write_runner(hostname="other-host")
            with self.assertRaises(ValidationError) as error:
                terminate_run(runner.run.run_dir, reason="remote")
            self.assertIn("runner metadata hostname does not match", str(error.exception))

            write_runner(heartbeat_at_utc="2000-01-01T00:00:00.000Z")
            with self.assertRaises(ValidationError) as error:
                terminate_run(runner.run.run_dir, reason="stale")
            self.assertIn("runner metadata heartbeat is too old", str(error.exception))

            write_runner(heartbeat_at_utc=future_runner_heartbeat())
            with self.assertRaises(ValidationError) as error:
                terminate_run(runner.run.run_dir, reason="future")
            self.assertIn("runner metadata heartbeat is from the future", str(error.exception))

            write_runner(heartbeat_at_utc=fresh_runner_heartbeat().replace("Z", "+00:00"))
            with self.assertRaises(ValidationError) as error:
                terminate_run(runner.run.run_dir, reason="offset")
            self.assertIn("runner metadata heartbeat is missing or invalid", str(error.exception))

            write_runner(run_status="paused")
            with self.assertRaises(ValidationError) as error:
                terminate_run(runner.run.run_dir, reason="mismatch")
            self.assertIn("runner metadata run_status does not match", str(error.exception))

            current_group = os.getpgrp()
            write_runner(pid=current_group, process_group_id=current_group, session_id=current_group)
            with self.assertRaises(ValidationError) as error:
                terminate_run(runner.run.run_dir, reason="same group")
            self.assertIn("refusing to terminate", str(error.exception))

            current_session = os.getsid(0)
            write_runner(pid=current_session, process_group_id=current_session, session_id=current_session)
            with self.assertRaises(ValidationError) as error:
                terminate_run(runner.run.run_dir, reason="same session")
            self.assertIn("refusing to terminate", str(error.exception))

            write_runner()
            with patch("conductor_extras.runtime.run_control._pid_is_running", return_value=False):
                with self.assertRaises(ValidationError) as error:
                    terminate_run(runner.run.run_dir, reason="dead")
            self.assertIn("runner pid is not running", str(error.exception))

            write_runner(process_group_id=123)
            with patch("conductor_extras.runtime.run_control.os.killpg") as killpg:
                with self.assertRaises(ValidationError) as error:
                    terminate_run(runner.run.run_dir, reason="nope")
            self.assertIn("runner is not session-isolated", str(error.exception))
            killpg.assert_not_called()

            write_runner(pid=os.getpid(), process_group_id=os.getpid(), session_id=os.getpid())
            with self.assertRaises(ValidationError) as error:
                terminate_run(runner.run.run_dir, reason="self")
            self.assertIn("refusing to terminate the current process", str(error.exception))

            state = runner.run.read_state()
            state["status"] = "completed"
            runner.run.save_state(state)
            write_runner()
            with self.assertRaises(ValidationError) as error:
                terminate_run(runner.run.run_dir, reason="late")
            self.assertIn("run cannot be terminated from completed status", str(error.exception))

