    def test_restart_run_resets_completed_run_and_invalidates_agent_map_cache(self):
        workflow = workflow_with_steps(
            [
                {"id": "one", "kind": "write_artifact", "output": "one.txt", "content": "one"},
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "depends_on": ["one"],
                    "items": ["alpha", "beta"],
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                    "max_items": 5,
                },
            ]
        )
        workflow["max_workers"] = 1
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            first = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
            )
            run = first.execute()
            self.assertEqual(first.agent_calls, ["001-alpha.md", "002-beta.md"])

            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(["restart-run", str(run.run_dir), "--reason", "token=restartsecret"])
            self.assertEqual(code, 0)
            self.assertIn("Affected steps: one, packet", stdout.getvalue())
            self.assertIn("Status: needs_resume", stdout.getvalue())
            state = json.loads((run.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["status"], "needs_resume")
            self.assertNotIn("control_request", state)
            self.assertNotIn("finished_at_utc", state)
            self.assertNotIn("duration_ms", state)
            self.assertEqual(state["steps"]["one"]["status"], "pending")
            self.assertEqual(state["steps"]["packet"]["status"], "pending")
            self.assertEqual(state["agent_map_cache_generations"]["packet"], 1)
            self.assertEqual(state["control_events"][-1]["action"], "restart-run")
            self.assertEqual(state["control_events"][-1]["affected_steps"], ["one", "packet"])
            self.assertNotIn("restartsecret", json.dumps(state))
            self.assertTrue((run.artifacts_dir / "packets" / "001-alpha.md").is_file())

            second = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                resume_dir=run.run_dir,
                policy=RuntimePolicy(allow_agent=True),
            )
            resumed = second.execute()
            self.assertEqual(second.agent_calls, ["001-alpha.md", "002-beta.md"])
            state = json.loads((resumed.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["status"], "completed")
            self.assertNotIn("reused", state["steps"]["packet"]["detail"])

    def test_restart_run_is_honored_at_step_boundary(self):
        class RestartingRunner(WorkflowRunner):
            def _execute_step(self, step):
                super()._execute_step(step)
                if step["id"] == "one":
                    restart_run(self.run.run_dir, reason="operator restart")

        workflow = workflow_with_steps(
            [
                {"id": "one", "kind": "write_artifact", "output": "one.txt", "content": "one"},
                {"id": "two", "kind": "write_artifact", "output": "two.txt", "content": "two"},
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            run = RestartingRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            ).execute()
            state = json.loads((run.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["status"], "needs_resume")
            self.assertNotIn("control_request", state)
            self.assertEqual(state["steps"]["one"]["status"], "pending")
            self.assertEqual(state["steps"]["one"]["previous_status"], "completed")
            self.assertEqual(state["steps"]["two"]["status"], "pending")
            self.assertNotIn("previous_status", state["steps"]["two"])
            self.assertEqual(state["control_events"][-1]["action"], "restart-run")
            self.assertTrue((run.artifacts_dir / "one.txt").is_file())
            self.assertFalse((run.artifacts_dir / "two.txt").exists())

            resumed = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
                resume_dir=run.run_dir,
            ).execute()
            state = json.loads((resumed.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["status"], "completed")
            self.assertEqual(state["steps"]["one"]["status"], "completed")
            self.assertEqual(state["steps"]["two"]["status"], "completed")

