    def test_save_run_workflow_rejects_parent_swap_after_validation(self):
        workflow = workflow_with_steps(
            [
                {"id": "one", "kind": "write_artifact", "output": "one.txt", "content": "one"},
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            run = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            ).execute()
            export_parent = root / "export-parent"
            export_parent.mkdir()
            outside = root / "outside"
            outside.mkdir()
            destination = export_parent / "workflow.json"

            import conductor_extras.runtime.run_control as run_control_module

            original_reject = run_control_module.reject_symlink_path
            checks = {"count": 0}

            def swapping_reject(path, label):
                original_reject(path, label)
                if label == "workflow destination" and Path(path) == destination:
                    checks["count"] += 1
                    if checks["count"] == 2:
                        export_parent.rmdir()
                        export_parent.symlink_to(outside, target_is_directory=True)

            stderr = StringIO()
            with patch("conductor_extras.runtime.run_control.reject_symlink_path", side_effect=swapping_reject):
                with redirect_stderr(stderr):
                    code = cli_main(["save-run-workflow", str(run.run_dir), str(destination)])
            self.assertEqual(code, 2)
            self.assertIn("failed to open workflow destination parent", stderr.getvalue())
            self.assertFalse((outside / "workflow.json").exists())

