    def test_repeated_active_pause_request_preserves_boundary_request(self):
        workflow = workflow_with_steps(
            [
                {"id": "one", "kind": "write_artifact", "output": "one.txt", "content": "one"},
                {"id": "two", "kind": "write_artifact", "output": "two.txt", "content": "two"},
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            )
            state_path = runner.run.run_dir / "state.json"
            state = json.loads(state_path.read_text(encoding="utf-8"))
            state["status"] = "running"
            state_path.write_text(json.dumps(state), encoding="utf-8")

            pause_run(runner.run.run_dir, reason="first")
            pause_run(runner.run.run_dir, reason="second")
            state = json.loads(state_path.read_text(encoding="utf-8"))
            self.assertEqual(state["status"], "pause_requested")
            self.assertEqual(state["control_request"]["action"], "pause")

            runner.run.mark_step("one", "completed", "finished while pause requested", kind="write_artifact")
            state = json.loads(state_path.read_text(encoding="utf-8"))
            self.assertEqual(state["control_request"]["action"], "pause")
            paused = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
                resume_dir=runner.run.run_dir,
            ).execute()
            paused_state = json.loads((paused.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(paused_state["status"], "paused")
            self.assertNotIn("two", paused_state["steps"])
            runner_metadata = json.loads((paused.run_dir / "runner.json").read_text(encoding="utf-8"))
            self.assertEqual(runner_metadata["status"], "finished")
            self.assertEqual(runner_metadata["run_status"], "paused")

