    def test_import_session_trace_record_usage_rejects_before_mutation(self):
        workflow = workflow_with_steps(
            [
                {"id": "one", "kind": "write_artifact", "output": "one.txt", "content": "one"},
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            run = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            ).execute()

            def expect_rejected(trace_payload, expected):
                trace = root / ("%s.json" % expected.split()[0])
                write_json(trace, trace_payload)
                stderr = StringIO()
                with redirect_stderr(stderr):
                    code = cli_main(
                        [
                            "import-session-trace",
                            str(run.run_dir),
                            str(trace),
                            "--step-id",
                            "one",
                            "--record-usage",
                        ]
                    )
                self.assertEqual(code, 2)
                self.assertIn(expected, stderr.getvalue())
                state = json.loads((run.run_dir / "state.json").read_text(encoding="utf-8"))
                self.assertNotIn("session_trace_events", state)
                self.assertNotIn("session_trace_summary", state)
                self.assertNotIn("usage", state)
                self.assertNotIn("usage_events", state)
                decision_log = (run.run_dir / "05-decision-log.md").read_text(encoding="utf-8")
                self.assertNotIn("Runtime session trace `import-session-trace`", decision_log)
                self.assertNotIn("Runtime usage `record-usage`", decision_log)

            expect_rejected(
                {"event": "agent_note", "status": "completed"},
                "session trace artifact does not contain measured usage fields",
            )
            expect_rejected(
                {"event": "agent_note", "input_tokens": 2, "output_tokens": 3, "total_tokens": 8},
                "session trace artifact total_tokens must equal input_tokens plus output_tokens",
            )
            expect_rejected(
                {
                    "events": [
                        {"event": "usage_summary", "total_tokens": 10},
                        {"event": "usage_detail", "input_tokens": 3, "output_tokens": 4},
                    ]
                },
                "session trace artifact contains ambiguous aggregate usage fields",
            )

