    def test_import_session_trace_rejects_bad_inputs_and_is_local_write(self):
        workflow = workflow_with_steps(
            [
                {"id": "one", "kind": "write_artifact", "output": "one.txt", "content": "one"},
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            )
            run = runner.execute()

            def expect_import_error(trace_path, expected):
                stderr = StringIO()
                with redirect_stderr(stderr):
                    code = cli_main(["import-session-trace", str(run.run_dir), str(trace_path)])
                self.assertEqual(code, 2)
                self.assertIn(expected, stderr.getvalue())

            malformed = root / "malformed.json"
            malformed.write_text('{"events": [', encoding="utf-8")
            expect_import_error(malformed, "session trace artifact is not valid JSON")

            oversized = root / "oversized.json"
            oversized.write_text(" " * (MAX_SESSION_TRACE_JSON_BYTES + 1), encoding="utf-8")
            expect_import_error(oversized, "session trace artifact must be at most")

            deep_value = {}
            current = deep_value
            for _ in range(20):
                current["next"] = {}
                current = current["next"]
            deep = root / "deep-trace.json"
            write_json(deep, {"events": [{"event": "agent_start", "nested": deep_value}]})
            expect_import_error(deep, "session trace artifact nesting is too deep")

            deep_jsonl = root / "deep-trace.jsonl"
            write_jsonl_value = {"event": "agent_start", "nested": deep_value}
            deep_jsonl.write_text(json.dumps(write_jsonl_value), encoding="utf-8")
            expect_import_error(deep_jsonl, "session trace artifact nesting is too deep")

            over_count = root / "over-count.json"
            write_json(over_count, [{"event": "agent_start"} for _ in range(MAX_SESSION_TRACE_EVENTS + 1)])
            expect_import_error(over_count, "session trace artifact contains more than")

            over_count_jsonl = root / "over-count.jsonl"
            over_count_jsonl.write_text(
                "\n".join(json.dumps({"event": "agent_start"}) for _ in range(MAX_SESSION_TRACE_EVENTS + 1)),
                encoding="utf-8",
            )
            expect_import_error(over_count_jsonl, "session trace artifact contains more than")

            non_finite = root / "non-finite.json"
            non_finite.write_text('{"events": [{"event": "agent_start", "cost_usd": NaN}]}', encoding="utf-8")
            expect_import_error(non_finite, "session trace artifact must not contain non-standard JSON constants")

            non_finite_jsonl = root / "non-finite.jsonl"
            non_finite_jsonl.write_text('{"event": "agent_start", "cost_usd": NaN}\n', encoding="utf-8")
            expect_import_error(non_finite_jsonl, "session trace artifact must not contain non-standard JSON constants")

            overflow_float = root / "overflow-float.json"
            overflow_float.write_text('{"event": 1e999}\n', encoding="utf-8")
            expect_import_error(overflow_float, "session trace artifact must not contain non-finite JSON numbers")

            overflow_float_jsonl = root / "overflow-float.jsonl"
            overflow_float_jsonl.write_text('{"event": 1e999}\n{"event": "agent_start"}\n', encoding="utf-8")
            expect_import_error(overflow_float_jsonl, "session trace artifact must not contain non-finite JSON numbers")

            duplicate_jsonl = root / "duplicate.jsonl"
            duplicate_jsonl.write_text('{"event": "agent_start", "event": "agent_stop"}\n', encoding="utf-8")
            expect_import_error(duplicate_jsonl, "duplicate JSON keys")

            ambiguous = root / "ambiguous.json"
            write_json(ambiguous, [{"foo": "bar"}])
            expect_import_error(ambiguous, "session trace artifact does not contain supported trace events")

            ambiguous_events = root / "ambiguous-events.json"
            write_json(ambiguous_events, {"events": [{"foo": "bar"}]})
            expect_import_error(ambiguous_events, "session trace artifact does not contain supported trace events")

            structured_detail = root / "structured-detail.json"
            write_json(structured_detail, {"detail": {"message": "raw nested prompt text"}})
            expect_import_error(structured_detail, "session trace artifact does not contain supported trace events")

            non_object_jsonl = root / "non-object.jsonl"
            non_object_jsonl.write_text('["event"]\n{"event": "agent_start"}\n', encoding="utf-8")
            expect_import_error(non_object_jsonl, "JSONL line 1 must contain a JSON object")

            malformed_jsonl = root / "malformed.jsonl"
            malformed_jsonl.write_text('{"event": "agent_start"}\n{"event": \n', encoding="utf-8")
            expect_import_error(malformed_jsonl, "not valid JSON or JSONL at line 2")

            bad_step = root / "bad-step.json"
            write_json(bad_step, [{"event": "agent_start", "step_id": "missing"}])
            expect_import_error(bad_step, "unknown workflow step")

            duplicate = root / "duplicate.json"
            duplicate.write_text('{"events": [], "events": []}', encoding="utf-8")
            expect_import_error(duplicate, "duplicate JSON keys")

            bad_source = root / "trace.json"
            write_json(bad_source, [{"event": "agent_start"}])
            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(
                    [
                        "import-session-trace",
                        str(run.run_dir),
                        str(bad_source),
                        "--source",
                        "token=trace-source-secret",
                    ]
                )
            self.assertEqual(code, 2)
            self.assertIn("session trace source must not contain secret-like values", stderr.getvalue())

            target = root / "target-trace.json"
            write_json(target, [{"event": "agent_start"}])
            link = root / "trace-link.json"
            try:
                link.symlink_to(target)
            except OSError:
                self.skipTest("symlinks are not supported on this filesystem")
            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(["import-session-trace", str(run.run_dir), str(link)])
            self.assertEqual(code, 2)
            self.assertIn("session trace artifact must not be a symlink", stderr.getvalue())

        assessment = assess_command(
            [
                "python3",
                "-B",
                "-m",
                "conductor_extras",
                "import-session-trace",
                ".runtime-state/runs/run-a",
                ".runtime-state/session-trace.json",
            ]
        )
        self.assertTrue(assessment.writes)
        self.assertFalse(assessment.network)
        self.assertFalse(assessment.destructive)

