    def test_run_control_rejects_invalid_or_unsafe_actions(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "gate",
                    "kind": "manual_gate",
                    "risk": "medium",
                    "approval_id": "continue",
                },
                {
                    "id": "after",
                    "kind": "write_artifact",
                    "depends_on": ["gate"],
                    "output": "after.txt",
                    "content": "after",
                },
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            run = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(approvals={"continue"}),
            ).execute()

            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(["retry-step", str(run.run_dir), "after"])
            self.assertEqual(code, 2)
            self.assertIn("can only be retried", stderr.getvalue())

            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(["reset-step", str(run.run_dir), "missing"])
            self.assertEqual(code, 2)
            self.assertIn("unknown workflow step", stderr.getvalue())

            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(["skip-step", str(run.run_dir), "gate", "--reason", "bypass"])
            self.assertEqual(code, 2)
            self.assertIn("manual_gate steps cannot be skipped", stderr.getvalue())

            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(["retry-step", str(run.run_dir), "gate", "--reason", "browser retry"])
            self.assertEqual(code, 2)
            self.assertIn("manual_gate steps cannot be retried", stderr.getvalue())

            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(["reset-step", str(run.run_dir), "gate", "--reason", "browser reset"])
            self.assertEqual(code, 2)
            self.assertIn("manual_gate steps cannot be reset", stderr.getvalue())

            state_path = run.run_dir / "state.json"
            real_state = root / "outside-state.json"
            real_state.write_text(state_path.read_text(encoding="utf-8"), encoding="utf-8")
            state_path.unlink()
            try:
                state_path.symlink_to(real_state)
            except OSError:
                self.skipTest("symlinks are not supported on this filesystem")
            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(["reset-step", str(run.run_dir), "after"])
            self.assertEqual(code, 2)
            self.assertIn("state.json must not be a symlink", stderr.getvalue())

