    def test_run_control_audit_replace_failure_rolls_back_state_and_log(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "one",
                    "kind": "write_artifact",
                    "output": "one.txt",
                    "content": "one",
                }
            ]
        )
        validate_workflow(workflow)
        import conductor_extras.runtime.artifacts as artifacts_module

        original_replace = artifacts_module.replace_text_file_no_follow

        def patched_replace(path, label, text, temp_prefix, *args, **kwargs):
            if Path(path).name == "05-decision-log.md":
                raise ValidationError("simulated replace failure")
            return original_replace(path, label, text, temp_prefix, *args, **kwargs)

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            run = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            ).execute()
            state_before = (run.run_dir / "state.json").read_text(encoding="utf-8")
            log_before = (run.run_dir / "05-decision-log.md").read_text(encoding="utf-8")
            with patch("conductor_extras.runtime.artifacts.replace_text_file_no_follow", side_effect=patched_replace):
                stderr = StringIO()
                with redirect_stderr(stderr):
                    code = cli_main(["reset-step", str(run.run_dir), "one", "--reason", "replace should fail"])
            self.assertEqual(code, 2)
            self.assertIn("failed to append standard artifact", stderr.getvalue())
            self.assertEqual((run.run_dir / "state.json").read_text(encoding="utf-8"), state_before)
            self.assertEqual((run.run_dir / "05-decision-log.md").read_text(encoding="utf-8"), log_before)

