    def test_status_rejects_state_symlink_swap_after_precheck(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "one",
                    "kind": "write_artifact",
                    "output": "one.txt",
                    "content": "one",
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            import conductor_extras.runtime.security as security_module

            root = Path(tmp)
            run = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            ).execute()
            state_path = run.run_dir / "state.json"
            outside_state = root / "outside-state.json"
            outside_state.write_text(state_path.read_text(encoding="utf-8"), encoding="utf-8")
            original_reject = security_module.reject_symlink_path

            def swapping_reject(path, label):
                original_reject(path, label)
                if label == "state.json" and Path(path) == state_path:
                    state_path.unlink()
                    try:
                        state_path.symlink_to(outside_state)
                    except OSError:
                        self.skipTest("symlinks are not supported on this filesystem")

            stderr = StringIO()
            with patch("conductor_extras.runtime.security.reject_symlink_path", side_effect=swapping_reject):
                with redirect_stderr(stderr):
                    code = cli_main(["status", str(run.run_dir)])
            self.assertEqual(code, 2)
            self.assertIn("failed to open state.json", stderr.getvalue())

