    def test_artifact_write_rejects_parent_swap_after_validation_without_side_effect(self):
        workflow = workflow_with_steps(
            [
                {"id": "one", "kind": "write_artifact", "output": "one.txt", "content": "one"},
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            import conductor_extras.runtime.security as security_module

            root = Path(tmp)
            run = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            ).run
            destination = run.artifacts_dir / "nested" / "out.txt"
            outside = root / "outside"
            outside.mkdir()
            original_reject = security_module.reject_symlink_path

            def swapping_reject(path, label):
                original_reject(path, label)
                if label == "artifact" and Path(path) == destination:
                    try:
                        (run.artifacts_dir / "nested").symlink_to(outside, target_is_directory=True)
                    except OSError:
                        self.skipTest("directory symlinks are not supported on this filesystem")

            with patch("conductor_extras.runtime.security.reject_symlink_path", side_effect=swapping_reject):
                with self.assertRaises(ValidationError) as caught:
                    run.write_artifact("nested/out.txt", "payload")
            self.assertIn("failed to open artifact parent", str(caught.exception))
            self.assertFalse((outside / "out.txt").exists())

