    def test_codex_exec_budget_failure_preserves_strict_redacted_partial_output(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "agent",
                    "kind": "codex_exec",
                    "risk": "medium",
                    "prompt": "Inspect the workspace.",
                    "sandbox": "read-only",
                    "capture": "agent.md",
                    "max_tokens": 1000,
                }
            ]
        )
        validate_workflow(workflow)
        secret = "token=budgetsecret"
        stream = codex_budget_exhausted_stream_fixture(
            "Useful partial result. %s" % secret
        )
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
            )
            with patch(
                "conductor_extras.runtime.runner.run_process",
                return_value=ProcessResult(1, stream, "shared rollout token budget exhausted"),
            ):
                with self.assertRaisesRegex(StepExecutionError, "token budget exhausted"):
                    runner.execute()
            output_path = runner.run.artifacts_dir / "agent.md"
            output = output_path.read_text(encoding="utf-8")
            state = runner.run.read_state()
            step = state["steps"]["agent"]
            self.assertEqual(step["status"], "failed")
            self.assertTrue(step["provider_stream_valid"])
            self.assertEqual(step["provider_terminal_status"], "budget-exhausted")
            self.assertTrue(step["runtime_budget_exhausted"])
            self.assertTrue(step["partial_output_preserved"])
            self.assertEqual(step["partial_output_source"], "agent-messages")
            self.assertEqual(step["partial_output_sha256"], hashlib.sha256(output.encode()).hexdigest())
            self.assertEqual(step["partial_output_bytes"], len(output.encode()))
            self.assertIn("Useful partial result", output)
            self.assertNotIn("budgetsecret", output)
            self.assertNotIn("budgetsecret", json.dumps(state))
            self.assertNotIn(
                "budgetsecret",
                (runner.run.logs_dir / "agent.stdout.log").read_text(encoding="utf-8"),
            )
            self.assertFalse(codex_step_terminal_path(runner.run, "agent").exists())
            detail = collect_run_detail(root / "runs", runner.run.run_dir.name)
            detail_step = detail["steps"][0]
            self.assertTrue(detail_step["partial_output_preserved"])
            self.assertEqual(detail_step["partial_output_status"], "valid")
            diagnostics = diagnose_run_detail(detail)
            self.assertIn(
                "codex_partial_output_preserved",
                {issue["code"] for issue in diagnostics["issues"]},
            )
            snapshot = build_run_console_snapshot(detail)
            console_step = snapshot["steps"][0]
            self.assertTrue(console_step["runtime_budget_exhausted"])
            self.assertTrue(console_step["partial_output_preserved"])
            self.assertEqual(console_step["partial_output_source"], "agent-messages")
            rendered = render_run_console(snapshot, width=120)
            self.assertIn("Failed-turn output preserved", rendered)
            self.assertIn("provider failure retained", rendered)
            self.assertNotIn("budgetsecret", rendered)
            output_path.write_text("tampered\n", encoding="utf-8")
            tampered_detail = collect_run_detail(root / "runs", runner.run.run_dir.name)
            self.assertEqual(tampered_detail["steps"][0]["partial_output_status"], "invalid")
            self.assertIn(
                "codex_partial_output_invalid",
                {issue["code"] for issue in tampered_detail["diagnostics"]["issues"]},
            )
            tampered_snapshot = build_run_console_snapshot(tampered_detail)
            self.assertFalse(tampered_snapshot["steps"][0]["partial_output_preserved"])
            self.assertEqual(tampered_snapshot["steps"][0]["partial_output_status"], "invalid")
            self.assertIn(
                "Failed-turn output evidence invalid",
                render_run_console(tampered_snapshot, width=120),
            )

