    def test_codex_progress_native_lifecycle_is_bounded_and_v1_compatible(self):
        statuses = [
            "pending_init",
            "running",
            "interrupted",
            "completed",
            "errored",
            "shutdown",
            "not_found",
            "future_status",
        ]

        def rehash(value):
            payload = dict(value)
            payload.pop("progress_sha256", None)
            encoded = json.dumps(
                payload,
                sort_keys=True,
                separators=(",", ":"),
                ensure_ascii=True,
            ).encode("utf-8")
            value["progress_sha256"] = hashlib.sha256(encoded).hexdigest()

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            path = root / "progress.json"
            observer = CodexProgressObserver(
                path=path,
                scope="step",
                step_id="agent",
                packet_index=None,
                workflow_fingerprint="a" * 64,
                attempt=1,
                started_at_utc="2020-01-01T00:00:00.000Z",
                sandbox="read-only",
                model=None,
                effort=None,
                max_tokens=1000,
                write_interval_seconds=0,
            )
            child_ids = []
            for index, status in enumerate(statuses, start=1):
                child_id = "30000000-0000-4000-8000-%012d" % index
                child_ids.append(child_id)
                observer.observe(
                    json.dumps(
                        {
                            "type": "item.updated",
                            "item": {
                                "type": "collab_tool_call",
                                "tool": "wait",
                                "prompt": PROVIDER_PROGRESS_PRIVATE_SENTINEL,
                                "receiver_thread_ids": [child_id],
                                "agents_states": {
                                    child_id: {
                                        "status": status,
                                        "message": PROVIDER_PROGRESS_PRIVATE_SENTINEL,
                                    }
                                },
                            },
                        }
                    )
                )
            observer.observe(
                json.dumps(
                    {
                        "type": "item.updated",
                        "item": {
                            "type": "collab_tool_call",
                            "receiver_thread_ids": ["not-a-uuid"],
                            "agents_states": {
                                "not-a-uuid": {"status": "running"}
                            },
                        },
                    }
                )
            )
            observer.finalize("completed")
            progress = load_codex_progress(path)
            self.assertEqual(progress["native_agent_count"], 8)
            self.assertEqual(set(progress["native_agent_status_counts"].values()), {1})
            self.assertEqual(progress["last_event"], "item-updated")
            self.assertFalse(progress["native_agent_observation_truncated"])
            raw = path.read_text(encoding="utf-8")
            self.assertNotIn(PROVIDER_PROGRESS_PRIVATE_SENTINEL, raw)
            for child_id in child_ids:
                self.assertNotIn(child_id, raw)

            tampered = copy.deepcopy(progress)
            tampered["native_agents_enabled_by_observer"] = True
            rehash(tampered)
            with self.assertRaises(ValidationError):
                validate_codex_progress(tampered)

            reconciliation_fields = (
                "native_agent_usage_status",
                "native_agent_usage_session_count",
                "native_agent_usage_child_count",
                "native_agent_usage_input_tokens",
                "native_agent_usage_cached_input_tokens",
                "native_agent_usage_output_tokens",
                "native_agent_usage_total_tokens",
                "native_agent_usage_rollout_tokens",
            )
            legacy_v3 = copy.deepcopy(progress)
            legacy_v3["schema"] = CODEX_PROGRESS_SCHEMA_V3
            legacy_v3["native_agent_usage_attributed"] = False
            for field in reconciliation_fields:
                legacy_v3.pop(field)
            rehash(legacy_v3)
            legacy_v3_path = root / "legacy-v3.json"
            legacy_v3_path.write_text(json.dumps(legacy_v3), encoding="utf-8")
            loaded_v3 = load_codex_progress(legacy_v3_path)
            self.assertEqual(loaded_v3["schema"], CODEX_PROGRESS_SCHEMA_V3)
            self.assertEqual(
                get_schema("codex-progress-v3")["properties"]["schema"]["const"],
                CODEX_PROGRESS_SCHEMA_V3,
            )

            legacy_v2 = copy.deepcopy(legacy_v3)
            legacy_v2["schema"] = CODEX_PROGRESS_SCHEMA_V2
            for field in (
                "native_agents_enabled_by_runner",
                "native_agent_max_threads",
                "native_agent_max_depth",
            ):
                legacy_v2.pop(field)
            rehash(legacy_v2)
            legacy_v2_path = root / "legacy-v2.json"
            legacy_v2_path.write_text(json.dumps(legacy_v2), encoding="utf-8")
            loaded_v2 = load_codex_progress(legacy_v2_path)
            self.assertEqual(loaded_v2["schema"], CODEX_PROGRESS_SCHEMA_V2)
            self.assertFalse(
                codex_progress_summary(loaded_v2)["native_agents_enabled_by_runner"]
            )
            self.assertEqual(
                get_schema("codex-progress-v2")["properties"]["schema"]["const"],
                CODEX_PROGRESS_SCHEMA_V2,
            )

            legacy = copy.deepcopy(legacy_v2)
            legacy["schema"] = CODEX_PROGRESS_SCHEMA_V1
            for field in (
                "collab_tool_counts",
                "collab_tool_failed_count",
                "native_agent_count",
                "native_agent_status_counts",
                "native_agent_observation_truncated",
                "native_agent_usage_attributed",
                "native_agents_enabled_by_observer",
            ):
                legacy.pop(field)
            legacy["item_counts"].pop("collab_tool_call")
            legacy["last_event"] = "other"
            rehash(legacy)
            legacy_path = root / "legacy.json"
            legacy_path.write_text(json.dumps(legacy), encoding="utf-8")
            loaded_legacy = load_codex_progress(legacy_path)
            self.assertEqual(loaded_legacy["schema"], CODEX_PROGRESS_SCHEMA_V1)
            legacy_summary = codex_progress_summary(loaded_legacy)
            self.assertEqual(legacy_summary["native_agent_count"], 0)
            self.assertEqual(legacy_summary["collab_tool_call_count"], 0)
            self.assertFalse(legacy_summary["native_agent_usage_attributed"])
            self.assertEqual(
                get_schema("codex-progress-v1")["properties"]["schema"]["const"],
                CODEX_PROGRESS_SCHEMA_V1,
            )

            bounded_path = root / "bounded.json"
            with patch(
                "conductor_extras.runtime.codex_progress.MAX_CODEX_PROGRESS_NATIVE_AGENTS",
                2,
            ):
                bounded = CodexProgressObserver(
                    path=bounded_path,
                    scope="step",
                    step_id="bounded",
                    packet_index=None,
                    workflow_fingerprint="b" * 64,
                    attempt=1,
                    started_at_utc="2020-01-01T00:00:00.000Z",
                    sandbox="read-only",
                    model=None,
                    effort=None,
                    max_tokens=1000,
                    write_interval_seconds=0,
                )
                for child_id in child_ids[:3]:
                    bounded.observe(
                        json.dumps(
                            {
                                "type": "item.updated",
                                "item": {
                                    "type": "collab_tool_call",
                                    "receiver_thread_ids": [child_id],
                                },
                            }
                        )
                    )
                bounded.finalize("completed")
                bounded_progress = load_codex_progress(bounded_path)
            self.assertEqual(bounded_progress["native_agent_count"], 2)
            self.assertTrue(bounded_progress["native_agent_observation_truncated"])

    def test_codex_progress_is_streamed_while_provider_is_active(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "agent",
                    "kind": "codex_exec",
                    "risk": "medium",
                    "prompt": "Observe bounded progress.",
                    "sandbox": "read-only",
                    "capture": "agent.md",
                    "max_tokens": 1000,
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workspace = root / "workspace"
            workspace.mkdir()
            runner = ProgressEventCodexWorkflowRunner(
                workflow=workflow,
                workspace=workspace,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
                provider_delay=0.75,
            )
            errors = []

            def execute():
                try:
                    runner.execute()
                except BaseException as exc:  # noqa: BLE001 - preserve worker failure for assertion.
                    errors.append(exc)

            worker = threading.Thread(target=execute)
            worker.start()
            progress_path = codex_step_progress_path(runner.run, "agent")
            active = None
            deadline = time.monotonic() + 3
            while worker.is_alive() and time.monotonic() < deadline:
                try:
                    candidate = load_codex_progress(progress_path)
                except (FileNotFoundError, ValidationError):
                    candidate = None
                if candidate is not None and candidate["last_event"] == "turn-started":
                    active = candidate
                    break
                time.sleep(0.01)
            self.assertIsNotNone(active)
            self.assertEqual(active["status"], "active")
            self.assertTrue(worker.is_alive())
            detail = collect_run_detail(root / "runs", runner.run.run_dir.name)
            self.assertEqual(detail["steps"][0]["codex_progress"]["status"], "active")
            snapshot = build_run_console_snapshot(detail)
            self.assertFalse(run_console_is_terminal(snapshot))
            self.assertNotIn(PROVIDER_PROGRESS_PRIVATE_SENTINEL, json.dumps(snapshot))
            worker.join(timeout=5)
            self.assertFalse(worker.is_alive())
            if errors:
                raise errors[0]
            self.assertEqual(load_codex_progress(progress_path)["status"], "completed")

    def test_agent_map_progress_tracks_parallel_packets_without_content(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": ["alpha", "beta", "gamma"],
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                    "max_tokens": 1200,
                }
            ]
        )
        workflow["max_workers"] = 2
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workspace = root / "workspace"
            workspace.mkdir()
            runner = ProgressEventCodexWorkflowRunner(
                workflow=workflow,
                workspace=workspace,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True, allow_parallel=True),
                provider_delay=0.6,
                native_events=True,
            )
            errors = []

            def execute():
                try:
                    runner.execute()
                except BaseException as exc:  # noqa: BLE001 - preserve worker failure for assertion.
                    errors.append(exc)

            worker = threading.Thread(target=execute)
            worker.start()
            active = []
            deadline = time.monotonic() + 3
            while worker.is_alive() and time.monotonic() < deadline:
                try:
                    observed = list_codex_packet_progress(
                        runner.run.run_dir,
                        "packet",
                    )
                except (FileNotFoundError, OSError, ValidationError):
                    observed = []
                active = [value for value in observed if value["status"] == "active"]
                if len(active) >= 2:
                    break
                time.sleep(0.01)
            self.assertGreaterEqual(len(active), 2)
            worker.join(timeout=8)
            self.assertFalse(worker.is_alive())
            if errors:
                raise errors[0]
            packet_progress = list_codex_packet_progress(
                runner.run.run_dir,
                "packet",
            )
            self.assertEqual(len(packet_progress), 3)
            self.assertEqual({value["status"] for value in packet_progress}, {"completed"})
            self.assertEqual({value["packet_index"] for value in packet_progress}, {1, 2, 3})
            self.assertTrue(all(value["max_tokens"] > 0 for value in packet_progress))
            self.assertTrue(
                all(not value["raw_provider_content_persisted"] for value in packet_progress)
            )
            self.assertEqual(sum(value["native_agent_count"] for value in packet_progress), 6)
            self.assertEqual(
                sum(value["collab_tool_call_count"] for value in packet_progress),
                12,
            )
            for index in (1, 2, 3):
                path = codex_packet_progress_path(runner.run, "packet", index)
                raw = path.read_text(encoding="utf-8")
                self.assertNotIn(PROVIDER_PROGRESS_PRIVATE_SENTINEL, raw)
                self.assertNotIn("provider-secret", raw)
                self.assertEqual(path.stat().st_mode & 0o777, 0o600)
            detail = collect_run_detail(root / "runs", runner.run.run_dir.name)
            snapshot = build_run_console_snapshot(detail)
            packets = snapshot["steps"][0]["codex_packet_progress"]
            self.assertEqual(packets["count"], 3)
            self.assertEqual(packets["completed"], 3)
            self.assertEqual(packets["active"], 0)
            self.assertEqual(packets["native_agent_count"], 6)
            self.assertEqual(packets["native_agent_error_count"], 3)
            self.assertEqual(packets["collab_tool_call_count"], 12)
            rendered = render_run_console(snapshot, width=RUN_CONSOLE_MAX_WIDTH)
            self.assertIn("Packets 0 active / 3 completed / 0 failed", rendered)
            self.assertIn("Native 6 observed / 0 active / 3 errors", rendered)
            self.assertNotIn(PROVIDER_PROGRESS_PRIVATE_SENTINEL, rendered)

    def test_codex_progress_parser_is_strict_and_write_failures_are_fail_open(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            path = root / "progress.json"
            observer = CodexProgressObserver(
                path=path,
                scope="step",
                step_id="agent",
                packet_index=None,
                workflow_fingerprint="a" * 64,
                attempt=1,
                started_at_utc="2020-01-01T00:00:00.000000Z",
                sandbox="read-only",
                model=None,
                effort=None,
                max_tokens=1000,
                write_interval_seconds=0,
            )
            observer.observe('{"type":"turn.started","type":"turn.completed"}')
            observer.observe("{malformed")
            observer.observe('{"type":"turn.started","value":NaN}')
            observer.finalize("interrupted")
            progress = load_codex_progress(path)
            self.assertEqual(progress["status"], "interrupted")
            self.assertEqual(progress["event_count"], 0)
            self.assertEqual(path.stat().st_mode & 0o777, 0o600)

            with patch(
                "conductor_extras.runtime.codex_progress.replace_text_file_no_follow",
                side_effect=OSError("simulated progress storage failure"),
            ):
                disabled = CodexProgressObserver(
                    path=root / "disabled.json",
                    scope="step",
                    step_id="agent",
                    packet_index=None,
                    workflow_fingerprint="b" * 64,
                    attempt=1,
                    started_at_utc="2020-01-01T00:00:00.000000Z",
                    sandbox="read-only",
                    model=None,
                    effort=None,
                    max_tokens=1000,
                )
                self.assertTrue(disabled.disabled)
                disabled.observe(json.dumps({"type": "turn.started"}))
                disabled.finalize("failed")
                self.assertFalse((root / "disabled.json").exists())

            throttled_path = root / "throttled.json"
            throttled = CodexProgressObserver(
                path=throttled_path,
                scope="step",
                step_id="agent",
                packet_index=None,
                workflow_fingerprint="c" * 64,
                attempt=1,
                started_at_utc="2020-01-01T00:00:00.000000Z",
                sandbox="read-only",
                model=None,
                effort=None,
                max_tokens=1000,
                write_interval_seconds=3600,
            )
            for _ in range(100):
                throttled.observe(json.dumps({"type": "item.started"}))
            persisted_before_finalize = load_codex_progress(throttled_path)
            self.assertEqual(persisted_before_finalize["event_count"], 0)
            throttled.finalize("interrupted")
            persisted_after_finalize = load_codex_progress(throttled_path)
            self.assertEqual(persisted_after_finalize["event_count"], 100)
            self.assertEqual(persisted_after_finalize["item_started_count"], 100)

