    def test_codex_progress_records_local_failure_outcomes(self):
        class OutcomeRunner(ProgressEventCodexWorkflowRunner):
            def __init__(self, *args, outcome, **kwargs):
                self.outcome = outcome
                super().__init__(*args, **kwargs)

            def _run_process(self, argv, *args, **kwargs):
                result = super()._run_process(argv, *args, **kwargs)
                if self.outcome == "missing-output":
                    Path(argv[-1]).unlink()
                    return result
                return ProcessResult(
                    returncode=7 if self.outcome == "nonzero" else result.returncode,
                    stdout=result.stdout,
                    stderr=result.stderr,
                    timed_out=self.outcome == "timed-out",
                )

        for outcome, expected_status in (
            ("nonzero", "failed"),
            ("timed-out", "timed-out"),
            ("missing-output", "failed"),
        ):
            with self.subTest(outcome=outcome), tempfile.TemporaryDirectory() as tmp:
                root = Path(tmp)
                workspace = root / "workspace"
                workspace.mkdir()
                workflow = workflow_with_steps(
                    [
                        {
                            "id": "agent",
                            "kind": "codex_exec",
                            "risk": "medium",
                            "prompt": "Exercise a local provider outcome.",
                            "sandbox": "read-only",
                            "capture": "agent.md",
                            "max_tokens": 1000,
                        }
                    ]
                )
                validate_workflow(workflow)
                runner = OutcomeRunner(
                    workflow=workflow,
                    workspace=workspace,
                    base_run_dir=root / "runs",
                    policy=RuntimePolicy(allow_agent=True),
                    outcome=outcome,
                )
                with self.assertRaises(StepExecutionError):
                    runner.execute()
                progress = load_codex_progress(
                    codex_step_progress_path(runner.run, "agent")
                )
                self.assertEqual(progress["status"], expected_status)
                self.assertEqual(runner.run.read_state()["status"], "failed")

    def test_run_console_follow_deduplicates_and_emits_no_redirected_ansi(self):
        active = {
            "id": "run-a",
            "workflow": "workflow-a",
            "status": "running",
            "duration_ms": 10,
            "runner": {
                "status": "active",
                "liveness": "alive",
                "active_process_count": 1,
            },
            "diagnostics": {"severity": "ok", "summary": "No issues.", "issues": []},
            "steps": [
                {
                    "id": "agent",
                    "status": "running",
                    "phase": "default",
                    "kind": "codex_exec",
                    "duration_ms": 10,
                    "detail": PROVIDER_PROGRESS_PRIVATE_SENTINEL,
                    "codex_progress": {
                        "status": "active",
                        "last_event": "turn-started",
                        "event_count": 2,
                        "item_started_count": 0,
                        "item_completed_count": 0,
                        "failed_item_count": 0,
                        "total_tokens": None,
                    },
                }
            ],
        }
        completed = copy.deepcopy(active)
        completed["status"] = "completed"
        completed["runner"]["status"] = "finished"
        completed["runner"]["liveness"] = "finished"
        completed["runner"]["active_process_count"] = 0
        completed["steps"][0]["status"] = "completed"
        completed["steps"][0]["codex_progress"]["status"] = "completed"
        completed["steps"][0]["codex_progress"]["last_event"] = "turn-completed"
        output = StringIO()
        with patch(
            "conductor_extras.cli.collect_run_detail",
            side_effect=[active, active, completed],
        ), patch("conductor_extras.cli.time.sleep"), redirect_stdout(output):
            self.assertEqual(
                cli_main(
                    [
                        "run-console",
                        "/tmp/run-a",
                        "--follow",
                        "--refresh-ms",
                        "100",
                        "--timeout-seconds",
                        "5",
                    ]
                ),
                0,
            )
        rendered = output.getvalue()
        self.assertEqual(rendered.count("Conductor run run-a"), 2)
        self.assertNotIn("\x1b", rendered)
        self.assertNotIn(PROVIDER_PROGRESS_PRIVATE_SENTINEL, rendered)
        self.assertIn("Codex active", rendered)
        self.assertIn("Codex completed", rendered)

    def test_codex_exec_recovers_local_terminal_without_provider_replay(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "agent",
                    "kind": "codex_exec",
                    "risk": "medium",
                    "prompt": "Inspect the exact bounded target.",
                    "sandbox": "read-only",
                    "capture": "agent.md",
                    "max_tokens": 1000,
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workspace = root / "workspace"
            workspace.mkdir()
            policy = RuntimePolicy(allow_agent=True)
            crashed = TerminalCodexWorkflowRunner(
                workflow=workflow,
                workspace=workspace,
                base_run_dir=root / "runs",
                policy=policy,
                terminal_crash_phase="written",
            )
            with self.assertRaises(SimulatedCodexStepCrash):
                crashed.execute()
            self.assertEqual(crashed.provider_calls, ["started"])
            terminal_path = codex_step_terminal_path(crashed.run, "agent")
            terminal = load_codex_step_terminal(terminal_path)
            self.assertEqual(terminal["schema"], CODEX_STEP_TERMINAL_SCHEMA)
            self.assertEqual(terminal["telemetry"]["total_tokens"], 15)
            progress = load_codex_progress(
                codex_step_progress_path(crashed.run, "agent")
            )
            self.assertEqual(progress["status"], "completed")
            self.assertEqual(progress["total_tokens"], 15)
            self.assertNotIn("terminal result", json.dumps(progress))
            self.assertEqual(terminal_path.stat().st_mode & 0o777, 0o600)
            summary = codex_step_terminal_summary(terminal)
            self.assertFalse(summary["provider_replay_required"])
            self.assertNotIn("session_id", summary)
            self.assertNotIn("output", summary)
            with redirect_stdout(StringIO()):
                self.assertEqual(
                    cli_main(["validate-codex-step-terminal", str(terminal_path)]),
                    0,
                )
            inspected = StringIO()
            with redirect_stdout(inspected):
                self.assertEqual(
                    cli_main(
                        [
                            "inspect-codex-step-terminal",
                            str(terminal_path),
                            "--json",
                        ]
                    ),
                    0,
                )
            public = inspected.getvalue()
            self.assertIn(terminal["terminal_sha256"], public)
            self.assertNotIn(terminal["session_id"], public)
            self.assertNotIn(terminal["output"], public)
            assessment = assess_command(
                [
                    "python3",
                    "-m",
                    "conductor_extras",
                    "inspect-codex-step-terminal",
                    str(terminal_path),
                ]
            )
            self.assertFalse(assessment.writes)
            self.assertFalse(assessment.network)
            self.assertEqual(
                get_schema("codex-step-terminal")["properties"]["schema"]["const"],
                CODEX_STEP_TERMINAL_SCHEMA,
            )
            detail = collect_run_detail(root / "runs", crashed.run.run_dir.name)
            terminal_detail = detail["steps"][0]["codex_terminal"]
            self.assertEqual(terminal_detail["terminal_sha256"], terminal["terminal_sha256"])
            self.assertEqual(terminal_detail["status"], "provider-terminal-recovery-pending")
            live_html = render_live_run_detail(detail)
            self.assertIn("Codex local terminal recovery pending", live_html)
            self.assertNotIn(terminal["session_id"], live_html)

            retry_step(
                crashed.run.run_dir,
                "agent",
                reason="recover completed local turn",
            )
            resumed = TerminalCodexWorkflowRunner(
                workflow=workflow,
                workspace=workspace,
                base_run_dir=root / "runs",
                resume_dir=crashed.run.run_dir,
                policy=policy,
            )
            resumed.execute()
            self.assertEqual(resumed.provider_calls, [])
            self.assertFalse(terminal_path.exists())
            state = resumed.run.read_state()
            self.assertEqual(state["steps"]["agent"]["status"], "completed")
            self.assertEqual(state["steps"]["agent"]["total_tokens"], 15)
            self.assertEqual(state["steps"]["agent"]["agent_invocations"], 0)
            self.assertEqual(state["steps"]["agent"]["agent_recovered_invocations"], 1)
            self.assertEqual(
                state["telemetry_receipts"].count(terminal["terminal_sha256"]),
                1,
            )
            self.assertEqual(load_codex_step_checkpoint(resumed.run, "agent")["status"], "completed")
            output = (resumed.run.artifacts_dir / "agent.md").read_text(encoding="utf-8")
            self.assertNotIn("codexterminal", output)
            self.assertIn("<redacted>", output)

