                crashed = TerminalCodexWorkflowRunner(
                    workflow=workflow,
                    workspace=workspace,
                    base_run_dir=runtime_parent / "runs",
                    policy=policy,
                    terminal_crash_phase="written",
                )
                with self.assertRaises(SimulatedCodexStepCrash):
                    crashed.execute()
                terminal = load_codex_step_terminal(
                    codex_step_terminal_path(crashed.run, "agent")
                )
                self.assertEqual(terminal["workspace_mode"], "direct-write")
                self.assertIsNotNone(terminal["workspace_result_sha256"])
                self.assertGreaterEqual(terminal["workspace_file_count"], 2)
                if tamper_sibling:
                    sibling.write_text("changed after terminal\n", encoding="utf-8")

                retry_step(crashed.run.run_dir, "agent", reason="recover exact run")
                resumed = TerminalCodexWorkflowRunner(
                    workflow=workflow,
                    workspace=workspace,
                    base_run_dir=runtime_parent / "runs",
                    resume_dir=crashed.run.run_dir,
                    policy=policy,
                )
                if tamper_sibling:
                    with self.assertRaisesRegex(ValidationError, "workspace changed"):
                        resumed.execute()
                else:
                    resumed.execute()
                self.assertEqual(resumed.provider_calls, [])

