    @unittest.skipUnless(os.name == "posix", "interrupted-run recovery requires POSIX locks")
    def test_resumed_codex_context_is_receipted_and_terminal_recovery_does_not_replay(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "agent",
                    "kind": "codex_exec",
                    "risk": "medium",
                    "prompt": "Continue the exact context-bound provider task.",
                    "sandbox": "read-only",
                    "capture": "agent.md",
                }
            ]
        )
        workflow["hooks"] = [
            {
                "id": "resume-context",
                "event": "agent_start",
                "command": ["printf", "resume lifecycle context\n"],
                "scopes": ["codex_exec"],
                "inject_context": True,
            }
        ]
        validate_workflow(workflow)

        class CrashOnResumedTerminal(CheckpointCodexWorkflowRunner):
            def __init__(self, *args, **kwargs):
                self.resumed_terminal_crashed = False
                super().__init__(*args, **kwargs)

            def _codex_step_terminal_checkpoint(self, phase, terminal):
                if (
                    not self.resumed_terminal_crashed
                    and phase == "written"
                    and terminal["mode"] == "resumed"
                ):
                    self.resumed_terminal_crashed = True
                    raise RuntimeError("simulated resumed terminal crash")

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            policy = RuntimePolicy(allow_agent=True)
            first = CheckpointCodexWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=policy,
            )
            run = first.execute()
            checkpoint = load_codex_step_checkpoint(run, "agent")
            checkpoint["schema"] = CODEX_STEP_CHECKPOINT_SCHEMA_V1
            for field in (
                "invocation_base_prompt_sha256",
                "invocation_effective_prompt_sha256",
                "lifecycle_context_receipt_sha256",
            ):
                checkpoint.pop(field)
            write_codex_step_checkpoint(run, checkpoint)
            initial_receipt_path = next(
                (run.artifacts_dir / ".agent-lifecycle-context").glob("*.json")
            )
            initial_receipt = load_agent_lifecycle_context_receipt(
                initial_receipt_path
            )
            initial_receipt["schema"] = AGENT_LIFECYCLE_CONTEXT_SCHEMA_V1
            for field in (
                "session_mode",
                "session_id_sha256",
                "member_id",
                "task_id",
                "generation",
                "round",
                "quality_retry_index",
                "plan_revision",
            ):
                initial_receipt.pop(field)
            initial_receipt_path.write_text(
                json.dumps(initial_receipt, indent=2, sort_keys=True) + "\n",
                encoding="utf-8",
            )
            mark_codex_run_interrupted(run)
            recover_run(
                run.run_dir,
                reason="resume context-bound provider call",
                resume_codex=True,
            )

            crashed = CrashOnResumedTerminal(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                resume_dir=run.run_dir,
                policy=policy,
            )
            with self.assertRaisesRegex(ValidationError, "provider stream callback failed"):
                crashed.execute()
            provider_inputs = [
                value
                for value in crashed.process_inputs
                if isinstance(value, str) and AGENT_LIFECYCLE_CONTEXT_BEGIN in value
            ]
            self.assertEqual(len(provider_inputs), 1)
            self.assertIn("resume lifecycle context", provider_inputs[0])
            receipts = [
                load_agent_lifecycle_context_receipt(path)
                for path in sorted(
                    (run.artifacts_dir / ".agent-lifecycle-context").glob("*.json")
                )
            ]
            self.assertEqual(
                {
                    agent_lifecycle_context_receipt_identity(receipt)[
                        "session_mode"
                    ]
                    for receipt in receipts
                },
                {"new", "resume"},
            )
            terminal = load_codex_step_terminal(codex_step_terminal_path(run, "agent"))
            self.assertEqual(terminal["mode"], "resumed")
            self.assertRegex(
                terminal["lifecycle_context_receipt_sha256"],
                r"^[0-9a-f]{64}$",
            )
            lifecycle_starts = sum(
                event["event"] == "agent_start" for event in run.read_state()["hook_events"]
            )

            retry_step(run.run_dir, "agent", reason="recover resumed context terminal")
            recovered = CheckpointCodexWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                resume_dir=run.run_dir,
                policy=policy,
            )
            recovered.execute()
            self.assertEqual(recovered.initial_commands, [])
            self.assertEqual(recovered.resume_commands, [])
            self.assertEqual(recovered.process_inputs, [])
            self.assertEqual(
                sum(
                    event["event"] == "agent_start"
                    for event in run.read_state()["hook_events"]
                ),
                lifecycle_starts,
            )

    @unittest.skipUnless(os.name == "posix", "interrupted-run recovery requires POSIX locks")
    def test_recover_run_resumes_checkpointed_codex_thread(self):
        original_prompt = "Continue the exact provider task phrase that must not be replayed."
        workflow = workflow_with_steps(
            [
                {
                    "id": "agent",
                    "kind": "codex_exec",
                    "risk": "medium",
                    "prompt": original_prompt,
                    "sandbox": "read-only",
                    "capture": "agent.md",
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            first = CheckpointCodexWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
            )
            run = first.execute()
            mark_codex_run_interrupted(run)

            detail = collect_run_detail(root / "runs", run.run_dir.name)
            issue = next(
                issue
                for issue in detail["diagnostics"]["issues"]
                if issue["code"] == "runner_finished_with_active_state"
            )
            self.assertIn("--resume-codex", issue["command"])
            self.assertEqual(detail["steps"][0]["codex_checkpoint"]["status"], "active")

            recovered = recover_run(
                run.run_dir,
                reason="provider process exited after thread checkpoint",
                resume_codex=True,
            )
            self.assertEqual(recovered["resolution"], "resume-codex")
            state = run.read_state()
            self.assertEqual(state["steps"]["agent"]["status"], "pending")
            self.assertEqual(
                state["codex_resume_bindings"]["agent"]["session_id"],
                FAKE_CODEX_SESSION_ID,
            )
            self.assertTrue(state["control_events"][-1]["provider_continuation"])

            second = CheckpointCodexWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                resume_dir=run.run_dir,
                policy=RuntimePolicy(allow_agent=True),
            )
            second.execute()
            self.assertEqual(
                second.resume_commands[0][-3:],
                ["resume", FAKE_CODEX_SESSION_ID, "-"],
            )
            self.assertNotIn(original_prompt, second.process_inputs[0])
            self.assertIn("prior turn", second.process_inputs[0])
            checkpoint = load_codex_step_checkpoint(run, "agent")
            self.assertEqual(checkpoint["status"], "completed")
            self.assertEqual(checkpoint["mode"], "resumed")
            self.assertEqual(checkpoint["resume_count"], 1)
            self.assertEqual((run.artifacts_dir / "agent.md").read_text(encoding="utf-8"), "resumed result")
            final_state = run.read_state()
            self.assertEqual(final_state["status"], "completed")
            self.assertNotIn("codex_resume_bindings", final_state)

