    def test_workflow_validation_and_schema_bound_codex_agent_budgets(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": ["a", "b"],
                    "prompt_template": "Review {item}",
                    "effort": "medium",
                    "max_tokens": 1000,
                    "max_total_tokens": 1500,
                }
            ]
        )
        workflow["agent_effort"] = "high"
        workflow["agent_max_tokens"] = 12000
        workflow["agent_map_max_total_tokens"] = 100000
        validate_workflow(workflow)

        invalid_cases = [
            ("agent_effort", "magic"),
            ("agent_max_tokens", 99),
            ("agent_map_max_total_tokens", True),
        ]
        for key, value in invalid_cases:
            with self.subTest(key=key):
                candidate = copy.deepcopy(workflow)
                candidate[key] = value
                with self.assertRaises(ValidationError):
                    validate_workflow(candidate)
        for key, value in (("effort", "magic"), ("max_tokens", 99), ("max_total_tokens", None)):
            with self.subTest(step_key=key):
                candidate = copy.deepcopy(workflow)
                candidate["steps"][0][key] = value
                with self.assertRaises(ValidationError):
                    validate_workflow(candidate)

        schema = get_schema("workflow")
        properties = schema["properties"]
        self.assertIn("agent_effort", properties)
        self.assertEqual(properties["agent_max_tokens"]["minimum"], 100)
        agent_map_schema = next(
            item
            for item in schema["properties"]["steps"]["items"]["oneOf"]
            if item["properties"]["kind"].get("const") == "agent_map"
        )
        self.assertEqual(agent_map_schema["properties"]["max_total_tokens"]["minimum"], 100)

    def test_agent_map_packetization_is_bounded_stable_and_schema_validated(self):
        items = ["scope-%03d" % index for index in range(100)]
        packets = packetize_agent_items(items, 25)
        self.assertEqual(len(packets), 25)
        self.assertTrue(all(len(packet.items) == 4 for packet in packets))
        self.assertEqual(json.loads(packets[0].value), items[:4])
        self.assertEqual(packets[0].label, "scope-000 (+3 more)")

        stable_packets = packetize_agent_items(items[:26], 25)
        self.assertEqual(len(stable_packets), 13)
        self.assertTrue(all(len(packet.items) == 2 for packet in stable_packets))
        self.assertEqual(packetize_agent_items(["only"], 25)[0].value, "only")
        with self.assertRaisesRegex(ValidationError, "use at least 2 packets"):
            packetize_agent_items(
                ["scope-%03d" % index for index in range(MAX_AGENT_ITEMS_PER_PACKET + 1)],
                1,
            )

        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": ["alpha", "beta"],
                    "prompt_template": "Review {item}",
                    "max_packets": 1,
                }
            ]
        )
        validate_workflow(workflow)
        for value in (None, 0, True, MAX_AGENT_PACKETS + 1):
            with self.subTest(max_packets=value):
                candidate = copy.deepcopy(workflow)
                candidate["steps"][0]["max_packets"] = value
                with self.assertRaises(ValidationError):
                    validate_workflow(candidate)
        schema = get_schema("workflow")
        agent_map_schema = next(
            item
            for item in schema["properties"]["steps"]["items"]["oneOf"]
            if item["properties"]["kind"].get("const") == "agent_map"
        )
        self.assertEqual(agent_map_schema["properties"]["max_packets"]["maximum"], MAX_AGENT_PACKETS)

