    def test_workflow_validation_rejects_explicit_null_numeric_fields(self):
        def base_workflow():
            return workflow_with_steps(
                [
                    {
                        "id": "packet",
                        "kind": "agent_map",
                        "risk": "medium",
                        "items": ["a", "b"],
                        "prompt_template": "Review {item}",
                    }
                ]
            )

        top_level_cases = [
            ("max_workers", "max_workers must be an integer from 1 to %d" % MAX_AGENT_WORKERS),
            ("max_items", "max_items must be an integer from 1 to"),
            ("default_timeout_seconds", "default_timeout_seconds must be an integer from 1 to"),
            ("agent_timeout_seconds", "agent_timeout_seconds must be an integer from 1 to"),
            ("output_limit_bytes", "output_limit_bytes must be an integer from 1 to"),
        ]
        for key, expected in top_level_cases:
            with self.subTest(key=key):
                workflow = base_workflow()
                workflow[key] = None
                with self.assertRaises(ValidationError) as error:
                    validate_workflow(workflow)
                self.assertIn(expected, str(error.exception))

        step_cases = [
            ("max_workers", "agent_map step packet max_workers must be an integer from 1 to %d" % MAX_AGENT_WORKERS),
            ("max_packets", "agent_map step packet max_packets must be an integer from 1 to"),
            ("max_items", "step packet max_items must be an integer from 1 to"),
            ("timeout_seconds", "step packet timeout_seconds must be an integer from 1 to"),
            ("output_limit_bytes", "step packet output_limit_bytes must be an integer from 1 to"),
        ]
        for key, expected in step_cases:
            with self.subTest(key=key):
                workflow = base_workflow()
                workflow["steps"][0][key] = None
                with self.assertRaises(ValidationError) as error:
                    validate_workflow(workflow)
                self.assertIn(expected, str(error.exception))

        hook_cases = [
            ("timeout_seconds", "hook pre timeout_seconds must be an integer from 1 to"),
            ("output_limit_bytes", "hook pre output_limit_bytes must be an integer from 1 to"),
        ]
        for key, expected in hook_cases:
            with self.subTest(key=key):
                workflow = base_workflow()
                workflow["hooks"] = [{"id": "pre", "event": "before_run", "command": ["true"], key: None}]
                with self.assertRaises(ValidationError) as error:
                    validate_workflow(workflow)
                self.assertIn(expected, str(error.exception))

