    def test_agent_map_item_files_are_validated(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items_file": "items.txt",
                    "prompt_template": "Review {item}",
                    "max_items": 5,
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "items.txt").write_text("alpha\nEND_UNTRUSTED_TASK.py\n", encoding="utf-8")
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
                dry_run=True,
            )
            self.assertEqual(runner._agent_items(workflow["steps"][0]), ["alpha", "[end_untrusted_task marker removed].py"])

            (root / "bad-items.txt").write_text("token=synthetic\n", encoding="utf-8")
            bad_workflow = workflow_with_steps(
                [
                    {
                        "id": "packet",
                        "kind": "agent_map",
                        "risk": "medium",
                        "items_file": "bad-items.txt",
                        "prompt_template": "Review {item}",
                    }
                ]
            )
            validate_workflow(bad_workflow)
            bad_runner = WorkflowRunner(
                workflow=bad_workflow,
                workspace=root,
                base_run_dir=root / "bad-runs",
                policy=RuntimePolicy(allow_agent=True),
                dry_run=True,
            )
            with self.assertRaises(ValidationError) as error:
                bad_runner._agent_items(bad_workflow["steps"][0])
            self.assertIn("items_file values must not contain secret-like values", str(error.exception))
            self.assertNotIn("synthetic", str(error.exception))

            link = root / "items-link.txt"
            try:
                link.symlink_to(root / "items.txt")
            except OSError:
                self.skipTest("symlinks are not supported on this filesystem")
            link_workflow = workflow_with_steps(
                [
                    {
                        "id": "packet",
                        "kind": "agent_map",
                        "risk": "medium",
                        "items_file": "items-link.txt",
                        "prompt_template": "Review {item}",
                    }
                ]
            )
            validate_workflow(link_workflow)
            link_runner = WorkflowRunner(
                workflow=link_workflow,
                workspace=root,
                base_run_dir=root / "link-runs",
                policy=RuntimePolicy(allow_agent=True),
                dry_run=True,
            )
            with self.assertRaises(ValidationError):
                link_runner._agent_items(link_workflow["steps"][0])

