    def test_agent_map_budget_is_divided_over_only_uncached_packets(self):
        class BudgetRunner(FakeAgentWorkflowRunner):
            def __init__(self, *args, **kwargs):
                self.command_budgets = []
                super().__init__(*args, **kwargs)

            def _codex_command(self, step, output_path):
                self.command_budgets.append((step.get("effort"), step.get("max_tokens")))
                return super()._codex_command(step, output_path)

        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": ["alpha", "beta", "gamma"],
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                    "max_items": 5,
                    "effort": "medium",
                    "max_tokens": 1000,
                    "max_total_tokens": 1500,
                }
            ]
        )
        workflow["max_workers"] = 1
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            first = BudgetRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
                fail_on_calls={2},
            )
            with self.assertRaises(StepExecutionError):
                first.execute()
            self.assertEqual(first.command_budgets, [("medium", 500)] * 3)
            failed = first.run.read_state()["steps"]["packet"]
            self.assertEqual(failed["agent_effort"], "medium")
            self.assertEqual(failed["agent_max_tokens"], 500)
            self.assertEqual(failed["agent_max_total_tokens"], 1500)
            self.assertEqual(failed["agent_budgeted_invocations"], 3)

            retry_step(first.run.run_dir, "packet", reason="retry one failed budgeted packet")
            second = BudgetRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                resume_dir=first.run.run_dir,
                policy=RuntimePolicy(allow_agent=True),
            )
            second.execute()
            self.assertEqual(second.command_budgets, [("medium", 1000)])
            completed = first.run.read_state()["steps"]["packet"]
            self.assertEqual(completed["agent_items_cached"], 2)
            self.assertEqual(completed["agent_budgeted_invocations"], 1)
            self.assertEqual(completed["agent_max_tokens"], 1000)
            detail = collect_run_detail(root / "runs", first.run.run_dir.name)
            self.assertEqual(detail["steps"][0]["agent_max_total_tokens"], 1500)
            self.assertEqual(detail["steps"][0]["agent_budgeted_invocations"], 1)

