    def test_agent_map_recovers_local_terminal_before_cache_receipt(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": ["alpha"],
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                    "max_tokens": 1000,
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            policy = RuntimePolicy(allow_agent=True)
            crashed = TerminalAgentMapRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=policy,
                terminal_crash_phase="written",
            )
            with self.assertRaises(SimulatedAgentMapCrash):
                crashed.execute()
            self.assertEqual(len(crashed.agent_calls), 1)
            terminals = list_agent_map_packet_terminal_paths(
                crashed.run,
                "packets",
                1,
            )
            self.assertEqual(len(terminals), 1)
            terminal = load_agent_map_packet_terminal(terminals[0])
            self.assertEqual(terminal["schema"], AGENT_MAP_PACKET_TERMINAL_SCHEMA)
            self.assertEqual(terminal["telemetry"]["total_tokens"], 10)
            self.assertFalse(
                (
                    crashed.run.artifacts_dir
                    / "packets"
                    / ".agent-map-cache-entries"
                    / "000001.json"
                ).exists()
            )
            summary = agent_map_packet_terminal_summary(terminal)
            self.assertEqual(summary["status"], "provider-terminal-recovery-pending")
            self.assertFalse(summary["provider_replay_required"])
            with redirect_stdout(StringIO()):
                self.assertEqual(
                    cli_main(
                        [
                            "validate-agent-map-packet-terminal",
                            str(terminals[0]),
                        ]
                    ),
                    0,
                )
            inspected = StringIO()
            with redirect_stdout(inspected):
                self.assertEqual(
                    cli_main(
                        [
                            "inspect-agent-map-packet-terminal",
                            str(terminals[0]),
                            "--json",
                        ]
                    ),
                    0,
                )
            public = inspected.getvalue()
            self.assertIn(terminal["terminal_sha256"], public)
            self.assertNotIn(terminal["session_id"], public)
            self.assertNotIn(terminal["output"], public)
            assessment = assess_command(
                [
                    "python3",
                    "-m",
                    "conductor_extras",
                    "inspect-agent-map-packet-terminal",
                    str(terminals[0]),
                ]
            )
            self.assertFalse(assessment.writes)
            self.assertFalse(assessment.network)
            self.assertEqual(
                get_schema("agent-map-packet-terminal")["properties"]["schema"]["const"],
                AGENT_MAP_PACKET_TERMINAL_SCHEMA,
            )
            detail = collect_run_detail(root / "runs", crashed.run.run_dir.name)
            pending_map = detail["agent_maps"][0]
            self.assertEqual(pending_map["status"], "recovery-pending")
            self.assertEqual(pending_map["terminal_pending_count"], 1)
            self.assertEqual(
                pending_map["terminal_pending"][0]["terminal_sha256"],
                terminal["terminal_sha256"],
            )
            self.assertEqual(pending_map["packets"][0]["status"], "recovery-pending")
            live_html = render_live_run_detail(detail)
            self.assertIn("Local packet terminal recovery pending", live_html)
            self.assertNotIn(terminal["session_id"], live_html)

            retry_step(
                crashed.run.run_dir,
                "packet",
                reason="recover local packet terminal",
            )
            resumed = TerminalAgentMapRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                resume_dir=crashed.run.run_dir,
                policy=policy,
            )
            resumed.execute()
            self.assertEqual(resumed.agent_calls, [])
            self.assertEqual(
                list_agent_map_packet_terminal_paths(resumed.run, "packets", 1),
                [],
            )
            state = resumed.run.read_state()
            self.assertEqual(state["steps"]["packet"]["status"], "completed")
            self.assertEqual(state["steps"]["packet"]["total_tokens"], 10)
            self.assertEqual(
                state["telemetry_receipts"].count(terminal["terminal_sha256"]),
                1,
            )
            usage = [
                event
                for event in state["usage_events"]
                if event.get("source") == "provider-runtime:codex"
            ]
            self.assertEqual(len(usage), 1)

