    def test_agent_map_terminal_blocks_destructive_controls_until_recovery(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": ["alpha"],
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                    "max_tokens": 1000,
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            policy = RuntimePolicy(allow_agent=True)
            crashed = TerminalAgentMapRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=policy,
                terminal_crash_phase="written",
            )
            with self.assertRaises(SimulatedAgentMapCrash):
                crashed.execute()
            state_path = crashed.run.run_dir / "state.json"
            controls = (
                lambda: retry_packet(
                    crashed.run.run_dir,
                    "packet",
                    1,
                    reason="force packet retry",
                ),
                lambda: reset_step(
                    crashed.run.run_dir,
                    "packet",
                    reason="force whole-step reset",
                ),
                lambda: skip_step(
                    crashed.run.run_dir,
                    "packet",
                    reason="abandon packet",
                ),
                lambda: restart_run(
                    crashed.run.run_dir,
                    reason="restart workflow",
                ),
            )
            for control in controls:
                with self.subTest(control=control):
                    before = state_path.read_bytes()
                    with self.assertRaisesRegex(
                        ValidationError,
                        "locally completed packet.*pending recovery",
                    ):
                        control()
                    self.assertEqual(state_path.read_bytes(), before)

            retry_step(
                crashed.run.run_dir,
                "packet",
                reason="recover local packet terminal",
            )
            resumed = TerminalAgentMapRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                resume_dir=crashed.run.run_dir,
                policy=policy,
            )
            resumed.execute()
            self.assertEqual(resumed.agent_calls, [])
            self.assertEqual(
                resumed.run.read_state()["steps"]["packet"]["total_tokens"],
                10,
            )

