    def test_agent_map_terminal_recovery_rejects_artifact_output_and_source_tamper(self):
        for tamper in ("artifact", "output", "source"):
            with self.subTest(tamper=tamper), tempfile.TemporaryDirectory() as tmp:
                root = Path(tmp)
                source = root / "source.txt"
                source.write_text("base\n", encoding="utf-8")
                workflow = workflow_with_steps(
                    [
                        {
                            "id": "packet",
                            "kind": "agent_map",
                            "risk": "medium",
                            "items": ["source.txt"],
                            "prompt_template": "Review {item}",
                            "capture_dir": "packets",
                            "max_tokens": 1000,
                        }
                    ]
                )
                validate_workflow(workflow)
                policy = RuntimePolicy(allow_agent=True)
                crashed = TerminalAgentMapRunner(
                    workflow=workflow,
                    workspace=root,
                    base_run_dir=root / "runs",
                    policy=policy,
                    terminal_crash_phase="written",
                )
                with self.assertRaises(SimulatedAgentMapCrash):
                    crashed.execute()
                terminal_path = agent_map_packet_terminal_path(
                    crashed.run,
                    "packets",
                    1,
                )
                terminal = load_agent_map_packet_terminal(terminal_path)
                if tamper == "artifact":
                    terminal["cache_key"] = "0" * 64
                    terminal_path.write_text(
                        json.dumps(terminal),
                        encoding="utf-8",
                    )
                elif tamper == "output":
                    crashed.run.resolve_artifact_path(terminal["output"]).write_text(
                        "changed\n",
                        encoding="utf-8",
                    )
                else:
                    source.write_text("changed\n", encoding="utf-8")
                retry_step(crashed.run.run_dir, "packet", reason="reject tamper")
                resumed = TerminalAgentMapRunner(
                    workflow=workflow,
                    workspace=root,
                    base_run_dir=root / "runs",
                    resume_dir=crashed.run.run_dir,
                    policy=policy,
                )
                with self.assertRaises(ValidationError):
                    resumed.execute()
                self.assertEqual(resumed.agent_calls, [])

