    def test_agent_map_cache_receipts_survive_manifest_loss_during_recovery(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": ["alpha", "beta"],
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                    "max_items": 5,
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            first = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
            )
            first.execute()
            receipt_dir = first.run.artifacts_dir / "packets" / ".agent-map-cache-entries"
            receipts = sorted(receipt_dir.glob("*.json"))
            self.assertEqual(len(receipts), 2)
            for index, path in enumerate(receipts, 1):
                receipt = json.loads(path.read_text(encoding="utf-8"))
                self.assertEqual(receipt["schema"], "conductor.agent_map_cache_entry.v1")
                self.assertEqual(receipt["step_id"], "packet")
                self.assertEqual(receipt["index"], index)

            cache_path = first.run.artifacts_dir / "packets" / ".agent-map-cache.json"
            cache = json.loads(cache_path.read_text(encoding="utf-8"))
            cache["entries"] = {}
            write_json(cache_path, cache)
            state = first.run.read_state()
            previous = state["steps"]["packet"]
            state["status"] = "running"
            state["steps"]["packet"] = {
                "status": "running",
                "kind": "agent_map",
                "started_at_utc": previous["started_at_utc"],
                "updated_at_utc": previous["updated_at_utc"],
                "attempt": previous["attempt"],
            }
            first.run.save_state(state)
            result = recover_run(
                first.run.run_dir,
                reason="runner stopped after packet receipts but before manifest flush",
                retry_running=True,
            )
            self.assertEqual(result["resolution"], "retry")

            second = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                resume_dir=first.run.run_dir,
                policy=RuntimePolicy(allow_agent=True),
            )
            resumed = second.execute()
            self.assertEqual(second.agent_calls, [])
            resumed_state = resumed.read_state()
            self.assertEqual(resumed_state["steps"]["packet"]["status"], "completed")
            self.assertIn("reused 2 cached item(s)", resumed_state["steps"]["packet"]["detail"])
            rebuilt = json.loads(cache_path.read_text(encoding="utf-8"))
            self.assertEqual(len(rebuilt["entries"]), 2)

