    def test_retry_packet_reruns_only_selected_item_and_preserves_sibling_cache(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": ["alpha", "beta", "gamma"],
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                    "max_items": 5,
                }
            ]
        )
        workflow["max_workers"] = 1
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            first = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
            )
            run = first.execute()
            alpha = run.artifacts_dir / "packets" / "001-alpha.md"
            gamma = run.artifacts_dir / "packets" / "003-gamma.md"
            sibling_hashes = (hashlib.sha256(alpha.read_bytes()).hexdigest(), hashlib.sha256(gamma.read_bytes()).hexdigest())

            control = retry_packet(run.run_dir, "packet", 2, reason="refresh one packet")
            self.assertEqual(control["action"], "retry-packet")
            self.assertEqual(control["packet_index"], 2)
            self.assertEqual(control["packet_generation"], 1)
            self.assertEqual(control["status"], "needs_resume")
            state = run.read_state()
            packet_state = state["agent_map_packet_generations"]["packet"]["2"]
            self.assertEqual(packet_state["generation"], 1)
            self.assertEqual(packet_state["item_sha256"], hashlib.sha256(b"beta").hexdigest())
            self.assertEqual(state["control_events"][-1]["packet_index"], 2)

            second = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                resume_dir=run.run_dir,
                policy=RuntimePolicy(allow_agent=True),
            )
            resumed = second.execute()
            self.assertEqual(second.agent_calls, ["002-beta.md"])
            self.assertEqual(
                (hashlib.sha256(alpha.read_bytes()).hexdigest(), hashlib.sha256(gamma.read_bytes()).hexdigest()),
                sibling_hashes,
            )
            state = resumed.read_state()
            self.assertEqual(state["steps"]["packet"]["agent_invocations"], 1)
            self.assertEqual(state["steps"]["packet"]["agent_items_cached"], 2)
            cache = json.loads((run.artifacts_dir / "packets" / ".agent-map-cache.json").read_text(encoding="utf-8"))
            self.assertEqual(len(cache["entries"]), 3)
            beta_entries = [entry for entry in cache["entries"].values() if entry["output"] == "packets/002-beta.md"]
            self.assertEqual(len(beta_entries), 1)
            detail = collect_run_detail(root / "runs", run.run_dir.name)
            self.assertEqual(detail["agent_maps"][0]["packets"][1]["retry_generation"], 1)
