            trace_rows = [
                json.loads(line)
                for line in (run.artifacts_dir / "packets" / ".agent-map-trace.jsonl").read_text(encoding="utf-8").splitlines()
            ]
            self.assertTrue(all(len(row["item_sha256"]) == 64 for row in trace_rows))

