    def test_retry_packet_binds_item_and_full_reset_clears_targeted_generation(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items_file": "items.txt",
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                    "max_items": 5,
                }
            ]
        )
        workflow["max_workers"] = 1
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            items_path = root / "items.txt"
            items_path.write_text("alpha\nbeta\n", encoding="utf-8")
            first = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
            )
            run = first.execute()
            retry_packet(run.run_dir, "packet", 1, reason="target alpha")
            items_path.write_text("changed\nbeta\n", encoding="utf-8")
            blocked = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                resume_dir=run.run_dir,
                policy=RuntimePolicy(allow_agent=True),
            )
            with self.assertRaisesRegex(ValidationError, "reset binding no longer matches"):
                blocked.execute()
            self.assertEqual(blocked.agent_calls, [])

            reset_step(run.run_dir, "packet", reason="accept changed item")
            state = run.read_state()
            self.assertNotIn("packet", state.get("agent_map_packet_generations", {}))
            resumed = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                resume_dir=run.run_dir,
                policy=RuntimePolicy(allow_agent=True),
            )
            resumed.execute()
            self.assertEqual(resumed.agent_calls, ["001-changed.md", "002-beta.md"])

    def test_retry_packet_rejects_invalid_targets_active_runs_and_tampered_state(self):
        workflow = workflow_with_steps(
            [
                {"id": "one", "kind": "write_artifact", "output": "one.txt", "content": "one"},
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "depends_on": ["one"],
                    "items": ["alpha"],
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                    "max_items": 5,
                },
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
            )
            run = runner.execute()
            with self.assertRaisesRegex(ValidationError, "requires an agent_map"):
                retry_packet(run.run_dir, "one", 1)
            for invalid in [0, True, 10001]:
                with self.subTest(packet_index=invalid):
                    with self.assertRaisesRegex(ValidationError, "packet_index"):
                        retry_packet(run.run_dir, "packet", invalid)
            with self.assertRaisesRegex(ValidationError, "item limit"):
                retry_packet(run.run_dir, "packet", 6)
            with self.assertRaisesRegex(ValidationError, "no current item hash"):
                retry_packet(run.run_dir, "packet", 2)

            state = run.read_state()
            state["status"] = "running"
            run.save_state(state)
            with self.assertRaisesRegex(ValidationError, "active run"):
                retry_packet(run.run_dir, "packet", 1)
            state["status"] = "completed"
            state["agent_map_packet_generations"] = []
            run.save_state(state)
            with self.assertRaisesRegex(ValidationError, "must be an object"):
                retry_packet(run.run_dir, "packet", 1)

            state.pop("agent_map_packet_generations")
            run.save_state(state)
            trace_path = run.artifacts_dir / "packets" / ".agent-map-trace.jsonl"
            trace_path.write_text(
                trace_path.read_text(encoding="utf-8") + '{"schema":"one","schema":"two"}\n',
                encoding="utf-8",
            )
            with self.assertRaisesRegex(ValidationError, "trace line"):
                retry_packet(run.run_dir, "packet", 1)

