    @unittest.skipUnless(os.name == "posix", "interrupted-run recovery requires POSIX locks")
    def test_recover_run_cli_is_audited_local_write(self):
        workflow = workflow_with_steps(
            [{"id": "write", "kind": "write_artifact", "output": "one.txt", "content": "one"}]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            )
            state = runner.run.read_state()
            state["status"] = "running"
            state["steps"] = {"write": {"status": "running", "kind": "write_artifact", "attempt": 1}}
            runner.run.save_state(state)
            write_json(
                runner.run.run_dir / "runner.json",
                {
                    "schema": "conductor.runner.v1",
                    "status": "finished",
                    "event": "execute-finished",
                    "pid": os.getpid(),
                    "hostname": os.uname().nodename,
                    "mode": "run",
                    "run_status": "running",
                    "started_at_utc": "2026-07-09T00:00:00.000Z",
                    "heartbeat_at_utc": "2026-07-09T00:00:01.000Z",
                    "finished_at_utc": "2026-07-09T00:00:01.000Z",
                    "max_workers": 1,
                    "active_processes": [],
                },
            )
            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(
                    [
                        "recover-run",
                        str(runner.run.run_dir),
                        "--retry-running",
                        "--reason",
                        "confirmed owner exited",
                    ]
                )
            self.assertEqual(code, 0)
            self.assertIn("Run control: recover-run", stdout.getvalue())
            self.assertIn("Recovery resolution: retry", stdout.getvalue())
            self.assertEqual(runner.run.read_state()["steps"]["write"]["status"], "pending")

            state = runner.run.read_state()
            state["status"] = "running"
            state["steps"]["write"] = {"status": "running", "kind": "write_artifact", "attempt": 2}
            runner.run.save_state(state)
            metadata = json.loads((runner.run.run_dir / "runner.json").read_text(encoding="utf-8"))
            metadata["status"] = "finished"
            metadata["event"] = "execute-finished"
            metadata["run_status"] = "running"
            metadata["active_processes"] = []
            write_json(runner.run.run_dir / "runner.json", metadata)
            html = render_live_dashboard(build_live_payload(root / "runs", root / "benchmarks"))
            self.assertIn('value="recover-run"', html)
            self.assertIn("Recover and retry", html)
            self.assertIn('value="recover-codex"', html)
            self.assertIn("Resume Codex thread", html)
            live_result = apply_live_control(
                root / "runs",
                {
                    "token": "unit-token",
                    "action": "recover-run",
                    "run_handle": run_handle(runner.run.run_dir.name),
                    "reason": "live confirmed owner exited",
                },
                "unit-token",
            )
            self.assertEqual(live_result["action"], "recover-run")
            self.assertEqual(live_result["resolution"], "retry")

        assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "recover-run", "run", "--reason", "done"]
        )
        self.assertFalse(assessment.network)
        self.assertTrue(assessment.writes)
        self.assertFalse(assessment.destructive)

