    def test_retry_packet_cascade_resets_downstream_without_invalidating_siblings(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": ["alpha", "beta"],
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                },
                {
                    "id": "downstream",
                    "kind": "agent_map",
                    "risk": "medium",
                    "depends_on": ["packet"],
                    "items": ["gamma"],
                    "prompt_template": "Synthesize {item}",
                    "capture_dir": "downstream",
                },
            ]
        )
        workflow["max_workers"] = 1
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            first = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
            )
            run = first.execute()
            result = retry_packet(run.run_dir, "packet", 1, reason="refresh upstream packet", cascade=True)
            self.assertEqual(result["affected_steps"], ["packet", "downstream"])
            state = run.read_state()
            self.assertEqual(state["steps"]["packet"]["status"], "pending")
            self.assertEqual(state["steps"]["downstream"]["status"], "pending")
            self.assertEqual(state["agent_map_packet_generations"]["packet"]["1"]["generation"], 1)
            self.assertEqual(state["agent_map_cache_generations"]["downstream"], 1)

            second = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                resume_dir=run.run_dir,
                policy=RuntimePolicy(allow_agent=True),
            )
            resumed = second.execute()
            self.assertEqual(second.agent_calls, ["001-alpha.md", "001-gamma.md"])
            state = resumed.read_state()
            self.assertEqual(state["steps"]["packet"]["agent_items_cached"], 1)
            self.assertEqual(state["steps"]["downstream"]["agent_items_cached"], 0)

