    def test_agent_map_directory_entry_budget_stops_streaming_entries(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": ["src/pkg"],
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                    "max_items": 5,
                }
            ]
        )
        workflow["max_workers"] = 1
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            import conductor_extras.runtime.runner as runner_module

            root = Path(tmp)
            (root / "src" / "pkg").mkdir(parents=True)
            for name in ["a.txt", "b.txt", "c.txt"]:
                (root / "src" / "pkg" / name).write_text(name, encoding="utf-8")
            original_scandir = os.scandir
            entries_seen = {"count": 0}

            class CountingScandir:
                def __init__(self, path):
                    self._inner = original_scandir(path)

                def __enter__(self):
                    self._inner.__enter__()
                    return self

                def __exit__(self, *args):
                    return self._inner.__exit__(*args)

                def __iter__(self):
                    return self

                def __next__(self):
                    entries_seen["count"] += 1
                    if entries_seen["count"] > 2:
                        raise AssertionError("directory scan consumed more than cap plus sentinel")
                    return next(self._inner)

            runner = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
            )
            with patch.object(runner_module, "MAX_DIRECTORY_FINGERPRINT_ENTRIES", 1):
                with patch.object(runner_module.os, "scandir", side_effect=CountingScandir):
                    source = runner._workspace_item_fingerprint("src/pkg")
            self.assertEqual(source["state"], "unhashable")
            self.assertEqual(source["kind"], "directory")
            self.assertEqual(source["reason"], "oversized")
            self.assertEqual(entries_seen["count"], 2)

