    def test_agent_map_oversized_workspace_file_item_is_not_cached(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": ["src/large.txt"],
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                    "max_items": 5,
                }
            ]
        )
        workflow["max_workers"] = 1
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            import conductor_extras.runtime.runner as runner_module

            root = Path(tmp)
            (root / "src").mkdir()
            (root / "src" / "large.txt").write_text("x" * 65, encoding="utf-8")
            with patch.object(runner_module, "MAX_HASH_FILE_BYTES", 64):
                first = FakeAgentWorkflowRunner(
                    workflow=workflow,
                    workspace=root,
                    base_run_dir=root / "runs",
                    policy=RuntimePolicy(allow_agent=True),
                    run_id="oversized-source",
                )
                run = first.execute()
                self.assertEqual(first.agent_calls, ["001-src-large-txt.md"])
                cache_path = run.artifacts_dir / "packets" / ".agent-map-cache.json"
                cache = json.loads(cache_path.read_text(encoding="utf-8"))
                self.assertEqual(cache["entries"], {})
                source = first._workspace_item_fingerprint("src/large.txt")
                self.assertEqual(source["state"], "unhashable")
                self.assertEqual(source["reason"], "oversized")
                self.assertEqual(source["max_bytes"], 64)

                state = run.read_state()
                state["steps"]["packet"]["status"] = "failed"
                run.save_state(state)
                retry_step(run.run_dir, "packet", reason="retry oversized source")
                second = FakeAgentWorkflowRunner(
                    workflow=workflow,
                    workspace=root,
                    base_run_dir=root / "runs",
                    resume_dir=run.run_dir,
                    policy=RuntimePolicy(allow_agent=True),
                )
                resumed = second.execute()
                self.assertEqual(second.agent_calls, ["001-src-large-txt.md"])
            state = json.loads((resumed.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertNotIn("reused", state["steps"]["packet"]["detail"])

