    def test_agent_map_oversized_cached_output_is_treated_as_cache_miss(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": ["alpha", "beta"],
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                    "max_items": 5,
                }
            ]
        )
        workflow["max_workers"] = 1
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            import conductor_extras.runtime.runner as runner_module

            root = Path(tmp)
            first = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
                fail_on_calls={2},
                run_id="oversized-output",
            )
            with self.assertRaises(StepExecutionError):
                first.execute()
            self.assertEqual(first.agent_calls, ["001-alpha.md", "002-beta.md"])

            alpha_output = first.run.artifacts_dir / "packets" / "001-alpha.md"
            oversized_content = "x" * 65
            alpha_output.write_text(oversized_content, encoding="utf-8")
            cache_path = first.run.artifacts_dir / "packets" / ".agent-map-cache.json"
            cache = json.loads(cache_path.read_text(encoding="utf-8"))
            entry = next(iter(cache["entries"].values()))
            entry["output_sha256"] = hashlib.sha256(oversized_content.encode("utf-8")).hexdigest()
            cache_path.write_text(json.dumps(cache, indent=2, sort_keys=True) + "\n", encoding="utf-8")

            retry_step(first.run.run_dir, "packet", reason="retry oversized cached output")
            with patch.object(runner_module, "MAX_HASH_FILE_BYTES", 64):
                second = FakeAgentWorkflowRunner(
                    workflow=workflow,
                    workspace=root,
                    base_run_dir=root / "runs",
                    resume_dir=first.run.run_dir,
                    policy=RuntimePolicy(allow_agent=True),
                )
                resumed = second.execute()
            self.assertEqual(second.agent_calls, ["001-alpha.md", "002-beta.md"])
            state = json.loads((resumed.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertNotIn("reused", state["steps"]["packet"]["detail"])

