    def test_agent_map_oversized_cache_and_lock_do_not_block_recovery(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": ["alpha"],
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                    "max_items": 5,
                }
            ]
        )
        workflow["max_workers"] = 1
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
                run_id="oversized-cache",
            )
            cache_dir = runner.run.artifacts_dir / "packets"
            cache_dir.mkdir(parents=True)
            cache_path = cache_dir / ".agent-map-cache.json"
            cache_path.write_text(" " * (MAX_AGENT_MAP_CACHE_BYTES + 1), encoding="utf-8")
            cache = runner._load_agent_map_cache(workflow["steps"][0], "packets")
            self.assertEqual(cache["schema"], "conductor.agent_map_cache.v1")
            self.assertEqual(cache["entries"], {})

            cache_path.write_bytes(b"\xff")
            cache = runner._load_agent_map_cache(workflow["steps"][0], "packets")
            self.assertEqual(cache["schema"], "conductor.agent_map_cache.v1")
            self.assertEqual(cache["entries"], {})

            lock_path = cache_dir / ".agent-map-cache.lock"
            lock_path.write_text("1" * (MAX_AGENT_MAP_CACHE_LOCK_BYTES + 1), encoding="utf-8")
            self.assertFalse(runner._remove_stale_agent_cache_lock(lock_path))
            self.assertTrue(lock_path.exists())

