    def test_benchmark_loaders_reject_symlinked_json_sources(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            suite = {
                "schema": "conductor.benchmark.v1",
                "name": "unit-suite",
                "tasks": [{"id": "echo", "command": ["printf", "ok"]}],
            }
            parity = {
                "schema": "conductor.parity_tasks.v1",
                "name": "unit-parity",
                "tasks": [
                    {
                        "id": "task-a",
                        "dimension": "correctness",
                        "prompt": "Do the task.",
                        "scoring": "score it",
                        "success_criteria": ["passes"],
                        "required_evidence": ["tests"],
                        "budget": {"max_minutes": 1, "max_agents": 0, "max_live_tool_cost": "none"},
                    }
                ],
            }
            manifest = run_manifest(system="codex")
            comparison = {
                "schema": "conductor.comparison.v1",
                "name": "compare",
                "systems": [
                    {"name": "codex", "report": "codex.json"},
                    {"name": "claude", "report": "claude.json"},
                ],
            }
            cases = [
                ("suite", suite, load_benchmark_suite, "benchmark suite must not be a symlink"),
                ("report", benchmark_report(system="codex"), load_benchmark_report, "benchmark report must not be a symlink"),
                ("parity", parity, load_parity_tasks, "parity tasks must not be a symlink"),
                ("manifest", manifest, load_run_manifest, "run manifest must not be a symlink"),
                ("comparison", comparison, load_comparison_manifest, "comparison manifest must not be a symlink"),
            ]
            for name, payload, loader, expected in cases:
                target = root / ("%s.json" % name)
                link = root / ("%s-link.json" % name)
                write_json(target, payload)
                try:
                    link.symlink_to(target)
                except OSError:
                    self.skipTest("symlinks are not supported on this filesystem")
                with self.subTest(name=name):
                    with self.assertRaises(ValidationError) as caught:
                        loader(link)
                    self.assertIn(expected, str(caught.exception))

