    def test_comparison_report_requires_matching_task_sets(self):
        manifest = {
            "schema": "conductor.comparison.v1",
            "name": "unit-comparison",
            "systems": [
                {"name": "codex", "report": "codex.json"},
                {"name": "claude", "report": "claude.json"},
            ],
        }
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            codex_report = {
                "schema": "conductor.benchmark_report.v1",
                "system": "codex",
                "suite": "suite",
                "total_tasks": 1,
                "passed_tasks": 1,
                "failed_tasks": 0,
                "duration_ms": 10,
                "results": [
                    {
                        "id": "task-a",
                        "passed": True,
                        "duration_ms": 10,
                        "timed_out": False,
                        "stdout_truncated": False,
                        "stderr_truncated": False,
                    }
                ],
            }
            claude_report = dict(codex_report)
            claude_report["system"] = "claude"
            claude_report["results"] = [dict(codex_report["results"][0])]
            (root / "codex.json").write_text(json.dumps(codex_report), encoding="utf-8")
