    def test_comparison_includes_manifest_scoring_provenance_and_safety(self):
        manifest = {
            "schema": "conductor.comparison.v1",
            "name": "unit-comparison",
            "systems": [
                {"name": "codex", "report": "codex.json", "manifest": "codex-manifest.json"},
                {"name": "claude", "report": "claude.json", "manifest": "claude-manifest.json"},
            ],
        }
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            write_json(root / "codex.json", benchmark_report(system="codex"))
            write_json(root / "claude.json", benchmark_report(system="claude"))
            codex_manifest = run_manifest(system="codex")
            codex_manifest["model"]["name"] = "token=supersecret"
            codex_manifest["permissions"]["approved_tokens"] = ["token=supersecret"]
            claude_manifest = run_manifest(system="claude")
            claude_manifest["live_run"] = False
            claude_manifest["safety"]["incidents"] = [
                {
                    "id": "incident-a",
                    "severity": "high",
                    "task_id": "task-a",
                    "description": "redacted in summary",
                }
            ]
            write_json(root / "codex-manifest.json", codex_manifest)
            write_json(root / "claude-manifest.json", claude_manifest)
            comparison = compare_benchmark_reports(manifest, root)
            self.assertTrue(comparison["provenance"]["complete"])
            self.assertEqual(comparison["systems"][0]["score"]["score"], 8)
            self.assertIsNone(comparison["systems"][1]["score"])
            self.assertEqual(comparison["systems"][1]["safety"]["incident_count"], 1)
            self.assertEqual(comparison["systems"][1]["safety"]["highest_severity"], "high")
            self.assertEqual(comparison["tasks"][0]["systems"][0]["score"]["max_score"], 10)
            self.assertIsNone(comparison["tasks"][0]["systems"][1]["score"])
            self.assertFalse(comparison["provenance"]["systems"][1]["live_run"])
            self.assertNotIn("redacted in summary", json.dumps(comparison))
            self.assertNotIn("supersecret", json.dumps(comparison))
            self.assertFalse(comparison["provenance"]["all_live"])
            self.assertFalse(comparison["provenance"]["claim_eligible"])
            self.assertEqual(comparison["provenance"]["non_live_manifests"], ["claude"])
            self.assertIn("non-live", " ".join(comparison["provenance"]["warnings"]))
            self.assertFalse(comparison["provenance"]["equivalence"]["model"]["equivalent"])

