    def test_comparison_declared_comparable_model_policy_allows_cross_vendor_with_complete_provenance(self):
        manifest = {
            "schema": "conductor.comparison.v1",
            "name": "unit-comparison",
            "claim_policy": {
                "model": {
                    "mode": "declared-comparable",
                    "rationale": "Unit test cross-vendor models with complete recorded provenance.",
                }
            },
            "systems": [
                {"name": "codex", "report": "codex.json", "manifest": "codex-manifest.json"},
                {"name": "claude", "report": "claude.json", "manifest": "claude-manifest.json"},
            ],
        }
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            write_json(root / "codex.json", benchmark_report(system="codex"))
            write_json(root / "claude.json", benchmark_report(system="claude"))
            codex_manifest = run_manifest(system="codex")
            claude_manifest = run_manifest(system="claude")
            for item in [codex_manifest, claude_manifest]:
                item["repository"] = {"state": "same", "commit": "abc", "dirty": "false"}
                item["budget"] = {
                    "max_minutes": 10,
                    "max_agents": 1,
                    "max_live_tool_cost": "none",
                    "max_cost_usd": 0,
                    "max_tokens": 0,
                }
                item["permissions"] = {
                    "allow_writes": False,
                    "allow_destructive": False,
                    "allow_network": False,
                    "allow_agent": False,
                    "allow_parallel": False,
                    "approved_tokens": [],
                }
            codex_manifest["model"] = {
                "provider": "openai",
                "name": "codex",
                "effort": "high",
                "version": "codex-version",
            }
            claude_manifest["model"] = {
                "provider": "anthropic",
                "name": "claude-code",
                "effort": "ultracode",
                "version": "claude-version",
            }
            write_json(root / "codex-manifest.json", codex_manifest)
            write_json(root / "claude-manifest.json", claude_manifest)

            comparison = compare_benchmark_reports(manifest, root)
            self.assertTrue(comparison["provenance"]["claim_eligible"])
            self.assertEqual(comparison["provenance"]["equivalence"]["model"]["mode"], "declared-comparable")
            self.assertTrue(comparison["provenance"]["equivalence"]["model"]["fields"]["version"])

            claude_manifest["model"].pop("version")
            write_json(root / "claude-manifest.json", claude_manifest)
            comparison = compare_benchmark_reports(manifest, root)

        self.assertFalse(comparison["provenance"]["claim_eligible"])
        self.assertFalse(comparison["provenance"]["equivalence"]["model"]["fields"]["version"])
        self.assertIn("model provenance is incomplete", " ".join(comparison["provenance"]["warnings"]))

