    def test_write_run_manifest_rejects_symlinked_output_parent(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            report = benchmark_report(system="conductor", suite="unit-benchmark")
            manifest = build_run_manifest_from_report(
                report=report,
                run_id="local-smoke",
                live_run=True,
                repository={"state": "local"},
                model={"provider": "openai", "name": "codex", "effort": "high"},
                budget={"max_minutes": 10, "max_agents": 0, "max_live_tool_cost": "none"},
                permissions={
                    "allow_writes": False,
                    "allow_destructive": False,
                    "allow_network": False,
                    "allow_agent": False,
                    "allow_parallel": False,
                    "approved_tokens": [],
                },
            )
            real_parent = root / "real"
            real_parent.mkdir()
            link_parent = root / "link"
            try:
                link_parent.symlink_to(real_parent, target_is_directory=True)
            except OSError:
                self.skipTest("directory symlinks are not supported on this filesystem")
            with self.assertRaises(ValidationError):
                write_run_manifest(manifest, link_parent / "manifest.json")

