    def test_routine_service_grant_is_hash_bound_executes_and_uninstalls_without_raw_approvals(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "authorize",
                    "kind": "manual_gate",
                    "approval_id": "durable-write-approval",
                    "prompt": "Approve the bounded durable write.",
                },
                {
                    "id": "write",
                    "kind": "write_artifact",
                    "depends_on": ["authorize"],
                    "output": "routine/service-result.txt",
                    "content": "service result",
                },
            ]
        )
        workflow["mode"] = "workspace_write"
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            home = root / "home"
            routines = root / "routines"
            workflow_path = root / "workflow.json"
            manifest_path = routines / "durable-check.json"
            runtime_path = root / "conductor-runtime.pyz"
            write_json(workflow_path, workflow)
            runtime_path.write_bytes(b"#!/usr/bin/env python3\nPK\x03\x04fake-runtime\n")
            with redirect_stdout(StringIO()):
                self.assertEqual(
                    cli_main(
                        [
                            "write-routine-manifest",
                            str(manifest_path),
                            "--name",
                            "durable-check",
                            "--workflow",
                            str(workflow_path),
                            "--workspace",
                            str(root),
                            "--runs-dir",
                            str(root / "runs"),
                            "--interval-minutes",
                            "10",
                            "--allow-writes",
                            "--approve",
                            "durable-write-approval",
                        ]
                    ),
                    0,
                )
            policy = RuntimePolicy(
                allow_writes=True,
                approvals={
                    ROUTINE_SERVICE_INSTALL_APPROVAL,
                    "routine:durable-check",
                    "durable-write-approval",
                },
            )
            grant = build_routine_service_grant(
                routines_dir=routines,
                routine_manifests=[manifest_path],
                runtime_path=runtime_path,
                policy=policy,
                allow_service_install=True,
                platform="launchd",
                poll_seconds=1,
                grant_days=7,
            )
            validate_routine_service_grant(grant)
            serialized = json.dumps(grant, sort_keys=True)
            self.assertNotIn("durable-write-approval", serialized)
            self.assertNotIn("routine:durable-check", serialized)
            self.assertFalse(grant["authorization"]["raw_approval_values_persisted"])
            self.assertEqual(len(grant["routines"][0]["approval_sha256"]), 1)
            authorizations = verify_routine_service_grant(grant)
            self.assertEqual(list(authorizations), [str(manifest_path.resolve())])

            manager_calls = []

            def fake_manager(argv, ignore_missing):
                manager_calls.append((list(argv), ignore_missing))

            installed = install_routine_service(
                grant,
                home=home,
                start=False,
                manager_runner=fake_manager,
            )
            self.assertFalse(installed["started"])
            self.assertEqual(manager_calls, [])
            paths = routine_service_paths(grant, home=home)
            self.assertTrue(paths["grant"].is_file())
            self.assertFalse(paths["descriptor"].exists())
            self.assertTrue(paths["staged_descriptor"].is_file())
            descriptor = paths["staged_descriptor"].read_text(encoding="utf-8")
            self.assertIn("_routine-service-worker", descriptor)
            self.assertNotIn("durable-write-approval", descriptor)
            loaded_grant = load_routine_service_grant(paths["grant"])
            self.assertEqual(loaded_grant, grant)

            self.assertEqual(
                run_routine_service_worker(
                    paths["grant"],
                    running_runtime_path=runtime_path,
                    max_cycles=1,
                ),
                0,
            )
            state = load_routine_service_state(paths["state"])
            self.assertEqual(state["status"], "stopped")
            self.assertEqual(state["cycles_completed"], 1)
            self.assertEqual(state["results_completed"], 1)
            self.assertFalse(state["raw_approval_values_persisted"])
            self.assertNotIn("durable-write-approval", json.dumps(state))
            state_before_duplicate = paths["state"].read_bytes()
            with patch(
                "conductor_extras.runtime.routine_service._service_lock",
                side_effect=RoutineServiceAlreadyActive("already active"),
            ):
                self.assertEqual(
                    run_routine_service_worker(
                        paths["grant"],
                        running_runtime_path=runtime_path,
                        max_cycles=1,
                    ),
                    0,
                )
            self.assertEqual(paths["state"].read_bytes(), state_before_duplicate)
            run_artifacts = list((root / "runs").glob("*/artifacts/routine/service-result.txt"))
            self.assertEqual(len(run_artifacts), 1)
            self.assertEqual(run_artifacts[0].read_text(encoding="utf-8"), "service result")
            service_status = status_routine_service(routines, home=home)
            self.assertFalse(service_status["installed"])
            self.assertEqual(service_status["effective_status"], "staged")
            self.assertEqual(service_status["liveness"], "not-running")
            dashboard_path = root / "routine-service-dashboard.html"
            with patch("conductor_extras.runtime.routine_service.Path.home", return_value=home):
                write_dashboard(
                    runs_dir=root / "runs",
                    benchmarks_dir=root / "benchmarks",
                    routines_dir=routines,
                    output=dashboard_path,
                )
                live_payload = build_live_payload(
                    runs_dir=root / "runs",
                    benchmarks_dir=root / "benchmarks",
                    routines_dir=routines,
                )
            dashboard_html = dashboard_path.read_text(encoding="utf-8")
            self.assertIn("Routine Service", dashboard_html)
            self.assertIn("launchd", dashboard_html)
            self.assertEqual(live_payload["routine_service"]["effective_status"], "staged")
            self.assertIn("Routine Service", render_live_dashboard(live_payload))

            original_descriptor = paths["staged_descriptor"].read_text(encoding="utf-8")
            paths["staged_descriptor"].write_text(original_descriptor + "\n", encoding="utf-8")
            descriptor_drift = status_routine_service(routines, home=home)
            self.assertEqual(descriptor_drift["effective_status"], "incomplete")
            self.assertFalse(descriptor_drift["staged_descriptor_valid"])
            self.assertTrue(descriptor_drift["needs_attention"])
            paths["staged_descriptor"].write_text(original_descriptor, encoding="utf-8")

            original_state = paths["state"].read_bytes()
            changed_state = load_routine_service_state(paths["state"])
            changed_state["grant_sha256"] = "0" * 64
            write_json(paths["state"], changed_state)
            state_drift = status_routine_service(routines, home=home)
            self.assertEqual(state_drift["effective_status"], "invalid")
            self.assertTrue(state_drift["needs_attention"])
            paths["state"].write_bytes(original_state)

            original_manifest = manifest_path.read_bytes()
            manifest_path.write_bytes(original_manifest + b"\n")
            with self.assertRaises(PolicyError):
                verify_routine_service_grant(grant)
            drift_status = status_routine_service(routines, home=home)
            self.assertEqual(drift_status["effective_status"], "invalid")
            self.assertTrue(drift_status["needs_attention"])
            self.assertNotIn(str(root), drift_status["error"])
            manifest_path.write_bytes(original_manifest)

            removed = uninstall_routine_service(
                routines,
                approvals=[ROUTINE_SERVICE_UNINSTALL_APPROVAL],
                allow_service_install=True,
                home=home,
                manager_runner=fake_manager,
            )
            self.assertTrue(removed["removed_grant"])
            self.assertTrue(removed["removed_descriptor"])
            self.assertFalse(paths["grant"].exists())
            self.assertFalse(paths["staged_descriptor"].exists())
            self.assertEqual(manager_calls, [])

