    def test_routine_service_manager_failure_is_visible_and_does_not_claim_running(self):
        workflow = workflow_with_steps(
            [{"id": "check", "kind": "shell", "risk": "low", "writes": False, "command": ["true"]}]
        )
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            home = root / "home"
            routines = root / "routines"
            workflow_path = root / "workflow.json"
            manifest_path = routines / "check.json"
            runtime_path = root / "runtime.pyz"
            write_json(workflow_path, workflow)
            runtime_path.write_bytes(b"PK\x03\x04runtime")
            with redirect_stdout(StringIO()):
                self.assertEqual(
                    cli_main(
                        [
                            "write-routine-manifest",
                            str(manifest_path),
                            "--name",
                            "check",
                            "--workflow",
                            str(workflow_path),
                            "--workspace",
                            str(root),
                            "--runs-dir",
                            str(root / "runs"),
                            "--manual",
                        ]
                    ),
                    0,
                )
            grant = build_routine_service_grant(
                routines_dir=routines,
                routine_manifests=[manifest_path],
                runtime_path=runtime_path,
                policy=RuntimePolicy(
                    approvals={ROUTINE_SERVICE_INSTALL_APPROVAL, "routine:check"}
                ),
                allow_service_install=True,
                platform="launchd",
            )

            def reject_manager(argv, ignore_missing):
                del argv, ignore_missing
                raise ValidationError("manager permission denied at /secret/path")

            with self.assertRaises(ValidationError):
                install_routine_service(
                    grant,
                    home=home,
                    start=True,
                    manager_runner=reject_manager,
                )
            paths = routine_service_paths(grant, home=home)
            failed_state = load_routine_service_state(paths["state"])
            self.assertEqual(failed_state["status"], "failed")
            self.assertNotIn("/secret/path", json.dumps(failed_state))
            service_status = status_routine_service(routines, home=home)
            self.assertEqual(service_status["effective_status"], "failed")
            self.assertTrue(service_status["needs_attention"])
            self.assertEqual(service_status["liveness"], "not-running")

            uninstall_routine_service(
                routines,
                approvals=[ROUTINE_SERVICE_UNINSTALL_APPROVAL],
                allow_service_install=True,
                home=home,
                manager_runner=lambda argv, ignore_missing: None,
            )

    def test_systemd_routine_service_descriptor_and_manager_lifecycle_are_bounded(self):
        workflow = workflow_with_steps(
            [{"id": "check", "kind": "shell", "risk": "low", "writes": False, "command": ["true"]}]
        )
        with tempfile.TemporaryDirectory(prefix="service space ") as tmp:
            root = Path(tmp)
            home = root / "home"
            routines = root / "routines"
            workflow_path = root / "workflow.json"
            manifest_path = routines / "check.json"
            runtime_path = root / "runtime.pyz"
            write_json(workflow_path, workflow)
            runtime_path.write_bytes(b"PK\x03\x04runtime")
            with redirect_stdout(StringIO()):
                self.assertEqual(
                    cli_main(
                        [
                            "write-routine-manifest",
                            str(manifest_path),
                            "--name",
                            "check",
                            "--workflow",
                            str(workflow_path),
                            "--workspace",
                            str(root),
                            "--runs-dir",
                            str(root / "runs"),
                            "--manual",
                        ]
                    ),
                    0,
                )
            grant = build_routine_service_grant(
                routines_dir=routines,
                routine_manifests=[manifest_path],
                runtime_path=runtime_path,
                policy=RuntimePolicy(
                    approvals={ROUTINE_SERVICE_INSTALL_APPROVAL, "routine:check"}
                ),
                allow_service_install=True,
                platform="systemd",
            )
            paths = routine_service_paths(grant, home=home)
            descriptor = render_routine_service_descriptor(grant, paths)
            self.assertIn("Restart=on-failure", descriptor)
            self.assertIn("WantedBy=default.target", descriptor)
            self.assertIn('"%s"' % runtime_path.resolve(), descriptor)
            self.assertNotIn("routine:check", descriptor)
            calls = []

            def manager(argv, ignore_missing):
                calls.append((list(argv), ignore_missing))

            install_routine_service(grant, home=home, start=True, manager_runner=manager)
            self.assertEqual(calls[0], (["systemctl", "--user", "daemon-reload"], False))
            self.assertEqual(calls[1][0][:4], ["systemctl", "--user", "enable", "--now"])
            uninstall_routine_service(
                routines,
                approvals=[ROUTINE_SERVICE_UNINSTALL_APPROVAL],
                allow_service_install=True,
                home=home,
                manager_runner=manager,
            )
            self.assertEqual(calls[2][0][:4], ["systemctl", "--user", "disable", "--now"])
            self.assertEqual(calls[3], (["systemctl", "--user", "daemon-reload"], False))

