    def test_routine_manifest_rejects_handcrafted_schema_mismatches(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "write",
                    "kind": "write_artifact",
                    "output": "one.txt",
                    "content": "one",
                }
            ]
        )
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workflow_path = root / "workflow.json"
            output_path = root / "routine.json"
            write_json(workflow_path, workflow)
            with redirect_stdout(StringIO()):
                code = cli_main(
                    [
                        "write-routine-manifest",
                        str(output_path),
                        "--name",
                        "strict-routine",
                        "--workflow",
                        str(workflow_path),
                        "--manual",
                    ]
                )
            self.assertEqual(code, 0)
            base = load_routine_manifest(output_path)

            cases = []
            tampered = json.loads(json.dumps(base))
            tampered["unexpected"] = True
            cases.append((tampered, "unsupported field"))

            tampered = json.loads(json.dumps(base))
            tampered.pop("created_at_utc")
            cases.append((tampered, "created_at_utc must be an ISO UTC timestamp"))

            tampered = json.loads(json.dumps(base))
            tampered["created_at_utc"] = "not-a-time"
            cases.append((tampered, "created_at_utc must be an ISO UTC timestamp"))

            tampered = json.loads(json.dumps(base))
            tampered["launch"]["command"] = "python3 -B -m conductor_runtime doctor"
            cases.append((tampered, "must match launch.command_argv"))

            tampered = json.loads(json.dumps(base))
            tampered["launch"]["command_argv"].extend(["--approve", "manual-approval"])
            tampered["external_supervisor_contract"]["may_run_command_argv"] = list(tampered["launch"]["command_argv"])
            cases.append((tampered, "must not persist approval token values"))

            tampered = json.loads(json.dumps(base))
            tampered["external_supervisor_contract"]["must_not_assume_conductor_daemon"] = False
            cases.append((tampered, "must_not_assume_conductor_daemon must be true"))

            tampered = json.loads(json.dumps(base))
            tampered["external_supervisor_contract"]["may_run_command_argv"] = ["python3", "-B", "-m", "conductor_extras", "doctor"]
            cases.append((tampered, "must match launch.command_argv"))

            tampered = json.loads(json.dumps(base))
            tampered["budget"]["unexpected"] = 1
            cases.append((tampered, "routine budget contains unsupported field"))

            tampered = json.loads(json.dumps(base))
            tampered["budget"]["max_cost_usd"] = float("nan")
            cases.append((tampered, "max_cost_usd must be a non-negative number"))

            tampered = json.loads(json.dumps(base))
            tampered["launch"]["max_workers"] = 0
            cases.append((tampered, "max_workers must be an integer"))

            tampered = json.loads(json.dumps(base))
            tampered.pop("budget")
            cases.append((tampered, "budget must be an object"))

            for index, (manifest, expected) in enumerate(cases):
                path = root / ("tampered-%s.json" % index)
                write_json(path, manifest)
                with self.assertRaises(ValidationError) as context:
                    load_routine_manifest(path)
                self.assertIn(expected, str(context.exception))

