    def test_routine_manifest_output_parent_swap_is_fail_closed(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "write",
                    "kind": "write_artifact",
                    "output": "one.txt",
                    "content": "one",
                }
            ]
        )
        with tempfile.TemporaryDirectory() as tmp:
            import conductor_extras.runtime.routines as routines_module

            root = Path(tmp)
            workflow_path = root / "workflow.json"
            write_json(workflow_path, workflow)
            output_parent = root / "output-parent"
            output_parent.mkdir()
            outside = root / "outside"
            outside.mkdir()
            destination = output_parent / "routine.json"
            original_reject = routines_module.reject_symlink_path
            parent_checks = {"count": 0}

            def swapping_reject(path, label):
                original_reject(path, label)
                if label == "routine manifest output parent" and Path(path) == output_parent:
                    parent_checks["count"] += 1
                    if parent_checks["count"] == 1:
                        output_parent.rmdir()
                        output_parent.symlink_to(outside, target_is_directory=True)

            stderr = StringIO()
            with patch("conductor_extras.runtime.routines.reject_symlink_path", side_effect=swapping_reject):
                with redirect_stderr(stderr):
                    code = cli_main(
                        [
                            "write-routine-manifest",
                            str(destination),
                            "--name",
                            "race",
                            "--workflow",
                            str(workflow_path),
                            "--manual",
                        ]
                    )
            self.assertEqual(code, 2)
            self.assertIn("must not include symlink path component", stderr.getvalue())
            self.assertFalse((outside / "routine.json").exists())

