    def test_routine_manifest_cli_policy_classification(self):
        validate_assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "validate-routine-manifest", "routine.json"]
        )
        list_assessment = assess_command(["python3", "-B", "-m", "conductor_extras", "list-routines"])
        status_assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "status-routine", "routine.json"]
        )
        controls_validate_assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "validate-routine-controls", "controls.json"]
        )
        state_validate_assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "validate-routine-state", "state.json"]
        )
        write_assessment = assess_command(
            [
                "python3",
                "-B",
                "-m",
                "conductor_extras",
                "write-routine-manifest",
                "routine.json",
                "--name",
                "routine",
                "--workflow",
                "workflow.json",
                "--manual",
            ]
        )
        personal_write_assessment = assess_command(
            [
                "python3",
                "-B",
                "-m",
                "conductor_extras",
                "write-routine-manifest",
                "routine.json",
                "--name",
                "routine",
                "--saved-workflow",
                "saved-smoke",
                "--manual",
                "--include-personal",
            ]
        )
        self.assertFalse(validate_assessment.writes)
        self.assertFalse(list_assessment.writes)
        self.assertFalse(status_assessment.writes)
        self.assertFalse(controls_validate_assessment.writes)
        self.assertFalse(state_validate_assessment.writes)
        self.assertTrue(write_assessment.writes)
        self.assertFalse(write_assessment.network)
        self.assertFalse(write_assessment.destructive)
        self.assertTrue(personal_write_assessment.writes)
        self.assertTrue(personal_write_assessment.external_path)
        self.assertFalse(personal_write_assessment.network)
        self.assertFalse(personal_write_assessment.destructive)
        for command in [
            ["pause-routine", "routine.json"],
            ["resume-routine", "routine.json", "--approve", "routine:routine"],
            ["update-routine-schedule", "routine.json", "--manual", "--approve", "routine:routine"],
        ]:
            assessment = assess_command(["python3", "-B", "-m", "conductor_extras"] + command)
            self.assertTrue(assessment.writes)
            self.assertFalse(assessment.network)
            self.assertFalse(assessment.destructive)
        run_now_assessment = assess_command(
            [
                "python3",
                "-B",
                "-m",
                "conductor_extras",
                "run-routine-now",
                "routine.json",
                "--approve",
                "routine:routine",
            ]
        )
        self.assertTrue(run_now_assessment.writes)
        self.assertTrue(run_now_assessment.network)
        self.assertTrue(run_now_assessment.destructive)

