    def test_routine_due_slots_cover_catchup_weekdays_once_and_latest_interval(self):
        now = datetime(2026, 7, 8, 8, 0, tzinfo=timezone.utc)
        base = {"created_at_utc": "2026-06-01T00:00:00.000Z"}

        daily = dict(base, schedule=build_schedule(daily_at="09:00", timezone="UTC"))
        self.assertEqual(routine_due_slot(daily, {}, now), datetime(2026, 7, 7, 9, 0, tzinfo=timezone.utc))
        self.assertIsNone(
            routine_due_slot(
                daily,
                {"last_scheduled_for_utc": "2026-07-07T09:00:00.000Z"},
                now,
            )
        )

        weekdays = dict(base, schedule=build_schedule(weekdays_at="09:00", timezone="UTC"))
        self.assertEqual(
            routine_due_slot(weekdays, {}, datetime(2026, 7, 6, 8, 0, tzinfo=timezone.utc)),
            datetime(2026, 7, 3, 9, 0, tzinfo=timezone.utc),
        )

        weekly = dict(base, schedule=build_schedule(weekly_at="wednesday:09:00", timezone="UTC"))
        self.assertEqual(routine_due_slot(weekly, {}, now), datetime(2026, 7, 1, 9, 0, tzinfo=timezone.utc))

        monthly = dict(base, schedule=build_schedule(monthly_at="31:09:00", timezone="UTC"))
        self.assertEqual(
            routine_due_slot(monthly, {}, datetime(2026, 7, 31, 10, 0, tzinfo=timezone.utc)),
            datetime(2026, 7, 31, 9, 0, tzinfo=timezone.utc),
        )
        self.assertEqual(
            routine_due_slot(monthly, {}, datetime(2028, 2, 29, 10, 0, tzinfo=timezone.utc)),
            datetime(2028, 2, 29, 9, 0, tzinfo=timezone.utc),
        )
        self.assertIsNone(
            routine_due_slot(
                monthly,
                {"last_scheduled_for_utc": "2028-02-29T09:00:00.000Z"},
                datetime(2028, 2, 29, 10, 0, tzinfo=timezone.utc),
            )
        )

        once = dict(base, schedule=build_schedule(once_at="2026-07-02T08:00:00.000Z"))
        self.assertEqual(routine_due_slot(once, {}, now), datetime(2026, 7, 2, 8, 0, tzinfo=timezone.utc))
        expired_once = dict(base, schedule=build_schedule(once_at="2026-06-30T07:59:59.000Z"))
        self.assertIsNone(routine_due_slot(expired_once, {}, now))

        interval = dict(base, schedule=build_schedule(interval_minutes=10))
        self.assertEqual(
            routine_due_slot(
                interval,
                {"last_scheduled_for_utc": "2026-07-08T07:01:00.000Z"},
                now,
            ),
            datetime(2026, 7, 8, 7, 51, tzinfo=timezone.utc),
        )

        self.assertEqual(
            build_schedule(monthly_at="15:08:30", timezone="America/Los_Angeles"),
            {"kind": "monthly", "day": 15, "time": "08:30", "timezone": "America/Los_Angeles"},
        )
        for invalid in ["0:08:30", "32:08:30", "01:08:30", "last:08:30", "15:24:00"]:
            with self.assertRaises(ValidationError):
                build_schedule(monthly_at=invalid)

