    def test_automatic_run_directories_are_atomically_suffixed_on_same_second_collision(self):
        workflow = workflow_with_steps([])
        with tempfile.TemporaryDirectory() as tmp:
            runs = Path(tmp) / "runs"
            with patch("conductor_extras.runtime.artifacts.utc_stamp", return_value="20260709-040000"):
                first = RunArtifacts.create(workflow, runs)
                second = RunArtifacts.create(workflow, runs)
            self.assertEqual(first.run_dir.name, "20260709-040000-test-workflow")
            self.assertEqual(second.run_dir.name, "20260709-040000-test-workflow-002")

            RunArtifacts.create(workflow, runs, run_id="operator-fixed")
            with self.assertRaises(FileExistsError):
                RunArtifacts.create(workflow, runs, run_id="operator-fixed")

    @unittest.skipUnless(os.name == "posix", "background routine supervision requires POSIX")
    def test_active_background_supervisor_observes_pause_resume_and_schedule_update(self):
        workflow = workflow_with_steps(
            [{"id": "check", "kind": "shell", "risk": "low", "writes": False, "command": ["true"]}]
        )
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            routines = root / "routines"
            workflow_path = root / "workflow.json"
            manifest_path = routines / "live-managed.json"
            write_json(workflow_path, workflow)
            with redirect_stdout(StringIO()):
                self.assertEqual(
                    cli_main(
                        [
                            "write-routine-manifest",
                            str(manifest_path),
                            "--name",
                            "live-managed",
                            "--workflow",
                            str(workflow_path),
                            "--workspace",
                            str(root),
                            "--runs-dir",
                            str(root / "runs"),
                            "--interval-minutes",
                            "1",
                        ]
                    ),
                    0,
                )
                self.assertEqual(cli_main(["pause-routine", str(manifest_path)]), 0)

            repository_root = str(Path(__file__).resolve().parents[1])
            environment = dict(os.environ)
            environment["PYTHONPATH"] = repository_root + (
                os.pathsep + environment["PYTHONPATH"] if environment.get("PYTHONPATH") else ""
            )
            with patch.dict(os.environ, environment, clear=True), redirect_stdout(StringIO()):
                self.assertEqual(
                    cli_main(
                        [
                            "supervise-routines",
                            "--routines-dir",
                            str(routines),
                            "--background",
                            "--poll-seconds",
                            "1",
                            "--approve",
                            "background-supervisor",
                            "--approve",
                            "routine:live-managed",
                        ]
                    ),
                    0,
                )
            metadata_path = next((routines / "_supervisor" / "workers").glob("*.json"))
            worker_pid = load_background_routine_supervisor(metadata_path)["worker"]["pid"]
            deadline = time.monotonic() + 5
            while time.monotonic() < deadline:
                state = load_supervisor_state(routines)
                if state.get("routines", {}).get("live-managed", {}).get("last_status") == "skipped":
                    break
                time.sleep(0.05)
            else:
                self.fail("background supervisor did not record the paused due slot")
            self.assertFalse((root / "runs").exists())

            fire_at = datetime.now(timezone.utc) + timedelta(seconds=2)
            fire_text = fire_at.isoformat(timespec="milliseconds").replace("+00:00", "Z")
            with redirect_stdout(StringIO()):
                self.assertEqual(
                    cli_main(
                        [
                            "resume-routine",
                            str(manifest_path),
                            "--approve",
                            "routine:live-managed",
                        ]
                    ),
                    0,
                )
                self.assertEqual(
                    cli_main(
                        [
                            "update-routine-schedule",
                            str(manifest_path),
                            "--once-at",
                            fire_text,
                            "--approve",
                            "routine:live-managed",
                        ]
                    ),
                    0,
                )

            deadline = time.monotonic() + 8
            while time.monotonic() < deadline:
                execution = load_supervisor_state(routines).get("routines", {}).get("live-managed", {})
                if execution.get("executions") == 1 and execution.get("last_status") == "completed":
                    break
                time.sleep(0.05)
            else:
                self.fail("background supervisor did not observe the resumed one-shot schedule")
            self.assertEqual([row["status"] for row in execution["history"]], ["skipped", "completed"])
            self.assertEqual(execution["history"][-1]["scheduled_for_utc"], fire_text)

            terminate_background_routine_supervisor(metadata_path)
            final = wait_for_background_routine_supervisor(
                metadata_path,
                timeout_seconds=10,
                poll_interval_seconds=0.05,
            )
            self.assertEqual(final["supervisor_status"], "terminated")
            self.assertEqual(final["completed_count"], 1)
            try:
                os.waitpid(worker_pid, 0)
            except ChildProcessError:
                pass

    @unittest.skipUnless(os.name == "posix", "background routine supervision requires POSIX")
    def test_background_routine_supervisor_executes_due_routine_without_persisting_approvals(self):
        workflow = workflow_with_steps(
            [{"id": "check", "kind": "shell", "risk": "low", "writes": False, "command": ["true"]}]
        )
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            routines = root / "routines"
            workflow_path = root / "workflow.json"
            write_json(workflow_path, workflow)
            with redirect_stdout(StringIO()):
                self.assertEqual(
                    cli_main(
                        [
                            "write-routine-manifest",
                            str(routines / "background-check.json"),
                            "--name",
                            "background-check",
                            "--workflow",
                            str(workflow_path),
                            "--workspace",
                            str(root),
                            "--runs-dir",
                            str(root / "runs"),
                            "--interval-minutes",
                            "10",
                        ]
                    ),
                    0,
                )

            repository_root = str(Path(__file__).resolve().parents[1])
            environment = dict(os.environ)
            environment["PYTHONPATH"] = repository_root + (
                os.pathsep + environment["PYTHONPATH"] if environment.get("PYTHONPATH") else ""
            )
            secret_approval = "ephemeral-background-supervisor-approval"
            stdout = StringIO()
            with patch.dict(os.environ, environment, clear=True), redirect_stdout(stdout):
                code = cli_main(
                    [
                        "supervise-routines",
                        "--routines-dir",
                        str(routines),
                        "--background",
                        "--max-cycles",
                        "1",
                        "--poll-seconds",
                        "1",
                        "--approve",
                        "background-supervisor",
                        "--approve",
                        "routine:background-check",
                        "--approve",
                        secret_approval,
                    ]
                )
                self.assertEqual(code, 0)
                metadata_path = next((routines / "_supervisor" / "workers").glob("*.json"))
                launched = load_background_routine_supervisor(metadata_path)
                worker_pid = launched["worker"]["pid"]
                final = wait_for_background_routine_supervisor(
                    metadata_path,
                    timeout_seconds=10,
                    poll_interval_seconds=0.05,
                )

            self.assertEqual(final["schema"], BACKGROUND_ROUTINE_SUPERVISOR_SCHEMA)
            self.assertEqual(final["status"], "finished")
            self.assertEqual(final["supervisor_status"], "completed")
            self.assertEqual(final["cycles_completed"], 1)
            self.assertEqual(final["results_count"], 1)
            self.assertEqual(final["completed_count"], 1)
            self.assertEqual(final["exit_code"], 0)
            self.assertTrue(final["worker"]["ready"])
            self.assertNotIn("--approve", final["worker"]["argv"])
            state = load_supervisor_state(routines)
            self.assertEqual(state["routines"]["background-check"]["last_status"], "completed")
            self.assertEqual(state["routines"]["background-check"]["executions"], 1)

            status_stdout = StringIO()
            with redirect_stdout(status_stdout):
                self.assertEqual(
                    cli_main(["status-background-routine-supervisor", str(metadata_path)]),
                    0,
                )
            status = json.loads(status_stdout.getvalue())
            self.assertEqual(status["liveness"], "finished")
            self.assertIn("background-check", status["routine_state"]["routines"])

            validate_stdout = StringIO()
            with redirect_stdout(validate_stdout):
                self.assertEqual(
                    cli_main(["validate-background-routine-supervisor", str(metadata_path)]),
                    0,
                )
            self.assertIn("OK:", validate_stdout.getvalue())

            list_stdout = StringIO()
            with redirect_stdout(list_stdout):
                self.assertEqual(
                    cli_main(["list-routines", "--routines-dir", str(routines), "--json"]),
                    0,
                )
            listing = json.loads(list_stdout.getvalue())
            self.assertEqual(listing["background_supervisor"]["supervisor_status"], "completed")
            self.assertEqual(listing["background_supervisor"]["completed_count"], 1)

            dashboard_path = root / "routine-supervisor-dashboard.html"
            write_dashboard(
                root / "runs",
                root / "benchmarks",
                dashboard_path,
                routines_dir=routines,
            )
            dashboard_html = dashboard_path.read_text(encoding="utf-8")
            self.assertIn("Routine Supervisor", dashboard_html)
            self.assertIn("1 completed / 0 blocked / 0 failed", dashboard_html)
            live_payload = build_live_payload(
                root / "runs",
                root / "benchmarks",
                routines_dir=routines,
            )
            self.assertEqual(live_payload["routine_supervisor"]["supervisor_status"], "completed")
            live_html = render_live_dashboard(live_payload)
            self.assertIn("Routine Supervisor", live_html)
            self.assertIn("1 completed / 0 blocked / 0 failed", live_html)

            persisted = "\n".join(
                path.read_text(encoding="utf-8")
                for path in list((routines / "_supervisor").rglob("*")) + list((root / "runs").rglob("*"))
                if path.is_file()
            )
            self.assertNotIn(secret_approval, persisted)
            self.assertFalse(final["policy"]["approval_values_persisted"])
            self.assertFalse(final["handoff"]["payload_persisted"])
            try:
                os.waitpid(worker_pid, 0)
            except ChildProcessError:
                pass

            tampered = copy.deepcopy(final)
            tampered["policy"]["approval_values_persisted"] = True
            with self.assertRaisesRegex(ValidationError, "policy metadata"):
                validate_background_routine_supervisor(tampered)

            tampered = copy.deepcopy(final)
            tampered["worker"]["argv"].append("--approve=persisted-secret")
            with self.assertRaisesRegex(ValidationError, "must not persist approval values"):
                validate_background_routine_supervisor(tampered)

            tampered = copy.deepcopy(final)
            tampered["exit_code"] = 1
            with self.assertRaisesRegex(ValidationError, "completed supervisor result is inconsistent"):
                validate_background_routine_supervisor(tampered)

            tampered = copy.deepcopy(final)
            tampered["results_count"] = 51
            tampered["failed_count"] = 50
