    def test_routine_launch_reservation_blocks_concurrent_supervisors(self):
        workflow = workflow_with_steps(
            [{"id": "check", "kind": "shell", "risk": "low", "writes": False, "command": ["true"]}]
        )
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workflow_path = root / "workflow.json"
            manifest_path = root / "routines" / "exclusive.json"
            write_json(workflow_path, workflow)
            with redirect_stdout(StringIO()):
                self.assertEqual(
                    cli_main(
                        [
                            "write-routine-manifest",
                            str(manifest_path),
                            "--name",
                            "exclusive",
                            "--workflow",
                            str(workflow_path),
                            "--workspace",
                            str(root),
                            "--runs-dir",
                            str(root / "runs"),
                            "--manual",
                        ]
                    ),
                    0,
                )
            entered = threading.Event()
            release = threading.Event()
            errors = []

            def blocking_process(*_args, **_kwargs):
                entered.set()
                release.wait(timeout=5)
                return ProcessResult(returncode=0, stdout="done", stderr="")

            def first_launch():
                try:
                    execute_routine_manifest(manifest_path, approvals={"routine:exclusive"})
                except Exception as exc:
                    errors.append(exc)

            with patch("conductor_extras.runtime.routine_supervisor.run_process", side_effect=blocking_process):
                thread = threading.Thread(target=first_launch)
                thread.start()
                self.assertTrue(entered.wait(timeout=5))
                with self.assertRaisesRegex(PolicyError, "already running"):
                    execute_routine_manifest(manifest_path, approvals={"routine:exclusive"})
                release.set()
                thread.join(timeout=5)
            self.assertFalse(thread.is_alive())
            self.assertEqual(errors, [])
            state = load_supervisor_state(manifest_path.parent)
            self.assertEqual(state["routines"]["exclusive"]["last_status"], "completed")
            self.assertEqual(state["routines"]["exclusive"]["executions"], 1)

