    def test_evidence_bundle_rejects_bad_schema_limits_and_symlinks(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            bundle = build_evidence_bundle(
                runs_dir=root / "runs",
                benchmarks_dir=root / "benchmarks",
                goals_dir=root / "goals",
                routines_dir=root / "routines",
            )
            good = root / "bundle.json"
            write_json(good, bundle)
            loaded = load_evidence_bundle(good)
            self.assertEqual(loaded["schema"], "conductor.evidence_bundle.v1")

            bad = json.loads(json.dumps(bundle))
            bad["unexpected"] = True
            bad_path = root / "bad.json"
            write_json(bad_path, bad)
            with self.assertRaises(ValidationError):
                load_evidence_bundle(bad_path)

            bad_claim = json.loads(json.dumps(bundle))
            bad_claim["claim"]["status"] = "claim-eligible"
            bad_claim_path = root / "bad-claim.json"
            write_json(bad_claim_path, bad_claim)
            with self.assertRaises(ValidationError):
                load_evidence_bundle(bad_claim_path)

            bad_count = json.loads(json.dumps(bundle))
            bad_count["counts"]["reports"] = 99
            bad_count_path = root / "bad-count.json"
            write_json(bad_count_path, bad_count)
            with self.assertRaises(ValidationError):
                load_evidence_bundle(bad_count_path)

            bad_superiority = json.loads(json.dumps(bundle))
            bad_superiority["claim"]["superiority_claim_eligible"] = True
            bad_superiority_path = root / "bad-superiority.json"
            write_json(bad_superiority_path, bad_superiority)
            with self.assertRaises(ValidationError):
                load_evidence_bundle(bad_superiority_path)

            bad_hash = json.loads(json.dumps(bundle))
            bad_hash["reports"] = [
                {
                    "name": "bad-report.json",
                    "kind": "benchmark",
                    "schema": "conductor.benchmark_report.v1",
                    "suite": "unit",
                    "system": "codex",
                    "result": "unknown",
                    "failed_tasks": None,
                    "duration_ms": None,
                    "claim_eligible": None,
                    "provenance_complete": None,
                    "all_live": None,
                    "warnings": [],
                    "error": None,
                    "evidence_status": "benchmark-evidence",
                    "evidence_label": "local benchmark evidence",
                    "evidence_attention": False,
                    "mtime_utc": "2026-07-08T00:00:00Z",
                    "source_sha256": "not-a-sha",
                }
            ]
            bad_hash["counts"]["reports"] = 1
            bad_hash_path = root / "bad-report-hash.json"
            write_json(bad_hash_path, bad_hash)
            with self.assertRaisesRegex(ValidationError, "sha256 hex string"):
                load_evidence_bundle(bad_hash_path)

            with self.assertRaises(ValidationError):
                build_evidence_bundle(
                    runs_dir=root / "runs",
                    benchmarks_dir=root / "benchmarks",
                    goals_dir=root / "goals",
                    routines_dir=root / "routines",
                    max_runs=0,
                )

            link = root / "bundle-link.json"
            link.symlink_to(good)
            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(["validate-evidence-bundle", str(link)])
            self.assertEqual(code, 2)
            self.assertIn("symlink", stderr.getvalue())

            routines = root / "routines"
            routines.mkdir()
            routines_link = root / "routines-link"
            routines_link.symlink_to(routines, target_is_directory=True)
            with self.assertRaises(ValidationError):
                build_evidence_bundle(
                    runs_dir=root / "runs",
                    benchmarks_dir=root / "benchmarks",
                    goals_dir=root / "goals",
                    routines_dir=routines_link,
                )

    def test_evidence_bundle_cli_policy_classification(self):
        read_assessment = assess_command(["python3", "-B", "-m", "conductor_extras", "evidence-bundle"])
        validate_assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "validate-evidence-bundle", "bundle.json"]
        )
        write_assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "write-evidence-bundle", "bundle.json"]
        )
        self.assertFalse(read_assessment.writes)
        self.assertFalse(read_assessment.network)
        self.assertFalse(read_assessment.destructive)
        self.assertFalse(validate_assessment.writes)
        self.assertTrue(write_assessment.writes)
        self.assertFalse(write_assessment.network)
        self.assertFalse(write_assessment.destructive)

    def test_mutating_network_and_package_commands_require_write_policy(self):
        mutating_commands = [
            ["git", "init"],
            ["git", "clone", "https://example.invalid/repo.git"],
            ["git", "fetch"],
            ["git", "pull"],
            ["git", "push"],
            ["gh", "issue", "create", "--title", "x", "--body", "y"],
            ["npm", "install"],
            ["pip", "install", "package"],
            ["wget", "https://example.invalid/file"],
            ["curl", "-o", "file.txt", "https://example.invalid/file"],
            ["curl", "--remote-name", "https://example.invalid/file"],
            ["curl", "-X", "POST", "https://example.invalid/item"],
            ["curl", "--request=DELETE", "https://example.invalid/item"],
            ["curl", "--data", "{}", "https://example.invalid/item"],
        ]
        for command in mutating_commands:
            assessment = assess_command(command)
            self.assertTrue(assessment.writes, command)
            with self.assertRaises(PolicyError, msg=str(command)):
                enforce_shell_policy(
                    {"id": "mutating-network", "risk": "low", "command": command},
                    RuntimePolicy(allow_network=True),
                )

        stdout_curl = assess_command(["curl", "https://example.invalid/file"])
        self.assertFalse(stdout_curl.writes)
        self.assertTrue(stdout_curl.network)
        head_curl = assess_command(["curl", "-I", "https://example.invalid/file"])
        self.assertFalse(head_curl.writes)
        self.assertTrue(head_curl.network)

