    def test_claude_provider_evidence_rejects_opus_malformed_streams_and_tampering(self):
        opus = analyze_claude_output(
            ProcessResult(0, claude_stream_fixture(main_model="claude-opus-5"), ""),
            cli_version="2.1.205 (Claude Code)",
            max_budget_usd=0.75,
            max_turns=8,
            timeout_seconds=900,
            output_limit_bytes=1024 * 1024,
        )["provider_evidence"]
        self.assertEqual(opus["status"], "model-rejected")
        self.assertTrue(opus["observed"]["opus_observed"])
        self.assertIn("opus-observed", {item["id"] for item in opus["incidents"]})

        unavailable = analyze_claude_output(
            ProcessResult(0, claude_stream_fixture(include_token_usage=False), ""),
            cli_version="2.1.205 (Claude Code)",
            max_budget_usd=0.75,
            max_turns=8,
            timeout_seconds=900,
            output_limit_bytes=1024 * 1024,
        )["provider_evidence"]
        self.assertEqual(unavailable["observed"]["token_usage_source"], "unavailable")
        self.assertIsNone(unavailable["observed"]["total_tokens"])

        partial_events = [json.loads(line) for line in claude_stream_fixture().splitlines()]
        del partial_events[-1]["modelUsage"]["claude-sonnet-5"]["outputTokens"]
        partial_stream = "\n".join(json.dumps(event) for event in partial_events) + "\n"
        partial = analyze_claude_output(
            ProcessResult(1, partial_stream, ""),
            cli_version="2.1.205 (Claude Code)",
            max_budget_usd=0.75,
            max_turns=8,
            timeout_seconds=900,
            output_limit_bytes=1024 * 1024,
        )["provider_evidence"]
        self.assertEqual(partial["status"], "malformed-output")
        self.assertIn("complete or unavailable", partial["observed"]["parse_error"])

        malformed = analyze_claude_output(
            ProcessResult(1, "not-json\n", "token=stderrsecret"),
            cli_version="2.1.205 (Claude Code)",
            max_budget_usd=0.75,
            max_turns=8,
            timeout_seconds=900,
            output_limit_bytes=1024 * 1024,
        )["provider_evidence"]
        self.assertEqual(malformed["status"], "malformed-output")
        self.assertIn("provider-output-malformed", {item["id"] for item in malformed["incidents"]})

        duplicate = analyze_claude_output(
            ProcessResult(1, '{"type":"result","type":"result"}\n', ""),
            cli_version="2.1.205 (Claude Code)",
            max_budget_usd=0.75,
            max_turns=8,
            timeout_seconds=900,
            output_limit_bytes=1024 * 1024,
        )["provider_evidence"]
        self.assertEqual(duplicate["status"], "malformed-output")
        self.assertIn("duplicate key", duplicate["observed"]["parse_error"])

        template = load_claude_provider_evidence(Path("benchmark-suites/claude-provider-evidence-template.json"))
        legacy_v2 = load_claude_provider_evidence(Path("benchmark-suites/claude-provider-evidence-v2-template.json"))
        legacy = load_claude_provider_evidence(Path("benchmark-suites/claude-provider-evidence-v1-template.json"))
        self.assertEqual(legacy_v2["schema"], CLAUDE_PROVIDER_EVIDENCE_SCHEMA_V2)
        self.assertEqual(legacy_v2["requested"]["permission_mode"], "plan")
        self.assertEqual(legacy["schema"], CLAUDE_PROVIDER_EVIDENCE_SCHEMA_V1)
        self.assertNotIn("total_tokens", legacy["observed"])
        tampered = copy.deepcopy(template)
        tampered["requested"]["permission_mode"] = "plan"
        with self.assertRaisesRegex(ValidationError, "tool and permission contract"):
            validate_claude_provider_evidence(tampered)
        tampered = copy.deepcopy(legacy_v2)
        tampered["requested"]["permission_mode"] = "dontAsk"
        with self.assertRaisesRegex(ValidationError, "tool and permission contract"):
            validate_claude_provider_evidence(tampered)
        tampered = copy.deepcopy(template)
        tampered["policy"]["approval_values_persisted"] = True
        with self.assertRaisesRegex(ValidationError, "policy metadata"):
            validate_claude_provider_evidence(tampered)
        tampered = copy.deepcopy(template)
        tampered["observed"]["cost_usd"] = 1.0
        with self.assertRaisesRegex(ValidationError, "overshoot"):
            validate_claude_provider_evidence(tampered)
        tampered = copy.deepcopy(template)
        tampered["status"] = "provider-error"
        with self.assertRaisesRegex(ValidationError, "status is inconsistent"):
            validate_claude_provider_evidence(tampered)
        tampered = copy.deepcopy(template)
        tampered["observed"]["total_tokens"] += 1
        with self.assertRaisesRegex(ValidationError, "total tokens"):
            validate_claude_provider_evidence(tampered)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            duplicate_path = root / "duplicate.json"
            duplicate_path.write_text(
                '{"schema":"conductor.claude_provider_evidence.v1",'
                '"schema":"conductor.claude_provider_evidence.v1"}\n',
                encoding="utf-8",
            )
            with self.assertRaisesRegex(ValidationError, "duplicate key"):
                load_claude_provider_evidence(duplicate_path)
            link = root / "linked.json"
            try:
                link.symlink_to(Path("benchmark-suites/claude-provider-evidence-template.json").resolve())
            except OSError:
                pass
            else:
                with self.assertRaisesRegex(ValidationError, "must not be a symlink"):
                    load_claude_provider_evidence(link)

    def test_claude_readonly_task_requires_paid_network_agent_policy_and_fixture_bounds(self):
        fixtures = parity_tasks_fixture()
        base = {
            "parity_tasks": fixtures,
            "task_id": "task-a",
            "workspace": Path("."),
            "max_budget_usd": 0.75,
            "max_turns": 8,
            "timeout_seconds": 120,
        }
        policies = [
            RuntimePolicy(allow_network=True, approvals={CLAUDE_PAID_RUN_APPROVAL}),
            RuntimePolicy(allow_agent=True, approvals={CLAUDE_PAID_RUN_APPROVAL}),
            RuntimePolicy(allow_agent=True, allow_network=True),
        ]
        expected = ["allow-agent", "allow-network", CLAUDE_PAID_RUN_APPROVAL]
        for policy, message in zip(policies, expected):
            with self.subTest(message=message), self.assertRaisesRegex(PolicyError, message):
                run_claude_readonly_task(policy=policy, **base)

        approved = RuntimePolicy(
            allow_agent=True,
            allow_network=True,
            approvals={CLAUDE_PAID_RUN_APPROVAL},
        )
        with self.assertRaisesRegex(ValidationError, "exceeds parity task"):
            run_claude_readonly_task(policy=approved, max_budget_usd=2.0, **{k: v for k, v in base.items() if k != "max_budget_usd"})
        with self.assertRaisesRegex(ValidationError, "max_turns"):
            run_claude_readonly_task(policy=approved, max_turns=0, **{k: v for k, v in base.items() if k != "max_turns"})

