            self.assertEqual(evidence["observed"]["gross_token_upper_bound"], 150)
            self.assertEqual(evidence["observed"]["rollout_budget_lower_bound"], 130)
            self.assertEqual(evidence["observed"]["rollout_budget_upper_bound"], 130)
            self.assertTrue(evidence["workspace"]["source_unchanged"])
            self.assertTrue(evidence["workspace"]["stage_unchanged"])
            self.assertEqual(source_file.read_text(encoding="utf-8"), "before\n")
            self.assertEqual((stage / "file.txt").read_text(encoding="utf-8"), "before\n")
            provider_argv, provider_kwargs = calls[1]
            self.assertIn("--ephemeral", provider_argv)
