    def test_codex_readonly_task_requires_policy_and_fixture_bounds(self):
        fixtures = parity_tasks_fixture()
        base = {
            "parity_tasks": fixtures,
            "task_id": "task-a",
            "workspace": Path("."),
            "stage_dir": Path("/tmp/codex-policy-stage"),
            "model": "gpt-5.6-sol",
            "effort": "ultra",
            "max_tokens": 1000,
            "timeout_seconds": 120,
        }
        policies = [
            RuntimePolicy(allow_network=True, approvals={CODEX_LIVE_RUN_APPROVAL}),
            RuntimePolicy(allow_agent=True, approvals={CODEX_LIVE_RUN_APPROVAL}),
            RuntimePolicy(allow_agent=True, allow_network=True),
            RuntimePolicy(allow_agent=True, allow_network=True, allow_writes=True, approvals={CODEX_LIVE_RUN_APPROVAL}),
        ]
        expected = ["allow-agent", "allow-network", CODEX_LIVE_RUN_APPROVAL, "forbids write"]
        for policy, message in zip(policies, expected):
            with self.subTest(message=message), self.assertRaisesRegex(PolicyError, message):
                run_codex_readonly_task(policy=policy, **base)
        approved = RuntimePolicy(
            allow_agent=True,
            allow_network=True,
            approvals={CODEX_LIVE_RUN_APPROVAL},
        )
        with self.assertRaisesRegex(ValidationError, "exceeds parity task"):
            run_codex_readonly_task(policy=approved, max_tokens=1001, **{k: v for k, v in base.items() if k != "max_tokens"})

