    def test_codex_executable_path_is_canonical_and_rejects_invalid_input(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            target = root / "codex-real"
            target.write_text("#!/bin/sh\nexit 0\n", encoding="utf-8")
            target.chmod(0o755)
            link = root / "codex"
            link.symlink_to(target)
            self.assertEqual(canonicalize_codex_executable_path(str(link)), str(target.resolve()))
            loop = root / "loop"
            loop.symlink_to(loop.name)
            with self.assertRaises(ValidationError):
                canonicalize_codex_executable_path(str(loop))
        for value in ("", "bad\npath", None):
            with self.subTest(value=value), self.assertRaises(ValidationError):
                canonicalize_codex_executable_path(value)

