def canonical_event_name(value: str) -> str:
    """Return one validated, case-folded dotted event name."""
    if not isinstance(value, str):
        raise TypeError("event name must be a string")
    parts = [part for part in re.split(r"[\\s._-]+", value.casefold()) if part]
    if not parts or any(not part.isalnum() for part in parts):
        raise ValueError("event name contains no valid segments or unsupported punctuation")
    return ".".join(parts)
