    def test_codex_staged_repair_pauses_resumes_without_replaying_completed_attempts(self):
        fixtures = parity_tasks_fixture()
        fixtures["tasks"][0]["budget"]["max_tokens"] = 2000
        policy = RuntimePolicy(
            allow_agent=True,
            allow_network=True,
            allow_writes=True,
            approvals={CODEX_LIVE_RUN_APPROVAL, CODEX_STAGED_WRITE_APPROVAL, "ephemeral-secret"},
        )
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            source = root / "source"
            source.mkdir()
            (source / "file.txt").write_text("before\n", encoding="utf-8")
            repair_dir = root / "repair"
            provider_calls = []
            verifier_calls = []

            def fake_provider(argv, **kwargs):
                provider_calls.append(list(argv))
                (kwargs["cwd"] / "file.txt").write_text(
                    "attempt-%d\n" % len(provider_calls),
                    encoding="utf-8",
                )
                return ProcessResult(0, codex_stream_fixture(), "")

            def fake_verifier(argv, **kwargs):
                verifier_calls.append(list(argv))
                return ProcessResult(7 if len(verifier_calls) == 1 else 0, "", "fix it")

            common = {
                "parity_tasks": fixtures,
                "task_id": "task-a",
                "workspace": source,
                "repair_dir": repair_dir,
                "check_command": ["true"],
                "policy": policy,
                "model": "gpt-5.6-sol",
                "effort": "ultra",
                "max_attempts": 2,
                "max_tokens_per_attempt": 1000,
                "provider_timeout_seconds": 60,
                "check_timeout_seconds": 10,
                "attempts_this_run": 1,
            }
            with patch("conductor_extras.runtime.codex_staged.shutil.which", return_value="/fake/codex"), patch(
                "conductor_extras.runtime.codex_staged._codex_cli_version",
                return_value="codex-cli 0.143.0",
            ), patch("conductor_extras.runtime.codex_staged.run_process", side_effect=fake_provider), patch(
                "conductor_extras.runtime.claude_staged.run_process",
                side_effect=fake_verifier,
            ):
                paused = run_codex_staged_repair(**common)

            self.assertEqual(paused["schema"], CODEX_STAGED_REPAIR_STATE_SCHEMA)
            self.assertEqual(paused["status"], "paused")
            self.assertEqual(len(paused["attempts"]), 1)
            self.assertEqual(len(provider_calls), 1)
            state_path = repair_dir / "repair-state.json"
            state_text = state_path.read_text(encoding="utf-8")
            self.assertNotIn("ephemeral-secret", state_text)
            self.assertNotIn(str(source), state_text)
            self.assertNotIn('"true"', state_text)
            self.assertFalse((repair_dir / "repair.json").exists())
            first_report = repair_dir / "attempt-001.report.json"
            first_report_hash = hashlib.sha256(first_report.read_bytes()).hexdigest()
            self.assertEqual(load_codex_staged_repair_state(state_path), paused)

            with patch("conductor_extras.runtime.codex_staged.shutil.which", return_value="/fake/codex"), patch(
                "conductor_extras.runtime.codex_staged._codex_cli_version",
                return_value="codex-cli 0.143.0",
            ), patch("conductor_extras.runtime.codex_staged.run_process", side_effect=fake_provider), patch(
                "conductor_extras.runtime.claude_staged.run_process",
                side_effect=fake_verifier,
            ):
                completed = run_codex_staged_repair(**common, resume=True)

            self.assertEqual(completed["status"], "success")
            self.assertEqual(len(completed["attempts"]), 2)
            self.assertEqual(len(provider_calls), 2)
            self.assertEqual(hashlib.sha256(first_report.read_bytes()).hexdigest(), first_report_hash)
            completed_state = load_codex_staged_repair_state(state_path)
            self.assertEqual(completed_state["status"], "completed")
            self.assertEqual(completed_state["active_duration_ms"], completed["duration_ms"])
            self.assertFalse(completed_state["policy"]["active_attempt_replay_allowed"])
            self.assertEqual(completed_state["final"]["patch_name"], "final.patch")
            validate_codex_staged_repair_state(completed_state, base_dir=repair_dir)

            with patch("conductor_extras.runtime.codex_staged.run_process") as replayed_provider, patch(
                "conductor_extras.runtime.claude_staged.run_process"
            ) as replayed_verifier:
                repeated = run_codex_staged_repair(**common, resume=True)
            self.assertEqual(repeated, completed)
            replayed_provider.assert_not_called()
            replayed_verifier.assert_not_called()

    def test_codex_staged_repair_resume_rejects_drift_tampering_and_active_attempts(self):
        fixtures = parity_tasks_fixture()
        fixtures["tasks"][0]["budget"]["max_tokens"] = 2000
        policy = RuntimePolicy(
            allow_agent=True,
            allow_network=True,
            allow_writes=True,
            approvals={CODEX_LIVE_RUN_APPROVAL, CODEX_STAGED_WRITE_APPROVAL},
        )
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            source = root / "source"
            source.mkdir()
            source_file = source / "file.txt"
            source_file.write_text("before\n", encoding="utf-8")
            repair_dir = root / "repair"
            calls = []

            def fake_provider(argv, **kwargs):
                calls.append(list(argv))
                (kwargs["cwd"] / "file.txt").write_text("attempt-one\n", encoding="utf-8")
                return ProcessResult(0, codex_stream_fixture(), "")

            common = {
                "parity_tasks": fixtures,
                "task_id": "task-a",
                "workspace": source,
                "repair_dir": repair_dir,
                "check_command": ["true"],
                "policy": policy,
                "model": "gpt-5.6-sol",
                "effort": "ultra",
                "max_attempts": 2,
                "max_tokens_per_attempt": 1000,
                "provider_timeout_seconds": 60,
                "check_timeout_seconds": 10,
                "attempts_this_run": 1,
            }
            with patch("conductor_extras.runtime.codex_staged.shutil.which", return_value="/fake/codex"), patch(
                "conductor_extras.runtime.codex_staged._codex_cli_version",
                return_value="codex-cli 0.143.0",
            ), patch("conductor_extras.runtime.codex_staged.run_process", side_effect=fake_provider), patch(
                "conductor_extras.runtime.claude_staged.run_process",
                return_value=ProcessResult(7, "", "still failing"),
            ):
                paused = run_codex_staged_repair(**common)
            self.assertEqual(paused["status"], "paused")
            self.assertEqual(len(calls), 1)

            with patch("conductor_extras.runtime.codex_staged.run_process") as provider:
                with self.assertRaisesRegex(ValidationError, "configuration"):
                    run_codex_staged_repair(**{**common, "provider_timeout_seconds": 61}, resume=True)
                provider.assert_not_called()

            source_file.write_text("drifted\n", encoding="utf-8")
            with patch("conductor_extras.runtime.codex_staged.run_process") as provider:
                with self.assertRaisesRegex(ValidationError, "source has drifted"):
                    run_codex_staged_repair(**common, resume=True)
                provider.assert_not_called()
            source_file.write_text("before\n", encoding="utf-8")

            stage_file = repair_dir / "attempt-001.stage" / "file.txt"
            stage_file.write_text("tampered\n", encoding="utf-8")
            with patch("conductor_extras.runtime.codex_staged.run_process") as provider:
                with self.assertRaisesRegex(ValidationError, "stage fingerprint"):
                    run_codex_staged_repair(**common, resume=True)
                provider.assert_not_called()
            stage_file.write_text("attempt-one\n", encoding="utf-8")

            state_path = repair_dir / "repair-state.json"
            active = load_codex_staged_repair_state(state_path)
            active["status"] = "attempt-active"
            active["active_attempt"] = 2
            state_path.write_text(json.dumps(active, indent=2, sort_keys=True) + "\n", encoding="utf-8")
            with patch("conductor_extras.runtime.codex_staged.run_process") as provider:
                with self.assertRaisesRegex(ValidationError, "cannot be replayed safely"):
                    run_codex_staged_repair(**common, resume=True)
                provider.assert_not_called()

            duplicate_text = state_path.read_text(encoding="utf-8").replace(
                '  "schema":',
                '  "schema": "duplicate",\n  "schema":',
                1,
            )
            state_path.write_text(duplicate_text, encoding="utf-8")
            with self.assertRaisesRegex(ValidationError, "duplicate key"):
                load_codex_staged_repair_state(state_path, validate_artifacts=False)

