    def test_codex_staged_cli_verified_stage_exit_contract_accepts_cutoff_without_relabeling(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            source = root / "source"
            source.mkdir()
            (source / "file.txt").write_text("before\n", encoding="utf-8")
            fixtures = root / "parity.json"
            write_json(fixtures, parity_tasks_fixture())

            def command(output, *, verified_stage=False):
                argv = [
                    "run-codex-staged-task",
                    str(fixtures),
                    "task-a",
                    "--workspace",
                    str(source),
                    "--output",
                    str(output),
                    "--check-command-json",
                    '["true"]',
                    "--model",
                    "gpt-5.6-sol",
                    "--effort",
                    "low",
                    "--max-tokens",
                    "1000",
                    "--tool-output-token-limit",
                    "512",
                    "--timeout-seconds",
                    "120",
                    "--check-timeout-seconds",
                    "30",
                    "--allow-agent",
                    "--allow-network",
                    "--allow-writes",
                    "--approve",
                    CODEX_LIVE_RUN_APPROVAL,
                    "--approve",
                    CODEX_STAGED_WRITE_APPROVAL,
                ]
                if verified_stage:
                    argv.extend(["--exit-contract", "verified-stage"])
                return argv

            def fake_run(argv, **kwargs):
                if argv[0] == "/fake/codex":
                    (kwargs["cwd"] / "file.txt").write_text("after\n", encoding="utf-8")
                    return ProcessResult(1, codex_budget_exhausted_stream_fixture(), "")
                return ProcessResult(0, "OK\n", "")

            strict_output = root / "reports" / "strict.json"
            delivery_output = root / "reports" / "delivery.json"
            delivery_stdout = StringIO()
            provider_patches = (
                patch("conductor_extras.runtime.codex_staged.shutil.which", return_value="/fake/codex"),
                patch(
                    "conductor_extras.runtime.codex_staged._codex_cli_version",
                    return_value="codex-cli 0.144.1",
                ),
                patch("conductor_extras.runtime.codex_staged.run_process", side_effect=fake_run),
                patch("conductor_extras.runtime.claude_staged.run_process", side_effect=fake_run),
            )
            with provider_patches[0], provider_patches[1], provider_patches[2], provider_patches[3], redirect_stdout(
                StringIO()
            ):
                self.assertEqual(cli_main(command(strict_output)), 1)

            provider_patches = (
                patch("conductor_extras.runtime.codex_staged.shutil.which", return_value="/fake/codex"),
                patch(
                    "conductor_extras.runtime.codex_staged._codex_cli_version",
                    return_value="codex-cli 0.144.1",
                ),
                patch("conductor_extras.runtime.codex_staged.run_process", side_effect=fake_run),
                patch("conductor_extras.runtime.claude_staged.run_process", side_effect=fake_run),
            )
            with provider_patches[0], provider_patches[1], provider_patches[2], provider_patches[3], redirect_stdout(
                delivery_stdout
            ):
                self.assertEqual(cli_main(command(delivery_output, verified_stage=True)), 0)

            for output in [strict_output, delivery_output]:
                report = load_benchmark_report(output)
                result = report["results"][0]
                self.assertEqual(report["failed_tasks"], 1)
                self.assertFalse(result["passed"])
                self.assertEqual(result["provider_evidence"]["status"], "token-budget-exceeded")
                self.assertEqual(result["staged_evidence"]["status"], "success")
                self.assertEqual(result["staged_evidence"]["verification"]["status"], "passed")
                self.assertTrue(_verified_stage_delivery(result, output.parent / (output.stem + ".patch")))
            accepted = load_benchmark_report(delivery_output)["results"][0]
            for mutate in [
                lambda value: value["provider_evidence"].update(status="provider-error"),
                lambda value: value["staged_evidence"]["source"].update(unchanged=False),
                lambda value: value["staged_evidence"]["stage"].update(verifier_mutated_files=True),
                lambda value: value["staged_evidence"]["changes"].update(change_count=0),
                lambda value: value["staged_evidence"]["verification"].update(status="failed"),
                lambda value: value["staged_evidence"]["policy"].update(automatic_apply=True),
                lambda value: value["completion_summary"].update(verification_performed=False),
            ]:
                rejected = copy.deepcopy(accepted)
                mutate(rejected)
                self.assertFalse(_verified_stage_delivery(rejected, delivery_output.parent / "delivery.patch"))
            claude_cutoff = copy.deepcopy(accepted)
            claude_cutoff["provider_evidence"]["status"] = "budget-exceeded"
            self.assertTrue(_verified_stage_delivery(claude_cutoff, delivery_output.parent / "delivery.patch"))
            (delivery_output.parent / "delivery.patch").write_text("tampered\n", encoding="utf-8")
            self.assertFalse(_verified_stage_delivery(accepted, delivery_output.parent / "delivery.patch"))
            self.assertIn("Verified stage accepted: yes", delivery_stdout.getvalue())
            self.assertIn("Provider/report outcome remains failed", delivery_stdout.getvalue())
            self.assertEqual((source / "file.txt").read_text(encoding="utf-8"), "before\n")

