    def test_verified_stage_apply_is_transactional_idempotent_and_cli_visible(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)

            def mutate(stage):
                (stage / "file.txt").write_text("after\n", encoding="utf-8")
                (stage / "new.txt").write_text("created\n", encoding="utf-8")

            source, report, _stage, _patch = create_verified_stage_fixture(
                root,
                {
                    "file.txt": "before\n",
                    ".git/HEAD": "ref: refs/heads/main\n",
                },
                mutate,
            )
            excluded_drift = source / ".hg"
            excluded_drift.mkdir()
            (excluded_drift / "hgrc").write_text("drift\n", encoding="utf-8")

            # Even excluded-directory presence is bound; Git content that existed at staging remains untouched.
            with self.assertRaises(ValidationError):
                apply_verified_stage(
                    report,
                    source,
                    policy=RuntimePolicy(
                        allow_writes=True,
                        approvals={STAGED_APPLY_APPROVAL},
                    ),
                )
            shutil.rmtree(excluded_drift)

            with self.assertRaisesRegex(PolicyError, "allow-writes"):
                apply_verified_stage(report, source)
            with self.assertRaisesRegex(PolicyError, STAGED_APPLY_APPROVAL):
                apply_verified_stage(
                    report,
                    source,
                    policy=RuntimePolicy(allow_writes=True),
                )

            stdout = StringIO()
            with redirect_stdout(stdout):
                self.assertEqual(
                    cli_main(
                        [
                            "apply-verified-stage",
                            str(report),
                            "--workspace",
                            str(source),
                            "--allow-writes",
                            "--approve",
                            STAGED_APPLY_APPROVAL,
                        ]
                    ),
                    0,
                )
            self.assertEqual((source / "file.txt").read_text(encoding="utf-8"), "after\n")
            self.assertEqual((source / "new.txt").read_text(encoding="utf-8"), "created\n")
            self.assertEqual(
                (source / ".git" / "HEAD").read_text(encoding="utf-8"),
                "ref: refs/heads/main\n",
            )
            self.assertIn("Provider/verifier calls: 0/0", stdout.getvalue())

            receipt_path = root / "delivery.apply.json"
            receipt = load_staged_apply_receipt(receipt_path)
            self.assertEqual(receipt["status"], "merged")
            self.assertEqual(receipt["policy"]["provider_calls"], 0)
            self.assertEqual(receipt["policy"]["verifier_calls"], 0)
            self.assertFalse(receipt["policy"]["approval_values_persisted"])
            self.assertNotIn(STAGED_APPLY_APPROVAL, receipt_path.read_text(encoding="utf-8"))

            before_receipt = receipt_path.read_bytes()
            with redirect_stdout(StringIO()):
                self.assertEqual(
                    cli_main(
                        [
                            "apply-verified-stage",
                            str(report),
                            "--workspace",
                            str(source),
                        ]
                    ),
                    0,
                )
            self.assertEqual(receipt_path.read_bytes(), before_receipt)
            with redirect_stdout(StringIO()):
                self.assertEqual(cli_main(["validate-staged-apply", str(receipt_path)]), 0)

    def test_verified_stage_apply_rejects_source_stage_patch_and_receipt_tampering(self):
        def fixture(root):
            return create_verified_stage_fixture(
                root,
                {"file.txt": "before\n"},
                lambda stage: (stage / "file.txt").write_text("after\n", encoding="utf-8"),
            )

        policy = RuntimePolicy(allow_writes=True, approvals={STAGED_APPLY_APPROVAL})
        with tempfile.TemporaryDirectory() as tmp:
            source, report, _stage, _patch = fixture(Path(tmp))
            (source / "file.txt").write_text("drift\n", encoding="utf-8")
            with self.assertRaisesRegex(ValidationError, "source workspace changed"):
                apply_verified_stage(report, source, policy=policy)

        with tempfile.TemporaryDirectory() as tmp:
            source, report, stage, _patch = fixture(Path(tmp))
            (stage / "file.txt").write_text("tampered\n", encoding="utf-8")
            with self.assertRaisesRegex(ValidationError, "stage tracked fingerprint"):
                apply_verified_stage(report, source, policy=policy)

        with tempfile.TemporaryDirectory() as tmp:
            source, report, _stage, patch_path = fixture(Path(tmp))
            patch_path.write_text("tampered\n", encoding="utf-8")
            with self.assertRaises(ValidationError):
                apply_verified_stage(report, source, policy=policy)

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            source, report, _stage, _patch = fixture(root)
            result = apply_verified_stage(report, source, policy=policy)
            self.assertEqual(result["status"], "merged")
            receipt_path = root / "delivery.apply.json"
            receipt = json.loads(receipt_path.read_text(encoding="utf-8"))
            receipt["change_count"] = 2
            receipt_path.write_text(json.dumps(receipt), encoding="utf-8")
            with self.assertRaises(ValidationError):
                load_staged_apply_receipt(receipt_path)

    def test_verified_stage_apply_deletions_require_independent_destructive_gates(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)

            def mutate(stage):
                (stage / "delete.txt").unlink()
                (stage / "keep.txt").write_text("after\n", encoding="utf-8")

            source, report, _stage, _patch = create_verified_stage_fixture(
                root,
                {"delete.txt": "remove\n", "keep.txt": "before\n"},
                mutate,
            )
            with self.assertRaisesRegex(PolicyError, "allow-destructive"):
                apply_verified_stage(
                    report,
                    source,
                    policy=RuntimePolicy(
                        allow_writes=True,
                        approvals={STAGED_APPLY_APPROVAL},
                    ),
                )
            self.assertTrue((source / "delete.txt").exists())
            self.assertFalse((root / "delivery.apply.json").exists())

            with self.assertRaisesRegex(PolicyError, STAGED_APPLY_DELETE_APPROVAL):
                apply_verified_stage(
                    report,
                    source,
                    policy=RuntimePolicy(
                        allow_writes=True,
                        allow_destructive=True,
                        approvals={STAGED_APPLY_APPROVAL},
                    ),
                )
            result = apply_verified_stage(
                report,
                source,
                policy=RuntimePolicy(
                    allow_writes=True,
                    allow_destructive=True,
                    approvals={STAGED_APPLY_APPROVAL, STAGED_APPLY_DELETE_APPROVAL},
                ),
            )
            self.assertTrue(result["destructive"])
            self.assertFalse((source / "delete.txt").exists())
            self.assertEqual((source / "keep.txt").read_text(encoding="utf-8"), "after\n")

    def test_verified_stage_apply_recovers_an_interrupted_partial_merge(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)

            def mutate(stage):
                (stage / "a.txt").write_text("after-a\n", encoding="utf-8")
                (stage / "b.txt").write_text("after-b\n", encoding="utf-8")

            source, report, stage, _patch = create_verified_stage_fixture(
                root,
                {"a.txt": "before-a\n", "b.txt": "before-b\n"},
                mutate,
            )
            policy = RuntimePolicy(allow_writes=True, approvals={STAGED_APPLY_APPROVAL})

            def fail_after_one_file(*_args, **_kwargs):
                (source / "a.txt").write_bytes((stage / "a.txt").read_bytes())
                raise RuntimeError("simulated crash after first file")

            with patch(
                "conductor_extras.runtime.staged_apply.apply_workspace_delta_merge",
                side_effect=fail_after_one_file,
            ):
                with self.assertRaisesRegex(RuntimeError, "simulated crash"):
                    apply_verified_stage(report, source, policy=policy)

            receipt_path = root / "delivery.apply.json"
            self.assertEqual(load_staged_apply_receipt(receipt_path)["status"], "merging")
            self.assertEqual((source / "a.txt").read_text(encoding="utf-8"), "after-a\n")
            self.assertEqual((source / "b.txt").read_text(encoding="utf-8"), "before-b\n")

            result = apply_verified_stage(report, source, policy=policy)
            self.assertEqual(result["status"], "merged")
            self.assertEqual((source / "a.txt").read_text(encoding="utf-8"), "after-a\n")
            self.assertEqual((source / "b.txt").read_text(encoding="utf-8"), "after-b\n")
            self.assertTrue(apply_verified_stage(report, source)["already_applied"])

