    def test_verified_stage_apply_rejects_duplicate_json_semantic_tampering_and_path_substitution(self):
        policy = RuntimePolicy(allow_writes=True, approvals={STAGED_APPLY_APPROVAL})
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            source, report, _stage, _patch = create_verified_stage_fixture(
                root,
                {"file.txt": "before\n"},
                lambda stage: (stage / "file.txt").write_text("after\n", encoding="utf-8"),
            )
            original = report.read_text(encoding="utf-8")
            report.write_text('{"schema":"duplicate",' + original.lstrip()[1:], encoding="utf-8")
            with self.assertRaisesRegex(ValidationError, "invalid JSON"):
                apply_verified_stage(report, source, policy=policy)

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            source, report, _stage, _patch = create_verified_stage_fixture(
                root,
                {"file.txt": "before\n"},
                lambda stage: (stage / "file.txt").write_text("after\n", encoding="utf-8"),
            )
            evidence = json.loads(report.read_text(encoding="utf-8"))
            evidence["results"][0]["staged_evidence"]["policy"]["automatic_apply"] = True
            report.write_text(json.dumps(evidence), encoding="utf-8")
            with self.assertRaises(ValidationError):
                apply_verified_stage(report, source, policy=policy)

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            source, report, stage, _patch = create_verified_stage_fixture(
                root,
                {"file.txt": "before\n"},
                lambda candidate: (candidate / "file.txt").write_text("after\n", encoding="utf-8"),
            )
            substitute = root / "substitute.stage"
            shutil.copytree(stage, substitute)
            with self.assertRaisesRegex(ValidationError, "stage .*binding"):
                apply_verified_stage(
                    report,
                    source,
                    stage_dir=substitute,
                    policy=policy,
                )

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            source, report, _stage, _patch = create_verified_stage_fixture(
                root,
                {"file.txt": "before\n"},
                lambda stage: (stage / "file.txt").write_text("after\n", encoding="utf-8"),
            )
            apply_verified_stage(report, source, policy=policy)
            receipt_path = root / "delivery.apply.json"
            original = receipt_path.read_text(encoding="utf-8")
            receipt_path.write_text('{"schema":"duplicate",' + original.lstrip()[1:], encoding="utf-8")
            with self.assertRaisesRegex(ValidationError, "invalid JSON"):
                load_staged_apply_receipt(receipt_path)

        if hasattr(os, "symlink"):
            with tempfile.TemporaryDirectory() as tmp:
                root = Path(tmp)
                source, report, _stage, _patch = create_verified_stage_fixture(
                    root,
                    {"file.txt": "before\n"},
                    lambda stage: (stage / "file.txt").write_text("after\n", encoding="utf-8"),
                )
                target = root / "target.json"
                target.write_text("{}", encoding="utf-8")
                receipt_link = root / "linked-receipt.json"
                receipt_link.symlink_to(target)
                with self.assertRaisesRegex(ValidationError, "must not be a symlink"):
                    apply_verified_stage(
                        report,
                        source,
                        receipt_path=receipt_link,
                        policy=policy,
                    )

