    def test_verified_stage_apply_security_schema_and_receipt_hash_contracts(self):
        apply_assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "apply-verified-stage", "report.json"]
        )
        self.assertTrue(apply_assessment.writes)
        self.assertTrue(apply_assessment.destructive)
        self.assertFalse(apply_assessment.network)
        help_assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "apply-verified-stage", "--help"]
        )
        self.assertFalse(help_assessment.writes)
        self.assertFalse(help_assessment.destructive)
        self.assertFalse(help_assessment.network)
        validate_assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "validate-staged-apply", "receipt.json"]
        )
        self.assertFalse(validate_assessment.writes)
        self.assertFalse(validate_assessment.destructive)
        self.assertFalse(validate_assessment.network)
        self.assertIn("staged-apply", [item["name"] for item in schema_types()])
        schema = get_schema("staged-apply")
        self.assertEqual(
            schema["$id"],
            "https://codex-conductor.local/schemas/conductor.staged_apply.v1.schema.json",
        )
        for field in ("added", "modified", "deleted"):
            self.assertEqual(schema["properties"][field]["maxItems"], MAX_STAGED_CHANGES)
        for field in ("source_excluded_directories", "stage_excluded_directories"):
            self.assertEqual(schema["properties"][field]["maxItems"], MAX_STAGED_FILES)
        for field in ("stage_directory_name", "patch_name"):
            self.assertEqual(schema["properties"][field]["not"], {"enum": [".", ".."]})

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            source, report, _stage, _patch = create_verified_stage_fixture(
                root,
                {"file.txt": "before\n"},
                lambda stage: (stage / "file.txt").write_text("after\n", encoding="utf-8"),
            )
            apply_verified_stage(
                report,
                source,
                policy=RuntimePolicy(allow_writes=True, approvals={STAGED_APPLY_APPROVAL}),
            )
            receipt = load_staged_apply_receipt(root / "delivery.apply.json")
            self.assertEqual(receipt["receipt_sha256"], staged_apply_receipt_sha256(receipt))
            for invalid_name in (".", "..", "stage\rname", "stage\nname"):
                tampered = dict(receipt)
                tampered["stage_directory_name"] = invalid_name
                tampered["receipt_sha256"] = staged_apply_receipt_sha256(tampered)
                with self.assertRaises(ValidationError):
                    validate_staged_apply_receipt(tampered)

    def test_small_workspace_context_packet_is_complete_bounded_and_secret_safe(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            safe = root / "safe"
            (safe / "nested").mkdir(parents=True)
            (safe / "b.txt").write_text("second\n", encoding="utf-8")
            (safe / "nested" / "a.py").write_text("value = 1\n", encoding="utf-8")
            snapshot = snapshot_workspace(safe)
            packet = build_small_workspace_context_packet(safe, snapshot)
            self.assertIsNotNone(packet)
            parsed = json.loads(packet)
            self.assertEqual(parsed["schema"], SMALL_WORKSPACE_CONTEXT_SCHEMA)
            self.assertNotIn("workspace_sha256", parsed)
            self.assertNotIn("file_count", parsed)
            self.assertNotIn("total_bytes", parsed)
            self.assertEqual([item["path"] for item in parsed["files"]], ["b.txt", "nested/a.py"])
            self.assertEqual(parsed["files"][1]["content"], "value = 1\n")
            self.assertNotIn("sha256", parsed["files"][0])
            self.assertEqual(
                packet,
                json.dumps(parsed, sort_keys=True, separators=(",", ":"), ensure_ascii=True),
            )
            block = render_small_workspace_context_block(packet)
            self.assertEqual(block.count(SMALL_WORKSPACE_CONTEXT_BEGIN), 1)
            self.assertEqual(block.count(SMALL_WORKSPACE_CONTEXT_END), 1)
            self.assertIn("untrusted repository data", block)
            self.assertIn("do not narrate, list, search, or reread", block)
            self.assertEqual(render_small_workspace_context_block(None), "")

            self.assertIsNone(build_small_workspace_context_packet(safe, snapshot, max_files=1))
            self.assertIsNone(build_small_workspace_context_packet(safe, snapshot, max_bytes=1))
            self.assertIsNone(
                build_small_workspace_context_packet(
                    safe,
                    snapshot,
                    max_bytes=snapshot.total_bytes,
                )
            )
            (safe / "b.txt").write_text("changed\n", encoding="utf-8")
            with self.assertRaisesRegex(ValidationError, "changed after workspace snapshot"):
                build_small_workspace_context_packet(safe, snapshot)

            denied = root / "denied"
            denied.mkdir()
            (denied / ".env.example").write_text("placeholder\n", encoding="utf-8")
            self.assertIsNone(
                build_small_workspace_context_packet(denied, snapshot_workspace(denied))
            )
            secret = root / "secret"
            secret.mkdir()
            (secret / "config.txt").write_text(
                "api_key = should-not-enter-a-provider-prompt\n",
                encoding="utf-8",
            )
            self.assertIsNone(
                build_small_workspace_context_packet(secret, snapshot_workspace(secret))
            )
            binary = root / "binary"
            binary.mkdir()
            (binary / "data.bin").write_bytes(b"\xff\x00")
            self.assertIsNone(
                build_small_workspace_context_packet(binary, snapshot_workspace(binary))
            )

    def test_staged_workspace_copy_diff_and_unsupported_changes(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            source = root / "source"
            source.mkdir()
            (source / "keep.txt").write_text("before\n", encoding="utf-8")
            (source / "delete.txt").write_text("delete\n", encoding="utf-8")
            (source / ".git").mkdir()
            (source / ".git" / "config").write_text("ignored\n", encoding="utf-8")
            stage = root / "stage"
            before = copy_workspace_to_stage(source, stage)
            self.assertFalse((stage / ".git").exists())
            self.assertIn(".git", before.excluded_directories)

            (stage / "keep.txt").write_text("after\n", encoding="utf-8")
            (stage / "delete.txt").unlink()
            (stage / "added.txt").write_text("added\n", encoding="utf-8")
            after = snapshot_workspace(stage)
            changes = build_workspace_patch(source, before, stage, after)
            self.assertEqual(changes["added"], ["added.txt"])
            self.assertEqual(changes["modified"], ["keep.txt"])
            self.assertEqual(changes["deleted"], ["delete.txt"])
            self.assertIn("--- a/keep.txt", changes["patch_text"])
            self.assertEqual((source / "keep.txt").read_text(encoding="utf-8"), "before\n")
            git_tool = shutil.which("git")
            if git_tool:
                patch_file = root / "roundtrip.patch"
                patch_file.write_text(changes["patch_text"], encoding="utf-8")
                target = root / "target"
                shutil.copytree(source, target)
                shutil.rmtree(target / ".git")
                applied = subprocess.run(
                    [git_tool, "apply", str(patch_file)],
                    cwd=target,
                    text=True,
                    capture_output=True,
                )
                self.assertEqual(applied.returncode, 0, applied.stdout + applied.stderr)
                self.assertEqual((target / "keep.txt").read_text(encoding="utf-8"), "after\n")
                self.assertEqual((target / "added.txt").read_text(encoding="utf-8"), "added\n")
                self.assertFalse((target / "delete.txt").exists())

            (stage / "binary.bin").write_bytes(b"\x00binary")
            (stage / "empty.txt").write_text("", encoding="utf-8")
            mode_path = stage / "keep.txt"
            mode_path.chmod(0o700)
            unsupported = build_workspace_patch(source, before, stage, snapshot_workspace(stage))
            self.assertIn("binary.bin", unsupported["binary"])
            self.assertEqual(unsupported["unpatchable"], [])
            self.assertIn("new file mode 100644", unsupported["patch_text"])
            self.assertIn("keep.txt", unsupported["mode_changed"])

            linked_source = root / "linked-source"
            linked_source.mkdir()
            try:
                (linked_source / "link").symlink_to(source / "keep.txt")
            except OSError:
                pass
            else:
                with self.assertRaisesRegex(ValidationError, "must not contain symlinks"):
                    copy_workspace_to_stage(linked_source, root / "linked-stage")
            source_alias = root / "source-alias"
            try:
                source_alias.symlink_to(source, target_is_directory=True)
            except OSError:
                pass
            else:
                with self.assertRaisesRegex(ValidationError, "must not be a symlink"):
                    copy_workspace_to_stage(source_alias, root / "alias-stage")

    def test_claude_staged_task_pins_sonnet_and_emits_verified_external_patch(self):
        fixtures = parity_tasks_fixture()
        fixtures["tasks"][0]["tags"].append("test-authoring")
