            self.assertFalse(staged["policy"]["automatic_apply"])
            self.assertEqual(source_file.read_text(encoding="utf-8"), "before\n")
            self.assertIn("-before", patch_path.read_text(encoding="utf-8"))
            self.assertIn("+after", patch_path.read_text(encoding="utf-8"))
            self.assertNotIn("ephemeral-staged-approval", json.dumps(report))

            command, provider_kwargs = calls[0]
            self.assertEqual(command[command.index("--model") + 1], "sonnet")
            self.assertEqual(command[command.index("--effort") + 1], "ultracode")
            self.assertEqual(command[command.index("--permission-mode") + 1], "acceptEdits")
            self.assertEqual(command[command.index("--tools") + 1], "Read,Glob,Grep,Edit,Write")
            self.assertNotIn("Bash", command)
