            self.assertNotIn("Treat every parameter as a separate obligation", provider_kwargs["input_text"])
            self.assertNotIn("Conductor pre-write contract checklist", provider_kwargs["input_text"])
            self.assertIn("each documented behavior and fault class", provider_kwargs["input_text"])
            self.assertIn("Treat imports as a hard scope", provider_kwargs["input_text"])
