    def test_parity_campaign_trial_runner_refuses_unknown_interrupted_launch(self):
        fixtures_path = Path("benchmark-suites/implementation-canary-tasks.json")
        fixtures = load_parity_tasks(fixtures_path)
        policy = RuntimePolicy(
            allow_agent=True,
            allow_network=True,
            allow_writes=True,
            approvals={
                PARITY_CAMPAIGN_TRIAL_APPROVAL,
                CLAUDE_PAID_RUN_APPROVAL,
                CLAUDE_STAGED_WRITE_APPROVAL,
                CODEX_LIVE_RUN_APPROVAL,
                CODEX_STAGED_WRITE_APPROVAL,
            },
        )
        with tempfile.TemporaryDirectory(prefix="campaign-interrupted-") as tmp:
            root = Path(tmp)
            campaign_path = root / "campaign.json"
            campaign = build_parity_campaign(
                fixtures,
                run_id="campaign-interrupted-unit",
                seed=73,
                repetitions=1,
                artifacts_dir=str(root / "trials"),
                codex_model="gpt-5.6-sol",
            )
            write_parity_campaign(campaign, campaign_path)
            trial = next(item for item in campaign["trials"] if item["system_order"][0] == "codex")

            with patch("conductor_extras.runtime.parity_campaign_run.shutil.which", return_value="/fake/tool"), patch(
                "conductor_extras.runtime.parity_campaign_run.run_codex_staged_task",
                side_effect=StepExecutionError("simulated interrupted launch"),
            ):
                with self.assertRaisesRegex(StepExecutionError, "simulated interrupted launch"):
                    run_parity_campaign_trial(
                        campaign_path=campaign_path,
                        parity_tasks_path=fixtures_path,
                        trial_id=trial["id"],
                        policy=policy,
                    )

            trial_root = Path(trial["artifacts"]["codex"]["report"]).parent
            receipt_path = trial_root / "trial-run.json"
            receipt_text = receipt_path.read_text(encoding="utf-8")
            receipt = json.loads(receipt_text)
            self.assertEqual(receipt["systems"]["codex"]["launch_state"], "launching")
            receipt_path.write_text(
                receipt_text.replace('"status": "active"', '"status": "active", "status": "active"', 1),
                encoding="utf-8",
            )
            with patch("conductor_extras.runtime.parity_campaign_run.shutil.which", return_value="/fake/tool"):
                with self.assertRaisesRegex(ValidationError, "not valid JSON"):
                    run_parity_campaign_trial(
                        campaign_path=campaign_path,
                        parity_tasks_path=fixtures_path,
                        trial_id=trial["id"],
                        policy=policy,
                        resume=True,
                    )
            receipt_path.write_text(receipt_text, encoding="utf-8")
            with patch("conductor_extras.runtime.parity_campaign_run.shutil.which", return_value="/fake/tool"), patch(
                "conductor_extras.runtime.parity_campaign_run.run_codex_staged_task"
            ) as rerun:
                with self.assertRaisesRegex(ValidationError, "refusing an automatic rerun"):
                    run_parity_campaign_trial(
                        campaign_path=campaign_path,
                        parity_tasks_path=fixtures_path,
                        trial_id=trial["id"],
                        policy=policy,
                        resume=True,
                    )
            rerun.assert_not_called()

    def test_live_parity_runbook_builder_generates_instruction_only_runbook(self):
        fixtures = parity_tasks_fixture()
        runbook = build_live_parity_runbook(
            fixtures,
            run_id="unit-live-parity",
            report_dir=".runtime-state/benchmarks/unit",
            workflow_dir=".runtime-state/generated/unit",
        )
        validate_live_parity_runbook(runbook)
        self.assertEqual(runbook["schema"], LIVE_PARITY_RUNBOOK_SCHEMA)
        self.assertEqual(runbook["evidence_status"], "planned-not-evidence")
        self.assertFalse(runbook["claim_gate"]["eligible_for_parity_claims"])
        self.assertIn("--require-claim-eligible", runbook["claim_gate"]["claim_check_command"])
        self.assertEqual(runbook["aggregate_budget"]["max_minutes"], 5)
        self.assertEqual(runbook["aggregate_budget"]["max_agents"], 2)
        self.assertEqual(runbook["aggregate_budget"]["max_live_tool_cost"], "low")
        self.assertEqual(runbook["aggregate_budget"]["max_cost_usd"], 1.5)
        self.assertEqual(runbook["aggregate_budget"]["max_tokens"], 1000)
        self.assertTrue(any("cap enforcement" in item for item in runbook["claim_gate"]["required_before_claim"]))
        self.assertTrue(any("independent quality" in item for item in runbook["claim_gate"]["required_before_claim"]))
        systems = {system["name"]: system for system in runbook["systems"]}
        self.assertTrue(systems["conductor"]["requires_external_tool"])
        self.assertTrue(systems["conductor"]["requires_paid_approval"])
        conductor_invocations = systems["conductor"]["invocation_templates"]
        self.assertEqual(len(conductor_invocations), 5)
        strict_codex_argv = conductor_invocations[0]["argv_template"]
        self.assertIn("run-codex-readonly-task", strict_codex_argv)
        self.assertIn("codex-live-run", strict_codex_argv)
        self.assertIn("--max-tokens", strict_codex_argv)
        staged_codex_argv = conductor_invocations[1]["argv_template"]
        self.assertIn("run-codex-staged-task", staged_codex_argv)
        self.assertIn("--check-command-json", staged_codex_argv)
        self.assertIn("--allow-writes", staged_codex_argv)
        self.assertIn("codex-live-run", staged_codex_argv)
        self.assertIn("codex-staged-write", staged_codex_argv)
        repair_codex_argv = conductor_invocations[2]["argv_template"]
        self.assertIn("run-codex-staged-repair", repair_codex_argv)
        self.assertIn("--max-attempts", repair_codex_argv)
        self.assertIn("--max-tokens-per-attempt", repair_codex_argv)
        self.assertIn("codex-staged-write", repair_codex_argv)
        self.assertIn("plan-model-workflow", conductor_invocations[3]["argv_template"])
        self.assertIn("--allow-agent", conductor_invocations[3]["argv_template"])
        conductor_argv = conductor_invocations[3]["argv_template"]
        self.assertEqual(conductor_argv[conductor_argv.index("--planner-effort") + 1], "high")
        self.assertEqual(systems["conductor"]["model_manifest_template"]["effort"], "high")
        self.assertTrue(conductor_invocations[3]["launches_external_tools"])
        self.assertIn("plan-workflow", conductor_invocations[4]["argv_template"])
        self.assertFalse(conductor_invocations[4]["launches_external_tools"])
        self.assertTrue(systems["claude"]["requires_paid_approval"])
        self.assertTrue(systems["claude"]["invocation_templates"][0]["launches_external_tools"])
        self.assertEqual(len(systems["claude"]["invocation_templates"]), 2)
        strict_claude_argv = systems["claude"]["invocation_templates"][0]["argv_template"]
        self.assertIn("run-claude-readonly-task", strict_claude_argv)
        self.assertIn("claude-paid-run", strict_claude_argv)
        claude_argv = systems["claude"]["invocation_templates"][1]["argv_template"]
        self.assertIn("run-claude-staged-task", claude_argv)
        self.assertIn("--check-command-json", claude_argv)
        self.assertIn("--allow-writes", claude_argv)
        self.assertIn("claude-paid-run", claude_argv)
        self.assertIn("claude-staged-write", claude_argv)
        self.assertNotIn("<task.prompt_path>", claude_argv)
        self.assertEqual(systems["claude"]["model_manifest_template"]["name"], "sonnet")
        self.assertTrue(systems["claude"]["permissions_template"]["allow_network"])
        self.assertFalse(systems["claude"]["permissions_template"]["allow_parallel"])
        task = runbook["tasks"][0]
        self.assertEqual(task["scorecard_template"]["score"], None)
        self.assertEqual(set(task["system_artifacts"]), {"conductor", "claude"})
        self.assertTrue(task["system_artifacts"]["conductor"]["workflow_receipt_path"].endswith(".receipt.json"))
        self.assertTrue(
            task["system_artifacts"]["conductor"]["deterministic_workflow_path"].endswith(".deterministic.json")
        )
        self.assertTrue(task["system_artifacts"]["conductor"]["readonly_report_path"].endswith(".readonly.json"))
        self.assertTrue(task["system_artifacts"]["conductor"]["staged_report_path"].endswith(".staged.json"))
        self.assertTrue(task["system_artifacts"]["conductor"]["patch_path"].endswith(".patch"))
        self.assertIn("/repairs/conductor/", task["system_artifacts"]["conductor"]["repair_dir"])
        self.assertTrue(task["system_artifacts"]["claude"]["patch_path"].endswith(".patch"))
        self.assertTrue(task["system_artifacts"]["claude"]["staged_report_path"].endswith(".staged.json"))
        self.assertIn("template-not-run", json.dumps(runbook))

