    def test_live_parity_runbook_command_policy_classification(self):
        plan = assess_command(
            [
                "python3",
                "-B",
                "-m",
                "conductor_extras",
                "plan-live-parity-runbook",
                "benchmark-suites/parity-tasks.json",
            ]
        )
        self.assertFalse(plan.writes)
        self.assertFalse(plan.network)
        self.assertFalse(plan.destructive)

        validate = assess_command(
            [
                "python3",
                "-B",
                "-m",
                "conductor_extras",
                "validate-live-parity-runbook",
                "runbook.json",
            ]
        )
        self.assertFalse(validate.writes)
        self.assertFalse(validate.network)
        self.assertFalse(validate.destructive)

        write = assess_command(
            [
                "python3",
                "-B",
                "-m",
                "conductor_extras",
                "write-live-parity-runbook",
                "benchmark-suites/parity-tasks.json",
                ".runtime-state/benchmarks/runbook.json",
            ]
        )
        self.assertTrue(write.writes)
        self.assertFalse(write.network)
        self.assertFalse(write.destructive)

    def test_parity_task_validation_rejects_invalid_shapes(self):
        fixtures = {
            "schema": "conductor.parity_tasks.v1",
            "name": "bad-fixtures",
            "tasks": [
                {
                    "id": "task-a",
                    "dimension": "dimension",
                    "prompt": "prompt",
                    "scoring": "scoring",
                    "success_criteria": [],
                    "required_evidence": ["evidence"],
                    "budget": {"max_minutes": 1, "max_agents": 1, "max_live_tool_cost": "low"},
                }
            ],
        }
        with self.assertRaises(ValidationError):
            validate_parity_tasks(fixtures)

        fixtures["tasks"][0]["budget"] = {"max_minutes": 1, "max_agents": 1, "max_live_tool_cost": "low"}
        fixtures["unexpected"] = "field"
        with self.assertRaises(ValidationError) as caught:
            validate_parity_tasks(fixtures)
        self.assertIn("unsupported fields", str(caught.exception))
        fixtures.pop("unexpected")

        fixtures["tasks"][0]["succcess_criteria"] = ["typo"]
        with self.assertRaises(ValidationError) as caught:
            validate_parity_tasks(fixtures)
        self.assertIn("unsupported fields", str(caught.exception))
        fixtures["tasks"][0].pop("succcess_criteria")
        fixtures["tasks"][0]["success_criteria"] = ["criterion"]

        fixtures["tasks"][0]["budget"]["unexpected"] = 1
        with self.assertRaises(ValidationError) as caught:
            validate_parity_tasks(fixtures)
        self.assertIn("unsupported fields", str(caught.exception))
        fixtures["tasks"][0]["budget"] = {"max_minutes": 0}
        with self.assertRaises(ValidationError):
            validate_parity_tasks(fixtures)
        fixtures["tasks"][0]["budget"] = {"max_minutes": 1, "max_agents": "many", "max_live_tool_cost": "low"}
        with self.assertRaises(ValidationError):
            validate_parity_tasks(fixtures)
        fixtures["tasks"][0]["budget"] = {"max_minutes": 1, "max_agents": 1, "max_live_tool_cost": "unbounded"}
        with self.assertRaises(ValidationError):
            validate_parity_tasks(fixtures)
        fixtures["tasks"][0]["budget"] = {
            "max_minutes": 1,
            "max_agents": 1,
            "max_live_tool_cost": "low",
            "max_cost_usd": -1,
        }
        with self.assertRaises(ValidationError):
            validate_parity_tasks(fixtures)
        fixtures["tasks"][0]["budget"] = {
            "max_minutes": 1,
            "max_agents": 1,
            "max_live_tool_cost": "low",
            "max_cost_usd": float("inf"),
        }
        with self.assertRaisesRegex(ValidationError, "finite number"):
            validate_parity_tasks(fixtures)

