    def test_parity_task_validation_enforces_required_dimension_coverage(self):
        fixtures = {
            "schema": "conductor.parity_tasks.v1",
            "name": "coverage-fixtures",
            "required_dimensions": ["dimension-a", "dimension-b"],
            "tasks": [
                {
                    "id": "task-a",
                    "dimension": "dimension-a",
                    "tags": ["coverage"],
                    "prompt": "prompt",
                    "scoring": "scoring",
                    "success_criteria": ["criterion"],
                    "required_evidence": ["evidence"],
                    "budget": {
                        "max_minutes": 1,
                        "max_agents": 0,
                        "max_live_tool_cost": "none",
                        "max_tokens": 0,
                    },
                }
            ],
        }
        with self.assertRaises(ValidationError) as caught:
            validate_parity_tasks(fixtures)
        self.assertIn("missing required parity dimensions: dimension-b", str(caught.exception))

        fixtures["required_dimensions"] = ["dimension-a", "dimension-a"]
        with self.assertRaises(ValidationError) as caught:
            validate_parity_tasks(fixtures)
        self.assertIn("required_dimensions contains duplicates: dimension-a", str(caught.exception))

        fixtures["required_dimensions"] = ["dimension-a"]
        validate_parity_tasks(fixtures)

        fixtures["tasks"][0]["tags"] = []
        with self.assertRaises(ValidationError) as caught:
            validate_parity_tasks(fixtures)
        self.assertIn("parity task task-a tags must be a non-empty string list", str(caught.exception))

    def test_plan_workflow_cli_generates_valid_bugfix_workflow(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            output = root / "generated.json"
            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(
                    [
                        "plan-workflow",
                        "--task",
                        "Fix the failing checkout regression.",
                        "--failing-command",
                        "python3 -B -m unittest discover -s tests",
                        "--check-command",
                        "python3 -B -m unittest discover -s tests",
                        "--output",
                        str(output),
                    ]
                )
            self.assertEqual(code, 0)
            self.assertIn("Workflow draft:", stdout.getvalue())
            workflow = load_workflow(output)
            self.assertEqual(workflow["schema"], "conductor.workflow.v1")
            self.assertEqual(workflow["generated_by"]["kind"], "bugfix")
            step_ids = [step["id"] for step in workflow["steps"]]
            self.assertIn("reproduce-1", step_ids)
            self.assertIn("analyze-task", step_ids)
            self.assertIn("verify-1", step_ids)
            reproduce = next(step for step in workflow["steps"] if step["id"] == "reproduce-1")
            self.assertTrue(reproduce["writes"])

