    def test_saved_workflow_rejects_malformed_ambiguous_and_escaping_scripts(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "write",
                    "kind": "write_artifact",
                    "output": "one.txt",
                    "content": "one",
                }
            ]
        )
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workflows = root / ".claude" / "workflows"
            write_saved_workflow_script(workflows / "one.js", workflow, name="duplicate")
            write_saved_workflow_script(workflows / "two.mjs", workflow, name="duplicate")

            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(["inspect-saved-workflow", "duplicate", "--workspace", str(root)])
            self.assertEqual(code, 2)
            self.assertIn("ambiguous", stderr.getvalue())

            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(["validate-saved-workflows", "--workspace", str(root)])
            self.assertEqual(code, 2)
            self.assertIn("duplicate saved workflow command name", stderr.getvalue())

            malformed = workflows / "malformed.js"
            malformed.write_text(
                "export const meta = {\"name\":\"malformed\"};\nexport const workflow = buildWorkflow();\n",
                encoding="utf-8",
            )
            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(["inspect-saved-workflow", "malformed", "--workspace", str(root)])
            self.assertEqual(code, 2)
            self.assertIn("must start with a JSON object", stderr.getvalue())

            commented = workflows / "commented.js"
            commented.write_text(
                "/*\nexport const meta = {\"name\":\"commented\"};\nexport const workflow = %s;\n*/\n"
                % json.dumps(workflow),
                encoding="utf-8",
            )
            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(
                    ["inspect-saved-workflow", ".claude/workflows/commented.js", "--workspace", str(root)]
                )
            self.assertEqual(code, 2)
            self.assertIn("must export const meta", stderr.getvalue())

            string_fake = workflows / "string-fake.js"
            string_fake.write_text(
                "const fake = \"export const meta = {\\\"name\\\":\\\"string-fake\\\"}\";\n"
                "export const workflow = %s;\n" % json.dumps(workflow),
                encoding="utf-8",
            )
            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(
                    ["inspect-saved-workflow", ".claude/workflows/string-fake.js", "--workspace", str(root)]
                )
            self.assertEqual(code, 2)
            self.assertIn("must export const meta", stderr.getvalue())

            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(["inspect-saved-workflow", "../outside-workflow.js", "--workspace", str(root)])
            self.assertEqual(code, 2)
            self.assertIn("must be relative", stderr.getvalue())

            try:
                link = workflows / "linked.js"
                link.symlink_to(workflows / "one.js")
            except OSError:
                return
            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(["list-saved-workflows", "--workspace", str(root)])
            self.assertEqual(code, 0)
            self.assertIn("INVALID:", stdout.getvalue())
            self.assertIn("must not be a symlink", stdout.getvalue())

