    def test_saved_workflow_read_rejects_parent_swap_after_validation(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "write",
                    "kind": "write_artifact",
                    "output": "one.txt",
                    "content": "one",
                }
            ]
        )
        with tempfile.TemporaryDirectory() as tmp:
            import conductor_extras.runtime.saved_workflows as saved_workflows_module

            root = Path(tmp)
            claude_dir = root / ".claude"
            script = claude_dir / "workflows" / "read-race.js"
            write_saved_workflow_script(script, workflow, name="read-race")
            outside_claude = root / "outside-claude"
            write_saved_workflow_script(
                outside_claude / "workflows" / "read-race.js",
                workflow,
                name="read-race",
                description="outside workflow should not be read",
            )
            backup_claude = root / ".claude-backup"
            original_reject = saved_workflows_module.reject_symlink_path
            saved_workflow_checks = {"count": 0}

            def swapping_reject(path, label):
                original_reject(path, label)
                if label == "saved workflow" and Path(path).name == "read-race.js":
                    saved_workflow_checks["count"] += 1
                    if saved_workflow_checks["count"] == 3:
                        claude_dir.rename(backup_claude)
                        claude_dir.symlink_to(outside_claude, target_is_directory=True)

            stderr = StringIO()
            with patch("conductor_extras.runtime.saved_workflows.reject_symlink_path", side_effect=swapping_reject):
                with redirect_stderr(stderr):
                    code = cli_main(["inspect-saved-workflow", "read-race", "--workspace", str(root)])
            self.assertEqual(code, 2)
            self.assertIn("failed to open saved workflow parent", stderr.getvalue())
            self.assertNotIn("outside workflow should not be read", stderr.getvalue())

    def test_saved_workflow_read_only_cli_commands_are_classified_read_only(self):
        validate_assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "validate-saved-workflows"]
        )
        list_assessment = assess_command(["python3", "-B", "-m", "conductor_extras", "list-saved-workflows"])
        list_runs_assessment = assess_command(["python3", "-B", "-m", "conductor_extras", "list-runs"])
        inspect_assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "inspect-saved-workflow", "saved-smoke"]
        )
        export_assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "export-saved-workflow", "saved-smoke", "out.json"]
        )
        personal_list_assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "list-saved-workflows", "--include-personal"]
        )
        personal_export_assessment = assess_command(
            [
                "python3",
                "-B",
                "-m",
                "conductor_extras",
                "export-saved-workflow",
                "saved-smoke",
                "out.json",
                "--include-personal",
            ]
        )
        dry_run_assessment = assess_command(
            [
                "python3",
                "-B",
                "-m",
                "conductor_extras",
                "run-saved-workflow",
                "saved-smoke",
                "--dry-run",
            ]
        )
        self.assertFalse(validate_assessment.writes)
        self.assertFalse(list_assessment.writes)
        self.assertFalse(list_runs_assessment.writes)
        self.assertFalse(inspect_assessment.writes)
        self.assertTrue(export_assessment.writes)
        self.assertFalse(export_assessment.destructive)
        self.assertFalse(export_assessment.network)
        self.assertFalse(personal_list_assessment.writes)
        self.assertTrue(personal_list_assessment.external_path)
        self.assertTrue(personal_export_assessment.writes)
        self.assertTrue(personal_export_assessment.external_path)
        self.assertFalse(personal_export_assessment.destructive)
        self.assertFalse(personal_export_assessment.network)
        self.assertTrue(dry_run_assessment.writes)
        self.assertFalse(dry_run_assessment.destructive)
        self.assertFalse(dry_run_assessment.network)

    def test_saved_workflow_args_render_then_revalidate(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "write",
                    "kind": "write_artifact",
                    "output": "rendered/{{args.file}}.txt",
                    "content": "Hello {{args.name}}.",
                }
            ]
        )
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            script = root / ".claude" / "workflows" / "arg-smoke.js"
            write_saved_workflow_script(script, workflow, name="arg-smoke")

            export_path = root / "rendered-workflow.json"
            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(
                    [
                        "export-saved-workflow",
                        "arg-smoke",
                        str(export_path),
                        "--workspace",
                        str(root),
                        "--arg",
                        "file=greeting",
                        "--arg",
                        "name=Conductor",
                    ]
                )
            self.assertEqual(code, 0)
            exported = load_workflow(export_path)
            self.assertEqual(exported["steps"][0]["output"], "rendered/greeting.txt")
            self.assertEqual(exported["steps"][0]["content"], "Hello Conductor.")

            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(
                    [
                        "run-saved-workflow",
                        "arg-smoke",
                        "--workspace",
                        str(root),
                        "--runs-dir",
                        str(root / "runs"),
                        "--run-id",
                        "arg-run",
                        "--arg",
                        "file=greeting",
                        "--arg",
                        "name=Conductor",
                    ]
                )
            self.assertEqual(code, 0)
            artifact = root / "runs" / "arg-run" / "artifacts" / "rendered" / "greeting.txt"
            self.assertEqual(artifact.read_text(encoding="utf-8"), "Hello Conductor.")

            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(
                    [
                        "run-saved-workflow",
                        "arg-smoke",
                        "--workspace",
                        str(root),
                        "--runs-dir",
                        str(root / "runs"),
                        "--run-id",
                        "arg-missing",
                        "--arg",
                        "file=greeting",
                    ]
                )
            self.assertEqual(code, 2)
            self.assertIn("requires missing arg(s): name", stderr.getvalue())

            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(
                    [
                        "export-saved-workflow",
                        "arg-smoke",
                        str(root / "bad-rendered.json"),
                        "--workspace",
                        str(root),
                        "--arg",
                        "file=../escape",
                        "--arg",
                        "name=Conductor",
                    ]
                )
            self.assertEqual(code, 2)
            self.assertIn("must be relative", stderr.getvalue())

            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(
                    [
                        "inspect-saved-workflow",
                        "arg-smoke",
                        "--workspace",
                        str(root),
                        "--arg",
                        "file=greeting",
                        "--arg",
                        "name=token=argsecret",
                    ]
            )
            self.assertEqual(code, 2)
            self.assertIn("must not contain secret-like values", stderr.getvalue())
            self.assertNotIn("argsecret", stderr.getvalue())

