    def test_plan_workflow_write_capable_adds_manual_gate(self):
        workflow = build_workflow_plan(
            task="Implement a small report renderer.",
            kind="implementation",
            write_capable=True,
            check_commands=["python3 -B -m unittest discover -s tests"],
        )
        validate_workflow(workflow)
        step_map = {step["id"]: step for step in workflow["steps"]}
        self.assertEqual(step_map["implementation-gate"]["kind"], "manual_gate")
        self.assertEqual(step_map["implementation-gate"]["approval_id"], "implement-generated-workflow")
        self.assertEqual(step_map["implement-with-codex"]["sandbox"], "workspace-write")
        self.assertEqual(workflow["agent_effort"], "high")
        self.assertEqual(workflow["agent_max_tokens"], 12000)
        self.assertEqual(step_map["implement-with-codex"]["max_tokens"], 24000)
        self.assertIn("implementation-gate", step_map["implement-with-codex"]["depends_on"])
        self.assertIn("implement-with-codex", step_map["verify-1"]["depends_on"])

    def test_plan_workflow_ultracode_profile_generates_multi_phase_auto_packet_workflow(self):
        workflow = build_workflow_plan(
            task="Fix the checkout regression and verify the runtime.",
            profile="ultracode",
            write_capable=True,
            check_commands=["true"],
            max_workers=3,
        )
        validate_workflow(workflow)
        step_map = {step["id"]: step for step in workflow["steps"]}
        self.assertEqual(workflow["generated_by"]["profile"], "ultracode")
        self.assertTrue(workflow["generated_by"]["auto_packet_source"])
        self.assertTrue(workflow["generated_by"]["packetized"])
        self.assertEqual(step_map["workflow-charter"]["phase"], "intake")
        self.assertEqual(step_map["risk-register"]["depends_on"], ["workflow-charter"])
        self.assertEqual(step_map["context-map"]["depends_on"], ["collect-files"])
        self.assertEqual(step_map["context-map"]["context_from"], ["collect-files"])
        self.assertEqual(step_map["analyze-task"]["context_from"], ["context-map"])
        packet = step_map["packet-review"]
        self.assertEqual(packet["items_artifact"], "context/repo-files.txt")
        self.assertEqual(packet["max_workers"], 3)
        self.assertEqual(packet["max_items"], MAX_PACKET_ITEMS)
        self.assertEqual(packet["effort"], "medium")
        self.assertEqual(packet["max_tokens"], 4000)
        self.assertEqual(packet["max_total_tokens"], 100000)
        self.assertEqual(packet["max_packets"], BALANCED_AGENT_MAP_MAX_PACKETS)
        self.assertEqual(workflow["generated_by"]["agent_budget_profile"], "balanced-v2")
        self.assertEqual(
            step_map["synthesize-findings"]["depends_on"],
            ["packet-review", "analyze-task"],
        )
        self.assertEqual(
            step_map["synthesize-findings"]["context_from"],
            ["packet-review", "analyze-task"],
        )
        self.assertIn(
            "share one first faulty executable line or one repair site",
            step_map["synthesize-findings"]["prompt"],
        )
        self.assertIn("synthesize-findings", step_map["implement-with-codex"]["depends_on"])
        self.assertEqual(step_map["implement-with-codex"]["context_from"], ["synthesize-findings"])
        self.assertEqual(
            step_map["final-review"]["depends_on"],
            ["verify-1", "synthesize-findings", "implement-with-codex"],
        )
        self.assertEqual(
            step_map["final-review"]["context_from"],
            ["synthesize-findings", "implement-with-codex", "verify-1"],
        )
        self.assertEqual(step_map["final-review"]["completion_verdict"], "strict-v1")
        phases = {step.get("phase") for step in workflow["steps"]}
        self.assertGreaterEqual(
            phases,
            {"intake", "context", "analysis", "review", "integration", "implementation", "verification", "final-review"},
        )

