    def test_plan_workflow_cli_writes_saved_workflow_command(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            saved_output = root / ".claude" / "workflows" / "generated-review.js"
            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(
                    [
                        "plan-workflow",
                        "--task",
                        "Review runtime files.",
                        "--packet-item",
                        "conductor_extras/runtime/planner.py",
                        "--check-command",
                        "true",
                        "--saved-command",
                        "generated-review",
                        "--saved-output",
                        str(saved_output),
                    ]
                )
            self.assertEqual(code, 0)
            self.assertIn("Saved workflow command:", stdout.getvalue())
            text = saved_output.read_text(encoding="utf-8")
            self.assertIn("export const meta =", text)
            self.assertIn("export const workflow =", text)
            self.assertNotIn("agent(", text)
            self.assertNotIn("pipeline(", text)

            saved = load_saved_workflow(saved_output, workspace=root)
            self.assertEqual(saved.command_name, "generated-review")
            self.assertEqual(saved.workflow["generated_by"]["tool"], "conductor_extras plan-workflow")
            packet = next(step for step in saved.workflow["steps"] if step["id"] == "packet-review")
            self.assertEqual(packet["items"], ["conductor_extras/runtime/planner.py"])

            with redirect_stdout(StringIO()):
                code = cli_main(["validate-saved-workflows", "generated-review", "--workspace", str(root)])
            self.assertEqual(code, 0)

            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(
                    [
                        "run-saved-workflow",
                        "generated-review",
                        "--workspace",
                        str(root),
                        "--runs-dir",
                        str(root / "runs"),
                        "--run-id",
                        "blocked-without-agent",
                        "--dry-run",
                    ]
            )
            self.assertEqual(code, 2)
            self.assertIn("requires --allow-agent", stderr.getvalue())

            with redirect_stdout(StringIO()):
                code = cli_main(
                    [
                        "run-saved-workflow",
                        "generated-review",
                        "--workspace",
                        str(root),
                        "--runs-dir",
                        str(root / "runs"),
                        "--run-id",
                        "saved-dry-run",
                        "--dry-run",
                        "--allow-agent",
                        "--allow-parallel",
                    ]
                )
            self.assertEqual(code, 0)
            state = json.loads((root / "runs" / "saved-dry-run" / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["status"], "planned")
            self.assertTrue(state["workflow_source"].endswith(".claude/workflows/generated-review.js"))

