            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(
                    [
                        "plan-workflow",
                        "--task",
                        "Review runtime files.",
                        "--saved-output",
                        str(root / "missing-command.js"),
                    ]
                )
