            self.assertIn("--saved-output requires --saved-command", stderr.getvalue())

            previous = os.getcwd()
            try:
                os.chdir(root)
                stderr = StringIO()
                with redirect_stderr(stderr):
                    code = cli_main(
                        [
                            "plan-workflow",
                            "--task",
                            "Review runtime files.",
                            "--saved-command",
                            "../escape",
                        ]
                    )
            finally:
                os.chdir(previous)
            self.assertEqual(code, 2)
            self.assertIn("saved workflow command name must be a safe non-empty identifier", stderr.getvalue())
            self.assertFalse((root / ".claude").exists())

            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(
                    [
                        "plan-workflow",
                        "--task",
                        "Review runtime files.",
                        "--saved-command",
                        "bad-suffix",
                        "--saved-output",
                        str(root / "bad.txt"),
                    ]
                )
