    def test_plan_workflow_packet_glob_resolves_workspace_files(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            src = root / "src"
            src.mkdir()
            (src / "alpha.py").write_text("print('alpha')\n", encoding="utf-8")
            (src / "beta.py").write_text("print('beta')\n", encoding="utf-8")
            (src / "ignored.txt").write_text("ignored\n", encoding="utf-8")
            symlink_created = False
            try:
                (src / "alpha-link.py").symlink_to(src / "alpha.py")
                symlink_created = True
            except OSError:
                pass
            symlink_dir_created = False
            real_dir = root / "real-dir"
            real_dir.mkdir()
            (real_dir / "gamma.py").write_text("print('gamma')\n", encoding="utf-8")
            try:
                (src / "linked-dir").symlink_to(real_dir, target_is_directory=True)
                symlink_dir_created = True
            except OSError:
                pass

            workflow = build_workflow_plan(
                task="Review runtime files.",
                packet_globs=["src/*.py", "src/linked-dir/*.py"],
                packet_max_items=5,
                workspace=root,
            )
            validate_workflow(workflow)
            packet = next(step for step in workflow["steps"] if step["id"] == "packet-review")
            self.assertEqual(packet["items"], ["src/alpha.py", "src/beta.py"])
            if symlink_created:
                self.assertNotIn("src/alpha-link.py", packet["items"])
            if symlink_dir_created:
                self.assertNotIn("src/linked-dir/gamma.py", packet["items"])

