            self.assertIn("[task marker removed]", captured_prompts[0])
            top_level_contract = next(
                line for line in captured_prompts[0].splitlines() if line.startswith("top-level={")
            )
            self.assertNotIn("generated_by", top_level_contract)

            loaded_workflow = load_workflow(output)
