    def test_external_verifier_plan_uses_full_write_ceiling_and_stream_floor(self):
        captured_prompts = []

        def fake_model_planner(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            del cwd, timeout, output_limit_bytes
            captured_prompts.append(input_text)
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            draft = valid_model_workflow(write_capable=True)
            draft["output_limit_bytes"] = 18000
            draft["agent_profiles"] = [
                {
                    "schema": "conductor.agent_profile.v1",
                    "name": "bounded-writer",
                    "instructions": "Implement only the scoped change.",
                    "sandbox": "workspace-write",
                    "model": "planner-authored-model",
                    "effort": "medium",
                    "max_tokens": 7000,
                }
            ]
            implement = next(step for step in draft["steps"] if step["id"] == "implement")
            implement["agent_profile"] = "bounded-writer"
            implement["prompt"] = "Implement the scoped repair, then run visible tests."
            implement["model"] = "planner-authored-model"
            implement["effort"] = "medium"
            implement["max_tokens"] = 7000
            implement["output_limit_bytes"] = 18000
            output_path.write_text(json.dumps(draft), encoding="utf-8")
            return ProcessResult(
                0,
                json.dumps({"type": "turn.completed"}) + "\n",
                "",
            )

        policy = RuntimePolicy(
            allow_agent=True,
            allow_writes=True,
            approvals={MODEL_WORKFLOW_WRITE_APPROVAL},
        )
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            with patch(
                "conductor_extras.runtime.model_planner.run_process",
                side_effect=fake_model_planner,
            ):
                external = plan_model_workflow(
                    task="Implement the bounded behavior.",
                    workspace=root,
                    output_path=root / "external.json",
                    receipt_path=None,
                    policy=policy,
                    write_capable=True,
                    external_verifier=True,
                    model="gpt-5.6-sol",
                    reasoning_effort="ultra",
                    max_workers=2,
                    max_steps=8,
                )
                ordinary = plan_model_workflow(
                    task="Implement the bounded behavior.",
                    workspace=root,
                    output_path=root / "ordinary.json",
                    receipt_path=None,
                    policy=policy,
                    write_capable=True,
                    external_verifier=False,
                    model="gpt-5.6-sol",
                    reasoning_effort="ultra",
                    max_workers=2,
                    max_steps=8,
                )

        external_step = next(
            step for step in external.workflow["steps"] if step["id"] == "implement"
        )
        ordinary_step = next(
            step for step in ordinary.workflow["steps"] if step["id"] == "implement"
        )
        self.assertEqual(
            external.workflow["output_limit_bytes"],
            MIN_MODEL_PROVIDER_OUTPUT_LIMIT_BYTES,
        )
        self.assertEqual(
            external_step["output_limit_bytes"],
            MIN_MODEL_PROVIDER_OUTPUT_LIMIT_BYTES,
        )
        self.assertEqual(external_step["max_tokens"], BALANCED_WRITE_AGENT_MAX_TOKENS)
        self.assertEqual(external.workflow["agent_effort"], "ultra")
        self.assertEqual(external_step["model"], "gpt-5.6-sol")
        self.assertEqual(external_step["effort"], "ultra")
        self.assertEqual(
            external.workflow["agent_profiles"][0]["max_tokens"],
            BALANCED_WRITE_AGENT_MAX_TOKENS,
        )
        self.assertEqual(external.workflow["agent_profiles"][0]["model"], "gpt-5.6-sol")
        self.assertEqual(external.workflow["agent_profiles"][0]["effort"], "ultra")
        self.assertIn("complete workflow for this step", external_step["prompt"])
        self.assertIn("Do not invoke, inspect, or mention external Codex skills", external_step["prompt"])
        self.assertIn("Do not run tests, language runtimes", external_step["prompt"])
        self.assertGreater(
            external_step["prompt"].rfind("Do not run tests"),
            external_step["prompt"].rfind("run visible tests"),
        )
        self.assertIn("staged write-progress checkpoint", external_step["prompt"])
        self.assertIn("Before the first write, make an internal contract checklist", external_step["prompt"])
        self.assertIn(
            "complete workflow for this step",
            external.workflow["agent_profiles"][0]["instructions"],
        )
        self.assertEqual(ordinary_step["max_tokens"], 7000)
        self.assertEqual(ordinary_step["model"], "planner-authored-model")
        self.assertEqual(ordinary_step["effort"], "medium")
        self.assertEqual(ordinary.workflow["agent_profiles"][0]["max_tokens"], 7000)
        self.assertEqual(ordinary.workflow["agent_profiles"][0]["model"], "planner-authored-model")
        self.assertEqual(ordinary.workflow["agent_profiles"][0]["effort"], "medium")
        self.assertNotIn("complete workflow for this step", ordinary_step["prompt"])
        self.assertIn("run visible tests", ordinary_step["prompt"])
        self.assertNotIn(
            "complete workflow for this step",
            ordinary.workflow["agent_profiles"][0]["instructions"],
        )
        self.assertIn(
            "Do not call any workspace-inspection tool while authoring this graph",
            captured_prompts[0],
        )
        self.assertNotIn(
            "Use no more than two combined read-only workspace-inspection tool calls",
            captured_prompts[0],
        )
        self.assertIn(
            "Use no more than two combined read-only workspace-inspection tool calls",
            captured_prompts[1],
        )

    def test_plan_model_workflow_resumes_only_the_bound_codex_session(self):
        commands = []

        def planner_with_session(session_id):
            def fake(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
                commands.append(list(argv))
                output_path = Path(argv[argv.index("--output-last-message") + 1])
                output_path.write_text(json.dumps(valid_model_workflow()), encoding="utf-8")
                return ProcessResult(
                    0,
                    "\n".join(
                        [
                            json.dumps({"type": "thread.started", "thread_id": session_id}),
                            json.dumps({"type": "turn.completed"}),
                        ]
                    )
                    + "\n",
                    "",
                )

            return fake

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            policy = RuntimePolicy(allow_agent=True)
            with patch(
                "conductor_extras.runtime.model_planner.run_process",
                side_effect=planner_with_session(FAKE_CODEX_SESSION_ID),
            ):
                first = plan_model_workflow(
                    task="Inspect the current workspace.",
                    workspace=root,
                    output_path=root / "first.json",
                    receipt_path=None,
                    policy=policy,
                    max_workers=2,
                    max_items=100,
                    max_steps=8,
                )
                second = plan_model_workflow(
                    task="Continue from the prior planner turn.",
                    workspace=root,
                    output_path=root / "second.json",
                    receipt_path=None,
                    policy=policy,
                    max_workers=2,
                    max_items=100,
                    max_steps=8,
                    model="codex-test-model",
                    reasoning_effort="ultra",
                    planner_session_id=FAKE_CODEX_SESSION_ID,
                )

            self.assertEqual(first.planner_session_id, FAKE_CODEX_SESSION_ID)
            self.assertFalse(first.planner_session_resumed)
            self.assertEqual(second.planner_session_id, FAKE_CODEX_SESSION_ID)
            self.assertTrue(second.planner_session_resumed)
            self.assertEqual(commands[0][:2], ["codex", "exec"])
            self.assertNotEqual(commands[0][2], "resume")
            self.assertEqual(commands[1][:3], ["codex", "exec", "resume"])
            self.assertEqual(commands[1][3:5], ["--model", "codex-test-model"])
            self.assertIn(FAKE_CODEX_SESSION_ID, commands[1])
            self.assertIn('sandbox_mode="read-only"', commands[1])
            self.assertTrue(any("limit_tokens=20000" in value for value in commands[1]))
            self.assertIn(["--disable", "code_mode_host"], [commands[1][index : index + 2] for index in range(len(commands[1]) - 1)])
            self.assertNotIn("--sandbox", commands[1])
            self.assertNotIn("--cd", commands[1])

            other_session = "019f0000-0000-7000-8000-000000000002"
            with patch(
                "conductor_extras.runtime.model_planner.run_process",
                side_effect=planner_with_session(other_session),
            ):
                with self.assertRaisesRegex(ModelPlannerSessionError, "different Codex session"):
                    plan_model_workflow(
                        task="Reject session identity drift.",
                        workspace=root,
                        output_path=root / "mismatch.json",
                        receipt_path=None,
                        policy=policy,
                        max_workers=2,
                        max_items=100,
                        max_steps=8,
                        planner_session_id=FAKE_CODEX_SESSION_ID,
                    )
            self.assertFalse((root / "mismatch.json").exists())

            def planner_without_session(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
                output_path = Path(argv[argv.index("--output-last-message") + 1])
                output_path.write_text(json.dumps(valid_model_workflow()), encoding="utf-8")
                return ProcessResult(0, json.dumps({"type": "turn.completed"}) + "\n", "")

            with patch(
                "conductor_extras.runtime.model_planner.run_process",
                side_effect=planner_without_session,
            ):
                with self.assertRaisesRegex(ModelPlannerSessionError, "did not report the resumed"):
                    plan_model_workflow(
                        task="Reject unverified session attachment.",
                        workspace=root,
                        output_path=root / "missing-session.json",
                        receipt_path=None,
                        policy=policy,
                        max_workers=2,
                        max_items=100,
                        max_steps=8,
                        planner_session_id=FAKE_CODEX_SESSION_ID,
                    )
            self.assertFalse((root / "missing-session.json").exists())

            with patch("conductor_extras.runtime.model_planner.run_process") as process:
                with self.assertRaisesRegex(ValidationError, "canonical UUID"):
                    plan_model_workflow(
                        task="Reject ambiguous thread names.",
                        workspace=root,
                        output_path=root / "invalid.json",
                        receipt_path=None,
                        policy=policy,
                        planner_session_id="latest-thread",
                    )
                process.assert_not_called()

    def test_plan_model_workflow_cli_requires_agent_and_defaults_to_external_state(self):
        validate_assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "validate-model-workflow-receipt", "receipt.json"]
        )
        self.assertFalse(validate_assessment.writes)
        self.assertFalse(validate_assessment.network)
        self.assertFalse(validate_assessment.destructive)
        plan_assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "plan-model-workflow", "--task", "review"]
        )
        self.assertTrue(plan_assessment.writes)
        self.assertTrue(plan_assessment.network)
        self.assertTrue(plan_assessment.destructive)

        def fake_model_planner(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(json.dumps(valid_model_workflow()), encoding="utf-8")
            return ProcessResult(0, "", "")

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            workspace = root / "workspace"
            workspace.mkdir()
            conductor_home = root / "conductor-home"
            with patch.dict(os.environ, {"CODEX_CONDUCTOR_HOME": str(conductor_home)}):
                with patch("conductor_extras.runtime.model_planner.run_process") as process:
                    stderr = StringIO()
                    with redirect_stderr(stderr):
                        code = cli_main(
                            [
                                "plan-model-workflow",
                                "--task",
                                "Review the workspace.",
                                "--workspace",
                                str(workspace),
                            ]
                        )
                    self.assertEqual(code, 2)
                    self.assertIn("requires --allow-agent", stderr.getvalue())
                    process.assert_not_called()

                stdout = StringIO()
                with patch("conductor_extras.runtime.model_planner.run_process", side_effect=fake_model_planner):
                    with redirect_stdout(stdout):
                        code = cli_main(
                            [
                                "plan-model-workflow",
                                "--task",
                                "Review the workspace.",
                                "--workspace",
                                str(workspace),
                                "--allow-agent",
                                "--max-workers",
                                "2",
                                "--max-items",
                                "100",
                            ]
                        )
                self.assertEqual(code, 0)
                self.assertIn("Status: validated-draft", stdout.getvalue())
                self.assertIn("Workspace binding: bound", stdout.getvalue())
                self.assertIn("Execution: not started", stdout.getvalue())
                drafts = list(conductor_home.glob("workspaces/*/generated/model-workflows/*.json"))
                workflow_files = [path for path in drafts if not path.name.endswith(".receipt.json")]
                receipt_files = [path for path in drafts if path.name.endswith(".receipt.json")]
                self.assertEqual(len(workflow_files), 1)
                self.assertEqual(len(receipt_files), 1)
                receipt = load_model_workflow_receipt(receipt_files[0])
                self.assertEqual(receipt["workspace"]["mode"], "bound")
                self.assertFalse(receipt["workspace"]["raw_paths_persisted"])
                self.assertFalse((workspace / ".codex-conductor").exists())

                in_workspace_output = workspace / "bound-output.json"
                with patch("conductor_extras.runtime.model_planner.run_process") as process:
                    stderr = StringIO()
                    with redirect_stderr(stderr):
                        code = cli_main(
                            [
                                "plan-model-workflow",
                                "--task",
                                "Reject a bound output inside the workspace.",
                                "--workspace",
                                str(workspace),
                                "--output",
                                str(in_workspace_output),
                                "--allow-agent",
                            ]
                        )
                    self.assertEqual(code, 2)
                    self.assertIn("outside the source workspace", stderr.getvalue())
                    process.assert_not_called()

                unbound_output = workspace / "explicit-unbound.json"
                stdout = StringIO()
                with patch("conductor_extras.runtime.model_planner.run_process", side_effect=fake_model_planner):
                    with redirect_stdout(stdout):
                        code = cli_main(
                            [
                                "plan-model-workflow",
                                "--task",
                                "Create an explicitly unbound compatibility draft.",
                                "--workspace",
                                str(workspace),
                                "--output",
                                str(unbound_output),
                                "--no-workspace-binding",
                                "--allow-agent",
                            ]
                        )
                self.assertEqual(code, 0)
                self.assertIn("Workspace binding: unbound", stdout.getvalue())
                self.assertEqual(
                    load_model_workflow_receipt(Path(str(unbound_output) + ".receipt.json"))["workspace"]["mode"],
                    "unbound",
                )

    def test_auto_orchestration_decision_uses_explicit_inputs_not_task_text(self):
        serial = decide_auto_orchestration(
            policy=RuntimePolicy(allow_agent=True),
            strategy="auto",
            plan_only=False,
            background=False,
            check_command=None,
            check_prompt=None,
            max_workers=None,
            output_path=None,
            run_id=None,
            goal_id=None,
            resume_goal=None,
        )
        self.assertEqual(serial["route"], "direct-workflow")
        self.assertEqual(serial["reason_code"], "serial-direct-no-verifier")
        self.assertEqual(serial["execution_mode"], "plan-only")
        self.assertEqual(serial["execution_reason_code"], "execute-approval-absent")
        self.assertEqual(serial["max_workers"], 1)
        self.assertEqual(serial["worker_source"], "efficient-default")
        self.assertFalse(serial["task_text_controls_route"])
        self.assertFalse(serial["task_text_controls_capabilities"])

        adaptive = decide_auto_orchestration(
            policy=RuntimePolicy(
                allow_agent=True,
                allow_parallel=True,
                approvals={MODEL_WORKFLOW_EXECUTE_APPROVAL},
            ),
            strategy="auto",
            plan_only=False,
            background=False,
            check_command=["true"],
            check_prompt=None,
            max_workers=4,
            output_path=None,
            run_id=None,
            goal_id="auto-goal",
            resume_goal=None,
        )
        self.assertEqual(adaptive["route"], "adaptive-progressive-goal")
        self.assertEqual(adaptive["reason_code"], "verifier-progressive")
        self.assertEqual(adaptive["execution_mode"], "foreground")
        self.assertEqual(adaptive["max_workers"], 4)
        self.assertEqual(adaptive["worker_source"], "explicit")

        composite = decide_auto_orchestration(
            policy=RuntimePolicy(
                allow_agent=True,
                approvals={MODEL_WORKFLOW_EXECUTE_APPROVAL},
            ),
            strategy="auto",
            plan_only=False,
            background=False,
            check_command=["true"],
            check_prompt="Require semantic evidence after deterministic checks.",
            max_workers=1,
            output_path=None,
            run_id=None,
            goal_id=None,
            resume_goal=None,
        )
        self.assertEqual(composite["route"], "adaptive-direct-goal")
        self.assertEqual(composite["verifier_kind"], "command+model")

        with self.assertRaisesRegex(PolicyError, MODEL_WORKFLOW_EXECUTE_APPROVAL):
            decide_auto_orchestration(
                policy=RuntimePolicy(allow_agent=True),
                strategy="auto",
                plan_only=False,
                background=False,
                check_command=["true"],
                check_prompt=None,
                max_workers=None,
                output_path=None,
                run_id=None,
                goal_id=None,
                resume_goal=None,
            )
        with self.assertRaisesRegex(ValidationError, "requires max_workers 1"):
            decide_auto_orchestration(
                policy=RuntimePolicy(allow_agent=True, allow_parallel=True),
                strategy="direct",
                plan_only=True,
                background=False,
                check_command=None,
                check_prompt=None,
                max_workers=2,
                output_path=None,
                run_id=None,
                goal_id=None,
                resume_goal=None,
            )
        with self.assertRaisesRegex(ValidationError, "requires max_workers above 1"):
            decide_auto_orchestration(
                policy=RuntimePolicy(allow_agent=True),
                strategy="progressive",
                plan_only=False,
                background=False,
                check_command=["true"],
                check_prompt=None,
                max_workers=None,
                output_path=None,
                run_id=None,
                goal_id=None,
                resume_goal=None,
            )

    def test_auto_effort_selects_low_only_for_tiny_verified_direct_work(self):
        slug_prompt = next(
            task["prompt"]
            for task in load_parity_tasks(
                Path("benchmark-suites/implementation-canary-completion-reserve-tasks.json")
            )["tasks"]
            if task["id"] == "slug-normalization"
        )
        backoff_prompt = next(
            task["prompt"]
            for task in load_parity_tasks(
                Path("benchmark-suites/implementation-canary-completion-reserve-tasks.json")
            )["tasks"]
            if task["id"] == "backoff-test-authoring"
        )
        self.assertEqual(
            resolve_auto_reasoning_effort(
                slug_prompt,
                AUTO_REASONING_EFFORT,
                route="adaptive-direct-goal",
                verifier_kind="command",
            ),
            "low",
        )
        self.assertEqual(
            resolve_auto_reasoning_effort(
                backoff_prompt,
                AUTO_REASONING_EFFORT,
                route="adaptive-progressive-goal",
                verifier_kind="command",
            ),
            "low",
        )
        for prompt in [slug_prompt, backoff_prompt]:
            self.assertEqual(
                resolve_auto_reasoning_effort(
                    prompt,
                    AUTO_REASONING_EFFORT,
                    route="adaptive-direct-goal",
                    verifier_kind="command",
                    policy=AUTO_EFFORT_POLICY_V5,
                ),
                "medium",
            )
        self.assertEqual(
            resolve_auto_reasoning_effort(
                "Repair the bounded slug behavior.",
                AUTO_REASONING_EFFORT,
                route="adaptive-direct-goal",
                verifier_kind="command",
            ),
            "medium",
        )
        self.assertEqual(
            resolve_auto_reasoning_effort(
                "Repair the bounded behavior.",
                AUTO_REASONING_EFFORT,
                route="adaptive-progressive-goal",
                verifier_kind="command+model",
            ),
            "medium",
        )
        self.assertEqual(
            resolve_auto_reasoning_effort(
                "Repair the retry-policy migration without changing public signatures.",
                AUTO_REASONING_EFFORT,
                route="adaptive-direct-goal",
                verifier_kind="command",
            ),
            "medium",
        )
        self.assertEqual(
            resolve_auto_reasoning_effort(
                "Repair the retry-policy migration without changing public signatures.",
                AUTO_REASONING_EFFORT,
                route="adaptive-direct-goal",
                verifier_kind="command",
                policy=AUTO_EFFORT_POLICY_V1,
            ),
            "high",
        )
        self.assertEqual(
            resolve_auto_reasoning_effort(
                "Author a focused unittest suite without modifying production code.",
                AUTO_REASONING_EFFORT,
                route="adaptive-progressive-goal",
                verifier_kind="command",
            ),
            "medium",
        )
        self.assertEqual(
            resolve_auto_reasoning_effort(
                "Author a focused unittest suite without modifying production code.",
                AUTO_REASONING_EFFORT,
                route="adaptive-progressive-goal",
                verifier_kind="command",
                policy=AUTO_EFFORT_POLICY_V2,
            ),
            "high",
        )
        self.assertEqual(
            resolve_auto_reasoning_effort(
                "Repair the bounded idempotency contract.",
                AUTO_REASONING_EFFORT,
                route="adaptive-direct-goal",
                verifier_kind="command",
            ),
            "medium",
        )
        self.assertEqual(
            resolve_auto_reasoning_effort(
                "Repair the bounded idempotency contract.",
                AUTO_REASONING_EFFORT,
                route="adaptive-direct-goal",
                verifier_kind="command",
                policy=AUTO_EFFORT_POLICY_V3,
            ),
            "high",
        )
        self.assertEqual(
            resolve_auto_reasoning_effort(
                "Refactor event-name handling while preserving every public signature.",
                AUTO_REASONING_EFFORT,
                route="adaptive-direct-goal",
                verifier_kind="command",
            ),
            "medium",
        )
        self.assertEqual(
            resolve_auto_reasoning_effort(
                "Refactor event-name handling while preserving every public signature.",
                AUTO_REASONING_EFFORT,
                route="adaptive-direct-goal",
                verifier_kind="command",
                policy=AUTO_EFFORT_POLICY_V4,
            ),
            "high",
        )
        for task in [
            "Perform a repository-wide security audit.",
            "Complete the multi-file migration.",
            "Repair concurrent idempotency in the distributed service.",
            "Write tests for the concurrent production service.",
            "Author tests without modifying production codebase behavior.",
            "Repair the production database transaction.",
            "x" * 1001,
        ]:
            self.assertEqual(
                resolve_auto_reasoning_effort(
                    task,
                    AUTO_REASONING_EFFORT,
                    route="adaptive-progressive-goal",
                    verifier_kind="command",
                ),
                "high",
            )
        self.assertEqual(
            resolve_auto_reasoning_effort(
                "Repair the bounded behavior.",
                AUTO_REASONING_EFFORT,
                route="adaptive-direct-goal",
                verifier_kind="none",
            ),
            "high",
        )
        self.assertEqual(
            resolve_auto_reasoning_effort(
                "Repair the bounded behavior.",
                AUTO_REASONING_EFFORT,
                route="model-workflow",
                verifier_kind="command",
            ),
            "high",
        )
        self.assertEqual(
            resolve_auto_reasoning_effort(
                "Perform a repository-wide migration.",
                "ultra",
                route="adaptive-progressive-goal",
                verifier_kind="command",
            ),
            "ultra",
        )
        with self.assertRaises(ValidationError):
            resolve_auto_reasoning_effort(
                "Repair the bounded behavior.",
                "invalid",
                route="adaptive-direct-goal",
                verifier_kind="command",
            )

    def test_direct_write_prompt_defers_to_external_verifier_without_recursive_orchestration(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            result = plan_direct_model_workflow(
                task="Repair the bounded slug behavior.",
                workspace=root,
                output_path=root / "workflow.json",
                receipt_path=root / "workflow-receipt.json",
                policy=RuntimePolicy(
                    allow_agent=True,
                    allow_writes=True,
                    approvals={MODEL_WORKFLOW_WRITE_APPROVAL},
                ),
                write_capable=True,
                external_verifier=True,
                reasoning_effort="medium",
                timeout_seconds=29,
            )
            high_result = plan_direct_model_workflow(
                task="Complete the multi-file migration.",
                workspace=root,
                output_path=root / "high-workflow.json",
                receipt_path=root / "high-workflow-receipt.json",
                policy=RuntimePolicy(
                    allow_agent=True,
                    allow_writes=True,
                    approvals={MODEL_WORKFLOW_WRITE_APPROVAL, "high-risk"},
                ),
                write_capable=True,
                external_verifier=True,
                reasoning_effort="high",
            )
            ultra_result = plan_direct_model_workflow(
                task="Complete the multi-file migration.",
                workspace=root,
                output_path=root / "ultra-workflow.json",
                receipt_path=root / "ultra-workflow-receipt.json",
                policy=RuntimePolicy(
                    allow_agent=True,
                    allow_writes=True,
                    approvals={MODEL_WORKFLOW_WRITE_APPROVAL, "high-risk"},
                ),
                write_capable=True,
                external_verifier=True,
                reasoning_effort="ultra",
            )
            low_result = plan_direct_model_workflow(
                task="Repair the bounded slug behavior.",
                workspace=root,
                output_path=root / "low-workflow.json",
                receipt_path=root / "low-workflow-receipt.json",
                policy=RuntimePolicy(
                    allow_agent=True,
                    allow_writes=True,
                    approvals={MODEL_WORKFLOW_WRITE_APPROVAL},
                ),
                write_capable=True,
                external_verifier=True,
                reasoning_effort="low",
            )
            override_result = plan_direct_model_workflow(
                task="Repair the bounded slug behavior.",
                workspace=root,
                output_path=root / "override-workflow.json",
                receipt_path=root / "override-workflow-receipt.json",
                policy=RuntimePolicy(
                    allow_agent=True,
                    allow_writes=True,
                    approvals={MODEL_WORKFLOW_WRITE_APPROVAL},
                ),
                write_capable=True,
                external_verifier=True,
                reasoning_effort="low",
                max_tokens=12345,
            )
        prompt = result.workflow["steps"][-1]["prompt"]
        self.assertEqual(result.workflow["agent_timeout_seconds"], 29)
        self.assertEqual(result.receipt["limits"]["timeout_seconds"], 29)
        self.assertIn("do not invoke or inspect external skills", prompt)
        self.assertIn("Do not run tests, invoke language runtimes", prompt)
        self.assertIn("configured authoritative verifier runs immediately afterward", prompt)
        self.assertIn("at most one focused read-only command before the first edit", prompt)
        self.assertIn("prefer one multi-file patch call", prompt)
        self.assertIn("return one short completion sentence", prompt)
        self.assertIn("Conductor pre-write contract checklist", prompt)
        self.assertIn("Treat every parameter as a separate obligation", prompt)
        self.assertIn("validate the outer type before reading attributes or keys", prompt)
        self.assertIn("incidental AttributeError or KeyError", prompt)
        self.assertLess(prompt.index("END_UNTRUSTED_TASK"), prompt.index("Conductor pre-write contract checklist"))
        low_prompt = low_result.workflow["steps"][-1]["prompt"]
        self.assertIn("at most one focused read-only command before the first edit", low_prompt)
        self.assertIn("prefer one multi-file patch call", low_prompt)
        high_prompt = high_result.workflow["steps"][-1]["prompt"]
        self.assertIn("configured authoritative verifier runs immediately afterward", high_prompt)
        self.assertIn("at most two focused read-only commands", high_prompt)
        self.assertIn("prefer one multi-file patch call", high_prompt)
        self.assertNotIn("at most one focused read-only command", high_prompt)
        ultra_prompt = ultra_result.workflow["steps"][-1]["prompt"]
        self.assertIn("configured authoritative verifier runs immediately afterward", ultra_prompt)
        self.assertNotIn("at most one focused read-only command", ultra_prompt)
        self.assertNotIn("at most two focused read-only commands", ultra_prompt)
        self.assertNotIn("prefer one multi-file patch call", ultra_prompt)
        self.assertEqual(
            CODEX_DIRECT_WRITE_TOKEN_CAPS,
            {
                "low": 8000,
                "medium": 16000,
                "high": 24000,
                "xhigh": 32000,
                "ultra": 40000,
            },
        )
        self.assertEqual(low_result.workflow["agent_max_tokens"], 8000)
        self.assertEqual(result.workflow["agent_max_tokens"], 16000)
        self.assertEqual(high_result.workflow["agent_max_tokens"], 24000)
