    @unittest.skipUnless(os.name == "posix", "background auto workflow requires POSIX")
    def test_auto_orchestration_background_handoff_records_mutable_child_receipt(self):
        generated = {
            "schema": "conductor.workflow.v1",
            "name": "auto-background-workflow",
            "description": "Approved detached auto fixture.",
            "mode": "review",
            "max_workers": 1,
            "steps": [
                {
                    "id": "record",
                    "kind": "write_artifact",
                    "output": "auto-background.md",
                    "content": "approved detached auto execution\n",
                }
            ],
        }

        def fake_model_planner(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(json.dumps(generated), encoding="utf-8")
            return ProcessResult(0, "", "")

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            output = root / "generated" / "model-workflows" / "background.json"
            auto_receipt = root / "generated" / "auto" / "background-auto.json"
            with patch("conductor_extras.runtime.model_planner.run_process", side_effect=fake_model_planner):
                result = run_auto_orchestration(
                    task="Create one detached automatic artifact.",
                    workspace=root,
                    runs_dir=root / "runs",
                    goals_dir=root / "goals",
                    policy=RuntimePolicy(
                        allow_agent=True,
                        approvals={MODEL_WORKFLOW_EXECUTE_APPROVAL},
                    ),
                    strategy="workflow",
                    background=True,
                    output_path=output,
                    receipt_path=auto_receipt,
                    run_id="auto-background-run",
                )

            self.assertEqual(result.status, "running")
            self.assertEqual(result.execution_mode, "background")
            self.assertIsNotNone(result.background_pid)
            self.assertTrue(result.receipt["result"]["background_handoff"])
            child_receipts = [
                item
                for item in result.receipt["artifacts"]
                if item["kind"] == "model-workflow-run-receipt"
            ]
            self.assertEqual(len(child_receipts), 1)
            self.assertEqual(child_receipts[0]["content_state"], "handoff-mutable")
            final = wait_for_background_run(
                result.run_dir,
                timeout_seconds=10,
                poll_interval_seconds=0.05,
            )
            self.assertEqual(final["run_status"], "completed")
            os.waitpid(result.background_pid, 0)
            self.assertEqual(load_model_workflow_run_receipt(Path(str(output) + ".run-receipt.json"))["status"], "completed")
            self.assertEqual(load_auto_orchestration_receipt(result.receipt_path)["status"], "running")
            summary = summarize_auto_orchestration(
                auto_receipt,
                generated_dir=root / "generated",
                goals_dir=root / "goals",
                runs_dir=root / "runs",
            )
            self.assertEqual(summary["status"], "running")
            self.assertEqual(summary["effective_status"], "completed")
            self.assertEqual(summary["child"]["resolution"], "resolved")
            self.assertEqual(summary["child"]["kind"], "model-workflow-run-receipt")
            self.assertEqual(summary["liveness"], "finished")
            self.assertFalse(summary["needs_attention"])

            records = collect_auto_orchestrations(
                root / "generated" / "auto",
                generated_dir=root / "generated",
                goals_dir=root / "goals",
                runs_dir=root / "runs",
            )
            self.assertEqual(len(records), 1)
            self.assertEqual(records[0]["effective_status"], "completed")

            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(
                    [
                        "status-auto",
                        str(auto_receipt),
                        "--generated-dir",
                        str(root / "generated"),
                        "--runs-dir",
                        str(root / "runs"),
                        "--goals-dir",
                        str(root / "goals"),
                        "--json",
                    ]
                )
            self.assertEqual(code, 0)
            self.assertEqual(json.loads(stdout.getvalue())["effective_status"], "completed")

            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(
                    [
                        "list-auto",
                        "--auto-dir",
                        str(root / "generated" / "auto"),
                        "--generated-dir",
                        str(root / "generated"),
                        "--runs-dir",
                        str(root / "runs"),
                        "--goals-dir",
                        str(root / "goals"),
                        "--json",
                    ]
                )
            self.assertEqual(code, 0)
            self.assertEqual(json.loads(stdout.getvalue())["records"][0]["effective_status"], "completed")

            dashboard_path = root / "dashboard.html"
            write_dashboard(
                runs_dir=root / "runs",
                benchmarks_dir=root / "benchmarks",
                goals_dir=root / "goals",
                generated_dir=root / "generated",
                auto_dir=root / "generated" / "auto",
                output=dashboard_path,
            )
            dashboard_html = dashboard_path.read_text(encoding="utf-8")
            self.assertIn("Automatic Orchestration", dashboard_html)
            self.assertIn("background-auto.json", dashboard_html)
            self.assertIn("completed", dashboard_html)

            payload = build_live_payload(
                root / "runs",
                root / "benchmarks",
                goals_dir=root / "goals",
                generated_dir=root / "generated",
                auto_dir=root / "generated" / "auto",
            )
            self.assertEqual(payload["auto_orchestrations"][0]["effective_status"], "completed")
            live_html = render_live_dashboard(payload)
            self.assertIn("Automatic Orchestration", live_html)
            self.assertIn("background-auto.json", live_html)

