    @unittest.skipUnless(os.name == "posix", "background direct goals require POSIX session isolation")
    def test_auto_direct_adaptive_background_preserves_zero_planner_contract(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            fake_bin = install_fake_codex(root)
            goals_dir = root / "goals"
            environment = {
                "PATH": "%s%s%s" % (fake_bin, os.pathsep, os.environ.get("PATH", "")),
                "CODEX_CONDUCTOR_HOME": str(root / "conductor-home"),
            }
            stdout = StringIO()
            with patch.dict(os.environ, environment):
                with redirect_stdout(stdout):
                    code = cli_main(
                        [
                            "auto",
                            "--task",
                            "Complete one detached direct review.",
                            "--check-command-json",
                            '["true"]',
                            "--workspace",
                            str(root),
                            "--runs-dir",
                            str(root / "runs"),
                            "--goals-dir",
                            str(goals_dir),
                            "--goal-id",
                            "auto-direct-background",
                            "--background",
                            "--allow-agent",
                            "--approve",
                            MODEL_WORKFLOW_EXECUTE_APPROVAL,
                        ]
                    )
                self.assertEqual(code, 0)
                self.assertIn("Auto route: adaptive-direct-goal", stdout.getvalue())
                metadata_path = next((goals_dir / "background-workers").glob("*.json"))
                launched = load_background_model_goal(metadata_path)
                worker_pid = launched["worker"]["pid"]
                final = wait_for_background_model_goal(
                    metadata_path,
                    timeout_seconds=10,
                    poll_interval_seconds=0.05,
                )
                self.assertEqual(final["goal_status"], "completed")
                try:
                    os.waitpid(worker_pid, 0)
                except ChildProcessError:
                    pass

            goal = load_goal_state(goals_dir / "auto-direct-background.json")
            self.assertEqual(goal["planner"]["kind"], "deterministic-direct-per-iteration")
            self.assertEqual(goal["planner"]["session"]["turns"], 0)
