            self.assertIn("not used by deterministic direct planning", live_detail)
            receipt = next((root / "conductor-home").glob("workspaces/*/generated/auto/*.json"))
            self.assertEqual(load_auto_orchestration_receipt(receipt)["decision"]["route"], "adaptive-direct-goal")

