    def test_auto_orchestration_rejects_capability_gaps_before_provider_launch(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            with patch("conductor_extras.runtime.model_planner.run_process") as process:
                with self.assertRaisesRegex(PolicyError, MODEL_WORKFLOW_EXECUTE_APPROVAL):
                    run_auto_orchestration(
                        task="Try an adaptive route without execution approval.",
                        workspace=root,
                        runs_dir=root / "runs",
                        goals_dir=root / "goals",
                        policy=RuntimePolicy(allow_agent=True),
                        check_command=["true"],
                        receipt_path=root / "missing-execute.json",
                    )
                process.assert_not_called()
                self.assertFalse((root / "missing-execute.json").exists())

            with patch("conductor_extras.runtime.model_planner.run_process") as process:
                with self.assertRaisesRegex(PolicyError, MODEL_WORKFLOW_WRITE_APPROVAL):
                    run_auto_orchestration(
                        task="Try an unapproved write route.",
                        workspace=root,
                        runs_dir=root / "runs",
                        goals_dir=root / "goals",
                        policy=RuntimePolicy(
                            allow_agent=True,
                            allow_writes=True,
                            approvals={MODEL_WORKFLOW_EXECUTE_APPROVAL},
                        ),
                        receipt_path=root / "missing-write.json",
                    )
                process.assert_not_called()
                self.assertFalse((root / "missing-write.json").exists())

            with patch("conductor_extras.runtime.model_planner.run_process") as process:
                with self.assertRaisesRegex(ValidationError, "cannot accept an adaptive verifier"):
                    run_auto_orchestration(
                        task="Reject conflicting route inputs.",
                        workspace=root,
                        runs_dir=root / "runs",
                        goals_dir=root / "goals",
                        policy=RuntimePolicy(
                            allow_agent=True,
                            approvals={MODEL_WORKFLOW_EXECUTE_APPROVAL},
                        ),
                        strategy="workflow",
                        check_command=["true"],
                        receipt_path=root / "conflict.json",
                    )
                process.assert_not_called()

    def test_auto_status_collection_fails_closed_on_invalid_and_symlinked_inputs(self):
        list_assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "list-auto", "--json"]
        )
        status_assessment = assess_command(
            ["python3", "-B", "-m", "conductor_extras", "status-auto", "receipt.json"]
        )
        for assessment in (list_assessment, status_assessment):
            self.assertFalse(assessment.writes)
            self.assertFalse(assessment.network)
            self.assertFalse(assessment.destructive)

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            auto_dir = root / "generated" / "auto"
            auto_dir.mkdir(parents=True)
            (auto_dir / "invalid.json").write_text('{"schema":', encoding="utf-8")
            records = collect_auto_orchestrations(
                auto_dir,
                generated_dir=root / "generated",
                goals_dir=root / "goals",
                runs_dir=root / "runs",
            )
            self.assertEqual(len(records), 1)
            self.assertEqual(records[0]["effective_status"], "invalid")
            self.assertTrue(records[0]["needs_attention"])
            self.assertEqual(records[0]["child"]["resolution"], "invalid")
            self.assertNotIn(str(root), json.dumps(records))
            with self.assertRaisesRegex(ValidationError, "max_records"):
                collect_auto_orchestrations(
                    auto_dir,
                    generated_dir=root / "generated",
                    goals_dir=root / "goals",
                    runs_dir=root / "runs",
                    max_records=0,
                )
            if hasattr(os, "symlink"):
                linked = root / "linked-auto"
                linked.symlink_to(auto_dir, target_is_directory=True)
                with self.assertRaisesRegex(ValidationError, "must not be a symlink"):
                    collect_auto_orchestrations(
                        linked,
                        generated_dir=root / "generated",
                        goals_dir=root / "goals",
                        runs_dir=root / "runs",
                    )

    def test_auto_status_resolves_background_goal_metadata_and_rejects_path_drift(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            goals_dir = root / "goals"
            metadata_path = goals_dir / "background-workers" / "auto-goal-worker.json"
            metadata_path.parent.mkdir(parents=True)
            metadata_text = "{}\n"
            metadata_path.write_text(metadata_text, encoding="utf-8")
            receipt = json.loads(
                (Path(__file__).resolve().parents[1] / "benchmark-suites" / "auto-orchestration-receipt-template.json").read_text(
                    encoding="utf-8"
                )
            )
            receipt["status"] = "running"
            receipt["decision"].update(
                {
                    "execution_mode": "background",
                    "execution_reason_code": "execute-approval-present",
                    "reason_code": "serial-direct-verifier",
                    "route": "adaptive-direct-goal",
                    "verifier_kind": "command",
                }
            )
            receipt["policy"]["approval_count"] = 1
            receipt["policy"]["execution_approval_present"] = True
            receipt["result"].update(
                {
                    "status": "running",
                    "execution_started": True,
                    "background_handoff": True,
                }
            )
            receipt["artifacts"] = [
                {
                    "kind": "background-model-goal",
                    "filename": metadata_path.name,
                    "path_sha256": hashlib.sha256(str(metadata_path.resolve()).encode("utf-8")).hexdigest(),
                    "content_sha256": hashlib.sha256(metadata_text.encode("utf-8")).hexdigest(),
                    "content_state": "handoff-mutable",
                }
            ]
            receipt_path = root / "generated" / "auto" / "goal-auto.json"
            receipt_path.parent.mkdir(parents=True)
            receipt_path.write_text(json.dumps(receipt), encoding="utf-8")
            fake_metadata = {
                "status": "finished",
                "goal_status": "completed",
                "updated_at_utc": "2026-07-09T00:00:02.000Z",
            }
            with patch("conductor_extras.runtime.auto_orchestrator.load_background_model_goal", return_value=fake_metadata):
                with patch("conductor_extras.runtime.auto_orchestrator.background_model_goal_liveness", return_value="finished"):
                    summary = summarize_auto_orchestration(
                        receipt_path,
                        generated_dir=root / "generated",
                        goals_dir=goals_dir,
                        runs_dir=root / "runs",
                    )
            self.assertEqual(summary["effective_status"], "completed")
            self.assertEqual(summary["child"]["kind"], "background-model-goal")
            self.assertEqual(summary["liveness"], "finished")

            receipt["artifacts"][0]["path_sha256"] = "b" * 64
            receipt_path.write_text(json.dumps(receipt), encoding="utf-8")
            drifted = summarize_auto_orchestration(
                receipt_path,
                generated_dir=root / "generated",
                goals_dir=goals_dir,
                runs_dir=root / "runs",
            )
            self.assertEqual(drifted["effective_status"], "invalid")
            self.assertEqual(drifted["child"]["resolution"], "invalid")
            self.assertTrue(drifted["needs_attention"])

