    def test_run_model_workflow_preflights_then_executes_with_receipts(self):
        generated = {
            "schema": "conductor.workflow.v1",
            "name": "model-auto-workflow",
            "description": "Create one bounded run artifact.",
            "mode": "review",
            "risk": "low",
            "max_workers": 1,
            "steps": [
                {
                    "id": "record-result",
                    "kind": "write_artifact",
                    "risk": "low",
                    "output": "model-result.md",
                    "content": "Validated model workflow execution.\n",
                }
            ],
        }

        def fake_model_planner(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(json.dumps(generated), encoding="utf-8")
            return ProcessResult(
                0,
                json.dumps(
                    {
                        "type": "turn.completed",
                        "model": "codex-test-model",
                        "usage": {"input_tokens": 12, "output_tokens": 8, "total_tokens": 20},
                    }
                )
                + "\n",
                "",
            )

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            output = root / "generated" / "auto.json"
            task = "Create a bounded review artifact for token=autorunsecret."
            policy = RuntimePolicy(
                allow_agent=True,
                approvals={MODEL_WORKFLOW_EXECUTE_APPROVAL},
            )
            with patch("conductor_extras.runtime.model_planner.run_process", side_effect=fake_model_planner):
                result = run_model_workflow(
                    task=task,
                    workspace=root,
                    output_path=output,
                    planning_receipt_path=None,
                    run_receipt_path=None,
                    runs_dir=root / "runs",
                    policy=policy,
                    max_workers=1,
                    max_items=10,
                    max_steps=4,
                )

            self.assertEqual(result.status, "completed")
            self.assertEqual(result.error_class, "")
            self.assertIsNotNone(result.run_dir)
            self.assertEqual((result.run_dir / "artifacts" / "model-result.md").read_text(encoding="utf-8"), generated["steps"][0]["content"])
            self.assertEqual(result.receipt["schema"], MODEL_WORKFLOW_RUN_RECEIPT_SCHEMA)
            self.assertTrue(result.receipt["preflight"]["completed"])
            self.assertEqual(result.receipt["preflight"]["status"], "planned")
