    @unittest.skipUnless(os.name == "posix", "background model workflow requires POSIX")
    def test_run_model_workflow_background_finalizes_hash_bound_receipt(self):
        generated = {
            "schema": "conductor.workflow.v1",
            "name": "model-background-workflow",
            "description": "Create one detached model-run artifact.",
            "mode": "review",
            "risk": "low",
            "max_workers": 1,
            "steps": [
                {
                    "id": "record-result",
                    "kind": "write_artifact",
                    "risk": "low",
                    "output": "model-background.md",
                    "content": "Detached model workflow completed.\n",
                }
            ],
        }

        def fake_model_planner(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(json.dumps(generated), encoding="utf-8")
            return ProcessResult(0, "", "")

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            output = root / "generated" / "background.json"
            policy = RuntimePolicy(
                allow_agent=True,
                approvals={MODEL_WORKFLOW_EXECUTE_APPROVAL, "ephemeral-model-launch"},
            )
            with patch("conductor_extras.runtime.model_planner.run_process", side_effect=fake_model_planner):
                result = run_model_workflow(
                    task="Create detached evidence without token=modelbackgroundsecret.",
                    workspace=root,
                    output_path=output,
                    planning_receipt_path=None,
                    run_receipt_path=None,
                    runs_dir=root / "runs",
                    policy=policy,
                    max_workers=1,
                    max_items=10,
                    max_steps=4,
                    background=True,
                )

            self.assertEqual(result.status, "running")
            self.assertIsNotNone(result.background_pid)
            self.assertEqual(result.receipt["schema"], MODEL_WORKFLOW_RUN_RECEIPT_SCHEMA)
            self.assertEqual(result.receipt["status"], "running")
            self.assertFalse(result.receipt["execution"]["foreground"])
            self.assertTrue(result.receipt["execution"]["started"])
            self.assertFalse(result.receipt["execution"]["background_service"])

            background = wait_for_background_run(
                result.run_dir,
                timeout_seconds=10,
                poll_interval_seconds=0.05,
            )
            self.assertEqual(background["run_status"], "completed")
            self.assertEqual(background["exit_code"], 0)
            os.waitpid(result.background_pid, 0)
            self.assertEqual(
                (result.run_dir / "artifacts" / "model-background.md").read_text(encoding="utf-8"),
                generated["steps"][0]["content"],
            )
            final_receipt = load_model_workflow_run_receipt(result.receipt_path)
            self.assertEqual(final_receipt["status"], "completed")
            self.assertEqual(final_receipt["run"]["status"], "completed")
            self.assertFalse(final_receipt["execution"]["foreground"])
            persisted = "\n".join(
                path.read_text(encoding="utf-8")
                for path in [
                    result.receipt_path,
                    result.run_dir / "background.json",
                    result.run_dir / "launch.json",
                    result.run_dir / "logs" / "background-worker.stdout.log",
                    result.run_dir / "logs" / "background-worker.stderr.log",
                ]
            )
            self.assertNotIn("modelbackgroundsecret", persisted)
            self.assertNotIn("ephemeral-model-launch", persisted)
            self.assertNotIn(str(result.receipt_path.resolve()), (result.run_dir / "background.json").read_text(encoding="utf-8"))

