            self.assertEqual(load_model_workflow_run_receipt(result.receipt_path)["status"], "running")
            self.assertIn(
                "completion receipt finalization failed",
                (result.run_dir / "logs" / "background-worker.stderr.log").read_text(encoding="utf-8"),
            )

