    def test_run_model_workflow_records_planning_timeout_without_partial_handoff(self):
        def timed_out_planner(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            self.assertIn('model_reasoning_effort="medium"', argv)
            return ProcessResult(-9, "", "", timed_out=True)

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            output = root / "workflow.json"
            run_receipt = root / "planning-attempt.json"
            with patch("conductor_extras.runtime.model_planner.run_process", side_effect=timed_out_planner):
                result = run_model_workflow(
                    task="Plan a bounded read-only audit.",
                    workspace=root,
                    output_path=output,
                    planning_receipt_path=None,
                    run_receipt_path=run_receipt,
                    runs_dir=root / "runs",
                    policy=RuntimePolicy(allow_agent=True),
                    planner_effort="medium",
                    planning_timeout_seconds=7,
                    dry_run=True,
                )

            self.assertEqual(result.status, "failed")
            self.assertEqual(result.error_class, "ModelPlannerTimeoutError")
            self.assertIsInstance(
                ModelPlannerTimeoutError("bounded timeout"),
                StepExecutionError,
            )
            self.assertIsNone(result.draft)
            self.assertIsNone(result.run_dir)
            self.assertFalse(output.exists())
            self.assertFalse(Path(str(output) + ".receipt.json").exists())
            self.assertTrue(run_receipt.is_file())
            self.assertEqual(result.receipt["planning"]["status"], "failed")
            self.assertFalse(result.receipt["workflow"]["available"])
            self.assertEqual(result.receipt["limits"]["planner_effort"], "medium")
            self.assertEqual(result.receipt["limits"]["planning_timeout_seconds"], 7)
            self.assertFalse(result.receipt["preflight"]["completed"])
            self.assertFalse(result.receipt["execution"]["automatic_handoff"])
            self.assertFalse(result.receipt["execution"]["started"])
            self.assertEqual(
                result.receipt["error"]["class"],
                "ModelPlannerTimeoutError",
            )
            load_model_workflow_run_receipt(run_receipt)

            tampered = json.loads(run_receipt.read_text(encoding="utf-8"))
            tampered["execution"]["automatic_handoff"] = True
            with self.assertRaisesRegex(ValidationError, "dry-run must not record workflow execution"):
                validate_model_workflow_run_receipt(tampered)

