    def test_model_planner_failure_taxonomy_covers_local_boundaries(self):
        def launch_failure(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            raise OSError("launch detail must not persist")

        def output_limit(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            return ProcessResult(0, "", "", stdout_truncated=True)

        def invalid_telemetry(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(json.dumps(valid_model_workflow()), encoding="utf-8")
            return ProcessResult(
                0,
                json.dumps(
                    {
                        "type": "turn.completed",
                        "usage": {"input_tokens": 1, "output_tokens": 1, "total_tokens": 3},
                    }
                ),
                "",
            )

        def missing_output(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            return ProcessResult(0, "", "")

        cases = [
            ("launch", launch_failure, ModelPlannerLaunchError),
            ("output-limit", output_limit, ModelPlannerOutputLimitError),
            ("telemetry", invalid_telemetry, ModelPlannerTelemetryError),
            ("missing-output", missing_output, ModelPlannerOutputError),
        ]
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            for label, behavior, expected in cases:
                output = root / (label + ".json")
                with self.subTest(label=label):
                    with patch("conductor_extras.runtime.model_planner.run_process", side_effect=behavior):
                        with self.assertRaises(expected):
                            plan_model_workflow(
                                task="Plan a bounded read-only audit.",
                                workspace=root,
                                output_path=output,
                                receipt_path=None,
                                policy=RuntimePolicy(allow_agent=True),
                            )
                    self.assertFalse(output.exists())
                    self.assertFalse(Path(str(output) + ".receipt.json").exists())

