    def test_run_model_goal_replans_from_bounded_verifier_feedback(self):
        planner_prompts = []
        planner_commands = []
        planner_calls = 0

        def fake_model_planner(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            nonlocal planner_calls
            planner_calls += 1
            planner_prompts.append(input_text)
            planner_commands.append(list(argv))
            generated = {
                "schema": "conductor.workflow.v1",
                "name": "adaptive-workflow-%d" % planner_calls,
                "description": "Adaptive iteration %d." % planner_calls,
                "mode": "review",
                "max_workers": 1,
                "steps": [
                    {
                        "id": "record-iteration",
                        "kind": "write_artifact",
                        "output": "iteration.md",
                        "content": "Iteration %d completed.\n" % planner_calls,
                    }
                ],
            }
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(json.dumps(generated), encoding="utf-8")
            return ProcessResult(
                0,
                "\n".join(
                    [
                        json.dumps({"type": "thread.started", "thread_id": FAKE_CODEX_SESSION_ID}),
                        json.dumps({"type": "turn.completed"}),
                    ]
                )
                + "\n",
                "",
            )

        verifier_results = [
            ProcessResult(1, "missing concrete regression evidence", ""),
            ProcessResult(0, "verified", ""),
        ]
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            conductor_home = root / "conductor-home"
            with patch.dict(os.environ, {"CODEX_CONDUCTOR_HOME": str(conductor_home)}):
                with patch("conductor_extras.runtime.model_planner.run_process", side_effect=fake_model_planner):
                    with patch("conductor_extras.runtime.goal_loop.run_process", side_effect=verifier_results):
                        result = run_model_goal_loop(
                            task="Create evidence without exposing token=modelgoalsecret.",
                            workspace=root,
                            runs_dir=root / "runs",
                            goals_dir=root / "goals",
                            policy=RuntimePolicy(
                                allow_agent=True,
                                approvals={MODEL_WORKFLOW_EXECUTE_APPROVAL},
                            ),
                            check_command=["true"],
                            check_prompt=None,
                            max_iterations=3,
                            goal_id="adaptive-unit-goal",
                            max_workers=1,
                            max_items=10,
                            max_steps=4,
                        )

            self.assertEqual(result.status, "completed")
            self.assertEqual(result.iterations, 2)
            self.assertEqual(len(result.run_dirs), 2)
            self.assertEqual(planner_calls, 2)
            self.assertNotIn("modelgoalsecret", "\n".join(planner_prompts))
            self.assertTrue(
                all(
                    "A trusted enclosing verifier runs after this workflow" in prompt
                    for prompt in planner_prompts
                )
            )
            self.assertTrue(
                all(
                    "Include evidence synthesis, verification, and final review appropriate to the task"
                    not in prompt
                    for prompt in planner_prompts
                )
            )
            self.assertIn("missing concrete regression evidence", planner_prompts[1])
            self.assertEqual(planner_prompts[1].count("BEGIN_UNTRUSTED_PRIOR_VERIFIER_FEEDBACK"), 1)
            self.assertNotIn("Create evidence without exposing", planner_prompts[1])
            self.assertNotEqual(planner_commands[0][2], "resume")
            self.assertEqual(planner_commands[1][:3], ["codex", "exec", "resume"])
            self.assertIn(FAKE_CODEX_SESSION_ID, planner_commands[1])
            state = load_goal_state(result.goal_path)
            self.assertEqual(state["goal_kind"], MODEL_GOAL_KIND)
            self.assertEqual(state["status"], "completed")
            self.assertEqual(len(state["iterations"]), 2)
            self.assertFalse(state["task"]["raw_persisted"])
            self.assertNotEqual(
                state["iterations"][0]["workflow_fingerprint"],
                state["iterations"][1]["workflow_fingerprint"],
            )
            self.assertFalse(state["iterations"][0]["feedback_input"]["present"])
            self.assertTrue(state["iterations"][1]["feedback_input"]["present"])
            self.assertEqual(state["planner"]["session"]["mode"], "same-session")
            self.assertEqual(state["planner"]["session"]["id"], FAKE_CODEX_SESSION_ID)
            self.assertEqual(
                state["planner"]["session"]["id_sha256"],
                hashlib.sha256(FAKE_CODEX_SESSION_ID.encode("utf-8")).hexdigest(),
            )
            self.assertEqual(state["planner"]["session"]["turns"], 2)
            self.assertEqual(state["iterations"][0]["planner_session"]["mode"], "started")
            self.assertEqual(state["iterations"][1]["planner_session"]["mode"], "resumed")
            self.assertNotIn("id", state["iterations"][1]["planner_session"])
            self.assertNotIn("modelgoalsecret", result.goal_path.read_text(encoding="utf-8"))
            self.assertEqual(len(list(conductor_home.glob("workspaces/*/generated/model-workflows/*.run-receipt.json"))), 2)
            self.assertFalse((root / ".codex-conductor").exists())

    def test_run_model_goal_replans_from_private_completion_verdict_feedback(self):
        planner_prompts = []
        planner_calls = 0
        worker_prompts = []
        feedback = "Replan to cover the missing parser boundary case."
        verdicts = [
            {
                "satisfied": False,
                "feedback": feedback,
                "evidence": ["The parser boundary case is not covered."],
                "confidence": "high",
            },
            {
                "satisfied": True,
                "feedback": "",
                "evidence": ["The replanned review covers the parser boundary case."],
                "confidence": "high",
            },
        ]

        def fake_model_planner(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            nonlocal planner_calls
            planner_calls += 1
            planner_prompts.append(input_text)
            generated = {
                "schema": "conductor.workflow.v1",
                "name": "completion-adaptive-%d" % planner_calls,
                "description": "Completion-verdict adaptive fixture.",
                "mode": "review",
                "risk": "medium",
                "max_workers": 1,
                "steps": [
                    {
                        "id": "final-review",
                        "kind": "codex_exec",
                        "risk": "medium",
                        "sandbox": "read-only",
                        "prompt": "Review the current workspace against the task.",
                        "capture": "final-review.json",
                        "effort": "high",
                        "max_tokens": 4000,
                        "completion_verdict": "strict-v1",
                    }
                ],
            }
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(json.dumps(generated), encoding="utf-8")
            return ProcessResult(
                0,
                "\n".join(
                    [
                        json.dumps(
                            {
                                "type": "thread.started",
                                "thread_id": FAKE_CODEX_SESSION_ID,
                            }
                        ),
                        json.dumps({"type": "turn.completed"}),
                    ]
                )
                + "\n",
                "",
            )

        def fake_worker(
            self,
            argv,
            cwd,
            timeout,
            input_text=None,
            output_limit_bytes=None,
            stdout_line_callback=None,
        ):
            worker_prompts.append(input_text)
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(json.dumps(verdicts.pop(0)), encoding="utf-8")
            return ProcessResult(0, "", "")

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            conductor_home = root / "conductor-home"
            with patch.dict(os.environ, {"CODEX_CONDUCTOR_HOME": str(conductor_home)}):
                with patch(
                    "conductor_extras.runtime.model_planner.run_process",
                    side_effect=fake_model_planner,
                ):
                    with patch.object(WorkflowRunner, "_run_process", new=fake_worker):
                        with patch(
                            "conductor_extras.runtime.goal_loop.run_process",
                            return_value=ProcessResult(0, "verified", ""),
                        ) as verifier:
                            result = run_model_goal_loop(
                                task="Review parser boundary behavior.",
                                workspace=root,
                                runs_dir=root / "runs",
                                goals_dir=root / "goals",
                                policy=RuntimePolicy(
                                    allow_agent=True,
                                    approvals={MODEL_WORKFLOW_EXECUTE_APPROVAL},
                                ),
                                check_command=["true"],
                                check_prompt=None,
                                max_iterations=2,
                                goal_id="completion-model-goal",
                                max_workers=1,
                                max_items=10,
                                max_steps=4,
                            )

            self.assertEqual(result.status, "completed")
            self.assertEqual(result.iterations, 2)
            self.assertEqual(planner_calls, 2)
            self.assertEqual(len(worker_prompts), 2)
            self.assertEqual(verifier.call_count, 1)
            self.assertNotIn(feedback, planner_prompts[0])
            self.assertIn(feedback, planner_prompts[1])
            state_text = result.goal_path.read_text(encoding="utf-8")
            state = json.loads(state_text)
            self.assertEqual(
                [entry["status"] for entry in state["iterations"]],
                ["completion_not_satisfied", "goal_satisfied"],
            )
            self.assertFalse(state["iterations"][0]["feedback_input"]["present"])
            self.assertTrue(state["iterations"][1]["feedback_input"]["present"])
            self.assertNotIn("check", state["iterations"][0])
            self.assertEqual(
                state["iterations"][0]["completion_verdict"]["schema"],
                "conductor.completion_verdict_feedback.v1",
            )
            self.assertNotIn(feedback, state_text)

