    def test_run_model_goal_resume_replans_with_matching_fingerprints(self):
        planner_calls = 0
        planner_commands = []

        def fake_model_planner(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            nonlocal planner_calls
            planner_calls += 1
            planner_commands.append(list(argv))
            generated = {
                "schema": "conductor.workflow.v1",
                "name": "resume-adaptive-%d" % planner_calls,
                "description": "Resume adaptive fixture.",
                "mode": "review",
                "max_workers": 1,
                "steps": [
                    {
                        "id": "record",
                        "kind": "write_artifact",
                        "output": "resume.md",
                        "content": "resume iteration %d\n" % planner_calls,
                    }
                ],
            }
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(json.dumps(generated), encoding="utf-8")
            return ProcessResult(
                0,
                json.dumps({"type": "thread.started", "thread_id": FAKE_CODEX_SESSION_ID}) + "\n",
                "",
            )

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            conductor_home = root / "conductor-home"
            policy = RuntimePolicy(allow_agent=True, approvals={MODEL_WORKFLOW_EXECUTE_APPROVAL})
            with patch.dict(os.environ, {"CODEX_CONDUCTOR_HOME": str(conductor_home)}):
                with patch("conductor_extras.runtime.model_planner.run_process", side_effect=fake_model_planner):
                    with patch(
                        "conductor_extras.runtime.goal_loop.run_process",
                        side_effect=[ProcessResult(1, "still missing", ""), ProcessResult(0, "verified", "")],
                    ):
                        first = run_model_goal_loop(
                            task="Produce resumable evidence.",
                            workspace=root,
                            runs_dir=root / "runs",
                            goals_dir=root / "goals",
                            policy=policy,
                            check_command=["true"],
                            check_prompt=None,
                            max_iterations=1,
                            goal_id="resume-adaptive-goal",
                            max_items=10,
                            max_steps=4,
                        )
                        self.assertEqual(first.status, "max_iterations_exhausted")
                        planner_calls_before_mismatch = planner_calls
                        with self.assertRaisesRegex(ValidationError, "task does not match"):
                            run_model_goal_loop(
                                task="A different objective.",
                                workspace=root,
                                runs_dir=root / "runs",
                                goals_dir=root / "goals",
                                policy=policy,
                                check_command=["true"],
                                check_prompt=None,
                                max_iterations=2,
                                resume_goal=first.goal_path,
                                max_items=10,
                                max_steps=4,
                            )
                        self.assertEqual(planner_calls, planner_calls_before_mismatch)
                        with self.assertRaisesRegex(ValidationError, "configuration fingerprint"):
                            run_model_goal_loop(
                                task="Produce resumable evidence.",
                                workspace=root,
                                runs_dir=root / "runs",
                                goals_dir=root / "goals",
                                policy=policy,
                                check_command=["true"],
                                check_prompt=None,
                                max_iterations=2,
                                resume_goal=first.goal_path,
                                max_items=10,
                                max_steps=4,
                                reuse_planner_session=False,
                            )
                        self.assertEqual(planner_calls, planner_calls_before_mismatch)
                        other_workspace = root / "other-workspace"
                        other_workspace.mkdir()
                        with self.assertRaisesRegex(ValidationError, "configuration fingerprint"):
                            run_model_goal_loop(
                                task="Produce resumable evidence.",
                                workspace=other_workspace,
                                runs_dir=root / "runs",
                                goals_dir=root / "goals",
                                policy=policy,
                                check_command=["true"],
                                check_prompt=None,
                                max_iterations=2,
                                resume_goal=first.goal_path,
                                max_items=10,
                                max_steps=4,
                            )
                        self.assertEqual(planner_calls, planner_calls_before_mismatch)
                        original_goal = first.goal_path.read_text(encoding="utf-8")
                        tampered_goal = json.loads(original_goal)
                        tampered_goal["planner"]["session"]["id_sha256"] = "0" * 64
                        first.goal_path.write_text(json.dumps(tampered_goal), encoding="utf-8")
                        with self.assertRaisesRegex(ValidationError, "session identity metadata"):
                            run_model_goal_loop(
                                task="Produce resumable evidence.",
                                workspace=root,
                                runs_dir=root / "runs",
                                goals_dir=root / "goals",
                                policy=policy,
                                check_command=["true"],
                                check_prompt=None,
                                max_iterations=2,
                                resume_goal=first.goal_path,
                                max_items=10,
                                max_steps=4,
                            )
                        first.goal_path.write_text(original_goal, encoding="utf-8")
                        self.assertEqual(planner_calls, planner_calls_before_mismatch)
                        second = run_model_goal_loop(
                            task="Produce resumable evidence.",
                            workspace=root,
                            runs_dir=root / "runs",
                            goals_dir=root / "goals",
                            policy=policy,
                            check_command=["true"],
                            check_prompt=None,
                            max_iterations=2,
                            resume_goal=first.goal_path,
                            max_items=10,
                            max_steps=4,
                        )

            self.assertEqual(second.status, "completed")
            self.assertEqual(second.iterations, 2)
            self.assertEqual(planner_calls, 2)
            self.assertEqual(planner_commands[1][:3], ["codex", "exec", "resume"])
            self.assertIn(FAKE_CODEX_SESSION_ID, planner_commands[1])
            state = load_goal_state(second.goal_path)
            self.assertEqual(len(state["resumes"]), 1)
            self.assertEqual(state["iterations"][1]["status"], "goal_satisfied")
            self.assertEqual(state["planner"]["session"]["turns"], 2)
            self.assertEqual(state["iterations"][1]["planner_session"]["mode"], "resumed")

    def test_run_model_goal_supports_fail_closed_model_verification(self):
        verifier_commands = []
        verifier_prompts = []
        generated = {
            "schema": "conductor.workflow.v1",
            "name": "adaptive-model-verifier-workflow",
            "description": "Model verifier fixture.",
            "mode": "review",
            "max_workers": 1,
            "steps": [
                {
                    "id": "record",
                    "kind": "write_artifact",
                    "output": "model-verifier.md",
                    "content": "model verifier evidence\n",
                }
            ],
        }

        def fake_model_planner(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(json.dumps(generated), encoding="utf-8")
            return ProcessResult(0, "", "")

        def fake_model_verifier(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            verifier_commands.append(list(argv))
            verifier_prompts.append(input_text)
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(
                json.dumps(
                    {
                        "satisfied": True,
                        "feedback": "",
                        "evidence": ["model-verifier.md exists in the completed run evidence"],
                        "confidence": "high",
                    }
                ),
                encoding="utf-8",
            )
            return ProcessResult(
                0,
                json.dumps(
                    {
                        "type": "turn.completed",
                        "model": "codex-verifier-test",
                        "usage": {"input_tokens": 9, "output_tokens": 4, "total_tokens": 13},
                    }
                )
                + "\n",
                "",
            )

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            conductor_home = root / "conductor-home"
            with patch.dict(os.environ, {"CODEX_CONDUCTOR_HOME": str(conductor_home)}):
                with patch("conductor_extras.runtime.model_planner.run_process", side_effect=fake_model_planner):
                    with patch("conductor_extras.runtime.goal_loop.run_process", side_effect=fake_model_verifier):
                        result = run_model_goal_loop(
                            task="Create model-verified evidence.",
                            workspace=root,
                            runs_dir=root / "runs",
                            goals_dir=root / "goals",
                            policy=RuntimePolicy(
                                allow_agent=True,
                                approvals={MODEL_WORKFLOW_EXECUTE_APPROVAL},
                            ),
                            check_command=None,
                            check_prompt="The completed run contains concrete model verifier evidence.",
                            max_iterations=2,
                            goal_id="adaptive-model-verifier-goal",
                            max_items=10,
                            max_steps=4,
                        )
            self.assertEqual(result.status, "completed")
            state = load_goal_state(result.goal_path)
            check = state["iterations"][0]["check"]
            self.assertEqual(check["kind"], "model")
            self.assertEqual(check["status"], "passed")
            self.assertEqual(check["usage"]["total_tokens"], 13)
            self.assertTrue(check["verdict"]["satisfied"])
            self.assertEqual(check["policy"]["effort"], MODEL_VERIFIER_EFFORT)
            self.assertEqual(check["policy"]["max_tokens"], MODEL_VERIFIER_MAX_TOKENS)
            self.assertEqual(check["policy"]["policy_version"], MODEL_VERIFIER_POLICY_VERSION)
            self.assertTrue(check["policy"]["isolated_profile"])
            self.assertTrue(check["policy"]["ephemeral_session"])
            self.assertEqual(state["verifier"]["effort"], MODEL_VERIFIER_EFFORT)
            self.assertEqual(state["verifier"]["max_tokens"], MODEL_VERIFIER_MAX_TOKENS)
            command = verifier_commands[0]
            self.assertIn('model_reasoning_effort="high"', command)
            self.assertTrue(any("limit_tokens=8000" in value for value in command))
            self.assertIn("--ephemeral", command)
            self.assertIn("--ignore-user-config", command)
            command_pairs = [command[index : index + 2] for index in range(len(command) - 1)]
            self.assertIn(["--disable", "code_mode_host"], command_pairs)
            self.assertIn(["--disable", "unified_exec"], command_pairs)
            self.assertIn(
                "hard rollout ceiling for this call is 8000 weighted tokens",
                verifier_prompts[0],
            )
            self.assertIn("50%-remaining point (4000 tokens remaining)", verifier_prompts[0])

