    @unittest.skipUnless(os.name == "posix", "background model goals require POSIX session isolation")
    def test_background_model_goal_cli_completes_without_persisting_task_or_approvals(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            fake_bin = install_fake_codex(root)
            goals_dir = root / "goals"
            runs_dir = root / "runs"
            secret = "detachedmodelgoalsecret"
            approval = "ephemeral-background-approval"
            stdout = StringIO()
            environment = {
                "PATH": "%s%s%s" % (fake_bin, os.pathsep, os.environ.get("PATH", "")),
                "CODEX_CONDUCTOR_HOME": str(root / "conductor-home"),
            }
            with patch.dict(os.environ, environment):
                with redirect_stdout(stdout):
                    code = cli_main(
                        [
                            "run-model-goal",
                            "--task",
                            "Produce detached evidence with token=%s." % secret,
                            "--check-command-json",
                            '["true"]',
                            "--workspace",
                            str(root),
                            "--runs-dir",
                            str(runs_dir),
                            "--goals-dir",
                            str(goals_dir),
                            "--goal-id",
                            "background-model-goal-success",
                            "--max-items",
                            "10",
                            "--max-steps",
                            "4",
                            "--background",
                            "--allow-agent",
                            "--approve",
                            MODEL_WORKFLOW_EXECUTE_APPROVAL,
                            "--approve",
                            approval,
                        ]
                    )
                self.assertEqual(code, 0)
                self.assertRegex(stdout.getvalue(), r"Status: (active|finished)")
                metadata_path = next((goals_dir / "background-workers").glob("*.json"))
                launched = load_background_model_goal(metadata_path)
                worker_pid = launched["worker"]["pid"]
                self.assertTrue(launched["worker"]["ready"])
                self.assertIn(background_model_goal_liveness(launched), {"alive", "finished"})

                status_stdout = StringIO()
                with redirect_stdout(status_stdout):
                    self.assertEqual(cli_main(["status-background-model-goal", str(metadata_path)]), 0)
                status = json.loads(status_stdout.getvalue())
                self.assertEqual(status["schema"], "conductor.background_model_goal_status.v1")
                self.assertIn(status["liveness"], {"alive", "finished"})

                wait_stdout = StringIO()
                with redirect_stdout(wait_stdout):
                    wait_code = cli_main(
                        [
                            "wait-background-model-goal",
                            str(metadata_path),
                            "--timeout-seconds",
                            "10",
                            "--poll-interval-ms",
                            "50",
                        ]
                    )
                self.assertEqual(wait_code, 0)
                final = json.loads(wait_stdout.getvalue())
                self.assertEqual(final["schema"], BACKGROUND_MODEL_GOAL_SCHEMA)
                self.assertEqual(final["status"], "finished")
                self.assertEqual(final["goal_status"], "completed")
                self.assertEqual(final["exit_code"], 0)

            goal_path = goals_dir / "background-model-goal-success.json"
            goal = load_goal_state(goal_path)
            self.assertEqual(goal["status"], "completed")
            self.assertFalse(goal["planner"]["foreground"])
            self.assertEqual(goal["iterations"][0]["status"], "goal_satisfied")
            self.assertEqual(goal["planner"]["session"]["id"], FAKE_CODEX_SESSION_ID)
            self.assertEqual(goal["planner"]["session"]["turns"], 1)
            self.assertEqual(latest_background_model_goal(goals_dir, goal["goal_id"])["liveness"], "finished")

            validate_stdout = StringIO()
            with redirect_stdout(validate_stdout):
                self.assertEqual(cli_main(["validate-background-model-goal", str(metadata_path)]), 0)
            self.assertIn("OK:", validate_stdout.getvalue())

            list_stdout = StringIO()
            with redirect_stdout(list_stdout):
                self.assertEqual(cli_main(["list-goals", "--goals-dir", str(goals_dir), "--json"]), 0)
            listed = json.loads(list_stdout.getvalue())
            self.assertEqual(listed["goals"][0]["background"]["goal_status"], "completed")
            self.assertEqual(listed["goals"][0]["planner_session"]["mode"], "same-session")
            self.assertTrue(listed["goals"][0]["planner_session"]["available"])
            self.assertEqual(listed["goals"][0]["planner_session"]["turns"], 1)
            self.assertNotIn(FAKE_CODEX_SESSION_ID, list_stdout.getvalue())

            dashboard_path = root / "background-model-goal-dashboard.html"
            write_dashboard(runs_dir, root / "benchmarks", dashboard_path, goals_dir=goals_dir)
            dashboard_html = dashboard_path.read_text(encoding="utf-8")
            self.assertIn("Worker", dashboard_html)
            self.assertIn("Planner: same-session / available / 1 turns", dashboard_html)
            self.assertNotIn(FAKE_CODEX_SESSION_ID, dashboard_html)
            detail = collect_goal_detail(goals_dir, goal_handle(goal_path.name))
            self.assertEqual(detail["background"]["status"], "finished")
            self.assertEqual(detail["planner_session"]["turns"], 1)
            live_html = render_live_goal_detail(detail)
            self.assertIn("Detached worker", live_html)
            self.assertIn("goal completed", live_html)
            self.assertIn("same-session / available / 1 turns", live_html)
            self.assertNotIn(FAKE_CODEX_SESSION_ID, live_html)

            persisted = "\n".join(
                [
                    metadata_path.read_text(encoding="utf-8"),
                    (metadata_path.parent / final["logs"]["stdout"]).read_text(encoding="utf-8"),
                    (metadata_path.parent / final["logs"]["stderr"]).read_text(encoding="utf-8"),
                    goal_path.read_text(encoding="utf-8"),
                ]
            )
            self.assertNotIn(secret, persisted)
            self.assertNotIn(approval, persisted)
            self.assertFalse(final["task"]["raw_persisted"])
            self.assertFalse(final["policy"]["approval_values_persisted"])
            self.assertFalse(final["handoff"]["payload_persisted"])
            try:
                os.waitpid(worker_pid, 0)
            except ChildProcessError:
                pass

            tampered = copy.deepcopy(final)
            tampered["handoff"]["payload_persisted"] = True
            with self.assertRaisesRegex(ValidationError, "handoff contract"):
                validate_background_model_goal(tampered)

