    def test_background_model_goal_resumes_matching_foreground_goal(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            fake_bin = install_fake_codex(root)
            goals_dir = root / "goals"
            goal_path = goals_dir / "background-model-goal-resume.json"
            common = [
                "--task",
                "Resume the same adaptive goal after external evidence appears.",
                "--check-command-json",
                '["test","-f","complete.marker"]',
                "--workspace",
                str(root),
                "--runs-dir",
                str(root / "runs"),
                "--goals-dir",
                str(goals_dir),
                "--goal-id",
                "background-model-goal-resume",
                "--allow-agent",
                "--approve",
                MODEL_WORKFLOW_EXECUTE_APPROVAL,
            ]
            environment = {
                "PATH": "%s%s%s" % (fake_bin, os.pathsep, os.environ.get("PATH", "")),
                "CODEX_CONDUCTOR_HOME": str(root / "conductor-home"),
            }
            with patch.dict(os.environ, environment):
                with redirect_stdout(StringIO()):
                    first_code = cli_main(["run-model-goal"] + common + ["--max-iterations", "1"])
                self.assertEqual(first_code, 1)
                first = load_goal_state(goal_path)
                self.assertEqual(first["status"], "max_iterations_exhausted")
                self.assertTrue(first["planner"]["foreground"])
                (root / "complete.marker").write_text("ready\n", encoding="utf-8")

                with redirect_stdout(StringIO()):
                    resume_code = cli_main(
                        ["run-model-goal"]
                        + common
                        + [
                            "--resume-goal",
                            str(goal_path),
                            "--max-iterations",
                            "2",
                            "--background",
                        ]
                    )
                self.assertEqual(resume_code, 0)
                metadata_path = next((goals_dir / "background-workers").glob("*.json"))
                final = wait_for_background_model_goal(
                    metadata_path,
                    timeout_seconds=10,
                    poll_interval_seconds=0.05,
                )
                self.assertEqual(final["goal_status"], "completed")
                self.assertTrue(final["goal"]["resumed"])
                worker_pid = final["worker"]["pid"]

            resumed = load_goal_state(goal_path)
            self.assertEqual(resumed["status"], "completed")
            self.assertEqual(len(resumed["iterations"]), 2)
            self.assertEqual(len(resumed["resumes"]), 1)
            self.assertFalse(resumed["planner"]["foreground"])
            self.assertEqual(resumed["planner"]["session"]["id"], FAKE_CODEX_SESSION_ID)
            self.assertEqual(resumed["planner"]["session"]["turns"], 2)
            self.assertEqual(resumed["iterations"][0]["planner_session"]["mode"], "started")
            self.assertEqual(resumed["iterations"][1]["planner_session"]["mode"], "resumed")
            try:
                os.waitpid(worker_pid, 0)
            except ChildProcessError:
                pass

