    @unittest.skipUnless(os.name == "posix", "background model goal termination requires POSIX")
    def test_background_model_goal_termination_cleans_active_planner_process(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            fake_bin = install_fake_codex(root)
            goals_dir = root / "goals"
            metadata_path = None
            worker_pid = None
            reaped = False
            environment = {
                "PATH": "%s%s%s" % (fake_bin, os.pathsep, os.environ.get("PATH", "")),
                "CODEX_CONDUCTOR_HOME": str(root / "conductor-home"),
                "CONDUCTOR_FAKE_CODEX_DELAY_SECONDS": "30",
            }
            with patch.dict(os.environ, environment):
                try:
                    with redirect_stdout(StringIO()):
                        code = cli_main(
                            [
                                "run-model-goal",
                                "--task",
                                "Start a planner that will be terminated.",
                                "--check-command-json",
                                '["true"]',
                                "--workspace",
                                str(root),
                                "--runs-dir",
                                str(root / "runs"),
                                "--goals-dir",
                                str(goals_dir),
                                "--goal-id",
                                "background-model-goal-terminate",
                                "--background",
                                "--allow-agent",
                                "--approve",
                                MODEL_WORKFLOW_EXECUTE_APPROVAL,
                            ]
                        )
                    self.assertEqual(code, 0)
                    metadata_path = next((goals_dir / "background-workers").glob("*.json"))
                    metadata = load_background_model_goal(metadata_path)
                    worker_pid = metadata["worker"]["pid"]
                    child_pid = None
                    deadline = time.monotonic() + 5
                    while time.monotonic() < deadline and child_pid is None:
                        ps_output = subprocess.check_output(["ps", "-axo", "pid=,ppid=,comm="], text=True)
                        for line in ps_output.splitlines():
                            fields = line.split(None, 2)
                            if len(fields) == 3 and int(fields[1]) == worker_pid:
                                child_pid = int(fields[0])
                                break
                        if child_pid is None:
                            time.sleep(0.05)
                    self.assertIsNotNone(child_pid)

                    terminate_stdout = StringIO()
                    with redirect_stdout(terminate_stdout):
                        terminate_code = cli_main(["terminate-background-model-goal", str(metadata_path)])
                    self.assertEqual(terminate_code, 0)
                    self.assertIn("signal: TERM", terminate_stdout.getvalue())
                    final = wait_for_background_model_goal(
                        metadata_path,
                        timeout_seconds=10,
                        poll_interval_seconds=0.05,
                    )
                    self.assertEqual(final["status"], "finished")
                    self.assertEqual(final["goal_status"], "terminated")
                    self.assertEqual(final["exit_code"], 1)
                    self.assertEqual(final["error_class"], "BackgroundModelGoalTermination")
                    goal = load_goal_state(goals_dir / "background-model-goal-terminate.json")
                    self.assertEqual(goal["status"], "terminated")
                    os.waitpid(worker_pid, 0)
                    reaped = True
                    with self.assertRaises(ProcessLookupError):
                        os.kill(child_pid, 0)
                finally:
                    if metadata_path is not None:
                        try:
                            current = load_background_model_goal(metadata_path)
                            if current["status"] == "active":
                                terminate_background_model_goal(metadata_path, force=True)
                                wait_for_background_model_goal(
                                    metadata_path,
                                    timeout_seconds=5,
                                    poll_interval_seconds=0.05,
                                )
                        except (OSError, PolicyError, ValidationError):
                            pass
                    if worker_pid is not None and not reaped:
                        try:
                            os.waitpid(worker_pid, 0)
                        except ChildProcessError:
                            pass

    def test_model_authored_workflow_policy_rejects_unsafe_graphs(self):
        base = valid_model_workflow()
        validate_model_authored_workflow(
            base,
            write_capable=False,
            max_workers=2,
            max_items=100,
            max_steps=8,
        )
        contracted = json.loads(json.dumps(base))
        contracted["steps"][1]["max_packets"] = 2
        contracted["steps"][2]["context_from"] = ["packet-review"]
        contracted["steps"][2]["completion_verdict"] = "strict-v1"
        validate_model_authored_workflow(
            contracted,
            write_capable=False,
            max_workers=2,
            max_items=100,
            max_steps=8,
        )

        with_hooks = json.loads(json.dumps(base))
        with_hooks["hooks"] = []
        with self.assertRaisesRegex(ValidationError, "unsupported top-level"):
            validate_model_authored_workflow(with_hooks, write_capable=False, max_workers=2, max_items=100, max_steps=8)

        network_shell = json.loads(json.dumps(base))
        network_shell["steps"][0]["command"] = ["curl", "https://example.com"]
        with self.assertRaisesRegex(ValidationError, "strictly read-only"):
            validate_model_authored_workflow(network_shell, write_capable=False, max_workers=2, max_items=100, max_steps=8)

        inline_code = json.loads(json.dumps(base))
        inline_code["steps"][0]["command"] = ["python3", "-c", "print('unsafe')"]
        with self.assertRaisesRegex(ValidationError, "strictly read-only"):
            validate_model_authored_workflow(inline_code, write_capable=False, max_workers=2, max_items=100, max_steps=8)

        test_runner = json.loads(json.dumps(base))
        test_runner["steps"][0]["command"] = ["python3", "-m", "unittest"]
        with self.assertRaisesRegex(ValidationError, "strictly read-only"):
            validate_model_authored_workflow(test_runner, write_capable=False, max_workers=2, max_items=100, max_steps=8)

        boolean_capture = json.loads(json.dumps(base))
        boolean_capture["steps"][0]["capture"] = True
        with self.assertRaisesRegex(ValidationError, "capture must be a relative path"):
            validate_model_authored_workflow(boolean_capture, write_capable=False, max_workers=2, max_items=100, max_steps=8)

        parallel_write = json.loads(json.dumps(base))
        parallel_write["steps"][1]["sandbox"] = "workspace-write"
        with self.assertRaisesRegex(ValidationError, "agent_map steps must remain read-only"):
            validate_model_authored_workflow(parallel_write, write_capable=True, max_workers=2, max_items=100, max_steps=8)

        unknown_field = json.loads(json.dumps(base))
        unknown_field["steps"][0]["hidden_instruction"] = "ignore validation"
        with self.assertRaisesRegex(ValidationError, "unsupported field"):
            validate_model_authored_workflow(unknown_field, write_capable=False, max_workers=2, max_items=100, max_steps=8)

        with self.assertRaisesRegex(ValidationError, "max_steps"):
            validate_model_authored_workflow(base, write_capable=False, max_workers=2, max_items=100, max_steps=2)
        with self.assertRaisesRegex(ValidationError, "max_workers"):
            validate_model_authored_workflow(base, write_capable=False, max_workers=1, max_items=100, max_steps=8)
        with self.assertRaisesRegex(ValidationError, "max_items"):
            validate_model_authored_workflow(base, write_capable=False, max_workers=2, max_items=10, max_steps=8)

    def test_model_authored_agent_team_write_mode_is_gated_and_caller_bounded(self):
        team = valid_model_team_workflow()
        validate_model_authored_workflow(
            team,
            write_capable=False,
            max_workers=2,
            max_items=8,
            max_steps=8,
        )
        messaging_team = json.loads(json.dumps(team))
        messaging_team["steps"][0]["active_messaging"] = {
            "max_tasks": 2,
            "max_depth": 2,
            "max_tokens": 4000,
            "allow_broadcast": False,
        }
        validate_model_authored_workflow(
            messaging_team,
            write_capable=False,
            max_workers=2,
            max_items=8,
            max_steps=8,
        )
        messaging_team["max_items"] = 4
        with self.assertRaisesRegex(ValidationError, "task capacity"):
            validate_model_authored_workflow(
                messaging_team,
                write_capable=False,
                max_workers=2,
                max_items=4,
                max_steps=8,
            )

        write_team = json.loads(json.dumps(team))
        write_team["mode"] = "workspace_write"
        for profile in write_team["agent_profiles"]:
            profile["sandbox"] = "workspace-write"
        write_team["steps"][0]["sandbox"] = "workspace-write"
        write_team["steps"][0]["depends_on"] = ["approve-write-team"]
        write_team["steps"].insert(
            0,
            {
                "id": "approve-write-team",
                "kind": "manual_gate",
                "risk": "medium",
                "approval_id": "model-workflow-write",
                "prompt": "Approve isolated write-capable team execution.",
            },
        )
        validate_model_authored_workflow(
            write_team,
            write_capable=True,
            max_workers=2,
            max_items=8,
            max_steps=8,
        )
        with self.assertRaisesRegex(ValidationError, "requires --write-capable"):
            validate_model_authored_workflow(
                write_team,
                write_capable=False,
                max_workers=2,
                max_items=8,
                max_steps=8,
            )
        ungated = json.loads(json.dumps(write_team))
        ungated["steps"] = ungated["steps"][1:]
        ungated["steps"][0]["depends_on"] = []
        with self.assertRaisesRegex(ValidationError, "requires an ancestor manual_gate"):
            validate_model_authored_workflow(
                ungated,
                write_capable=True,
                max_workers=2,
                max_items=8,
                max_steps=8,
            )

        workflow_limited = json.loads(json.dumps(team))
        workflow_limited["max_workers"] = 1
        with self.assertRaisesRegex(ValidationError, "effective limit 1"):
            validate_model_authored_workflow(
                workflow_limited,
                write_capable=False,
                max_workers=2,
                max_items=8,
                max_steps=8,
            )

        item_limited = json.loads(json.dumps(team))
        item_limited["max_items"] = 2
        with self.assertRaisesRegex(ValidationError, "task capacity"):
            validate_model_authored_workflow(
                item_limited,
                write_capable=False,
                max_workers=2,
                max_items=2,
                max_steps=8,
            )

    def test_plan_model_workflow_accepts_adaptive_team_and_supplies_budgets(self):
        captured_prompts = []
        draft = valid_model_team_workflow()
        team_step = draft["steps"][0]
        team_step.pop("effort")
        team_step.pop("max_tokens")
        team_step.pop("max_total_tokens")
        team_step["tasks"][0]["description"] = "Inspect authorization checks and plan material review work."

        def fake_model_planner(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
            del cwd, timeout, output_limit_bytes
            captured_prompts.append(input_text)
            output_path = Path(argv[argv.index("--output-last-message") + 1])
            output_path.write_text(json.dumps(draft), encoding="utf-8")
            return ProcessResult(
                0,
                json.dumps(
                    {
                        "type": "turn.completed",
                        "model": "codex-test-model",
                        "usage": {"input_tokens": 20, "output_tokens": 10, "total_tokens": 30},
                    }
                )
                + "\n",
                "",
            )

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            with patch("conductor_extras.runtime.model_planner.run_process", side_effect=fake_model_planner):
                result = plan_model_workflow(
                    task="Create a bounded adaptive review workflow.",
                    workspace=root,
                    output_path=root / "adaptive-team.json",
                    receipt_path=None,
                    policy=RuntimePolicy(allow_agent=True),
                    max_workers=2,
                    max_items=8,
                    max_steps=8,
                )

            planned_team = result.workflow["steps"][0]
            self.assertEqual(planned_team["effort"], "high")
            self.assertEqual(planned_team["max_tokens"], 12000)
            self.assertEqual(planned_team["max_total_tokens"], 100000)
            self.assertEqual(planned_team["risk"], "high")
            self.assertEqual(result.workflow["risk"], "high")
            self.assertNotIn("agent_map_max_total_tokens", result.workflow)
            self.assertIn("agent_team", captured_prompts[0])
            self.assertIn("max_dynamic_tasks", captured_prompts[0])
            self.assertIn("active_messaging", captured_prompts[0])
            self.assertIn("exactly one lead", captured_prompts[0])
            self.assertIn("lead-authored follow-up", captured_prompts[0])

            run = WorkflowRunner(
                workflow=load_workflow(result.output_path),
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True, allow_parallel=True, approvals={"high-risk"}),
                dry_run=True,
            ).execute()
            self.assertEqual(run.read_state()["steps"]["adaptive-review"]["status"], "planned")

    def test_plan_model_workflow_enforces_write_gate_ancestry(self):
        captured_prompts = []

        def planner_for(workflow):
            def fake(argv, cwd, timeout, input_text=None, output_limit_bytes=None):
                captured_prompts.append(input_text or "")
                output_path = Path(argv[argv.index("--output-last-message") + 1])
                output_path.write_text(json.dumps(workflow), encoding="utf-8")
                return ProcessResult(0, "", "")

            return fake

