            self.assertNotIn("stdoutsecret", serialized)

            all_goals = collect_goals(goals, max_goals=4)
            by_name = {goal["name"]: goal for goal in all_goals}
            self.assertEqual(by_name["bad-schema.json"]["status"], "invalid")
            self.assertEqual(by_name["malformed.json"]["status"], "invalid")
            self.assertNotIn("badsecret", json.dumps(all_goals, default=str))
            malformed_detail = collect_goal_detail(goals, goal_handle("malformed.json"))
            self.assertEqual(malformed_detail["status"], "invalid")
            self.assertEqual(malformed_detail["iterations_detail"], [])
            self.assertNotIn("badsecret", json.dumps(malformed_detail, default=str))

            output = root / "dashboard.html"
