            self.assertIn("visible-goal", html)
            self.assertIn("max_iterations_exhausted", html)
            self.assertIn("run-goal --resume-goal", html)
            self.assertIn("workflow &lt;script&gt;alert(1)&lt;/script&gt; token=&lt;redacted&gt;", html)
            self.assertNotIn("<script>alert(1)</script>", html)
            self.assertNotIn("goalsecret", html)
            self.assertNotIn("runsecret", html)
            self.assertNotIn("stdoutsecret", html)
            self.assertNotIn("badsecret", html)

            payload = build_live_payload(runs, benchmarks, goals_dir=goals, max_goals=4)
            self.assertEqual(payload["goals"][0]["goal_id"], "visible-goal")
            self.assertNotIn("path", payload["goals"][0])
            payload_text = json.dumps(payload)
