            self.assertIn("Resume with a higher --max-iterations cap", live_html)
            self.assertIn("workflow &lt;script&gt;alert(1)&lt;/script&gt; token=&lt;redacted&gt;", live_html)
            self.assertNotIn("<script>alert(1)</script>", live_html)
            self.assertNotIn("goalsecret", live_html)
            self.assertNotIn("runsecret", live_html)
            self.assertNotIn("stdoutsecret", live_html)

