            goals.mkdir()
            iterations = []
            for index in range(105):
                iteration = index + 1
                check = {
                    "status": "passed" if iteration == 105 else "failed",
                    "returncode": 0 if iteration == 105 else 1,
                    "started_at_utc": "2026-07-08T00:%02d:00Z" % (iteration % 60),
                    "finished_at_utc": "2026-07-08T00:%02d:01Z" % (iteration % 60),
                    "stdout_bytes": iteration,
                    "stderr_bytes": iteration + 1,
                    "stdout_truncated": iteration == 104,
                    "stderr_truncated": iteration == 105,
                    "stdout_excerpt": "token=stdoutsecret-%03d <script>alert(1)</script>" % iteration,
                    "stderr_excerpt": "token=stderrsecret-%03d" % iteration,
                }
                iterations.append(
                    {
                        "iteration": iteration,
                        "run_id": "run-%03d token=runsecret" % iteration,
                        "run_status": "completed",
                        "status": "goal_satisfied" if iteration == 105 else "goal_not_satisfied",
                        "started_at_utc": "2026-07-08T01:%02d:00Z" % (iteration % 60),
                        "finished_at_utc": "2026-07-08T01:%02d:01Z" % (iteration % 60),
                        "check": check,
                    }
                )
            write_json(
                goals / "visible.json",
                {
                    "schema": "conductor.goal_loop.v1",
                    "goal_id": "visible-goal",
                    "workflow": "workflow <script>alert(1)</script> token=goalsecret",
                    "status": "max_iterations_exhausted",
                    "started_at_utc": "2026-07-08T00:00:00Z",
                    "updated_at_utc": "2026-07-08T02:00:00Z",
                    "max_iterations": 120,
                    "iterations": iterations,
                },
            )
            handle = goal_handle("visible.json")
            detail = collect_goal_detail(goals, handle)
            self.assertEqual(detail["goal_handle"], handle)
            self.assertEqual(detail["iteration_display_count"], 100)
            self.assertTrue(detail["iterations_truncated"])
            self.assertEqual(detail["iterations_detail"][0]["iteration"], 6)
            self.assertEqual(detail["iterations_detail"][-1]["iteration"], 105)
            self.assertTrue(detail["iterations_detail"][-1]["check"]["output_excerpts_omitted"])
            detail_text = json.dumps(detail, default=str)
            self.assertIn("stdout_bytes", detail_text)
            self.assertNotIn("stdoutsecret", detail_text)
            self.assertNotIn("stderrsecret", detail_text)
            self.assertNotIn("runsecret", detail_text)

            output = root / "dashboard.html"
            write_dashboard(runs, benchmarks, output, goals_dir=goals)
            html = output.read_text(encoding="utf-8")
            self.assertIn("Goal Details", html)
            self.assertIn("goal-detail-%s" % handle, html)
            self.assertIn("Showing the latest 100 of 105 iterations.", html)
            self.assertIn("run-105 token=&lt;redacted&gt;", html)
            self.assertIn("excerpts omitted", html)
            self.assertIn("workflow &lt;script&gt;alert(1)&lt;/script&gt; token=&lt;redacted&gt;", html)
            self.assertNotIn("run-001", html)
            self.assertNotIn("stdoutsecret", html)
            self.assertNotIn("stderrsecret", html)
            self.assertNotIn("goalsecret", html)
            self.assertNotIn("<script>alert(1)</script>", html)

            payload = build_live_payload(runs, benchmarks, goals_dir=goals)
            self.assertEqual(payload["goals"][0]["goal_handle"], handle)
            self.assertNotIn("iterations_detail", payload["goals"][0])
            live_html = render_live_dashboard(payload)
            self.assertIn('href="/goal/%s"' % handle, live_html)
            selected_html = render_live_goal_detail(detail)
            self.assertIn("visible-goal", selected_html)
            self.assertIn("Showing the latest 100 of 105 iterations.", selected_html)
            self.assertIn("run-105 token=&lt;redacted&gt;", selected_html)
            self.assertIn("excerpts omitted", selected_html)
            self.assertNotIn("stdoutsecret", selected_html)
            self.assertNotIn("stderrsecret", selected_html)
            self.assertNotIn("<script>alert(1)</script>", selected_html)

            handler_cls = _handler_factory(
                runs_dir=runs,
                benchmarks_dir=benchmarks,
                goals_dir=goals,
                max_runs=50,
                max_reports=50,
                max_text_bytes=4096,
                title="Unit Live",
                control_token="unit-token",
            )
            status, headers, body = self._invoke_live_handler(handler_cls, "GET", "/goal/%s" % handle)
            self.assertEqual(status, 200)
            self.assertEqual(headers["X-Frame-Options"], "DENY")
            self.assertIn("visible-goal", body)
            self.assertNotIn("stdoutsecret", body)
            self.assertNotIn("<script>alert(1)</script>", body)

            status, _headers, body = self._invoke_live_handler(handler_cls, "GET", "/api/goal/%s" % handle)
            self.assertEqual(status, 200)
            api_detail = json.loads(body)
            self.assertEqual(api_detail["goal_handle"], handle)
            self.assertNotIn("path", api_detail)
            api_text = json.dumps(api_detail)
            self.assertNotIn("stdoutsecret", api_text)
            self.assertNotIn("stderrsecret", api_text)
            self.assertNotIn("runsecret", api_text)

            status, _headers, body = self._invoke_live_handler(handler_cls, "GET", "/goal/%2e")
            self.assertEqual(status, 400)
            self.assertIn("goal_handle", json.loads(body)["error"])

