    def test_dashboard_goal_sources_reject_symlinked_goal_dir_and_skip_symlinked_goal_file(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            goals = root / "goals"
            goals.mkdir()
            target_goal = root / "target.json"
            write_json(
                target_goal,
                {
                    "schema": "conductor.goal_loop.v1",
                    "goal_id": "outside-goal",
                    "workflow": "outside token=outsidesecret",
                    "status": "completed",
                    "iterations": [],
                },
            )
            linked_goal = goals / "linked.json"
            try:
                linked_goal.symlink_to(target_goal)
            except OSError:
                self.skipTest("symlinks are not supported on this filesystem")
            self.assertEqual(collect_goals(goals), [])
            handler_cls = _handler_factory(
                runs_dir=root / "runs",
                benchmarks_dir=root / "benchmarks",
                goals_dir=goals,
                max_runs=50,
                max_reports=50,
                max_text_bytes=4096,
                title="Unit Live",
                control_token="unit-token",
            )
            status, _headers, body = self._invoke_live_handler(handler_cls, "GET", "/api/goal/%s" % goal_handle("linked.json"))
            self.assertEqual(status, 400)
            self.assertIn("goal_handle", json.loads(body)["error"])
            self.assertNotIn("outsidesecret", body)

            linked_dir = root / "linked-goals"
            linked_dir.symlink_to(goals, target_is_directory=True)
            with self.assertRaises(ValidationError):
                collect_goals(linked_dir)
            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(
                    [
                        "dashboard",
                        "--runs-dir",
                        str(root / "runs"),
                        "--benchmarks-dir",
                        str(root / "benchmarks"),
                        "--goals-dir",
                        str(linked_dir),
                        "--output",
                        str(root / "dashboard.html"),
                    ]
                )
            self.assertEqual(code, 2)
            self.assertIn("goals_dir must not be a symlink", stderr.getvalue())
            self.assertNotIn("outsidesecret", stderr.getvalue())

