    def test_dashboard_rejects_symlinked_sources_and_output(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            real_runs = root / "real-runs"
            real_runs.mkdir()
            linked_runs = root / "linked-runs"
            try:
                linked_runs.symlink_to(real_runs, target_is_directory=True)
            except OSError:
                self.skipTest("symlinks are not supported on this filesystem")

            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(
                    [
                        "dashboard",
                        "--runs-dir",
                        str(linked_runs),
                        "--benchmarks-dir",
                        str(root / "benchmarks"),
                        "--output",
                        str(root / "dashboard.html"),
                    ]
                )
            self.assertEqual(code, 2)
            self.assertIn("runs_dir must not be a symlink", stderr.getvalue())

            target = root / "target.html"
            target.write_text("original", encoding="utf-8")
            output_link = root / "dashboard-link.html"
            output_link.symlink_to(target)
            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(
                    [
                        "dashboard",
                        "--runs-dir",
                        str(real_runs),
                        "--benchmarks-dir",
                        str(root / "benchmarks"),
                        "--output",
                        str(output_link),
                    ]
                )
            self.assertEqual(code, 2)
            self.assertIn("output must not be a symlink", stderr.getvalue())
            self.assertEqual(target.read_text(encoding="utf-8"), "original")

            real_parent = root / "real-parent"
            real_parent.mkdir()
            linked_parent = root / "linked-parent"
            try:
                linked_parent.symlink_to(real_parent, target_is_directory=True)
            except OSError:
                self.skipTest("directory symlinks are not supported on this filesystem")
            stderr = StringIO()
            with redirect_stderr(stderr):
                code = cli_main(
                    [
                        "dashboard",
                        "--runs-dir",
                        str(real_runs),
                        "--benchmarks-dir",
                        str(root / "benchmarks"),
                        "--output",
                        str(linked_parent / "dashboard.html"),
                    ]
                )
            self.assertEqual(code, 2)
            self.assertIn("dashboard output parent", stderr.getvalue())
            self.assertFalse((real_parent / "dashboard.html").exists())

    def test_dashboard_output_rejects_parent_swap_after_validation_without_side_effect(self):
        with tempfile.TemporaryDirectory() as tmp:
            import conductor_extras.runtime.dashboard as dashboard_module

            root = Path(tmp)
            runs = root / "runs"
            runs.mkdir()
            output_parent = root / "output-parent"
            output_parent.mkdir()
            outside = root / "outside"
            outside.mkdir()
            output = output_parent / "dashboard.html"
            original_ensure = dashboard_module.ensure_dir_no_follow

            def swapping_ensure(path, label, *args, **kwargs):
                if label == "dashboard output parent" and Path(path) == output_parent:
                    output_parent.rmdir()
                    try:
                        output_parent.symlink_to(outside, target_is_directory=True)
                    except OSError:
                        self.skipTest("directory symlinks are not supported on this filesystem")
                return original_ensure(path, label, *args, **kwargs)

            with patch("conductor_extras.runtime.dashboard.ensure_dir_no_follow", side_effect=swapping_ensure):
                with self.assertRaises(ValidationError):
                    write_dashboard(runs, root / "benchmarks", output)
            self.assertFalse((outside / "dashboard.html").exists())

    def test_dashboard_reads_reject_json_symlink_swap_after_listing(self):
        with tempfile.TemporaryDirectory() as tmp:
            import conductor_extras.runtime.security as security_module

            root = Path(tmp)
            reports = root / "reports"
            reports.mkdir()
            report_path = reports / "report.json"
            outside_report = root / "outside-report.json"
            write_json(report_path, benchmark_report(system="codex", suite="unit-suite"))
            write_json(outside_report, benchmark_report(system="codex", suite="outside-suite"))
            original_reject = security_module.reject_symlink_path

            def swapping_reject(path, label):
                original_reject(path, label)
                if label == "dashboard json" and Path(path) == report_path:
                    report_path.unlink()
                    try:
                        report_path.symlink_to(outside_report)
                    except OSError:
                        self.skipTest("symlinks are not supported on this filesystem")

            with patch("conductor_extras.runtime.security.reject_symlink_path", side_effect=swapping_reject):
                reports_summary = collect_reports(reports, max_reports=10)
            self.assertEqual(reports_summary[0]["error"], "ValidationError")
            self.assertNotEqual(reports_summary[0]["suite"], "outside-suite")

    def test_dashboard_collects_newest_runs_and_reports_with_caps(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runs = root / "runs"
            reports = root / "reports"
            runs.mkdir()
            reports.mkdir()
            for index in range(10):
                run_dir = runs / ("run-%02d" % index)
                run_dir.mkdir()
                write_json(
                    run_dir / "state.json",
                    {
                        "schema": "conductor.run_state.v1",
                        "workflow": "workflow-%02d" % index,
                        "status": "completed",
                        "steps": {"step": {"status": "completed"}},
                    },
                )
                write_json(run_dir / "workflow.json", workflow_with_steps([]))
                write_standard_files(run_dir)
                timestamp = 1000 + index
                os.utime(run_dir, (timestamp, timestamp))

                report_path = reports / ("report-%02d.json" % index)
                write_json(report_path, benchmark_report(system="codex", suite="suite-%02d" % index))
                os.utime(report_path, (timestamp, timestamp))

            selected_runs = collect_runs(runs, max_runs=3)
