    def test_dashboard_file_count_boundaries(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runs = root / "runs"
            runs.mkdir()
            for count in [999, 1000, 1001]:
                run_dir = runs / ("files-%04d" % count)
                artifacts = run_dir / "artifacts"
                artifacts.mkdir(parents=True)
                write_json(
                    run_dir / "state.json",
                    {
                        "schema": "conductor.run_state.v1",
                        "workflow": "count-%04d" % count,
                        "status": "completed",
                        "steps": {"verify": {"status": "completed"}},
                    },
                )
                write_json(run_dir / "workflow.json", workflow_with_steps([]))
                write_standard_files(run_dir)
                for index in range(count):
                    (artifacts / ("file-%04d.txt" % index)).write_text("x", encoding="utf-8")

            by_id = {item["id"]: item for item in collect_runs(runs, max_runs=3)}
            self.assertEqual(by_id["files-0999"]["artifact_count"], 999)
            self.assertFalse(by_id["files-0999"]["artifact_count_truncated"])
            self.assertEqual(by_id["files-1000"]["artifact_count"], 1000)
            self.assertFalse(by_id["files-1000"]["artifact_count_truncated"])
            self.assertEqual(by_id["files-1001"]["artifact_count"], 1000)
            self.assertTrue(by_id["files-1001"]["artifact_count_truncated"])

