    def test_run_detail_renders_agent_map_packet_details(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "phase": "review",
                    "risk": "medium",
                    "items": ["alpha", "beta"],
                    "prompt_template": "Review {item}\ntoken=packetsecret",
                    "capture_dir": "packets",
                    "max_items": 5,
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
                emit_secret_logs=True,
            )
            run = runner.execute()
            write_standard_files(run.run_dir)

            detail = collect_run_detail(root / "runs", run.run_dir.name, max_text_bytes=300)
            self.assertEqual(len(detail["agent_maps"]), 1)
            group = detail["agent_maps"][0]
            self.assertEqual(group["step_id"], "packet")
            self.assertEqual(group["step_handle"], step_handle("packet"))
            self.assertEqual(group["phase"], "review")
            self.assertEqual(group["status"], "completed")
            self.assertTrue(group["cache_present"])
            self.assertEqual(group["cache_entries"], 2)
            self.assertEqual(len(group["packets"]), 2)
            self.assertEqual([packet["item"] for packet in group["packets"]], ["alpha", "beta"])
            self.assertEqual([packet["status"] for packet in group["packets"]], ["completed", "completed"])
            self.assertTrue(group["packets"][0]["cached"])
            self.assertTrue(group["trace_present"])
            self.assertEqual(group["trace_entries"], 2)
            self.assertEqual(group["packets"][0]["trace"]["status"], "completed")
            self.assertFalse(group["packets"][0]["trace"]["cached"])
            self.assertEqual(group["packets"][0]["trace"]["returncode"], 0)
            self.assertIsNotNone(group["packets"][0]["trace"]["duration_ms"])
            self.assertGreater(group["packets"][0]["trace"]["stdout_bytes"], 0)
            self.assertTrue(group["packets"][0]["output"]["present"])
            self.assertTrue(group["packets"][0]["stdout"]["present"])
            self.assertTrue(group["packets"][0]["stderr"]["present"])
            serialized = json.dumps(detail)
            self.assertIn("token=<redacted>", serialized)
            self.assertNotIn("packetsecret", serialized)
            self.assertNotIn("stdoutsecret", serialized)
            self.assertNotIn("stderrsecret", serialized)

            output = root / "dashboard.html"
            with redirect_stdout(StringIO()):
                code = cli_main(
                    [
                        "dashboard",
                        "--runs-dir",
                        str(root / "runs"),
                        "--benchmarks-dir",
                        str(root / "benchmarks"),
                        "--output",
                        str(output),
                    ]
                )
            self.assertEqual(code, 0)
            dashboard_html = output.read_text(encoding="utf-8")
            self.assertIn("<h4>Agent Packets</h4>", dashboard_html)
            self.assertIn("alpha", dashboard_html)
            self.assertIn("2 cache entries", dashboard_html)
            self.assertIn("2 trace entries", dashboard_html)
            self.assertIn("completed /", dashboard_html)
            self.assertIn("rc 0", dashboard_html)
            self.assertIn("token=&lt;redacted&gt;", dashboard_html)
            self.assertNotIn("packetsecret", dashboard_html)
            self.assertNotIn("stdoutsecret", dashboard_html)
            self.assertNotIn("stderrsecret", dashboard_html)

            handle = run_handle(run.run_dir.name)
            live_html = render_live_run_detail(dict(detail, run_handle=handle))
            self.assertIn("<h2>Agent Packets</h2>", live_html)
            self.assertIn("alpha", live_html)
            self.assertIn("<th>Controls</th>", live_html)
            self.assertIn("Rerun packet", live_html)
            self.assertIn('name="packet_index" value="1"', live_html)
            self.assertIn('value="retry-packet"', live_html)
            self.assertIn('name="step_handle" value="%s"' % step_handle("packet"), live_html)
            self.assertIn('name="return_to" value="/run/%s"' % handle, live_html)
            self.assertNotIn('name="step_id" value="packet"', live_html)
            self.assertIn("2 cache entries", live_html)
            self.assertIn("2 trace entries", live_html)
            self.assertIn("completed /", live_html)
            self.assertIn("rc 0", live_html)
            self.assertIn("token=&lt;redacted&gt;", live_html)
            self.assertNotIn("packetsecret", live_html)
            self.assertNotIn("stdoutsecret", live_html)
            self.assertNotIn("stderrsecret", live_html)

    def test_run_detail_tracks_agent_map_failed_and_cached_trace_events(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": ["alpha", "beta"],
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                    "max_items": 5,
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            first = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
                fail_on_calls={2},
            )
            with self.assertRaises(StepExecutionError):
                first.execute()

            failed_detail = collect_run_detail(root / "runs", first.run.run_dir.name)
            failed_group = failed_detail["agent_maps"][0]
            self.assertTrue(failed_group["trace_present"])
            self.assertEqual(failed_group["trace_entries"], 2)
            self.assertEqual(failed_group["packets"][0]["trace"]["status"], "completed")
            self.assertEqual(failed_group["packets"][1]["trace"]["status"], "failed")
            self.assertEqual(failed_group["packets"][1]["trace"]["returncode"], 7)
            self.assertEqual(failed_group["packets"][1]["trace"]["detail"], "exit code 7")
            failed_diagnostics = failed_detail["diagnostics"]
            failed_codes = {issue["code"] for issue in failed_diagnostics["issues"]}
            self.assertIn("agent_map_packet_failed", failed_codes)
            failed_packet_issue = next(
                issue for issue in failed_diagnostics["issues"] if issue["code"] == "agent_map_packet_failed"
            )
            self.assertEqual(failed_packet_issue["severity"], "action_required")
            self.assertIn("retry-packet RUN_DIR packet 2", failed_packet_issue["command"])
            self.assertIn("Return code: 7", failed_packet_issue["detail"])

            retry_step(first.run.run_dir, "packet", reason="retry failed trace packet")
            second = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                resume_dir=first.run.run_dir,
                policy=RuntimePolicy(allow_agent=True),
            )
            run = second.execute()
            self.assertEqual(second.agent_calls, ["002-beta.md"])

            detail = collect_run_detail(root / "runs", run.run_dir.name)
            group = detail["agent_maps"][0]
            self.assertEqual(group["trace_entries"], 4)
            self.assertEqual(group["packets"][0]["trace"]["status"], "cached")
            self.assertTrue(group["packets"][0]["trace"]["cached"])
            self.assertIn("cache reuse", render_live_run_detail(detail))
            self.assertEqual(group["packets"][1]["trace"]["status"], "completed")
            self.assertEqual(group["packets"][1]["trace"]["returncode"], 0)

    def test_live_agent_packet_retry_control_targets_one_packet(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": ["alpha"],
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                    "max_items": 5,
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
                fail_on_calls={1},
            )
            with self.assertRaises(StepExecutionError):
                runner.execute()
            handle = run_handle(runner.run.run_dir.name)
            target = step_handle("packet")
            detail = collect_run_detail(root / "runs", runner.run.run_dir.name)
            live_html = render_live_run_detail(dict(detail, run_handle=handle))
            self.assertIn("Retry packet", live_html)
            self.assertIn('name="step_handle" value="%s"' % target, live_html)
            self.assertIn('name="packet_index" value="1"', live_html)
            self.assertIn('name="return_to" value="/run/%s"' % handle, live_html)
            self.assertIn('name="reason" value="agent_map packet 001 failed"', live_html)
            self.assertNotIn('name="step_id" value="packet"', live_html)

            self.assertEqual(resolve_live_step_handle(runner.run.run_dir, target), "packet")
            result = apply_live_control(
                root / "runs",
                {
                    "token": "unit-token",
                    "action": "retry-packet",
                    "run_handle": handle,
                    "step_handle": target,
                    "packet_index": "1",
                    "reason": "agent_map packet 001 failed",
                    "return_to": "/run/%s" % handle,
                },
                "unit-token",
            )
            self.assertEqual(result["action"], "retry-packet")
            self.assertEqual(result["requested_step"], "packet")
            self.assertEqual(result["packet_index"], 1)
            self.assertEqual(result["return_to"], "/run/%s" % handle)
            state = json.loads((runner.run.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["steps"]["packet"]["status"], "pending")
            self.assertEqual(state["status"], "needs_resume")

