    def test_agent_map_parallel_trace_append_records_every_packet(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "packet",
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": ["alpha", "beta", "gamma", "delta", "epsilon", "zeta"],
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                    "max_items": 10,
                    "max_workers": 3,
                }
            ]
        )
        workflow["max_workers"] = 3
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True, allow_parallel=True),
            )
            run = runner.execute()
            detail = collect_run_detail(root / "runs", run.run_dir.name)
            group = detail["agent_maps"][0]
            self.assertEqual(group["trace_entries"], 6)
            self.assertEqual(len(group["packets"]), 6)
            self.assertEqual([packet["trace"]["status"] for packet in group["packets"]], ["completed"] * 6)
            trace_path = run.artifacts_dir / "packets" / ".agent-map-trace.jsonl"
            trace_lines = [json.loads(line) for line in trace_path.read_text(encoding="utf-8").splitlines()]
            self.assertEqual(len(trace_lines), 6)
            self.assertEqual(sorted(record["index"] for record in trace_lines), [1, 2, 3, 4, 5, 6])

