    def test_run_detail_redacts_agent_map_step_id_and_cache_timestamp(self):
        secret_step = "sk-abcdefghijklmnop"
        workflow = workflow_with_steps(
            [
                {
                    "id": secret_step,
                    "kind": "agent_map",
                    "risk": "medium",
                    "items": ["alpha"],
                    "prompt_template": "Review {item}",
                    "capture_dir": "packets",
                    "max_items": 5,
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = FakeAgentWorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
            )
            run = runner.execute()
            cache_path = run.artifacts_dir / "packets" / ".agent-map-cache.json"
            cache = json.loads(cache_path.read_text(encoding="utf-8"))
            entry = next(iter(cache["entries"].values()))
            entry["updated_at_utc"] = "token=cachetimestampsecret"
            cache_path.write_text(json.dumps(cache, indent=2, sort_keys=True) + "\n", encoding="utf-8")

            detail = collect_run_detail(root / "runs", run.run_dir.name)
