    def test_run_detail_lists_artifacts_logs_and_redacts_excerpts(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runs = root / "runs"
            run_dir = runs / "detail-run"
            artifacts = run_dir / "artifacts" / "nested"
            logs = run_dir / "logs"
            artifacts.mkdir(parents=True)
            logs.mkdir(parents=True)
            write_json(
                run_dir / "state.json",
                {
                    "schema": "conductor.run_state.v1",
                    "workflow": "detail-workflow",
                    "status": "completed",
                    "duration_ms": 1250,
                    "steps": {
                        "review": {
                            "status": "completed",
                            "kind": "shell",
                            "detail": "ok",
                            "duration_ms": 12,
                        }
                    },
                },
            )
            write_json(run_dir / "workflow.json", workflow_with_steps([]))
            write_standard_files(run_dir, final_report="Summary <script>alert(1)</script>\ntoken=reportsecret\n")
            (artifacts / "out.txt").write_text("artifact <script>alert(1)</script>\ntoken=artifactsecret\n", encoding="utf-8")
            (logs / "run.log").write_text("log token=logsecret\n", encoding="utf-8")

            detail = collect_run_detail(runs, "detail-run", max_text_bytes=200)
            self.assertEqual(detail["id"], "detail-run")
            self.assertEqual(detail["steps"][0]["kind"], "shell")
            artifact_names = [item["name"] for item in detail["artifacts"]["files"]]
            log_names = [item["name"] for item in detail["logs"]["files"]]
            self.assertEqual(artifact_names, ["nested/out.txt"])
            self.assertEqual(log_names, ["run.log"])
            serialized = json.dumps(detail)
            self.assertNotIn("artifactsecret", serialized)
            self.assertNotIn("logsecret", serialized)
            self.assertIn("token=<redacted>", serialized)

            output = root / "dashboard.html"
            with redirect_stdout(StringIO()):
                code = cli_main(
                    [
                        "dashboard",
                        "--runs-dir",
                        str(runs),
                        "--benchmarks-dir",
                        str(root / "benchmarks"),
                        "--output",
                        str(output),
                    ]
                )
            self.assertEqual(code, 0)
            html = output.read_text(encoding="utf-8")
            self.assertIn("Run Details", html)
            self.assertIn("nested/out.txt", html)
            self.assertIn("&lt;script&gt;alert(1)&lt;/script&gt;", html)
            self.assertNotIn("<script>alert(1)</script>", html)
            self.assertNotIn("artifactsecret", html)

    def test_run_diagnostics_surface_recovery_guidance_without_leaking_details(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runs = root / "runs"
            run_dir = runs / "diagnostic-run"
            run_dir.mkdir(parents=True)
            write_json(
                run_dir / "workflow.json",
                workflow_with_steps(
                    [
                        {"id": "check", "kind": "shell", "risk": "low", "writes": False, "command": ["false"]},
                        {"id": "review", "kind": "shell", "risk": "low", "writes": False, "command": ["false"]},
                        {"id": "bad;step", "kind": "shell", "risk": "low", "writes": False, "command": ["false"]},
                    ]
                ),
            )
            write_json(
                run_dir / "state.json",
                {
                    "schema": "conductor.run_state.v1",
                    "workflow": "diagnostic",
                    "status": "failed",
                    "started_at_utc": "2026-07-08T00:00:00Z",
                    "steps": {
                        "check": {
                            "status": "failed",
                            "kind": "shell",
                            "detail": "command failed token=diagnosticsecret",
                        },
                        "review": {"status": "blocked", "kind": "shell", "detail": "waiting on check"},
                        "bad;step": {"status": "failed", "kind": "shell", "detail": "malformed persisted state"},
                    },
                },
            )
            write_json(
                run_dir / "runner.json",
                {
                    "schema": "conductor.runner.v1",
                    "status": "active",
                    "event": "step-start:check",
                    "heartbeat_at_utc": "2000-01-01T00:00:00Z",
                    "mode": "run",
                    "run_status": "running",
                },
            )

            detail = collect_run_detail(runs, "diagnostic-run")
            diagnostics = detail["diagnostics"]
            codes = {issue["code"] for issue in diagnostics["issues"]}
            self.assertEqual(diagnostics["schema"], "conductor.run_diagnostics.v1")
            self.assertEqual(diagnostics["severity"], "action_required")
            self.assertIn("run_failed", codes)
            self.assertIn("runner_stale", codes)
            self.assertIn("step_failed", codes)
            self.assertIn("step_blocked", codes)
            self.assertNotIn("diagnosticsecret", json.dumps(diagnostics))
            stale_issue = next(issue for issue in diagnostics["issues"] if issue["code"] == "runner_stale")
            self.assertIn("recover-run RUN_DIR --retry-running", stale_issue["command"])

            output = root / "dashboard.html"
            write_dashboard(runs, root / "benchmarks", output)
            dashboard_html = output.read_text(encoding="utf-8")
            self.assertIn("<h4>Diagnostics</h4>", dashboard_html)
            self.assertIn("retry-step RUN_DIR check", dashboard_html)
            self.assertIn("retry-step RUN_DIR &#x27;bad;step&#x27;", dashboard_html)
            self.assertNotIn("diagnosticsecret", dashboard_html)

            live_html = render_live_run_detail(detail)
            self.assertIn("<h2>Diagnostics</h2>", live_html)
            self.assertIn("retry-step RUN_DIR check", live_html)
            self.assertIn("retry-step RUN_DIR &#x27;bad;step&#x27;", live_html)
            self.assertNotIn("diagnosticsecret", live_html)

            stdout = StringIO()
            with redirect_stdout(stdout):
                code = cli_main(["diagnose-run", str(run_dir)])
            self.assertEqual(code, 0)
            text = stdout.getvalue()
            self.assertIn("Run diagnostics: action_required", text)
