            dashboard_html = output.read_text(encoding="utf-8")
            self.assertIn("Runtime Actions", dashboard_html)
            self.assertIn("Runtime actions: 1 operator, 2 recovery, 1 ready, 1 waiting, 1 active", dashboard_html)
            self.assertIn("waiter", dashboard_html)
            self.assertIn("upstream:failed", dashboard_html)
            self.assertNotIn("runtimesecret", dashboard_html)
            self.assertNotIn("runtimeapprovalsecret", dashboard_html)

            payload = build_live_payload(runs, root / "benchmarks")
