            live_detail = render_live_run_detail(dict(detail, run_handle=run_handle("runtime-run")))
            self.assertIn("<h2>Runtime Actions</h2>", live_detail)
            self.assertIn("retry-step RUN_DIR upstream", live_detail)
            self.assertIn("reset-step RUN_DIR blocked", live_detail)
            self.assertIn("upstream:failed", live_detail)
            self.assertNotIn("runtimesecret", live_detail)
            self.assertNotIn("runtimeapprovalsecret", live_detail)

