    def test_manual_gate_approval_guidance_is_redacted_and_not_live_approval(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "gate",
                    "kind": "manual_gate",
                    "approval_id": "token=approvalsecret;rm",
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            )
            with self.assertRaises(PolicyError):
                runner.execute()

            run_id = runner.run.run_dir.name
            detail = collect_run_detail(root / "runs", run_id)
            self.assertEqual(detail["status"], "blocked")
            self.assertEqual(detail["approvals"]["pending_count"], 1)
            self.assertEqual(detail["approvals"]["pending"][0]["step_id"], "gate")
            self.assertEqual(detail["steps"][0]["approval_id"], "<approval-id>")
            self.assertEqual(detail["steps"][0]["detail"], "missing approval <approval-id>")
            self.assertEqual(detail["approvals"]["pending"][0]["approval_id"], "<approval-id>")
            self.assertIn("--approve <approval-id>", detail["approvals"]["pending"][0]["command"])
            self.assertNotIn("approvalsecret", json.dumps(detail))
            self.assertNotIn("token=approvalsecret;rm", json.dumps(detail))
            issue_codes = {issue["code"] for issue in detail["diagnostics"]["issues"]}
            self.assertIn("manual_gate_approval_required", issue_codes)
            self.assertNotIn("step_blocked", issue_codes)
            approval_issue = next(
                issue for issue in detail["diagnostics"]["issues"] if issue["code"] == "manual_gate_approval_required"
            )
            self.assertIn("--approve <approval-id>", approval_issue["command"])
            self.assertNotIn("reset-step", approval_issue["command"])

            output = root / "dashboard.html"
            write_dashboard(root / "runs", root / "benchmarks", output)
            dashboard_html = output.read_text(encoding="utf-8")
            self.assertIn("Approval Guidance", dashboard_html)
            self.assertIn("live control token does not grant approval", dashboard_html)
            self.assertIn("Approvals needed: 1 manual gate(s)", dashboard_html)
            self.assertIn("&lt;approval-id&gt;", dashboard_html)
            self.assertIn("--approve &lt;approval-id&gt;", dashboard_html)
            self.assertNotIn("approvalsecret", dashboard_html)
            self.assertNotIn("token=approvalsecret;rm", dashboard_html)

            payload = build_live_payload(root / "runs", root / "benchmarks")
            self.assertEqual(payload["runs"][0]["approvals"]["pending_count"], 1)
            payload_text = json.dumps(payload)
            self.assertIn("<approval-id>", payload_text)
            self.assertIn("--approve <approval-id>", payload_text)
            self.assertNotIn("approvalsecret", payload_text)
            self.assertNotIn("token=approvalsecret;rm", payload_text)

            handle = run_handle(run_id)
            live_root = render_live_dashboard(payload)
            self.assertIn("Approval Queue", live_root)
            self.assertIn("Approvals needed: 1 manual gate(s)", live_root)
            self.assertIn('href="/run/%s"' % handle, live_root)
            self.assertIn("Manual gates require an explicit CLI resume", live_root)
            self.assertNotIn("approvalsecret", live_root)
            live_html = render_live_run_detail(dict(detail, run_handle=handle))
            self.assertIn("Approval Guidance", live_html)
            self.assertIn("live control token does not grant approval", live_html)
            self.assertIn("&lt;approval-id&gt;", live_html)
            self.assertIn("--approve &lt;approval-id&gt;", live_html)
            self.assertNotIn("approvalsecret", live_html)
            self.assertNotIn("token=approvalsecret;rm", live_html)
            self.assertNotIn('value="skip">Skip</button>', live_html)
            self.assertNotIn('value="retry">Retry</button>', live_html)
            self.assertNotIn('value="reset">Reset</button>', live_html)
            self.assertNotIn('value="approve"', live_html)

            handler_cls = _handler_factory(
                runs_dir=root / "runs",
                benchmarks_dir=root / "benchmarks",
                max_runs=50,
                max_reports=50,
                max_text_bytes=4096,
                title="Unit Live",
                control_token="unit-token",
            )
            status, _headers, body = self._invoke_live_handler(handler_cls, "GET", "/run/%s" % handle)
            self.assertEqual(status, 200)
            self.assertIn("Approval Guidance", body)
            self.assertNotIn("approvalsecret", body)
            workflow_status, workflow_headers, workflow_body = self._invoke_live_handler(
                handler_cls,
                "GET",
                "/run/%s/workflow.json" % handle,
            )
            self.assertEqual(workflow_status, 200)
            self.assertEqual(workflow_headers["Content-Type"], "application/json; charset=utf-8")
            self.assertIn('"approval_id": "<approval-id>"', workflow_body)
            self.assertNotIn("approvalsecret", workflow_body)
            self.assertNotIn("token=approvalsecret;rm", workflow_body)
            retry_body = "token=unit-token&action=retry&run_handle=%s&step_id=gate&reason=browser" % handle
            status, _headers, retry_error_body = self._invoke_live_handler(
                handler_cls,
                "POST",
                "/control",
                body=retry_body,
                headers={
                    "Content-Type": "application/x-www-form-urlencoded",
                    "Content-Length": str(len(retry_body)),
                    "Host": "127.0.0.1:8765",
                    "Origin": "http://127.0.0.1:8765",
                },
            )
            self.assertEqual(status, 400)
            self.assertIn("manual_gate steps cannot be retried", json.loads(retry_error_body)["error"])
            reset_body = "token=unit-token&action=reset&run_handle=%s&step_id=gate&reason=browser" % handle
            status, _headers, reset_error_body = self._invoke_live_handler(
                handler_cls,
                "POST",
                "/control",
                body=reset_body,
                headers={
                    "Content-Type": "application/x-www-form-urlencoded",
                    "Content-Length": str(len(reset_body)),
                    "Host": "127.0.0.1:8765",
                    "Origin": "http://127.0.0.1:8765",
                },
            )
            self.assertEqual(status, 400)
            self.assertIn("manual_gate steps cannot be reset", json.loads(reset_error_body)["error"])
            skip_body = "token=unit-token&action=skip&run_handle=%s&step_id=gate&reason=bypass" % handle
            status, _headers, error_body = self._invoke_live_handler(
                handler_cls,
                "POST",
                "/control",
                body=skip_body,
                headers={
                    "Content-Type": "application/x-www-form-urlencoded",
                    "Content-Length": str(len(skip_body)),
                    "Host": "127.0.0.1:8765",
                    "Origin": "http://127.0.0.1:8765",
                },
            )
            self.assertEqual(status, 400)
            self.assertIn("manual_gate steps cannot be skipped", json.loads(error_body)["error"])
            self.assertNotIn("approvalsecret", error_body)

