    def test_run_detail_rejects_bad_run_ids_and_skips_symlinks(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runs = root / "runs"
            run_dir = runs / "safe-run"
            artifacts = run_dir / "artifacts"
            artifacts.mkdir(parents=True)
            write_json(run_dir / "state.json", {"schema": "conductor.run_state.v1", "status": "completed", "steps": {}})
            write_json(run_dir / "workflow.json", workflow_with_steps([]))
            write_standard_files(run_dir)
            outside = root / "outside.txt"
            outside.write_text("token=outsidesecret\n", encoding="utf-8")
            link = artifacts / "linked.txt"
            outside_dir = root / "outside-dir"
            outside_dir.mkdir()
            (outside_dir / "secret.txt").write_text("token=outside-dir-secret\n", encoding="utf-8")
            link_dir = artifacts / "linked-dir"
            try:
                link.symlink_to(outside)
                link_dir.symlink_to(outside_dir, target_is_directory=True)
            except OSError:
                self.skipTest("symlinks are not supported on this filesystem")

            with self.assertRaises(ValidationError):
                collect_run_detail(runs, "../safe-run")
            with self.assertRaises(ValidationError):
                collect_run_detail(runs, ".")
            detail = collect_run_detail(runs, "safe-run")
            self.assertEqual(detail["artifacts"]["files"][0]["error"], "symlink skipped")
            self.assertNotIn("outsidesecret", json.dumps(detail))
            self.assertNotIn("outside-dir-secret", json.dumps(detail))
            self.assertNotIn("secret.txt", json.dumps(detail))

            target = root / "target-run"
            target.mkdir()
            linked_run = runs / "linked-run"
            linked_run.symlink_to(target, target_is_directory=True)
            with self.assertRaises(ValidationError):
                collect_run_detail(runs, "linked-run")

    def test_run_detail_rejects_excerpt_symlink_swap_without_leaking_target(self):
        with tempfile.TemporaryDirectory() as tmp:
            import conductor_extras.runtime.security as security_module

            root = Path(tmp)
            runs = root / "runs"
            run_dir = runs / "safe-run"
            artifacts = run_dir / "artifacts"
            artifacts.mkdir(parents=True)
            write_json(run_dir / "state.json", {"schema": "conductor.run_state.v1", "status": "completed", "steps": {}})
            write_json(run_dir / "workflow.json", workflow_with_steps([]))
            write_standard_files(run_dir)
            artifact = artifacts / "out.txt"
            artifact.write_text("safe", encoding="utf-8")
            outside = root / "outside.txt"
            outside.write_text("outside secret-like fixture\n", encoding="utf-8")
            original_reject = security_module.reject_symlink_path

            def swapping_reject(path, label):
                original_reject(path, label)
                if label == "dashboard excerpt" and Path(path) == artifact:
                    artifact.unlink()
                    try:
                        artifact.symlink_to(outside)
                    except OSError:
                        self.skipTest("symlinks are not supported on this filesystem")

            with patch("conductor_extras.runtime.security.reject_symlink_path", side_effect=swapping_reject):
                detail = collect_run_detail(runs, "safe-run")
            excerpt = detail["artifacts"]["files"][0]["excerpt"]
            self.assertEqual(excerpt["error"], "ValidationError")
            self.assertNotIn("outside", json.dumps(detail))

