    def test_live_run_api_rejects_unknown_and_symlink_paths_without_leaking_paths(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runs = root / "runs"
            runs.mkdir()
            outside = root / "token=outsidepathsecret"
            outside.mkdir()
            linked_run = runs / "linked-run"
            try:
                linked_run.symlink_to(outside, target_is_directory=True)
            except OSError:
                self.skipTest("directory symlinks are not supported on this filesystem")
            handler_cls = _handler_factory(
                runs_dir=runs,
                benchmarks_dir=root / "benchmarks",
                max_runs=50,
                max_reports=50,
                max_text_bytes=4096,
                title="Unit Live",
                control_token="unit-token",
            )

            status, _headers, body = self._invoke_live_handler(handler_cls, "GET", "/api/run/%s" % run_handle("missing-run"))
            self.assertEqual(status, 400)
            self.assertIn("run_handle does not exist", json.loads(body)["error"])
            self.assertNotIn(str(root), body)

            status, _headers, body = self._invoke_live_handler(handler_cls, "GET", "/api/run/%s" % run_handle("linked-run"))
            self.assertEqual(status, 400)
            self.assertIn("run_handle does not exist", json.loads(body)["error"])
            self.assertNotIn("outsidepathsecret", body)
            self.assertNotIn(str(outside), body)

            missing_runs = root / "token=missingrunssecret"
            missing_handler_cls = _handler_factory(
                runs_dir=missing_runs,
                benchmarks_dir=root / "benchmarks",
                max_runs=50,
                max_reports=50,
                max_text_bytes=4096,
                title="Unit Live",
                control_token="unit-token",
            )
            status, _headers, body = self._invoke_live_handler(missing_handler_cls, "GET", "/api/run/%s" % run_handle("anything"))
            self.assertEqual(status, 400)
            self.assertIn("runs_dir does not exist", json.loads(body)["error"])
            self.assertNotIn("missingrunssecret", body)
            self.assertNotIn(str(missing_runs), body)

            linked_runs = root / "token=linkedrunssecret"
            linked_runs.symlink_to(runs, target_is_directory=True)
            linked_handler_cls = _handler_factory(
                runs_dir=linked_runs,
                benchmarks_dir=root / "benchmarks",
                max_runs=50,
                max_reports=50,
                max_text_bytes=4096,
                title="Unit Live",
                control_token="unit-token",
            )
            status, _headers, body = self._invoke_live_handler(linked_handler_cls, "GET", "/api/run/%s" % run_handle("anything"))
            self.assertEqual(status, 400)
            self.assertIn("runs_dir must not be a symlink", json.loads(body)["error"])
            self.assertNotIn("linkedrunssecret", body)
            self.assertNotIn(str(linked_runs), body)

