    def test_live_http_queues_team_follow_up_with_opaque_handles_and_no_echo(self):
        workflow = valid_model_team_workflow()
        workflow["steps"][0]["max_operator_tasks"] = 1
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(allow_agent=True),
            )
            handle = run_handle(runner.run.run_dir.name)
            team_handle = step_handle("adaptive-review")
            handler_cls = _handler_factory(
                runs_dir=root / "runs",
                benchmarks_dir=root / "benchmarks",
                max_runs=50,
                max_reports=50,
                max_text_bytes=4096,
                title="Unit Live",
                control_token="unit-token",
            )
            instruction = "bounded-follow-up"
            body = (
                "token=unit-token&action=queue-team-task&run_handle=%s"
                "&step_handle=%s&member=worker&delivery=interrupt-current"
                "&instruction=%s&return_to=/run/%s"
                % (handle, team_handle, instruction, handle)
            )
            queued_entry = {
                "status": "pending",
                "task_id": "operator-g000000000-000001",
                "member_id": "worker",
                "delivery": "interrupt-current",
                "interrupt_round": 1,
                "interrupt_task_id": "review",
                "interrupted_at_utc": None,
                "instruction_sha256": "1" * 64,
            }
            with patch(
                "conductor_extras.runtime.live_server.queue_team_task",
                return_value=queued_entry,
            ) as queued:
                status, headers, _body = self._invoke_live_handler(
                    handler_cls,
                    "POST",
                    "/control",
                    body=body,
                    headers={
                        "Content-Type": "application/x-www-form-urlencoded",
                        "Content-Length": str(len(body)),
                        "Host": "127.0.0.1:8765",
                        "Origin": "http://127.0.0.1:8765",
                    },
                )
            self.assertEqual(status, 303)
            self.assertTrue(headers["Location"].startswith("/run/%s?message=" % handle))
            self.assertNotIn(instruction, headers["Location"])
            queued.assert_called_once_with(
                runner.run.run_dir,
                "adaptive-review",
                "worker",
                instruction,
                interrupt_current=True,
            )

    def test_live_run_level_controls_render_and_apply(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "one",
                    "kind": "write_artifact",
                    "output": "one.txt",
                    "content": "one",
                }
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            )
            handle = run_handle(runner.run.run_dir.name)
            payload = build_live_payload(root / "runs", root / "benchmarks")
            html = render_live_dashboard(payload)
            self.assertIn('value="pause-run"', html)
            self.assertIn("Request pause", html)
            self.assertIn('value="resume-run"', html)
            self.assertIn('value="stop-run"', html)
            self.assertIn("Request stop", html)
            self.assertIn('value="restart-run"', html)
            self.assertIn("Restart", html)

            result = apply_live_control(
                root / "runs",
                {
                    "token": "unit-token",
                    "action": "pause-run",
                    "run_handle": handle,
                    "reason": "token=livesecret",
                },
                "unit-token",
            )
            self.assertEqual(result["status"], "paused")
            state = json.loads((runner.run.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["status"], "paused")
            self.assertEqual(state["control_events"][-1]["action"], "pause-run")
            self.assertNotIn("livesecret", json.dumps(state))

            result = apply_live_control(
                root / "runs",
                {
                    "token": "unit-token",
                    "action": "resume-run",
                    "run_handle": handle,
                    "reason": "continue",
                },
                "unit-token",
            )
            self.assertEqual(result["status"], "needs_resume")

            result = apply_live_control(
                root / "runs",
                {
                    "token": "unit-token",
                    "action": "stop-run",
                    "run_handle": handle,
                    "reason": "cancel",
                },
                "unit-token",
            )
            self.assertEqual(result["status"], "stopped")

            result = apply_live_control(
                root / "runs",
                {
                    "token": "unit-token",
                    "action": "restart-run",
                    "run_handle": handle,
                    "reason": "fresh run",
                },
                "unit-token",
            )
            self.assertEqual(result["action"], "restart-run")
            self.assertEqual(result["status"], "needs_resume")
            state = json.loads((runner.run.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["control_events"][-1]["action"], "restart-run")

