    def test_live_control_delegates_to_run_control_with_token(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "optional",
                    "kind": "shell",
                    "risk": "low",
                    "writes": False,
                    "command": ["false"],
                },
                {
                    "id": "after",
                    "kind": "write_artifact",
                    "depends_on": ["optional"],
                    "output": "after.txt",
                    "content": "after",
                },
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=root / "runs",
                policy=RuntimePolicy(),
            )
            with self.assertRaises(StepExecutionError):
                runner.execute()
            run_id = runner.run.run_dir.name

            with self.assertRaises(ValidationError):
                apply_live_control(
                    root / "runs",
                    {"token": "wrong", "action": "skip", "run_id": run_id, "step_id": "optional", "reason": "skip"},
                    control_token="unit-token",
                )

            result = apply_live_control(
                root / "runs",
                {
                    "token": "unit-token",
                    "action": "skip",
                    "run_id": run_id,
                    "step_id": "optional",
                    "reason": "documented external evidence",
                    "cascade": "1",
                },
                control_token="unit-token",
            )
            self.assertEqual(result["action"], "skip-step")
            self.assertEqual(result["status"], "needs_resume")
            state = json.loads((runner.run.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["steps"]["optional"]["status"], "skipped")
            self.assertEqual(state["steps"]["after"]["status"], "pending")

    def test_live_control_path_safety_and_bind_validation(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            runs = root / "runs"
            safe = runs / "safe-run"
            safe.mkdir(parents=True)
            self.assertEqual(resolve_live_run_dir(runs, "safe-run"), safe)
            with self.assertRaises(ValidationError):
                resolve_live_run_dir(runs, "../safe-run")
            with self.assertRaises(ValidationError):
                resolve_live_run_dir(runs, "missing-run")

            target = root / "target-run"
            target.mkdir()
