    def test_live_control_form_parser_bounds_requests(self):
        form = _parse_control_form("31", BytesIO(b"token=t&action=skip&reason=ok"))
        self.assertEqual(form["token"], "t")
        self.assertEqual(form["reason"], "ok")
        instruction = "x" * 4000
        body = ("token=t&action=queue-team-task&instruction=" + instruction).encode("utf-8")
        parsed = _parse_control_form(str(len(body)), BytesIO(body))
        self.assertEqual(parsed["instruction"], instruction)
        for content_length in ["bad", "-1", str(MAX_CONTROL_REQUEST_BYTES + 1)]:
            with self.subTest(content_length=content_length):
                with self.assertRaises(ValidationError):
                    _parse_control_form(content_length, BytesIO(b""))
        with self.assertRaises(ValidationError):
            _parse_control_form("1", BytesIO(b"\xff"))

    def test_live_control_serializes_mutations_per_run(self):
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            run_dir = root / "runs" / "serial-run"
            run_dir.mkdir(parents=True)
            active = 0
            max_active = 0
            active_lock = threading.Lock()
            results = []

            def fake_reset(target_run_dir, step_id, reason="", cascade=False):
                nonlocal active, max_active
                with active_lock:
                    active += 1
                    max_active = max(max_active, active)
                time.sleep(0.03)
                with active_lock:
                    active -= 1
                return {
                    "action": "reset-step",
                    "requested_step": step_id,
                    "affected_steps": [step_id],
                    "status": "needs_resume",
                    "run_dir": str(target_run_dir),
                }

            def call_control(index):
                results.append(
                    apply_live_control(
                        root / "runs",
                        {
                            "token": "unit-token",
                            "action": "reset",
                            "run_id": "serial-run",
                            "step_id": "step-%d" % index,
                        },
                        control_token="unit-token",
                    )
                )

            with patch("conductor_extras.runtime.live_server.reset_step", fake_reset):
                threads = [threading.Thread(target=call_control, args=(index,)) for index in range(4)]
                for thread in threads:
                    thread.start()
                for thread in threads:
                    thread.join()

            self.assertEqual(len(results), 4)
            self.assertEqual(max_active, 1)

    def test_live_http_routes_headers_and_control_redirect(self):
        workflow = workflow_with_steps(
            [
                {
                    "id": "optional",
                    "kind": "shell",
                    "risk": "low",
                    "writes": False,
                    "command": ["false"],
                },
                {
                    "id": "after",
                    "kind": "write_artifact",
                    "depends_on": ["optional"],
                    "output": "after.txt",
                    "content": "after",
                },
            ]
        )
        validate_workflow(workflow)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            secret_root = root / "token=pathsecret"
            runner = WorkflowRunner(
                workflow=workflow,
                workspace=root,
                base_run_dir=secret_root / "runs",
                policy=RuntimePolicy(),
            )
            with self.assertRaises(StepExecutionError):
                runner.execute()
            run_id = runner.run.run_dir.name
            handler_cls = _handler_factory(
                runs_dir=secret_root / "runs",
                benchmarks_dir=secret_root / "benchmarks",
                max_runs=50,
                max_reports=50,
                max_text_bytes=4096,
                title="Unit Live",
                control_token="unit-token",
            )

            status, headers, html = self._invoke_live_handler(handler_cls, "GET", "/")
            self.assertEqual(status, 200)
            self.assertEqual(headers["X-Frame-Options"], "DENY")
            self.assertIn("frame-ancestors 'none'", headers["Content-Security-Policy"])
            self.assertIn('placeholder="control token"', html)
            self.assertNotIn("unit-token", html)

            status, headers, body = self._invoke_live_handler(handler_cls, "GET", "/api/state")
            payload = json.loads(body)
            self.assertEqual(status, 200)
            self.assertEqual(payload["runs_dir"].count("pathsecret"), 0)
            self.assertIn("token=<redacted>", payload["runs_dir"])
            self.assertEqual(headers["X-Frame-Options"], "DENY")

            body = "token=unit-token&action=skip&run_id=%s&step_id=optional&reason=route" % run_id
            status, headers, _body = self._invoke_live_handler(
                handler_cls,
                "POST",
                "/control",
                body=body,
                headers={
                    "Content-Type": "application/x-www-form-urlencoded",
                    "Content-Length": str(len(body)),
                    "Host": "127.0.0.1:8765",
                    "Origin": "http://127.0.0.1:8765",
                },
            )
            self.assertEqual(status, 303)
            self.assertIn("message=", headers["Location"])
            self.assertEqual(headers["X-Frame-Options"], "DENY")
            state = json.loads((runner.run.run_dir / "state.json").read_text(encoding="utf-8"))
            self.assertEqual(state["steps"]["optional"]["status"], "skipped")

            reset_body = "token=unit-token&action=reset&run_id=%s&step_id=after" % run_id
            status, _headers, error_body = self._invoke_live_handler(
                handler_cls,
                "POST",
                "/control",
                body=reset_body,
                headers={
                    "Content-Type": "application/x-www-form-urlencoded",
                    "Content-Length": str(len(reset_body)),
                    "Host": "127.0.0.1:8765",
                    "Origin": "http://example.invalid",
                },
            )
            error_payload = json.loads(error_body)
            self.assertEqual(status, 400)
            self.assertIn("Origin", error_payload["error"])

    def _invoke_live_handler(self, handler_cls, method, path, body="", headers=None):
        handler = object.__new__(handler_cls)
        handler.path = path
        handler.rfile = BytesIO(body.encode("utf-8"))
        handler.wfile = BytesIO()
        handler.headers = Message()
        for key, value in (headers or {}).items():
            handler.headers[key] = value
        sent_headers = {}

        def send_response(status, message=None):
            handler._test_status = status

        def send_header(key, value):
            sent_headers[key] = value

        handler.send_response = send_response
        handler.send_header = send_header
        handler.end_headers = lambda: None
        if method == "GET":
            handler.do_GET()
        elif method == "POST":
            handler.do_POST()
        else:
            raise AssertionError("unsupported method %s" % method)
        return handler._test_status, sent_headers, handler.wfile.getvalue().decode("utf-8")


